local run = function(func)
	local suc, err = pcall(func)
	if not suc then
		local vain = shared.vain
		if vain and vain.CreateNotification then
			vain:CreateNotification('Vain 6872274481', 'Failure executing function: ' .. tostring(err), 3)
		end
	end
end
