-- Lock a module that has been patched by the game: force it off, make its
-- Toggle a no-op, grey out the button and append a "[PATCHED]" marker so the
-- user can see why it won't enable. Safe against profile auto-load re-enabling it.
local function markPatched(module)
	if not module then return end
	if module.Enabled then
		pcall(function() module:Toggle(true) end)
	end
	module.Toggle = function(self)
		self.Enabled = false
		if vain and vain.CreateNotification then
			vain:CreateNotification(self.Name, 'This module has been patched and is disabled.', 3, 'alert')
		end
	end
	local btn = module.Object
	if btn then
		btn.TextColor3 = Color3.fromRGB(90, 90, 90)
		if not tostring(btn.Text):find('PATCHED') then
			btn.Text = btn.Text .. "   <font color='#8a4a4a'>[PATCHED]</font>"
			btn.RichText = true
		end
	end
end

-- universal.lua loads BEFORE this file and creates generic modules that
-- duplicate richer Bedwars versions (named without spaces). Since this file
-- loads second, vain.Modules already holds the universal copies — remove the
-- ones we replace, and patch the ones that are dead on Bedwars. This is
-- place-independent so it also works on custom-match places (8444591321).
run(function()
	for _, dupeName in {'Aim Assist', 'Auto Clicker', 'Hit Boxes'} do
		if vain.Modules[dupeName] then
			vain:Remove(dupeName)
		end
	end
	if vain.Modules['Invisible'] then
		markPatched(vain.Modules['Invisible'])
	end
end)

-- First person when the camera sits (almost) on the character's head.
local function isFirstPerson()
	local char = lplr.Character
	local head = char and char:FindFirstChild('Head')
	if not head or not gameCamera then return false end
	return (gameCamera.CFrame.Position - head.Position).Magnitude < 1.5
end

-- A blocking game GUI (shop, menu, chat) is open when the game has released
-- the mouse from the locked-center state it uses for normal gameplay.
local function isGUIOpen()
	return inputService.MouseBehavior == Enum.MouseBehavior.Default
end

-- True when an entity is a valid enemy target. Uses the cached Targetable
-- flag (entitylib keeps it in sync with entitylib.targetCheck), falling back
-- to a live targetCheck so it works before the flag is first computed.
local function isEnemy(ent)
	if not ent then return false end
	if ent.Targetable ~= nil then return ent.Targetable end
	local ok, res = pcall(entitylib.targetCheck, ent)
	return ok and res or false
end

-- True when the held item is a bow or crossbow. toolType is 'bow' for both in
-- some states, so also check the tool name to reliably catch crossbows.
local function isHoldingBowCrossbow()
	if not store.hand then return false end
	local tt = store.hand.toolType
	if tt == 'bow' or tt == 'crossbow' then return true end
	local name = store.hand.tool and store.hand.tool.Name
	return name ~= nil and (name:find('bow') ~= nil or name:find('crossbow') ~= nil)
end

local function collection(tags, module, customadd, customremove)
	tags = typeof(tags) ~= 'table' and {tags} or tags
	local objs, connections = {}, {}

	for _, tag in tags do
		table.insert(connections, collectionService:GetInstanceAddedSignal(tag):Connect(function(v)
			if customadd then
				customadd(objs, v, tag)
				return
			end
			table.insert(objs, v)
		end))
		table.insert(connections, collectionService:GetInstanceRemovedSignal(tag):Connect(function(v)
			if customremove then
				customremove(objs, v, tag)
				return
			end
			v = table.find(objs, v)
			if v then
				table.remove(objs, v)
			end
		end))

		for _, v in collectionService:GetTagged(tag) do
			if customadd then
				customadd(objs, v, tag)
				continue
			end
			table.insert(objs, v)
		end
	end

	local cleanFunc = function(self)
		for _, v in connections do
			v:Disconnect()
		end
		table.clear(connections)
		table.clear(objs)
		table.clear(self)
	end
	if module then
		module:Clean(cleanFunc)
	end
	return objs, cleanFunc
end

local function getBestArmor(slot)
	local closest, mag = nil, 0

	for _, item in store.inventory.inventory.items do
		local meta = item and bedwars.ItemMeta[item.itemType] or {}

		if meta.armor and meta.armor.slot == slot then
			local newmag = (meta.armor.damageReductionMultiplier or 0)

			if newmag > mag then
				closest, mag = item, newmag
			end
		end
	end

	return closest
end

local function getBow()
	local bestBow, bestBowSlot, bestBowDamage = nil, nil, 0
	for slot, item in store.inventory.inventory.items do
		local bowMeta = bedwars.ItemMeta[item.itemType].projectileSource
		if bowMeta and table.find(bowMeta.ammoItemTypes, 'arrow') then
			local bowDamage = bedwars.ProjectileMeta[bowMeta.projectileType('arrow')].combat.damage or 0
			if bowDamage > bestBowDamage then
				bestBow, bestBowSlot, bestBowDamage = item, slot, bowDamage
			end
		end
	end
	return bestBow, bestBowSlot
end

local function getItem(itemName, inv, find)
	for slot, item in (inv or store.inventory.inventory.items) do
		if find and item.itemType:find(itemName) or item.itemType == itemName then
			return item, slot
		end
	end
	return nil
end

