			}
		end,
		HudAliveCount = require(lplr.PlayerScripts.TS.controllers.global['top-bar'].ui.game['hud-alive-player-counts']).HudAlivePlayerCounts,
		ItemMeta = debug.getupvalue(require(replicatedStorage.TS.item['item-meta']).getItemMeta, 1),
		KillEffectMeta = require(replicatedStorage.TS.locker['kill-effect']['kill-effect-meta']).KillEffectMeta,
		KillFeedController = Flamework.resolveDependency('client/controllers/game/kill-feed/kill-feed-controller@KillFeedController'),
		Knit = Knit,
		KnockbackUtil = require(replicatedStorage.TS.damage['knockback-util']).KnockbackUtil,
		MageKitUtil = require(replicatedStorage.TS.games.bedwars.kit.kits.mage['mage-kit-util']).MageKitUtil,
		NametagController = Knit.Controllers.NametagController,
		PartyController = Flamework.resolveDependency('@easy-games/lobby:client/controllers/party-controller@PartyController'),
		ProjectileMeta = require(replicatedStorage.TS.projectile['projectile-meta']).ProjectileMeta,
		QueryUtil = require(replicatedStorage['rbxts_include']['node_modules']['@easy-games']['game-core'].out).GameQueryUtil,
		QueueCard = require(lplr.PlayerScripts.TS.controllers.global.queue.ui['queue-card']).QueueCard,
		QueueMeta = require(replicatedStorage.TS.game['queue-meta']).QueueMeta,
		Roact = require(replicatedStorage['rbxts_include']['node_modules']['@rbxts']['roact'].src),
		RankMeta = require(replicatedStorage.TS.rank['rank-meta']).RankMeta,
		RuntimeLib = require(replicatedStorage['rbxts_include'].RuntimeLib),
		SummonerKitBalance = require(replicatedStorage.TS.games.bedwars.kit.kits.summoner['summoner-kit-balance']).SummonerKitBalance,
		StatusEffectUtil = require(replicatedStorage.TS['status-effect']['status-effect-util']).StatusEffectUtil,
		StatusEffectMeta = require(replicatedStorage.TS['status-effect']['status-effect-type']).StatusEffectType,
		SharedConstants = canDebug and require(replicatedStorage.TS['shared-constants']).CpsConstants or {},
		SoundList = require(replicatedStorage.TS.sound['game-sound']).GameSound,
		SoundManager = require(replicatedStorage['rbxts_include']['node_modules']['@easy-games']['game-core'].out).SoundManager,
		Store = require(lplr.PlayerScripts.TS.ui.store).ClientStore,
		TeamUpgradeMeta = debug.getupvalue(require(replicatedStorage.TS.games.bedwars['team-upgrade']['team-upgrade-meta']).getTeamUpgradeMetaForQueue, 7),
		UILayers = require(replicatedStorage['rbxts_include']['node_modules']['@easy-games']['game-core'].out).UILayers,
		VisualizerUtils = require(lplr.PlayerScripts.TS.lib.visualizer['visualizer-utils']).VisualizerUtils,
		WeldTable = require(replicatedStorage.TS.util['weld-util']).WeldUtil,
		WinEffectMeta = require(replicatedStorage.TS.locker['win-effect']['win-effect-meta']).WinEffectMeta,
		ZapNetworking = require(lplr.PlayerScripts.TS.lib.network)
	}, {
		__index = function(self, ind)
			rawset(self, ind, Knit.Controllers[ind])
			return rawget(self, ind)
		end
	})
	getgenv().bedwars = bedwars
	store.enchants = setmetatable({}, {
		__index = function(self, plr)
			return {
				async = function()
					if plr and plr.Character then
						for i in plr.Character:GetAttributes() do
							if i:find('StatusEffect_') and not i:find('_stacks') then
								local name = bedwars.StatusEffectMeta[({i:gsub('StatusEffect_', '')})[1]]
								if bedwars.StatusEffectMeta[name] then
									name = bedwars.StatusEffectMeta[name]
									for num = 1, 3 do
										name = name:gsub(`_{num}`, '')
									end

									if bedwars.EnchantMeta[name] then
										return bedwars.EnchantMeta[name].image
									end
								end
							end
						end
					end
					return nil
				end,
			}
		end
	})

	local function createMethodHook(object, method)
		local original = object[method]
		local hooks, order = {}, 0
		local wrapper

		local function sync()
			if #hooks > 0 then
				object[method] = wrapper
			elseif object[method] == wrapper then
				object[method] = original
			end
		end

		wrapper = function(...)
			local index = 0
			local function nextHook(...)
				index += 1
				local hook = hooks[index]
				if hook then
					return hook.Callback(nextHook, ...)
				end
				return original(...)
			end
			return nextHook(...)
		end

		return {
			Add = function(_, id, priority, callback)
				for i = #hooks, 1, -1 do
					if hooks[i].Id == id then
						table.remove(hooks, i)
					end
				end

				order += 1
				local entry = {
					Id = id,
					Priority = priority or 100,
					Order = order,
					Callback = callback,
				}

				table.insert(hooks, entry)
				table.sort(hooks, function(a, b)
					return a.Priority == b.Priority and a.Order < b.Order or a.Priority < b.Priority
				end)
				sync()

				return function()
					for i = #hooks, 1, -1 do
						if hooks[i] == entry then
							table.remove(hooks, i)
						end
					end
					sync()
				end
			end,
			Destroy = function()
				table.clear(hooks)
				sync()
			end,
		}
	end

	bedwars.ProjectileLaunchHook = createMethodHook(bedwars.ProjectileController, 'calculateImportantLaunchValues')
	vain:Clean(function()
		bedwars.ProjectileLaunchHook:Destroy()
	end)

	local function getproto(...)
		local success, res = pcall(debug.getproto, ...)
		return success and res or function() end
	end
	local remoteNames = {
		AfkStatus = getproto(Knit.Controllers.AfkController.KnitStart, 1),
		AttackEntity = Knit.Controllers.SwordController.sendServerRequest,
		BeePickup = Knit.Controllers.BeeNetController.trigger,
		CannonAim = getproto(Knit.Controllers.CannonController.startAiming, 5),
		CannonLaunch = Knit.Controllers.CannonHandController.launchSelf,
		ConsumeBattery = getproto(Knit.Controllers.BatteryController.onKitLocalActivated, 1),
		ConsumeItem = getproto(Knit.Controllers.ConsumeController.onEnable, 1),
		ConsumeSoul = Knit.Controllers.GrimReaperController.consumeSoul,
		ConsumeTreeOrb = getproto(Knit.Controllers.EldertreeController.createTreeOrbInteraction, 1),
		DepositPinata = getproto(getproto(Knit.Controllers.PiggyBankController.KnitStart, 2), 5),
		DragonBreath = getproto(Knit.Controllers.VoidDragonController.onKitLocalActivated, 5),
		DragonEndFly = getproto(Knit.Controllers.VoidDragonController.flapWings, 1),
		DragonFly = Knit.Controllers.VoidDragonController.flapWings,
		DropItem = Knit.Controllers.ItemDropController.dropItemInHand,
		EquipItem = getproto(require(replicatedStorage.TS.entity.entities['inventory-entity']).InventoryEntity.equipItem, 4),
		FireProjectile = debug.getupvalue(Knit.Controllers.ProjectileController.launchProjectileWithValues, 2),
		GroundHit = Knit.Controllers.FallDamageController.KnitStart,
		GuitarHeal = Knit.Controllers.GuitarController.performHeal,
		HannahKill = getproto(Knit.Controllers.HannahController.registerExecuteInteractions, 1),
		HarvestCrop = getproto(getproto(Knit.Controllers.CropController.KnitStart, 4), 1),
		KaliyahPunch = getproto(Knit.Controllers.DragonSlayerController.onKitLocalActivated, 1),
		MageSelect = getproto(Knit.Controllers.MageController.registerTomeInteraction, 1),
		MinerDig = getproto(Knit.Controllers.MinerController.setupMinerPrompts, 1),
		PickupItem = Knit.Controllers.ItemDropController.checkForPickup,
		PickupMetal = getproto(Knit.Controllers.HiddenMetalController.onKitLocalActivated, 4),
		ReportPlayer = require(lplr.PlayerScripts.TS.controllers.global.report['report-controller']).default.reportPlayer,
		ResetCharacter = getproto(Knit.Controllers.ResetController.createBindable, 1),
		SpawnRaven = getproto(Knit.Controllers.RavenController.KnitStart, 1),
		SummonerClawAttack = Knit.Controllers.SummonerClawHandController.attack,
		WarlockTarget = getproto(Knit.Controllers.WarlockStaffController.KnitStart, 2)
	}

	local packages = httpService:JSONDecode(downloadFile('vain/profiles/packages.json'))	
	local function dumpRemote(tab)
		local ind
		for i, v in tab do
			if v == 'Client' then
				ind = i
				break
			end
		end
		return ind and tab[ind + 1] or ''
	end

	for i, v in remoteNames do
		local remote = dumpRemote(debug.getconstants(v))
		if remote == '' and packages.remotes[i] then
			remote = packages.remotes[i]
		end
		if remote == '' then
			notif('Vain', 'Failed to grab remote ('..i..')', 10, 'alert')
		end
		remotes[i] = remote
	end
    getgenv().remotes = remotes

	-- capture the PRISTINE originals (never an already-installed Vain wrapper) so a
	-- re-inject wraps the game's real functions, not last session's wrapper.
	OldBreak = vainOriginals.isBlockBreakable or bedwars.BlockController.isBlockBreakable
	vainOriginals.isBlockBreakable = OldBreak
	OldHit = vainOriginals.hitBlock or bedwars.BlockBreaker.hitBlock
	vainOriginals.hitBlock = OldHit

	bedwars.BlockBreaker.hitBlock = function(...)
        pcall(function() store.lastHit = tick() end)
        -- The game's hitBlock signature is (self, maid). We forward ... verbatim so
        -- we never mangle args. pcall it so a throw can't spam the console or abort
        -- the mining loop (that was the original Line 1198 flood).
        local results = table.pack(pcall(OldHit, ...))
        if results[1] then
            return table.unpack(results, 2, results.n)
        end
    end
	Client.Get = function(self, remoteName)
		local call = OldGet(self, remoteName)

		if remoteName == remotes.AttackEntity then
			return {
				instance = call.instance,
				SendToServer = function(_, attackTable, ...)
					local suc, plr = pcall(function()
						return playersService:GetPlayerFromCharacter(attackTable.entityInstance)
					end)

					local selfpos = attackTable.validate.selfPosition.value
					local targetpos = attackTable.validate.targetPosition.value
					store.attackReach = ((selfpos - targetpos).Magnitude * 100) // 1 / 100
					store.attackReachUpdate = tick() + 1

					if Reach.Enabled or HitBoxes.Enabled then
						attackTable.validate.raycast = attackTable.validate.raycast or {}
						attackTable.validate.selfPosition.value += CFrame.lookAt(selfpos, targetpos).LookVector * math.max((selfpos - targetpos).Magnitude - 14.399, 0)
					end

					if suc and plr then
						if not select(2, whitelist:get(plr)) then return end
					end

					return call:SendToServer(attackTable, ...)
				end
			}
		elseif remoteName == 'StepOnSnapTrap' and TrapDisabler.Enabled then
			return {SendToServer = function() end}
		end

		return call
	end

	bedwars.BlockController.isBlockBreakable = function(self, breakTable, plr)
		-- Only our bed-protection logic is custom; if anything in it throws,
		-- fall through to the original so a hook error can't make every block
		-- look unbreakable (i.e. silently disable mining on inject).
		local ok, deny = pcall(function()
			local obj = bedwars.BlockController:getStore():getBlockAt(breakTable.blockPosition)
			if obj and obj.Name == 'bed' then
				for _, other in playersService:GetPlayers() do
					if obj:GetAttribute('Team'..(other:GetAttribute('Team') or 0)..'NoBreak') and not select(2, whitelist:get(other)) then
						return true
					end
				end
			end
			return false
		end)

		if ok and deny then return false end

		return OldBreak(self, breakTable, plr)
	end

	local cache, blockhealthbar = {}, {blockHealth = -1, breakingBlockPosition = Vector3.zero}
	store.blockPlacer = bedwars.BlockPlacer.new(bedwars.BlockEngine, 'wool_white')

	local function getBlockHealth(block, blockpos)
		local blockdata = bedwars.BlockController:getStore():getBlockData(blockpos)
		return (blockdata and (blockdata:GetAttribute('1') or blockdata:GetAttribute('Health')) or block:GetAttribute('Health'))
	end

	getBlockHits = function(block, blockpos)
		if not block then return 0 end
		local breaktype = bedwars.ItemMeta[block.Name].block.breakType
		local tool = store.tools[breaktype]
		tool = tool and bedwars.ItemMeta[tool.itemType].breakBlock[breaktype] or 2
		return getBlockHealth(block, bedwars.BlockController:getBlockPosition(blockpos)) / tool
	end

	--[[
		Pathfinding using a luau version of dijkstra's algorithm
		Source: https://stackoverflow.com/questions/39355587/speeding-up-dijkstras-algorithm-to-solve-a-3d-maze
	]]
	local function calculatePath(target, blockpos, method, angle)
		if cache[blockpos] and cache[blockpos][4] > tick() then
			return unpack(cache[blockpos])
		end
		local visited, unvisited, distances, air, path = {}, {{0, blockpos}}, {[blockpos] = 0}, {}, {}

		for _ = 1, 10000 do
			local _, node = next(unvisited)
			if not node then break end
			table.remove(unvisited, 1)
			visited[node[2]] = true

			for _, side in sides do
				side = node[2] + side
				if visited[side] then continue end

				local block = getPlacedBlock(side)
				if not block or block:GetAttribute('NoBreak') or block == target then
					if not block then
						air[node[2]] = true
					end
					continue
				end

				if math.acos((gameCamera.CFrame.LookVector * Vector3.new(1, 0, 1)):Dot(((block.Position - entitylib.character.RootPart.Position) * Vector3.new(1, 0, 1)).Unit)) > (math.rad(angle) / 2) then
					continue
				end

				local curdist = (method and method(block, side) or getBlockHits(block, side)) + node[1]
				if curdist < (distances[side] or math.huge) then
					table.insert(unvisited, {curdist, side})
					distances[side] = curdist
					path[side] = node[2]
				end
			end
		end

		local pos, cost = nil, math.huge
		for node in air do
			if distances[node] < cost then
				pos, cost = node, distances[node]
			end
		end

		if pos then
			cache[blockpos] = {
				pos,
				cost,
				path,
				tick() + (inputService.TouchEnabled and 9e9 or 1)
			}
			return pos, cost, path
		end
		return nil
	end

	bedwars.placeBlock = function(pos, item)
		if getItem(item) then
			store.blockPlacer.blockType = item
			return store.blockPlacer:placeBlock(bedwars.BlockController:getBlockPosition(pos))
		end
	end

	bedwars.breakBlock = function(block, effects, anim, customHealthbar, visualise, sort, angle)
		if lplr:GetAttribute('DenyBlockBreak') or not entitylib.isAlive or InfiniteFly.Enabled then return end

		local handler = bedwars.BlockController:getHandlerRegistry():getHandler(block.Name)
		local cost, pos, target, path = math.huge, nil, nil, nil

		for _, v in (handler and handler:getContainedPositions(block) or {block.Position / 3}) do
			local dpos, dcost, dpath = calculatePath(block, v * 3, sort, angle or 360)
			if dpos and dcost < cost then
				cost, pos, target, path = dcost, dpos, v * 3, dpath
			end
		end

		if pos then
			if (entitylib.character.RootPart.Position - pos).Magnitude > 30 then return end
			local dblock, dpos = getPlacedBlock(pos)
			if not dblock then return end

			if (workspace:GetServerTimeNow() - bedwars.SwordController.lastAttack) > 0.4 then
				local breaktype = dblock.Name == 'gumdrop_bounce_pad' and 'stone' or bedwars.ItemMeta[dblock.Name].block.breakType
				local tool = store.tools[breaktype]
				if tool then
					if visualise then
						local hotbar = getHotbar(tool.tool)
						if hotbar then
							hotbarSwitch(hotbar)
						end
					else
						switchItem(tool.tool)
					end
				end
			end

			if blockhealthbar.blockHealth == -1 or dpos ~= blockhealthbar.breakingBlockPosition then
				blockhealthbar.blockHealth = getBlockHealth(dblock, dpos)
				blockhealthbar.breakingBlockPosition = dpos
			end

			bedwars.ClientDamageBlock:Get('DamageBlock'):CallServerAsync({
				blockRef = {blockPosition = dpos},
				hitPosition = pos,
				hitNormal = Vector3.FromNormalId(Enum.NormalId.Top)
			}):andThen(function(result)
				if result then
					if result == 'cancelled' then
						store.damageBlockFail = tick() + 1
						return
					end

					if effects then
						local blockdmg = (blockhealthbar.blockHealth - (result == 'destroyed' and 0 or getBlockHealth(dblock, dpos)))
						customHealthbar = customHealthbar or bedwars.BlockBreaker.updateHealthbar
						customHealthbar(bedwars.BlockBreaker, {blockPosition = dpos}, blockhealthbar.blockHealth, dblock:GetAttribute('MaxHealth'), blockdmg, dblock)
						blockhealthbar.blockHealth = math.max(blockhealthbar.blockHealth - blockdmg, 0)

						if blockhealthbar.blockHealth <= 0 then
							bedwars.BlockBreaker.breakEffect:playBreak(dblock.Name, dpos, lplr)
							bedwars.BlockBreaker.healthbarMaid:DoCleaning()
							blockhealthbar.breakingBlockPosition = Vector3.zero
						else
							bedwars.BlockBreaker.breakEffect:playHit(dblock.Name, dpos, lplr)
						end
					end

					if anim then
						local animation = bedwars.AnimationUtil:playAnimation(lplr, bedwars.BlockController:getAnimationController():getAssetId(1))
						bedwars.ViewmodelController:playAnimation(15)
						task.wait(0.3)
						animation:Stop()
						animation:Destroy()
					end
				end
			end)

			if effects then
				return pos, path, target
			end
		end
		return nil
	end

	for _, v in Enum.NormalId:GetEnumItems() do
		table.insert(sides, Vector3.FromNormalId(v) * 3)
	end

	local function updateStore(new, old)
		if new.Bedwars ~= old.Bedwars then
			store.equippedKit = new.Bedwars.kit ~= 'none' and new.Bedwars.kit or ''
		end

		if new.Game ~= old.Game then
			store.matchState = new.Game.matchState
			store.queueType = new.Game.queueType or 'bedwars_test'
		end

		if new.Inventory ~= old.Inventory then
			local newinv = (new.Inventory and new.Inventory.observedInventory or {inventory = {}})
			local oldinv = (old.Inventory and old.Inventory.observedInventory or {inventory = {}})
			store.inventory = newinv

			if newinv ~= oldinv then
				vainEvents.InventoryChanged:Fire()
			end

			if newinv.inventory.items ~= oldinv.inventory.items then
				vainEvents.InventoryAmountChanged:Fire()
				store.tools.sword = getSword()
				for _, v in {'stone', 'wood', 'wool'} do
					store.tools[v] = getTool(v)
				end
			end

			if newinv.inventory.hand ~= oldinv.inventory.hand then
				local currentHand, toolType = new.Inventory.observedInventory.inventory.hand, ''
				if currentHand then
					local handData = bedwars.ItemMeta[currentHand.itemType]
					toolType = handData.sword and 'sword' or handData.block and 'block' or currentHand.itemType:find('bow') and 'bow'
				end

				store.hand = {
					tool = currentHand and currentHand.tool,
					amount = currentHand and currentHand.amount or 0,
					toolType = toolType
				}
			end
		end
	end

	local storeChanged = bedwars.Store.changed:connect(updateStore)
	updateStore(bedwars.Store:getState(), {})

	for _, event in {'MatchEndEvent', 'EntityDeathEvent', 'BedwarsBedBreak', 'BalloonPopped', 'AngelProgress', 'GrapplingHookFunctions'} do
		if not vain.Connections then return end
		bedwars.Client:WaitFor(event):andThen(function(connection)
			vain:Clean(connection:Connect(function(...)
				vainEvents[event]:Fire(...)
			end))
		end)
	end

	vain:Clean(bedwars.ZapNetworking.EntityDamageEventZap.On(function(...)
		vainEvents.EntityDamageEvent:Fire({
			entityInstance = ...,
			damage = select(2, ...),
			damageType = select(3, ...),
			fromPosition = select(4, ...),
			fromEntity = select(5, ...),
			knockbackMultiplier = select(6, ...),
			knockbackId = select(7, ...),
			disableDamageHighlight = select(13, ...)
		})
	end))
	
	vain:Clean(workspace.ChildAdded:Connect(function(projectile)
		task.delay(0, function()
			if projectile and projectile.Parent and entitylib.isAlive and projectile:GetAttribute('ProjectileShooter') == lplr.UserId then
				table.insert(store.selfProjectiles, projectile)
				projectile.Destroying:Once(function()
					local index = table.find(store.selfProjectiles, projectile)
					if index then
						table.remove(store.selfProjectiles, index)
					end
				end)
			end
		end)
	end))

	for _, event in {'BreakBlockEvent'} do
		vain:Clean(bedwars.ZapNetworking[event..'Zap'].On(function(...)
			local data = {
				blockRef = {
					blockPosition = ...,
				},
				player = select(5, ...)
			}
			for i, v in cache do
				if ((data.blockRef.blockPosition * 3) - v[1]).Magnitude <= 30 then
					table.clear(v[3])
					table.clear(v)
					cache[i] = nil
				end
			end
			vainEvents[event]:Fire(data)
		end))
	end

	store.blocks = collection('block', vain)
	store.shop = collection({'BedwarsItemShop', 'TeamUpgradeShopkeeper'}, vain, function(tab, obj)
		table.insert(tab, {
			Id = obj.Name,
			RootPart = obj,
			Shop = obj:HasTag('BedwarsItemShop'),
			Upgrades = obj:HasTag('TeamUpgradeShopkeeper')
		})
	end)
	store.enchant = collection({'enchant-table', 'broken-enchant-table'}, vain, nil, function(tab, obj, tag)
		if obj:HasTag('enchant-table') and tag == 'broken-enchant-table' then return end
		obj = table.find(tab, obj)
		if obj then
			table.remove(tab, obj)
		end
	end)

	local kills = sessioninfo:AddItem('Kills')
	local beds = sessioninfo:AddItem('Beds')
	local wins = sessioninfo:AddItem('Wins')
	local games = sessioninfo:AddItem('Games')

	local mapname = 'Unknown'
	sessioninfo:AddItem('Map', 0, function()
		return mapname
	end, false)

	task.delay(1, function()
		games:Increment()
	end)

	task.spawn(function()
		pcall(function()
			repeat task.wait() until store.matchState ~= 0 or vain.Loaded == nil
			if vain.Loaded == nil then return end
			store.map = waitForChildYield(workspace, 9e9, 'Map', 'Worlds'):GetChildren()[1]
			mapname = store.map.Name
			mapname = string.gsub(string.split(mapname, '_')[2] or mapname, '-', '') or 'Blank'
			if store.map then
				vain:Clean(store.map.Blocks.ChildAdded:Connect(function(v) -- bedwars game is so bad bro 😭 how did you even break this event
					task.delay(0, function()
						if v:GetAttribute('Block') and (v:GetAttribute('PlacedByUserId') or 0) ~= 0 then
							local data = {
								blockRef = {
									blockPosition = v.Position / 3,
								},
								player = playersService:GetPlayerByUserId(v:GetAttribute('PlacedByUserId')),
							}
							for i, v in cache do
								if ((data.blockRef.blockPosition * 3) - v[1]).Magnitude <= 30 then
									table.clear(v[3])
									table.clear(v)
									cache[i] = nil
								end
							end
							vainEvents.PlaceBlockEvent:Fire(data)
						end
					end)
				end))
			end
		end)
	end)

	vain:Clean(vainEvents.BedwarsBedBreak.Event:Connect(function(bedTable)
		if bedTable.player and bedTable.player.UserId == lplr.UserId then
			beds:Increment()
		end
	end))

	vain:Clean(vainEvents.MatchEndEvent.Event:Connect(function(winTable)
		if (bedwars.Store:getState().Game.myTeam or {}).id == winTable.winningTeamId or lplr.Neutral then
			wins:Increment()
		end
	end))

	vain:Clean(vainEvents.EntityDeathEvent.Event:Connect(function(deathTable)
		local killer = playersService:GetPlayerFromCharacter(deathTable.fromEntity)
		local killed = playersService:GetPlayerFromCharacter(deathTable.entityInstance)
		if not killed or not killer then return end

		if killed ~= lplr and killer == lplr then
			kills:Increment()
		end
	end))

	task.spawn(function()
		local rayParams = RaycastParams.new()
		rayParams.FilterType = Enum.RaycastFilterType.Include
		rayParams.FilterDescendantsInstances = {workspace:WaitForChild('Map', 9e9)}
		store.airRay = rayParams

		repeat
			if entitylib.isAlive then
				entitylib.character.AirTime = workspace:Raycast((store.rootpart or entitylib.character.RootPart).Position, Vector3.new(0, -4.5, 0), rayParams) and tick() or entitylib.character.AirTime
			end

			for _, v in entitylib.List do
				v.LandTick = math.abs(v.RootPart.Velocity.Y) < 0.1 and v.LandTick or tick()
				if (tick() - v.LandTick) > 0.2 and v.Jumps ~= 0 then
					v.Jumps = 0
					v.Jumping = false
				end
			end
			task.wait()
		until vain.Loaded == nil
	end)

	pcall(function()
		if getthreadidentity and setthreadidentity then
			local old = getthreadidentity()
			setthreadidentity(2)

			bedwars.Shop = require(replicatedStorage.TS.games.bedwars.shop['bedwars-shop']).BedwarsShop
			bedwars.ShopItems = debug.getupvalue(debug.getupvalue(bedwars.Shop.getShopItem, 1), 2)
			bedwars.Shop.getShopItem('iron_sword', lplr)

			setthreadidentity(old)
			store.shopLoaded = true
		else
			task.spawn(function()
				repeat
					task.wait(0.1)
				until vain.Loaded == nil or bedwars.AppController:isAppOpen('BedwarsItemShopApp')

				bedwars.Shop = require(replicatedStorage.TS.games.bedwars.shop['bedwars-shop']).BedwarsShop
				bedwars.ShopItems = debug.getupvalue(debug.getupvalue(bedwars.Shop.getShopItem, 1), 2)
				store.shopLoaded = true
			end)
		end
	end)

	vain:Clean(function()
		Client.Get = OldGet
		bedwars.BlockController.isBlockBreakable = OldBreak
		bedwars.BlockBreaker.hitBlock = OldHit
		store.blockPlacer:disable()
		for _, v in vainEvents do
			v:Destroy()
		end
		for _, v in cache do
			table.clear(v[3])
			table.clear(v)
		end
		table.clear(store.blockPlacer)
		table.clear(vainEvents)
		table.clear(bedwars)
		table.clear(store)
		table.clear(cache)
		table.clear(sides)
		table.clear(remotes)
		storeChanged:disconnect()
		storeChanged = nil
	end)
end)

for _, v in {'Anti Ragdoll', 'Trigger Bot', 'Silent Aim', 'Auto Rejoin', 'Rejoin', 'Disabler', 'Timer', 'Server Hop', 'Mouse TP', 'Murder Mystery'} do
	vain:Remove(v)
end

local AntiFallDirection
local Fly
local LongJump
local Attacking

--[[
    Combat
]]

run(function()
local AimAssist
	local Targets
	local Sort
	local AimSpeed
	local Smoothness
	local SmoothnessToggle
	local Distance
	local AngleSlider
	local KillauraTarget
	local ClickAim
	local ShopCheck
	local AimPart
	local ViewMode
	local PriorityMode
	local ShakeToggle
	local ShakeAmount
	local WorkWithProjectiles
	local LimitToItem
	local MinDistance
	local HealthCheck
	local HealthThreshold

	local lockedTarget = nil
	local lastValidTarget = nil
	local lastValidTime = 0
	local GRACE_PERIOD = 0.15
	local rng = Random.new()
	local shakeTime = 0

	local function getSmoothedSpeed(speedVal, smoothVal, dt)
		local rawSpeed = 0.01 * (1.35 ^ speedVal)
		local smoothScale = math.max(1 - ((smoothVal - 1) / 9) * 0.88, 0.01)
		return math.min(rawSpeed * smoothScale, 0.95)
	end

	local function getClosestPartToCursor(character)
		local mousePos = inputService:GetMouseLocation()
		local mouseRay = gameCamera:ViewportPointToRay(mousePos.X, mousePos.Y, 0)
		local bestAngle = math.huge
		local bestPart = nil
		local partNames = {
			'Head', 'UpperTorso', 'LowerTorso', 'HumanoidRootPart',
			'LeftUpperArm', 'RightUpperArm', 'LeftLowerArm', 'RightLowerArm',
			'LeftUpperLeg', 'RightUpperLeg', 'LeftLowerLeg', 'RightLowerLeg',
			'LeftFoot', 'RightFoot', 'LeftHand', 'RightHand'
		}
		for _, partName in partNames do
			local part = character:FindFirstChild(partName)
			if part then
				local dirToPart = (part.Position - mouseRay.Origin).Unit
				local angle = math.acos(math.clamp(mouseRay.Direction:Dot(dirToPart), -1, 1))
				if angle < bestAngle then
					bestAngle = angle
					bestPart = part
				end
			end
		end
		return bestPart
	end

	local function isEntValid(ent)
		if not ent or not ent.RootPart or not ent.Character or not ent.Character.Parent then return false end
		if not entitylib.isAlive or not entitylib.character or not entitylib.character.RootPart then return false end
		local hum = ent.Character:FindFirstChildOfClass('Humanoid')
		if not hum or hum.Health <= 0 then return false end
		local dist = (ent.RootPart.Position - entitylib.character.RootPart.Position).Magnitude
		if dist > Distance.Value then return false end
		if not isEnemy(ent) then return false end
		return true
	end

	local function isInAngle(ent)
		if not ent or not ent.RootPart then return false end
		if not entitylib.character or not entitylib.character.RootPart then return false end
		local delta = (ent.RootPart.Position - entitylib.character.RootPart.Position)
		local localFacing = (ViewMode.Value == 'Third Person' and gameCamera.CFrame.LookVector or entitylib.character.RootPart.CFrame.LookVector) * Vector3.new(1, 0, 1)
		local flatDelta = delta * Vector3.new(1, 0, 1)
		if flatDelta.Magnitude <= 0.001 then return false end
		local angle = math.acos(math.clamp(localFacing:Dot(flatDelta.Unit), -1, 1))
		return angle < math.rad(AngleSlider.Value / 2)
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  SIGRID CHARGE  (Antler Uppercut -- press to fire the charge on a target)
	-- ══════════════════════════════════════════════════════════════════════════
	-- The Elk/Sigrid "Antler Uppercut" is server-driven but CLIENT-APPLIED: the
	-- server fires SigridBeginCharge{player=X} and X's own client pushes its root
	-- forward every Heartbeat. The charge is requested with the client-supplied
	-- target via bedwars.Client:Get('SigridBeginChargeRequest'):CallServer{player=X}.
	-- This is a BUTTON (press = one charge), it requires you to be mounted on your
	-- Elk first, targets the player you pick from the dropdown, and is Premium-only.
	do
		local SigridCharge, Target, Notify, AutoMount, SkipMount
		local function getRemote()
			local ok, r = pcall(function() return bedwars.Client:Get('SigridBeginChargeRequest') end)
			return ok and r or nil
		end
		-- mounted on the Elk? getActiveMounts() is keyed by player (place: line 451593)
		local function isMounted()
			local ok, mounts = pcall(function() return bedwars.MountController:getActiveMounts() end)
			return ok and mounts ~= nil and mounts[lplr] ~= nil
		end
		-- summon the Elk via the ELK_SUMMON ability ("elk_summon"), then wait up to
		-- ~1.5s for the mount to register. Returns true once mounted.
		local function ensureMounted()
			if isMounted() then return true end
			pcall(function()
				if bedwars.AbilityController:canUseAbility('elk_summon') then
					bedwars.AbilityController:useAbility('elk_summon')
				end
			end)
			local deadline = tick() + 1.5
			repeat task.wait(0.05) until isMounted() or tick() > deadline
			return isMounted()
		end
		local function resolveTarget()
			local name = Target and Target.Value
			if not name or name == 'None' then return nil end
			return playersService:FindFirstChild(name)
		end
		SigridCharge = vain.Categories.Kits:CreateModule({
			Name = 'Sigrid Charge',
			Tooltip = 'Press to fire the Elk/Sigrid Antler Uppercut charge at the player chosen in the Target dropdown. You must be mounted on your Elk first. Premium only.',
			Function = function(callback)
				if not callback then return end
				-- act like a one-shot button: do the work, then toggle straight back off
				local function done() if SigridCharge.Enabled then SigridCharge:Toggle() end end
				if (vain.Tier or 0) < 1 then
					vain:CreateNotification('Sigrid Charge', 'Premium only -- Free tier cannot use this.', 5, 'alert')
					return done()
				end
				-- Skip Mount Check: fire the request regardless of mount/character
				-- state (for spectator use / testing whether the server validates the
				-- requester). If it lands, the server only trusts the target field.
				if not (SkipMount and SkipMount.Enabled) and not isMounted() then
					if AutoMount and AutoMount.Enabled then
						if not ensureMounted() then
							vain:CreateNotification('Sigrid Charge', 'Could not mount the Elk (do you have the Sigrid kit?).', 5, 'warning')
							return done()
						end
					else
						vain:CreateNotification('Sigrid Charge', 'You must be mounted on your Elk first (or enable Auto Mount / Skip Mount Check).', 5, 'warning')
						return done()
					end
				end
				local remote = getRemote()
				if not remote then
					vain:CreateNotification('Sigrid Charge', 'Elk charge remote not found in this place.', 6, 'warning')
					return done()
				end
				local target = resolveTarget()
				if not target then
					vain:CreateNotification('Sigrid Charge', 'Pick a target player in the dropdown first.', 5, 'warning')
					return done()
				end
				pcall(function() remote:CallServer({ player = target }) end)
				if Notify and Notify.Enabled then
					vain:CreateNotification('Sigrid Charge', 'Charge fired on ' .. target.Name, 3)
				end
				done()
			end
		})
		Target = SigridCharge:CreateDropdown({ Name = 'Target', List = { 'None' }, Default = 'None',
			Function = function() end,
			Tooltip = 'Player to send the charge to (updates as players join/leave).' })
		AutoMount = SigridCharge:CreateToggle({ Name = 'Auto Mount', Default = false,
			Tooltip = 'If you are not on your Elk when you press, summon it first (uses the ELK_SUMMON ability) and wait for the mount before charging. Requires the Sigrid kit.' })
		SkipMount = SigridCharge:CreateToggle({ Name = 'Skip Mount Check', Default = false,
			Tooltip = 'Fire the charge even when not mounted (e.g. as a SPECTATOR). Only works if the server trusts the request without checking the sender is a mounted Sigrid -- test it and see.' })
		Notify = SigridCharge:CreateToggle({ Name = 'Notify', Default = true,
			Tooltip = 'Notify when a charge is fired.' })
		if SigridCharge.MarkPremium then SigridCharge:MarkPremium() end

		-- keep the Target dropdown in sync with the current players (excluding you)
		local function refreshTargets()
			if not Target then return end
			local names = {}
			for _, plr in playersService:GetPlayers() do
				if plr ~= lplr then table.insert(names, plr.Name) end
			end
			if #names == 0 then names = { 'None' } end
			if type(Target.Change) == 'function' then pcall(function() Target:Change(names) end) end
		end
		refreshTargets()
		vain:Clean(playersService.PlayerAdded:Connect(refreshTargets))
		vain:Clean(playersService.PlayerRemoving:Connect(function() task.defer(refreshTargets) end))
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  ADVANCED SPECTATE  (spectate anyone; optionally lock to one player)
	-- ══════════════════════════════════════════════════════════════════════════
	-- The game's SpectateController defaults to mode TEAM, which restricts the
	-- spectate cycle to your (or the reported ticket's) team. Its SpectateMode enum
	-- has ALL (0), TEAM (1), PLAYER (2). We simply force mode = ALL so the built-in
	-- getSpectateTargets returns EVERY in-game player (spectators aren't in-game, so
	-- they're naturally excluded). Fixed Spectate hooks getSpectateTargets to return
	-- only the chosen player, so the game's own auto-next-on-death can only ever
	-- land back on them.
	do
		local AdvancedSpectate, FixedSpectate, FixedPlayer, SpectateTeam
		local origGetTargets, spec
		-- maps the "Spectate Team" dropdown label -> team id (nil = All Teams)
		local teamLabelToId = {}

		local function getSpec()
			if spec then return spec end
			local ok, ctrl = pcall(function() return bedwars.SpectateController end)
			if ok and type(ctrl) == 'table' then spec = ctrl end
			return spec
		end

		-- resolve the currently-selected fixed player by name
		local function fixedPlr()
			local name = FixedPlayer and FixedPlayer.Value
			if not name or name == 'None' then return nil end
			return playersService:FindFirstChild(name)
		end

		-- OfflinePlayerUtil converts a live Player into the {userId=..} shape the
		-- store's spectatingPlayer field expects. Resolve it lazily/cached.
		local offlineUtil
		local function getOfflineUtil()
			if offlineUtil ~= nil then return offlineUtil or nil end
			local ok, mod = pcall(function()
				return require(replicatedStorage.TS.player['offline-player-util']).OfflinePlayerUtil
			end)
			offlineUtil = (ok and mod) or false
			return offlineUtil or nil
		end

		-- Snap the spectate camera straight onto `plr`. The game's
		-- switchSpectateTargets only understands "next"/"prev" (a Player arg is
		-- treated as "prev"), so we dispatch GameSetSpectator ourselves -- exactly
		-- what the server's SpectatePlayer remote does.
		local function snapTo(plr)
			if not plr then return false end
			local util = getOfflineUtil()
			local sp
			if util and util.getOfflinePlayer then
				local ok, res = pcall(function() return util.getOfflinePlayer(plr) end)
				if ok then sp = res end
			end
			if not sp then sp = { userId = plr.UserId } end
			return pcall(function()
				bedwars.Store:dispatch({
					type = 'GameSetSpectator',
					spectating = true,
					spectatingPlayer = sp,
				})
			end)
		end

		-- Un-fixate / leave the spectate view. Two cases:
		--  * live player -> stopSpectatingPlayer() returns your camera to your body.
		--  * genuine spectator (dead / lobby) the game refuses to release -> the
		--    camera stays glued to the locked player, so we advance to a DIFFERENT
		--    target so you're visibly un-pinned. Deferred one heartbeat so our
		--    spectatingPlayer=nil dispatch settles first (otherwise switchSpectateTargets
		--    re-reads 'current = locked player' and lands right back on them).
		-- Shared by BOTH the Fixed Spectate toggle-off AND the module toggle-off (the
		-- latter leaves FixedSpectate.Enabled true, so it can't gate on that).
		local function leaveSpectate(ctrl)
			if not ctrl then return end
			pcall(function() ctrl:stopSpectatingPlayer() end)
			task.defer(function()
				if lplr:GetAttribute('Spectator') == true then
					pcall(function()
						if ctrl.switchSpectateTargets then ctrl:switchSpectateTargets('next') end
					end)
				end
			end)
		end

		AdvancedSpectate = vain.Categories.Utility:CreateModule({
			Name = 'Better Spectating',
			Tooltip = 'Spectate ANYONE, not just your team (forces the spectate mode to ALL). Enable Fixed Spectate + pick a player to lock the view to them.',
			Function = function(callback)
				local ctrl = getSpec()
				if callback then
					if not ctrl then
						notif('Better Spectating', 'Spectate controller not found in this place.', 6, 'warning')
						AdvancedSpectate:Toggle()
						return
					end
					-- force ALL mode so every in-game player is spectatable
					pcall(function()
						local ALL = ctrl.SpectateMode and ctrl.SpectateMode.ALL or 0
						if ctrl.setSpectateMode then ctrl:setSpectateMode(ALL) else ctrl.mode = ALL end
					end)
					-- keep it pinned to ALL (the game may reset mode on events) and
					-- apply the Fixed Spectate hook.
					if not origGetTargets and ctrl.getSpectateTargets then
						origGetTargets = ctrl.getSpectateTargets
						ctrl.getSpectateTargets = function(selfc, ...)
							if FixedSpectate and FixedSpectate.Enabled then
								local p = fixedPlr()
								if p then return { p } end -- only ever this player
							end
							local targets = origGetTargets(selfc, ...)
							-- "Spectate Team": if a specific team is chosen, keep only its
							-- players; "All Teams" (nil) leaves the full ALL list intact.
							local teamId = SpectateTeam and teamLabelToId[SpectateTeam.Value]
							if teamId ~= nil and type(targets) == 'table' then
								local filtered = {}
								for _, pl in targets do
									if pl:GetAttribute('Team') == teamId then
										filtered[#filtered + 1] = pl
									end
								end
								if #filtered > 0 then return filtered end
							end
							return targets
						end
					end
					-- if Fixed Spectate is already on, snap onto the fixed player now
					-- (so re-enabling the module re-fixates as expected).
					if FixedSpectate and FixedSpectate.Enabled then
						snapTo(fixedPlr())
					end
				else
					-- restore the original target resolver + let the game manage mode
					if origGetTargets and ctrl and ctrl.getSpectateTargets ~= origGetTargets then
						ctrl.getSpectateTargets = origGetTargets
					end
					origGetTargets = nil
					if ctrl then
						-- Un-fixate even if Fixed Spectate is still enabled (module off
						-- doesn't flip that sub-toggle). Same robust leave as the toggle.
						leaveSpectate(ctrl)
						pcall(function()
							local TEAM = ctrl.SpectateMode and ctrl.SpectateMode.TEAM or 1
							if ctrl.setSpectateMode then ctrl:setSpectateMode(TEAM) else ctrl.mode = TEAM end
						end)
					end
				end
			end
		})
		FixedSpectate = AdvancedSpectate:CreateToggle({
			Name = 'Fixed Spectate',
			Tooltip = 'Lock spectating to the selected player. If they die, the game auto-switches — this snaps the view straight back to them.',
			Default = false,
			Function = function(callback)
				local ctrl = getSpec()
				if callback then
					-- ON: snap onto the fixed player (only if the module is enabled)
					if AdvancedSpectate.Enabled then
						snapTo(fixedPlr())
					end
				else
					-- OFF: un-fixate. The getSpectateTargets hook now falls through to
					-- everyone (FixedSpectate.Enabled is false). Two cases:
					--  * you're a live player -> stopSpectatingPlayer() returns your
					--    camera to your own body (that's the whole un-fixate).
					--  * you're a genuine spectator (dead / lobby) -> the game won't let
					--    you leave spectate, so instead of stopping we clear the lock and
					--    advance to a DIFFERENT player so you're no longer pinned. We do
					--    the advance on the next heartbeat so the spectatingPlayer=nil
					--    dispatch settles first (otherwise switchSpectateTargets re-reads
					--    the stale 'current = fixed player' state and lands right back).
					leaveSpectate(ctrl)
				end
			end
		})
		FixedPlayer = AdvancedSpectate:CreateDropdown({
			Name = 'Fixed Player',
			List = { 'None' },
			Default = 'None',
			Tooltip = 'Which player to lock onto when Fixed Spectate is on.',
			Function = function()
				-- snap onto the newly-picked player right away
				if AdvancedSpectate.Enabled and FixedSpectate and FixedSpectate.Enabled then
					snapTo(fixedPlr())
				end
			end
		})
		SpectateTeam = AdvancedSpectate:CreateDropdown({
			Name = 'Spectate Team',
			List = { 'All Teams' },
			Default = 'All Teams',
			Tooltip = 'Spectate every team ("All Teams") or restrict the spectate cycle to one specific team. Ignored while Fixed Spectate is on.',
			Function = function()
				-- advance to a valid target within the newly-chosen team right away
				local ctrl = getSpec()
				if AdvancedSpectate.Enabled and ctrl and not (FixedSpectate and FixedSpectate.Enabled) then
					pcall(function()
						if ctrl.switchSpectateTargets then ctrl:switchSpectateTargets('next') end
					end)
				end
			end
		})

		-- keep the Fixed Player + Spectate Team dropdowns in sync with the server
		local function refreshList()
			local names = { 'None' }
			for _, plr in playersService:GetPlayers() do
				if plr ~= lplr then names[#names + 1] = plr.Name end
			end
			pcall(function() FixedPlayer:Change(names) end)

			-- rebuild the team list from the store (label -> id map for filtering)
			local teamNames = { 'All Teams' }
			teamLabelToId = {}
			pcall(function()
				local teams = bedwars.Store:getState().Game.teams
				if type(teams) == 'table' then
					local list = {}
					for _, t in teams do list[#list + 1] = t end
					table.sort(list, function(a, b) return tostring(a.id) < tostring(b.id) end)
					for _, t in list do
						local label = (t.name and tostring(t.name)) or ('Team ' .. tostring(t.id))
						-- avoid a label clashing with 'All Teams' or duplicates
						if label ~= 'All Teams' and not teamLabelToId[label] then
							teamNames[#teamNames + 1] = label
							teamLabelToId[label] = t.id
						end
					end
				end
			end)
			pcall(function() SpectateTeam:Change(teamNames) end)
		end
		refreshList()
		vain:Clean(playersService.PlayerAdded:Connect(refreshList))
		vain:Clean(playersService.PlayerRemoving:Connect(function() task.defer(refreshList) end))
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  PREPARATION PREVIEW  (see teams/players/kits while spectating the draft)
	-- ══════════════════════════════════════════════════════════════════════════
	-- When you spectate a match that's still in the kit-ban / kit-selection phase,
	-- the game renders NOTHING for you (its draft UI bails when you have no myTeam).
	-- The data is still in the replicated ClientStore though:
	--   store.Game.teams[].members[].userId        -- teams + their players
	--   store.Draft.teamData.kitSelection[userId]  -- each player's chosen kit
	--   store.Draft.sharedData.kitBans[teamId]      -- banned kits per team
	-- bedwars.BedwarsKitMeta[kitId] = { name, renderImage }. We read all that and
	-- draw our own overlay: a column per team, each player row = avatar + name + kit.
	do
		local PrepPreview
		local gui

		local function kitMeta(kitId)
			if not kitId or kitId == '' then return nil end
			return bedwars.BedwarsKitMeta and bedwars.BedwarsKitMeta[kitId]
		end

		-- Resolve the MatchDraftPhase enum module once (values may be strings or
		-- numbers depending on the build) so we can name the current phase.
		local phaseEnum
		local function getPhaseEnum()
			if phaseEnum ~= nil then return phaseEnum or nil end
			local ok, mod = pcall(function()
				return require(replicatedStorage.TS.match.draft['match-draft-phase']).MatchDraftPhase
			end)
			phaseEnum = (ok and mod) or false
			return phaseEnum or nil
		end

		-- Friendly, user-facing label for the current draft phase.
		local PHASE_LABELS = {
			LOADING = 'Loading…',
			BANNING = 'Kit Banning',
			BANNING_TRANSITION = 'Kit Banning',
			KIT_SELECT = 'Kit Selection',
			KIT_SELECT_POST = 'Kit Selection',
			START_MATCH = 'Starting…',
		}
		local function phaseLabel(state)
			local raw = state.Draft and state.Draft.sharedData and state.Draft.sharedData.matchDraftPhase
			if raw == nil then return nil end
			-- If it's already the enum KEY string, use it directly.
			if type(raw) == 'string' and PHASE_LABELS[raw] then return PHASE_LABELS[raw], raw end
			-- Otherwise reverse-map the enum value back to its key name.
			local enum = getPhaseEnum()
			if enum then
				for k, v in pairs(enum) do
					if v == raw and PHASE_LABELS[k] then return PHASE_LABELS[k], k end
				end
			end
			return nil
		end

		local dbgOnce = false
		local function build()
			if gui then gui:Destroy() gui = nil end
			local ok, state = pcall(function() return bedwars.Store:getState() end)
			if not ok or type(state) ~= 'table' then return end
			local teams = state.Game and state.Game.teams
			if type(teams) ~= 'table' or not next(teams) then
				-- teams not populated during this draft phase -> tell us once so we
				-- know it's a data problem, not a rendering one.
				if not dbgOnce then
					dbgOnce = true
					notif('Preparation Preview', 'No team data in the store yet (Game.teams empty). If this persists during the draft, the data path differs.', 6, 'warning')
				end
				return
			end
			local draft = state.Draft or {}
			-- Your OWN team's picks live in Draft.teamData.kitSelection; every OTHER
			-- team's picks live in Draft.enemyTeamData[teamId].kitSelection. Both are
			-- keyed by tostring(userId). We resolve per-team below.
			local ownKitSel = (draft.teamData and draft.teamData.kitSelection) or {}
			local enemyTeamData = draft.enemyTeamData or {}
			local kitBans = (draft.sharedData and draft.sharedData.kitBans) or {}

			gui = Instance.new('ScreenGui')
			gui.Name = 'VainPrepPreview'
			gui.ResetOnSpawn = false
			gui.IgnoreGuiInset = true
			gui.DisplayOrder = 2147483647 -- above the game's draft UI
			gui.ZIndexBehavior = Enum.ZIndexBehavior.Global
			-- parent to a real GUI root, NOT vain.gui (a ScreenGui inside a ScreenGui
			-- doesn't render) -- this is why the overlay never showed.
			pcall(function()
				gui.Parent = (gethui and gethui()) or cloneref(game:GetService('CoreGui'))
			end)
			if not gui.Parent then
				gui.Parent = cloneref(game:GetService('Players')).LocalPlayer:WaitForChild('PlayerGui')
			end

			-- Phase banner (Kit Banning / Kit Selection) centred above the columns.
			local plabel = phaseLabel(state)
			local banner = Instance.new('TextLabel')
			banner.Name = 'PhaseBanner'
			banner.AnchorPoint = Vector2.new(0.5, 0)
			banner.Position = UDim2.new(0.5, 0, 0, 34)
			banner.Size = UDim2.fromOffset(360, 34)
			banner.BackgroundTransparency = 1
			banner.Text = plabel or 'Preparation Preview'
			banner.TextColor3 = Color3.fromRGB(255, 235, 150)
			banner.TextSize = 24
			banner.Font = Enum.Font.GothamBold
			banner.TextXAlignment = Enum.TextXAlignment.Center
			banner.Parent = gui

			-- collect teams into a stable ordered list
			local teamList = {}
			for _, t in teams do teamList[#teamList + 1] = t end
			table.sort(teamList, function(a, b) return tostring(a.id) < tostring(b.id) end)

			local cols = math.max(#teamList, 1)
			local COL_W = 420
			local ROW_H = 92
			local root = Instance.new('Frame')
			root.AnchorPoint = Vector2.new(0.5, 0)
			root.Position = UDim2.new(0.5, 0, 0, 80)
			root.Size = UDim2.fromOffset(COL_W * cols + (cols - 1) * 16, 0)
			root.AutomaticSize = Enum.AutomaticSize.Y
			root.BackgroundTransparency = 1
			root.Parent = gui
			local rootlist = Instance.new('UIListLayout')
			rootlist.FillDirection = Enum.FillDirection.Horizontal
			rootlist.Padding = UDim.new(0, 16)
			rootlist.HorizontalAlignment = Enum.HorizontalAlignment.Center
			rootlist.Parent = root

			for _, team in teamList do
				local col = Instance.new('Frame')
				col.Size = UDim2.fromOffset(COL_W, 0)
				col.AutomaticSize = Enum.AutomaticSize.Y
				col.BackgroundColor3 = Color3.fromRGB(18, 18, 22)
				col.BackgroundTransparency = 0.1
				col.BorderSizePixel = 0
				local cc = Instance.new('UICorner') cc.CornerRadius = UDim.new(0, 12) cc.Parent = col
				local cs = Instance.new('UIStroke') cs.Color = Color3.fromRGB(90, 90, 110) cs.Transparency = 0.4 cs.Parent = col
				col.Parent = root
				local pad = Instance.new('UIPadding')
				pad.PaddingTop = UDim.new(0, 14) pad.PaddingBottom = UDim.new(0, 14)
				pad.PaddingLeft = UDim.new(0, 14) pad.PaddingRight = UDim.new(0, 14)
				pad.Parent = col
				local collist = Instance.new('UIListLayout')
				collist.Padding = UDim.new(0, 10)
				collist.Parent = col

				local header = Instance.new('TextLabel')
				header.Size = UDim2.new(1, 0, 0, 32)
				header.BackgroundTransparency = 1
				header.Text = (team.name and tostring(team.name)) or ('Team ' .. tostring(team.id))
				header.TextColor3 = Color3.new(1, 1, 1)
				header.TextSize = 26
				header.Font = Enum.Font.GothamBold
				header.TextXAlignment = Enum.TextXAlignment.Left
				header.LayoutOrder = 0
				header.Parent = col

				local bans = kitBans[tostring(team.id)] or kitBans[team.id]
				if type(bans) == 'table' and next(bans) then
					local names = {}
					for _, k in pairs(bans) do local m = kitMeta(k) names[#names + 1] = (m and m.name) or tostring(k) end
					local banlbl = Instance.new('TextLabel')
					banlbl.Size = UDim2.new(1, 0, 0, 20)
					banlbl.BackgroundTransparency = 1
					banlbl.Text = 'Banned: ' .. table.concat(names, ', ')
					banlbl.TextColor3 = Color3.fromRGB(235, 120, 120)
					banlbl.TextSize = 14
					banlbl.Font = Enum.Font.Gotham
					banlbl.TextXAlignment = Enum.TextXAlignment.Left
					banlbl.TextWrapped = true
					banlbl.LayoutOrder = 1
					banlbl.Parent = col
				end

				-- Pick this team's kit-selection table: own team from teamData, every
				-- other team from enemyTeamData[teamId] (both keyed by string userId).
				local teamKitSel = ownKitSel
				do
					local ed = enemyTeamData[team.id] or enemyTeamData[tostring(team.id)]
					if type(ed) == 'table' and type(ed.kitSelection) == 'table' then
						teamKitSel = ed.kitSelection
					end
				end

				local members = team.members
				if type(members) == 'table' then
					local order = 2
					for _, mem in members do
						local uid = mem.userId or mem.UserId or mem
						local row = Instance.new('Frame')
						row.Size = UDim2.new(1, 0, 0, ROW_H)
						row.BackgroundColor3 = Color3.fromRGB(32, 32, 40)
						row.BackgroundTransparency = 0.2
						row.BorderSizePixel = 0
						row.LayoutOrder = order
						row.Parent = col
						local rc = Instance.new('UICorner') rc.CornerRadius = UDim.new(0, 10) rc.Parent = row
						order = order + 1

						local av = Instance.new('ImageLabel')
						av.Size = UDim2.fromOffset(ROW_H - 20, ROW_H - 20)
						av.Position = UDim2.fromOffset(10, 10)
						av.BackgroundTransparency = 1
						av.Image = 'rbxthumb://type=AvatarHeadShot&id=' .. tostring(uid) .. '&w=150&h=150'
						av.Parent = row
						local avc = Instance.new('UICorner') avc.CornerRadius = UDim.new(0, 8) avc.Parent = av

						local plr = playersService:GetPlayerByUserId(uid)
						local nm = Instance.new('TextLabel')
						nm.Size = UDim2.new(1, -(ROW_H - 20) - 24 - (ROW_H + 90), 0, 24)
						nm.Position = UDim2.fromOffset(ROW_H, 16)
						nm.BackgroundTransparency = 1
						nm.Text = plr and (plr.DisplayName ~= '' and plr.DisplayName or plr.Name) or ('#' .. tostring(uid))
						nm.TextColor3 = Color3.new(1, 1, 1)
						nm.TextSize = 18
						nm.Font = Enum.Font.GothamBold
						nm.TextXAlignment = Enum.TextXAlignment.Left
						nm.TextTruncate = Enum.TextTruncate.AtEnd
						nm.Parent = row

						-- Kit source, in priority order:
						--  1) this team's kitSelection (own team OR enemyTeamData) during
						--     the pick phase, keyed by string userId
						--  2) the player's replicated PlayingAsKit attribute (once they've
						--     spawned as their kit) -- this is how the game's own nametags
						--     read everyone's kit, so it's the reliable in-match source.
						local kitId = teamKitSel[tostring(uid)] or teamKitSel[uid]
						if (not kitId or kitId == '') and plr then
							kitId = plr:GetAttribute('PlayingAsKit')
						end
						local m = kitMeta(kitId)
						if m then
							if m.renderImage and m.renderImage ~= '' then
								local ki = Instance.new('ImageLabel')
								ki.Size = UDim2.fromOffset(ROW_H - 12, ROW_H - 12)
								ki.AnchorPoint = Vector2.new(1, 0.5)
								ki.Position = UDim2.new(1, -96, 0.5, 0)
								ki.BackgroundTransparency = 1
								ki.ScaleType = Enum.ScaleType.Fit
								ki.Image = m.renderImage
								ki.Parent = row
							end
							local kn = Instance.new('TextLabel')
							kn.AnchorPoint = Vector2.new(1, 0.5)
							kn.Size = UDim2.fromOffset(90, ROW_H)
							kn.Position = UDim2.new(1, -6, 0.5, 0)
							kn.BackgroundTransparency = 1
							kn.Text = m.name or tostring(kitId)
							kn.TextColor3 = Color3.fromRGB(130, 205, 255)
							kn.TextSize = 15
							kn.Font = Enum.Font.GothamBold
							kn.TextXAlignment = Enum.TextXAlignment.Right
							kn.TextWrapped = true
							kn.Parent = row
						else
							local kn = Instance.new('TextLabel')
							kn.AnchorPoint = Vector2.new(1, 0.5)
							kn.Size = UDim2.fromOffset(120, ROW_H)
							kn.Position = UDim2.new(1, -12, 0.5, 0)
							kn.BackgroundTransparency = 1
							kn.Text = 'picking...'
							kn.TextColor3 = Color3.fromRGB(150, 150, 150)
							kn.TextSize = 15
							kn.Font = Enum.Font.Gotham
							kn.TextXAlignment = Enum.TextXAlignment.Right
							kn.Parent = row
						end
					end
				end
			end
		end

		PrepPreview = vain.Categories.Render:CreateModule({
			Name = 'Preparation Preview',
			Tooltip = 'While spectating a match still in the kit-ban / selection phase, shows each team, its players (avatar + name) and their chosen kit — which the game normally hides from spectators.',
			Function = function(callback)
				if callback then
					task.spawn(function()
						repeat
							-- only during the PRE phase (matchState 0); rebuild from the
							-- live store so picks/bans update as they happen
							if store.matchState == 0 then
								pcall(build)
							elseif gui then
								gui:Destroy() gui = nil
							end
							task.wait(0.5)
						until not PrepPreview.Enabled
						if gui then gui:Destroy() gui = nil end
					end)
				else
					if gui then gui:Destroy() gui = nil end
				end
			end
		})
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  TABLIST WINSTREAK  (show each player's winstreak next to their tab-list name)
	-- ══════════════════════════════════════════════════════════════════════════
	-- BedWars uses a custom tab-list (the default PlayerList is disabled) and a
	-- player's winstreak isn't replicated. NametagController:requestNametagData(plr)
	-- returns any player's { winstreak, rankDivision }, so we fetch it once per
	-- player (staggered + cached) and paint it onto the matching name label in the
	-- tab-list, re-applying on a loop since the tab-list is Roact and re-renders.
	do
		local TablistWinstreak
		local Global
		local ShowStreak, ShowWinrate, ShowMatches, ShowKD, ShowBeds
		local fetched = {}    -- userId -> true once fetched (dedupe)
		local fetching = {}   -- userId -> true while a request is in flight
		local statData = {}   -- lowercased name -> { ws, winrate, matches, kd, beds } (persists after they leave)

		-- Build the display string from raw stats, honoring the per-stat toggles.
		-- Kept separate from the fetch so toggling a stat off/on repaints instantly
		-- without re-requesting the (cached) profile.
		local function buildLabel(d)
			if not d then return nil end
			local parts = {}
			if (not ShowStreak or ShowStreak.Enabled) and d.ws and d.ws > 0 then
				parts[#parts + 1] = '\u{1F525} ' .. tostring(d.ws)
			end
			if (not ShowWinrate or ShowWinrate.Enabled) and d.winrate then
				parts[#parts + 1] = ('\u{1F3C6} %d%%'):format(d.winrate)
			end
			if (not ShowMatches or ShowMatches.Enabled) and d.matches and d.matches > 0 then
				parts[#parts + 1] = ('\u{1F3AE} %d'):format(d.matches)
			end
			if (not ShowKD or ShowKD.Enabled) and d.kd then
				parts[#parts + 1] = ('\u{2694} %.2f'):format(d.kd)
			end
			if (not ShowBeds or ShowBeds.Enabled) and d.beds then
				parts[#parts + 1] = ('\u{1F6CF} %.2f'):format(d.beds)
			end
			if #parts > 0 then return table.concat(parts, '  ') end
			return nil
		end

		local function displayNameOf(plr)
			local ok, dn = pcall(function() return bedwars.GamePlayer.getGamePlayer(plr):getDisplayName() end)
			if ok and type(dn) == 'string' and dn ~= '' then return dn end
			return (plr.DisplayName ~= '' and plr.DisplayName) or plr.Name
		end

		local function fetchWinstreak(plr)
			local uid = plr.UserId
			if fetched[uid] or fetching[uid] then return end
			fetching[uid] = true
			local dn, nm = displayNameOf(plr):lower(), plr.Name:lower()
			task.spawn(function()
				local data
				-- Full profile -> per-CURRENT-gamemode stats (winstreak, winrate, K/D).
				-- Privacy-gated: private/friends-only users reject it; we suppress the
				-- resulting notification (see installNotifFilter) and fall back below.
				local ok, profile = pcall(function()
					return bedwars.Client:Get('RequestProfileData'):CallServerAsync(plr):expect()
				end)
				-- Extract RAW stats defensively (profile.queues can be proxy/userdata, and a
				-- bad field read would kill this thread). We store numbers, not a string, so
				-- the per-stat toggles can rebuild the label at paint time.
				pcall(function()
					if not (ok and profile and profile.queues) then return end
					local ws, wins, losses, matches, kills, deaths, beds
					if Global and Global.Enabled then
						-- GLOBAL: sum every queue's totals + highest win streak of any mode.
						wins, losses, matches, kills, deaths, beds = 0, 0, 0, 0, 0, 0
						local best = 0
						for _, v in pairs(profile.queues) do
							if type(v) == 'table' then
								wins    = wins    + (tonumber(v.wins) or 0)
								losses  = losses  + (tonumber(v.losses) or 0)
								matches = matches + (tonumber(v.matches) or 0)
								kills   = kills   + (tonumber(v.kills) or 0)
								deaths  = deaths  + (tonumber(v.deaths) or 0)
								best    = math.max(best, tonumber(v.highestWinStreak) or 0)
								beds    = beds    + (tonumber(v.bedBreaks) or 0)
							end
						end
						ws = best
						if matches <= 0 then matches = wins + losses end
					else
						-- CURRENT gamemode only.
						local qt = bedwars.Store:getState().Game.queueType
						local q = qt and profile.queues[qt]
						if not q then return end
						ws      = tonumber(q.currentWinStreak) or 0
						wins    = tonumber(q.wins) or 0
						losses  = tonumber(q.losses) or 0
						matches = tonumber(q.matches) or 0
						kills   = tonumber(q.kills) or 0
						deaths  = tonumber(q.deaths) or 0
						beds    = tonumber(q.bedBreaks) or 0
						if matches <= 0 then matches = wins + losses end
					end
					data = {
						ws      = ws,
						winrate = matches > 0 and math.floor(wins / matches * 100 + 0.5) or nil,
						matches = matches,
						kd      = (kills > 0 or deaths > 0) and (deaths > 0 and (kills / deaths) or kills) or nil,
						beds    = (matches > 0 and beds > 0) and (beds / matches) or nil,
					}
				end)
				-- private/friends-only profiles reject RequestProfileData -> data stays
				-- nil and nothing is shown for them (no global-streak fallback).
				fetched[uid] = true
				fetching[uid] = nil
				-- key by name so it still matches the row after the player leaves
				if data then statData[dn] = data; statData[nm] = data end
			end)
		end

		local function stripTags(s)
			return (s:gsub('<[^>]->', ''))
		end

		-- normalise a label's text for matching: drop rich-text tags, a leading
		-- "[..]" (level/kill) tag, and surrounding whitespace.
		local function clean(s)
			s = stripTags(s)
			s = s:gsub('^%s*%b[]%s*', '')
			s = s:gsub('^%s+', ''):gsub('%s+$', '')
			return s:lower()
		end

		local function paint()
			-- fetch everyone at once (each request is cached, so a player is only
			-- ever requested a single time -> the private-profile notif, which we
			-- also suppress, can fire at most once and we batch them away instantly)
			for _, plr in playersService:GetPlayers() do
				fetchWinstreak(plr)
			end
			if not next(statData) then return end

			-- Only paint the ALLOWED containers: the tab-list LEADERBOARD and the
			-- SPECTATE selector nametag. Matching player names anywhere in PlayerGui
			-- also caught the kill feed, target list, etc. -- so require the label to
			-- live inside one of those named ancestors. (The Preparation Preview UI
			-- renders its own stats separately and isn't scraped here.)
			local pg = lplr:FindFirstChild('PlayerGui')
			if not pg then return end
			local function isAllowedContainer(gui)
				local a = gui
				while a and a ~= pg do
					local n = a.Name:lower()
					if n:find('leaderboard') or n:find('tablist')
						or (n:find('tab') and n:find('list'))
						or n:find('spectat') then
						return true
					end
					a = a.Parent
				end
				return false
			end
			for _, gui in pg:GetDescendants() do
				if gui:IsA('TextLabel') and isAllowedContainer(gui) then
					-- Match on the ORIGINAL name, not the current text: once painted,
					-- gui.Text contains the visible stat glyphs (🔥 61% ...) which
					-- stripTags can't remove, so cleaning the live text no longer matches
					-- the player -> the row would flip painted/restored every second.
					local orig = gui:GetAttribute('VainWSOrig')
					-- If Roact recycled this label to a different player it resets .Text
					-- but keeps our attribute -> a stale orig. Detect that (current text no
					-- longer begins with orig) and drop it so we re-key off the fresh name.
					if orig and gui.Text:sub(1, #orig) ~= orig then
						orig = nil
						gui:SetAttribute('VainWSOrig', nil)
						gui:SetAttribute('VainWS', nil)
					end
					local key = clean(orig or gui.Text)
					local label = buildLabel(statData[key])
					local painted = gui:GetAttribute('VainWS')
					if label then
						-- Remember the untouched text once so we always rebuild FROM the
						-- original. Rebuilding every pass (instead of skip-if-painted) lets
						-- the per-stat toggles take effect without a Roact re-render.
						if not orig then
							orig = gui.Text
							gui:SetAttribute('VainWSOrig', orig)
						end
						local want = orig .. "  <font color='#FFD24D'>" .. label .. "</font>"
						if gui.Text ~= want then
							gui:SetAttribute('VainWS', true)
							gui.RichText = true
							gui.Text = want
						end
					elseif painted then
						-- All of this row's stats got toggled off -> restore the original.
						if type(orig) == 'string' then gui.Text = orig end
						gui:SetAttribute('VainWSOrig', nil)
						gui:SetAttribute('VainWS', nil)
					end
				end
			end
		end

		-- Drop the "profile visibility set to Private/Friends Only" spam that
		-- RequestProfileData triggers for private players. All notifications go
		-- through NotificationController.sendNotification, so we wrap it and drop
		-- any whose payload mentions "visibility", restoring it when disabled.
		local notifCtrl, origSendNotif
		local function installNotifFilter()
			if origSendNotif then return end
			local ok, ctrl = pcall(function()
				return Flamework.resolveDependency('@easy-games/game-core:client/controllers/notification-controller@NotificationController')
			end)
			if not ok or not ctrl or type(ctrl.sendNotification) ~= 'function' then return end
			notifCtrl, origSendNotif = ctrl, ctrl.sendNotification
			ctrl.sendNotification = function(selfc, payload, ...)
				if type(payload) == 'table' then
					for _, v in pairs(payload) do
						if type(v) == 'string' and v:lower():find('visibility') then return end
					end
				end
				return origSendNotif(selfc, payload, ...)
			end
		end
		local function removeNotifFilter()
			if notifCtrl and origSendNotif and notifCtrl.sendNotification ~= origSendNotif then
				notifCtrl.sendNotification = origSendNotif
			end
			origSendNotif = nil
		end

		TablistWinstreak = vain.Categories.Render:CreateModule({
			Name = 'Show Advanced Stats',
			Tooltip = "Shows each player's current-gamemode winstreak, winrate, K/D and total matches next to their name in the tab-list (Tab key). Private profiles show nothing. Fetches once per player and caches.",
			Function = function(callback)
				if callback then
					table.clear(fetched)
					table.clear(fetching)
					table.clear(statData)
					installNotifFilter()
					task.spawn(function()
						repeat
							pcall(paint)
							task.wait(1)
						until not TablistWinstreak.Enabled
						removeNotifFilter()
					end)
				end
			end
		})
		Global = TablistWinstreak:CreateToggle({
			Name = 'Global Stats',
			Tooltip = 'Show GLOBAL stats across ALL gamemodes (highest win streak of any mode, and total winrate / K-D over every match) instead of just the current mode.',
			Default = false,
			Function = function()
				-- Global vs current-mode changes the RAW numbers, so wipe the fetch
				-- cache + our painted tags; the paint loop rebuilds from fresh data.
				table.clear(fetched)
				table.clear(fetching)
				table.clear(statData)
				local pg = lplr:FindFirstChild('PlayerGui')
				if pg then
					for _, g in pg:GetDescendants() do
						if g:IsA('TextLabel') and g:GetAttribute('VainWS') then
							local orig = g:GetAttribute('VainWSOrig')
							if type(orig) == 'string' then g.Text = orig end
							g:SetAttribute('VainWSOrig', nil)
							g:SetAttribute('VainWS', nil)
						end
					end
				end
			end
		})
		-- Per-stat visibility toggles. These only affect the DISPLAY (buildLabel),
		-- so no cache wipe is needed -- the 1s paint loop repaints from cached raw
		-- numbers and rebuilds each label from its original text.
		ShowStreak = TablistWinstreak:CreateToggle({
			Name = 'Show Win Streak', Default = true,
			Tooltip = 'Show the \u{1F525} win streak stat.', Function = function() end,
		})
		ShowWinrate = TablistWinstreak:CreateToggle({
			Name = 'Show Winrate', Default = true,
			Tooltip = 'Show the \u{1F3C6} winrate stat.', Function = function() end,
		})
		ShowMatches = TablistWinstreak:CreateToggle({
			Name = 'Show Matches', Default = true,
			Tooltip = 'Show the \u{1F3AE} total matches stat.', Function = function() end,
		})
		ShowKD = TablistWinstreak:CreateToggle({
			Name = 'Show K/D', Default = true,
			Tooltip = 'Show the \u{2694} kill/death ratio stat.', Function = function() end,
		})
		ShowBeds = TablistWinstreak:CreateToggle({
			Name = 'Show Bed Breaks', Default = true,
			Tooltip = 'Show the \u{1F6CF} average beds broken per match stat.', Function = function() end,
		})
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  TABLIST PARTIES  (mark each player's party with a coloured tag in the tab-list)
	-- ══════════════════════════════════════════════════════════════════════════
	-- Same painting mechanism as the winstreak module, but the suffix is a coloured
	-- party marker. Players who queued together get the SAME colour + party number, so
	-- you can read the parties straight off the tab-list. Party groupings come from
	-- MatchController (works during the ranked kit-ban draft too).
	do
		local TablistParties

		-- distinct, readable colours per party index (cycles if there are more)
		local PARTY_COLORS = {
			'#FF5C5C', '#4DA6FF', '#5CE05C', '#FFD24D',
			'#C77DFF', '#33E0D0', '#FF9A4D', '#FF6FD8',
		}

		local function mc()
			local ok, c = pcall(function() return bedwars.Knit.Controllers.MatchController end)
			return ok and c or nil
		end

		-- build: userId -> { idx = partyNumber, color = hex } for every player who is
		-- in a party of 2+. Solo players are omitted (no tag).
		local function partyMap()
			local controller = mc()
			if not controller then return {} end
			local parties = {}
			local direct
			pcall(function() if controller.getParties then direct = controller:getParties() end end)

			local seen, list = {}, {}
			local function addParty(members)
				if type(members) ~= 'table' then return end
				local ids, key = {}, {}
				for _, m in members do
					local uid = tonumber(m) or (type(m) == 'table' and tonumber(m.userId or m.UserId))
					if uid then ids[#ids + 1] = uid key[#key + 1] = uid end
				end
				if #ids < 2 then return end   -- only real parties
				table.sort(key)
				local sig = table.concat(key, ',')
				if not seen[sig] then seen[sig] = true list[#list + 1] = ids end
			end

			if type(direct) == 'table' and next(direct) then
				for _, p in direct do addParty(type(p) == 'table' and (p.members or p) or nil) end
			else
				for _, plr in playersService:GetPlayers() do
					local ok, p = pcall(function() return controller:getPlayerParty(plr) end)
					if ok and type(p) == 'table' then addParty(p.members or p) end
				end
			end

			local map = {}
			for i, ids in list do
				local col = PARTY_COLORS[((i - 1) % #PARTY_COLORS) + 1]
				for _, uid in ids do
					map[uid] = { idx = i, color = col }
				end
			end
			return map
		end

		-- name (lowercased) -> party info, resolved from live players each pass so a
		-- recycled Roact row re-keys correctly.
		local function nameParty(map)
			local out = {}
			for _, plr in playersService:GetPlayers() do
				local info = map[plr.UserId]
				if info then
					out[plr.Name:lower()] = info
					if plr.DisplayName and plr.DisplayName ~= '' then
						out[plr.DisplayName:lower()] = info
					end
				end
			end
			return out
		end

		local function stripTags(s)
			return (s:gsub('<[^>]->', ''))
		end

		local function paint()
			local pg = lplr:FindFirstChild('PlayerGui')
			if not pg then return end
			local map = partyMap()
			local byName = nameParty(map)

			local function isAllowedContainer(gui)
				local a = gui
				while a and a ~= pg do
					local n = a.Name:lower()
					if n:find('leaderboard') or n:find('tablist')
						or (n:find('tab') and n:find('list'))
						or n:find('spectat') then
						return true
					end
					a = a.Parent
				end
				return false
			end

			for _, gui in pg:GetDescendants() do
				if gui:IsA('TextLabel') and isAllowedContainer(gui) then
					local orig = gui:GetAttribute('VainPartyOrig')
					if orig and gui.Text:sub(1, #orig) ~= orig then
						orig = nil
						gui:SetAttribute('VainPartyOrig', nil)
						gui:SetAttribute('VainParty', nil)
					end
					local key = stripTags((orig or gui.Text)):gsub('^%s+', ''):gsub('%s+$', ''):lower()
					local info = byName[key]
					local painted = gui:GetAttribute('VainParty')
					if info then
						if not orig then
							orig = gui.Text
							gui:SetAttribute('VainPartyOrig', orig)
						end
						local tag = "<font color='" .. info.color .. "'>\u{25CF} P" .. info.idx .. "</font>"
						local want = orig .. "  " .. tag
						if gui.Text ~= want then
							gui:SetAttribute('VainParty', true)
							gui.RichText = true
							gui.Text = want
						end
					elseif painted then
						if type(orig) == 'string' then gui.Text = orig end
						gui:SetAttribute('VainPartyOrig', nil)
						gui:SetAttribute('VainParty', nil)
					end
				end
			end
		end

		local function restoreAll()
			local pg = lplr:FindFirstChild('PlayerGui')
			if not pg then return end
			for _, gui in pg:GetDescendants() do
				if gui:IsA('TextLabel') and gui:GetAttribute('VainParty') then
					local orig = gui:GetAttribute('VainPartyOrig')
					if type(orig) == 'string' then gui.Text = orig end
					gui:SetAttribute('VainPartyOrig', nil)
					gui:SetAttribute('VainParty', nil)
				end
			end
		end

		TablistParties = vain.Categories.Render:CreateModule({
			Name = 'Tablist Parties',
			Tooltip = "Marks each player's party in the tab-list (Tab): everyone who queued together gets the same coloured \u{25CF} P# tag next to their name, so you can read the parties at a glance. Works in the ranked kit-ban draft too. Solo players get no tag.",
			Function = function(callback)
				if callback then
					task.spawn(function()
						repeat
							pcall(paint)
							task.wait(1)
						until not TablistParties.Enabled
						pcall(restoreAll)
					end)
				else
					pcall(restoreAll)
				end
			end
		})
	end

	-- ══════════════════════════════════════════════════════════════════════════
	--  PARTY LIST  (show which players queued together as a party in this match)
	-- ══════════════════════════════════════════════════════════════════════════
	-- BedWars replicates the match's PARTY groupings (who queued together) to the
	-- client on the MatchController: MatchController:getParties() returns a list of
	-- { members = { userId, ... } } and :getPlayerParty(plr) finds one player's party.
	-- This is distinct from teams -- in solos/duos a party is the friends grouped
	-- onto the same slot. We read that and draw a small overlay: one card per party
	-- of 2+ players, each row = avatar + name. Solo players (party of 1) are hidden.
	do
		local PartyList
		local OnlyMulti, gui

		local function matchController()
			local ok, mc = pcall(function() return bedwars.Knit.Controllers.MatchController end)
			return ok and mc or nil
		end

		-- return a list of parties, each a list of member userIds (numbers). Prefer the
		-- controller's getParties(); fall back to calling getPlayerParty per player and
		-- de-duping, so it still works if the direct list isn't populated.
		local function collectParties()
			local mc = matchController()
			if not mc then return {} end
			local seen, out = {}, {}

			local function addParty(members)
				if type(members) ~= 'table' then return end
				local ids, key = {}, {}
				for _, m in members do
					local uid = tonumber(m) or (type(m) == 'table' and (m.userId or m.UserId))
					uid = tonumber(uid)
					if uid then ids[#ids + 1] = uid key[#key + 1] = uid end
				end
				if #ids == 0 then return end
				table.sort(key)
				local sig = table.concat(key, ',')
				if not seen[sig] then seen[sig] = true out[#out + 1] = ids end
			end

			local direct = nil
			pcall(function()
				if mc.getParties then direct = mc:getParties() end
			end)
			if type(direct) == 'table' and next(direct) then
				for _, party in direct do
					addParty(type(party) == 'table' and (party.members or party) or nil)
				end
			else
				-- fallback: ask per player
				for _, plr in playersService:GetPlayers() do
					local ok, party = pcall(function() return mc:getPlayerParty(plr) end)
					if ok and type(party) == 'table' then
						addParty(party.members or party)
					end
				end
			end
			return out
		end

		local function build()
			if gui then gui:Destroy() gui = nil end
			local parties = collectParties()

			-- filter to multi-member parties if requested
			local shown = {}
			for _, ids in parties do
				if not (OnlyMulti and OnlyMulti.Enabled) or #ids >= 2 then
					shown[#shown + 1] = ids
				end
			end
			if #shown == 0 then return end

			gui = Instance.new('ScreenGui')
			gui.Name = 'VainPartyList'
			gui.ResetOnSpawn = false
			gui.IgnoreGuiInset = true
			gui.DisplayOrder = 50
			gui.Parent = gethui and gethui() or lplr:WaitForChild('PlayerGui')

			local root = Instance.new('Frame')
			root.Size = UDim2.fromOffset(220, 0)
			root.AutomaticSize = Enum.AutomaticSize.Y
			-- top-left, clear of the ranked kit-ban grid / player columns. Draggable.
			root.Position = UDim2.new(0, 12, 0, 90)
			root.BackgroundColor3 = Color3.fromRGB(18, 18, 24)
			root.BackgroundTransparency = 0.15
			root.BorderSizePixel = 0
			root.Active = true
			root.Draggable = true
			root.Parent = gui
			local rc = Instance.new('UICorner') rc.CornerRadius = UDim.new(0, 10) rc.Parent = root
			local pad = Instance.new('UIPadding')
			pad.PaddingTop = UDim.new(0, 8) pad.PaddingBottom = UDim.new(0, 8)
			pad.PaddingLeft = UDim.new(0, 8) pad.PaddingRight = UDim.new(0, 8)
			pad.Parent = root
			local list = Instance.new('UIListLayout')
			list.SortOrder = Enum.SortOrder.LayoutOrder
			list.Padding = UDim.new(0, 8)
			list.Parent = root

			local header = Instance.new('TextLabel')
			header.Size = UDim2.new(1, 0, 0, 22)
			header.BackgroundTransparency = 1
			header.Text = 'Parties (' .. #shown .. ')'
			header.TextColor3 = Color3.fromRGB(255, 178, 124)
			header.TextSize = 16
			header.Font = Enum.Font.GothamBold
			header.TextXAlignment = Enum.TextXAlignment.Left
			header.LayoutOrder = 0
			header.Parent = root

			for pi, ids in shown do
				local card = Instance.new('Frame')
				card.Size = UDim2.new(1, 0, 0, 0)
				card.AutomaticSize = Enum.AutomaticSize.Y
				card.BackgroundColor3 = Color3.fromRGB(30, 30, 40)
				card.BackgroundTransparency = 0.2
				card.BorderSizePixel = 0
				card.LayoutOrder = pi
				card.Parent = root
				local cc = Instance.new('UICorner') cc.CornerRadius = UDim.new(0, 8) cc.Parent = card
				local cpad = Instance.new('UIPadding')
				cpad.PaddingTop = UDim.new(0, 6) cpad.PaddingBottom = UDim.new(0, 6)
				cpad.PaddingLeft = UDim.new(0, 6) cpad.PaddingRight = UDim.new(0, 6)
				cpad.Parent = card
				local clist = Instance.new('UIListLayout')
				clist.SortOrder = Enum.SortOrder.LayoutOrder
				clist.Padding = UDim.new(0, 4)
				clist.Parent = card

				local order = 0
				for _, uid in ids do
					local row = Instance.new('Frame')
					row.Size = UDim2.new(1, 0, 0, 30)
					row.BackgroundTransparency = 1
					row.LayoutOrder = order
					row.Parent = card
					order = order + 1

					local av = Instance.new('ImageLabel')
					av.Size = UDim2.fromOffset(26, 26)
					av.Position = UDim2.fromOffset(0, 2)
					av.BackgroundColor3 = Color3.fromRGB(45, 45, 55)
					av.BorderSizePixel = 0
					av.Image = 'rbxthumb://type=AvatarHeadShot&id=' .. tostring(uid) .. '&w=150&h=150'
					av.Parent = row
					local avc = Instance.new('UICorner') avc.CornerRadius = UDim.new(0, 6) avc.Parent = av

					local plr = playersService:GetPlayerByUserId(uid)
					local nm = Instance.new('TextLabel')
					nm.Size = UDim2.new(1, -34, 1, 0)
					nm.Position = UDim2.fromOffset(34, 0)
					nm.BackgroundTransparency = 1
					nm.Text = plr and (plr.DisplayName ~= '' and plr.DisplayName or plr.Name) or ('#' .. tostring(uid))
					nm.TextColor3 = plr and (plr == lplr and Color3.fromRGB(120, 235, 140) or Color3.new(1, 1, 1)) or Color3.fromRGB(150, 150, 150)
					nm.TextSize = 15
					nm.Font = Enum.Font.GothamMedium
					nm.TextXAlignment = Enum.TextXAlignment.Left
					nm.TextTruncate = Enum.TextTruncate.AtEnd
					nm.Parent = row
				end
			end
		end

		PartyList = vain.Categories.Render:CreateModule({
			Name = 'Party List',
			Tooltip = "Shows which players queued together as a PARTY (friends grouped onto the same slot -- distinct from teams), including during the ranked kit-ban draft. Draws a small draggable overlay top-left, one card per party. Solo players hidden by default. If the panel doesn't appear, this match has no multi-player parties.",
			Function = function(callback)
				if callback then
					-- one-shot diagnostic: how many parties / multi-parties are visible
					local parties = collectParties()
					local multi = 0
					for _, ids in parties do if #ids >= 2 then multi += 1 end end
					notif('Party List', ('%d partie(s) found, %d with 2+ players%s'):format(
						#parties, multi,
						multi == 0 and ' -- nothing to show (all solo-queued)' or ''),
						6, multi > 0 and 'success' or 'warning')
					task.spawn(function()
						repeat
							pcall(build)
							task.wait(2)
						until not PartyList.Enabled
						if gui then gui:Destroy() gui = nil end
					end)
				else
					if gui then gui:Destroy() gui = nil end
				end
			end
		})
		OnlyMulti = PartyList:CreateToggle({
			Name = 'Hide Solos', Default = true,
			Tooltip = 'Only show parties of 2 or more players (hide players who queued alone).',
			Function = function()
				if PartyList.Enabled then pcall(build) end
			end,
		})
	end

	AimAssist = vain.Categories.Combat:CreateModule({
		Name = 'AimAssist',
		Tooltip = 'Smoothly deflects your camera toward nearby enemies',
		Function = function(callback)
			if callback then
				lockedTarget = nil
				lastValidTarget = nil
				lastValidTime = 0
				shakeTime = 0
				AimAssist:Clean(runService.Heartbeat:Connect(function(dt)

					if not entitylib.isAlive or not entitylib.character or not entitylib.character.RootPart then
						lockedTarget = nil
						return
					end

					-- By default AimAssist works with any held item. 'Limit to item'
					-- restores the old behavior: only assist while holding a sword
					-- (or a bow/crossbow when Work With Projectiles is on).
					if LimitToItem and LimitToItem.Enabled then
						local validWeapon = store.hand.toolType == 'sword'
						if WorkWithProjectiles and WorkWithProjectiles.Enabled then
							validWeapon = validWeapon or isHoldingBowCrossbow()
						end
						if not validWeapon then
							lockedTarget = nil
							return
						end
					end

					-- ClickAim gates on a recent sword swing, which never fires for a bow.
					-- Skip the gate while holding a bow/crossbow so projectile assist works.
					if ClickAim and ClickAim.Enabled and not isHoldingBowCrossbow() then
						local sc = bedwars.SwordController
						if not sc or not sc.lastAttack or (workspace:GetServerTimeNow() - sc.lastAttack) >= 0.4 then
							return
						end
					end

					local inFirstPerson = isFirstPerson()
					if ViewMode.Value == 'First Person' and not inFirstPerson then return end
					if ViewMode.Value == 'Third Person' and inFirstPerson then return end

					if ShopCheck and ShopCheck.Enabled then
						if isGUIOpen() then
							lockedTarget = nil
							return
						end
					end

					local ent = nil

					if KillauraTarget and KillauraTarget.Enabled then
						local ka = store.KillauraTarget
						if ka and ka.RootPart and ka.Character and ka.Character.Parent then
							local hum = ka.Character:FindFirstChildOfClass('Humanoid')
							if hum and hum.Health > 0 then
								ent = ka
							end
						end
					else
						if PriorityMode and PriorityMode.Enabled and lockedTarget then
							if isEntValid(lockedTarget) and isInAngle(lockedTarget) then
								ent = lockedTarget
							else
								lockedTarget = nil
							end
						end

						if not ent then
							local found = entitylib.EntityPosition({
								Range = Distance.Value,
								Part = 'RootPart',
								Wallcheck = Targets.Walls.Enabled,
								Players = Targets.Players.Enabled,
								NPCs = Targets.NPCs.Enabled,
								Sort = sortmethods[Sort.Value]
							})

							if found then
								lastValidTarget = found
								lastValidTime = tick()
								ent = found
							elseif lastValidTarget and (tick() - lastValidTime) < GRACE_PERIOD then
								if isEntValid(lastValidTarget) and isInAngle(lastValidTarget) then
									ent = lastValidTarget
								else
									lastValidTarget = nil
								end
							end

							if ent and PriorityMode and PriorityMode.Enabled then
								lockedTarget = ent
							end
						end
					end

					if not ent then return end

					if not (KillauraTarget and KillauraTarget.Enabled) then
						if not isEntValid(ent) then
							if PriorityMode and PriorityMode.Enabled then lockedTarget = nil end
							lastValidTarget = nil
							return
						end
						if not isInAngle(ent) then
							if PriorityMode and PriorityMode.Enabled then lockedTarget = nil end
							return
						end
					end

					-- Min Distance: don't assist on targets closer than this (avoids
					-- snapping at point-blank where you don't need help).
					if MinDistance and MinDistance.Value > 0 and ent.RootPart and entitylib.character.RootPart then
						if (ent.RootPart.Position - entitylib.character.RootPart.Position).Magnitude < MinDistance.Value then
							return
						end
					end

					-- Target Health filter: only assist when the target is at or below
					-- the chosen health. BedWars stores real health on the character's
					-- 'Health' attribute (Humanoid.Health is often a fixed 100), and
					-- entitylib mirrors it on ent.Health — use that, like the Health sort.
					if HealthCheck and HealthCheck.Enabled then
						local hp = ent.Health
						if hp == nil and ent.Character then
							hp = ent.Character:GetAttribute('Health')
						end
						if hp and hp > (HealthThreshold and HealthThreshold.Value or 100) then
							return
						end
					end

					targetinfo.Targets[ent] = tick() + 1

					local aimPosition
					if AimPart.Value == 'Head' then
						local head = ent.Character and ent.Character:FindFirstChild('Head')
						aimPosition = head and head.Position or ent.RootPart.Position
					elseif AimPart.Value == 'Torso' then
						local torso = ent.Character and (ent.Character:FindFirstChild('UpperTorso') or ent.Character:FindFirstChild('Torso'))
						aimPosition = torso and torso.Position or ent.RootPart.Position
					elseif AimPart.Value == 'Closest' then
						local closest = ent.Character and getClosestPartToCursor(ent.Character)
						aimPosition = closest and closest.Position or ent.RootPart.Position
					else
						aimPosition = ent.RootPart.Position
					end

					if ShakeToggle and ShakeToggle.Enabled and ShakeAmount.Value > 0 then
						shakeTime = shakeTime + dt
						local intensity = ShakeAmount.Value * 0.045
						local sx = math.sin(shakeTime * 17.3) * intensity + math.sin(shakeTime * 5.7) * intensity * 0.4
						local sy = math.cos(shakeTime * 13.1) * intensity + math.cos(shakeTime * 8.3) * intensity * 0.3
						local sz = math.sin(shakeTime * 9.7 + 1.2) * intensity * 0.5
						if rng:NextNumber() < 0.08 then
							sx = sx + (rng:NextNumber() - 0.5) * intensity * 1.6
							sy = sy + (rng:NextNumber() - 0.5) * intensity * 1.6
						end
						aimPosition = aimPosition + Vector3.new(sx, sy, sz)
					end

					local targetCFrame = CFrame.lookAt(gameCamera.CFrame.p, aimPosition)
					if SmoothnessToggle and SmoothnessToggle.Enabled then
						local speed = getSmoothedSpeed(AimSpeed.Value, Smoothness.Value, dt)
						gameCamera.CFrame = gameCamera.CFrame:Lerp(targetCFrame, math.min(speed * (dt * 60), 0.95))
					else
						gameCamera.CFrame = gameCamera.CFrame:Lerp(targetCFrame, math.clamp(AimSpeed.Value * dt, 0, 0.95))
					end
				end))
			else
				lockedTarget = nil
				lastValidTarget = nil
			end
		end,
		Tooltip = 'Aim assist with smooth target tracking'
	})

	Targets = AimAssist:CreateTargets({
		Tooltip = 'Configure which types of targets to include',
		Players = true,
		Walls = true
	})

	local methods = {'Damage', 'Distance'}
	for i in sortmethods do
		if not table.find(methods, i) then
			table.insert(methods, i)
		end
	end

	Sort = AimAssist:CreateDropdown({
		Name = 'Target Mode',
		List = methods,
		Tooltip = 'How to prioritize targets',
		ItemTooltips = {
			Distance = 'Targets the closest enemy by stud distance',
			Health = 'Targets the enemy with the lowest remaining health',
			Angle = 'Targets the enemy closest to your look direction',
			Cursor = 'Targets the enemy nearest to your mouse cursor',
			Damage = 'Targets the enemy who most recently took damage',
			Threat = 'Targets the enemy judged to be the greatest combat threat',
			Kit = 'Prioritizes dangerous kit users (Hannah, Spirit Assassin, etc.)',
		},
	})

	AimPart = AimAssist:CreateDropdown({
		Name = 'Aim Part',
		Tooltip = 'Which body part on the target to aim at',
		List = {'Torso', 'Head', 'Closest'},
		Default = 'Torso',
		ItemTooltips = {
			Torso = 'Aims at the center of the player\'s body — reliable and easy to hit',
			Head = 'Aims at the head — higher damage potential but smaller hitbox',
			Closest = 'Aims at whichever body part is nearest to your crosshair',
		}
	})

	ViewMode = AimAssist:CreateDropdown({
		Name = 'View Mode',
		List = {'First Person', 'Third Person', 'Both'},
		Default = 'Both',
		Tooltip = 'Only aim in first person, third person, or always',
		ItemTooltips = {
			['First Person'] = 'Assist only activates in first-person camera mode',
			['Third Person'] = 'Assist only activates in third-person camera mode',
			Both = 'Assist activates in both camera modes',
		},
	})

	AimSpeed = AimAssist:CreateSlider({
		Name = 'Aim Speed',
		Min = 1,
		Max = 20,
		Default = 6,
		Tooltip = 'How fast aim assist moves toward the target'
	})

	Distance = AimAssist:CreateSlider({
		Name = 'Distance',
		Tooltip = 'Maximum distance in studs',
		Min = 1,
		Max = 30,
		Default = 25,
		Suffix = function(val)
			return val == 1 and 'stud' or 'studs'
		end
	})

	AngleSlider = AimAssist:CreateSlider({
		Name = 'Max Angle',
		Min = 1,
		Max = 360,
		Default = 60,
		Tooltip = 'FOV cone for target acquisition'
	})

	MinDistance = AimAssist:CreateSlider({
		Name = 'Min Distance',
		Tooltip = 'Don\'t assist on targets closer than this (0 = no minimum)',
		Min = 0,
		Max = 50,
		Default = 0,
		Suffix = function(val)
			return val <= 1 and 'stud' or 'studs'
		end
	})

	SmoothnessToggle = AimAssist:CreateToggle({
		Name = 'Smoothness',
		Default = false,
		Tooltip = 'Makes aim assist feel more legit',
		Function = function(callback)
			if Smoothness then Smoothness.Object.Visible = callback end
		end
	})

	Smoothness = AimAssist:CreateSlider({
		Name = 'Smoothness Amount',
		Min = 1,
		Max = 10,
		Default = 5,
		Tooltip = 'Higher = smoother and more legit.',
		Visible = false
	})

	PriorityMode = AimAssist:CreateToggle({
		Name = 'Priority Mode',
		Default = false,
		Tooltip = 'Locks onto one target. Ignores closer targets until current is lost.'
	})

	ClickAim = AimAssist:CreateToggle({
		Name = 'Click Aim',
		Default = true,
		Tooltip = 'Only aims when attacking'
	})

	KillauraTarget = AimAssist:CreateToggle({
		Name = 'Use Killaura Target',
		Tooltip = 'Follow Killaura target only, bypasses all distance and wall filters'
	})

	ShakeToggle = AimAssist:CreateToggle({
		Name = 'Shake',
		Default = false,
		Tooltip = 'Adds legit-looking human jitter to aim',
		Function = function(callback)
			if ShakeAmount then ShakeAmount.Object.Visible = callback end
		end
	})

	ShakeAmount = AimAssist:CreateSlider({
		Name = 'Shake Amount',
		Tooltip = 'Adjusts the shake amount value',
		Min = 1,
		Max = 10,
		Default = 3,
		Visible = false
	})

	ShopCheck = AimAssist:CreateToggle({
		Name = 'Shop Check',
		Default = false,
		Tooltip = 'Disables aim assist when the shop is open'
	})

	WorkWithProjectiles = AimAssist:CreateToggle({
		Name = 'Work With Projectiles',
		Default = false,
		Tooltip = 'Also activates when holding bows or crossbows (only matters with Limit to item on)'
	})

	LimitToItem = AimAssist:CreateToggle({
		Name = 'Limit to item',
		Default = false,
		Tooltip = 'Only assist while holding a weapon (sword, or bow/crossbow with Work With Projectiles). Off = works with any held item.'
	})

	HealthCheck = AimAssist:CreateToggle({
		Name = 'Target HP Check',
		Default = false,
		Tooltip = 'Only assist when the target is at or below the chosen health',
		Function = function(callback)
			if HealthThreshold and HealthThreshold.Object then
				HealthThreshold.Object.Visible = callback
			end
		end
	})

	HealthThreshold = AimAssist:CreateSlider({
		Name = 'Target Health',
		Tooltip = 'Maximum target health to assist on',
		Min = 1,
		Max = 100,
		Default = 100,
		Darker = true,
		Visible = false
	})

	task.defer(function()
		if Smoothness and Smoothness.Object then
			Smoothness.Object.Visible = SmoothnessToggle and SmoothnessToggle.Enabled or false
		end
		if ShakeAmount and ShakeAmount.Object then
			ShakeAmount.Object.Visible = false
		end
	end)
end)

run(function()
    if isMobile then
        local AutoClicker
        local CPS
        local BlockCPS = {}
        local Thread

        local function getSafeCPS()
            if store.hand and store.hand.toolType == 'block' and BlockCPS and BlockCPS.GetRandomValue then
                return BlockCPS
            end
            if CPS and CPS.GetRandomValue then
                return CPS
            end
            return nil
        end

        local function AutoClick()
            if Thread then
                task.cancel(Thread)
                Thread = nil
            end

            local initialCPS = getSafeCPS()
            if not initialCPS then return end

            Thread = task.delay(1 / initialCPS.GetRandomValue(), function()
                repeat
                    if not bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then
                        local blockPlacer = bedwars.BlockPlacementController and bedwars.BlockPlacementController.blockPlacer
                        local toolType = store.hand and store.hand.toolType

                        if toolType == 'block' and blockPlacer then
                            task.spawn(function()
                                blockPlacer:autoBridge(workspace:GetServerTimeNow() - bedwars.KnockbackController:getLastKnockbackTime() >= 0.2)
                            end)
                        elseif toolType == 'sword' then
                            bedwars.SwordController:swingSwordAtMouse(0.39)
                        end
                    end

                    local currentCPS = getSafeCPS()
                    if not currentCPS then
                        task.wait(0.1)
                    else
                        task.wait(1 / currentCPS.GetRandomValue())
                    end
                until not AutoClicker.Enabled
            end)
        end

        local function StopClick()
            if Thread then
                task.cancel(Thread)
                Thread = nil
            end
        end

        AutoClicker = vain.Categories.Combat:CreateModule({
            Name = 'AutoClicker',
            Tooltip = 'Automatically clicks at a configurable CPS rate',
            Function = function(callback)
                if callback then
                    AutoClicker:Clean(inputService.InputBegan:Connect(function(input)
                        if input.UserInputType == Enum.UserInputType.MouseButton1 then
                            AutoClick()
                        end
                    end))

                    AutoClicker:Clean(inputService.InputEnded:Connect(function(input)
                        if input.UserInputType == Enum.UserInputType.MouseButton1 then
                            StopClick()
                        end
                    end))

                    for _, v in {'2', '5'} do
                        pcall(function()
                            AutoClicker:Clean(lplr.PlayerGui.MobileUI[v].MouseButton1Down:Connect(AutoClick))
                            AutoClicker:Clean(lplr.PlayerGui.MobileUI[v].MouseButton1Up:Connect(StopClick))
                        end)
                    end
                else
                    StopClick()
                end
            end,
            Tooltip = 'Hold attack button to automatically click'
        })

        CPS = AutoClicker:CreateTwoSlider({
            Name = 'CPS',
            Min = 1,
            Max = 9,
            DefaultMin = 7,
            DefaultMax = 7
        })

        AutoClicker:CreateToggle({
            Name = 'Place Blocks',
            Tooltip = 'Automatically places blocks while clicking',
            Default = true,
            Function = function(callback)
                if BlockCPS.Object then
                    BlockCPS.Object.Visible = callback
                end
            end
        })

        BlockCPS = AutoClicker:CreateTwoSlider({
            Name = 'Block CPS',
            Min = 1,
            Max = 20,
            DefaultMin = 12,
            DefaultMax = 12,
            Darker = true
        })

        task.defer(function()
            if BlockCPS and BlockCPS.Object then
                BlockCPS.Object.Visible = PlaceBlocksToggle and PlaceBlocksToggle.Enabled
            end
        end)

    else
        local AutoClicker
        local CPS
        local BlockCPS = {}
        local SwordCPS = {}
        local PlaceBlocksToggle
        local SwingSwordToggle
        local Thread

        local task_wait = task.wait
        local task_spawn = task.spawn
        local workspace_GetServerTimeNow = function() return workspace:GetServerTimeNow() end

        local function getSafeCPS()
            local toolType = store.hand and store.hand.toolType or nil
            if toolType == 'block' and PlaceBlocksToggle and PlaceBlocksToggle.Enabled and BlockCPS and BlockCPS.GetRandomValue then
                return BlockCPS
            elseif toolType == 'sword' and SwingSwordToggle and SwingSwordToggle.Enabled and SwordCPS and SwordCPS.GetRandomValue then
                return SwordCPS
            elseif CPS and CPS.GetRandomValue then
                return CPS
            end
            return nil
        end

        local function AutoClickAero()
            if Thread then task.cancel(Thread) end
            Thread = task_spawn(function()
                repeat
                    if not bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then
                        local toolType = store.hand and store.hand.toolType
                        if PlaceBlocksToggle.Enabled and toolType == 'block' then
                            local blockPlacer = bedwars.BlockPlacementController and bedwars.BlockPlacementController.blockPlacer
                            if blockPlacer then
                                if (workspace_GetServerTimeNow() - bedwars.BlockCpsController.lastPlaceTimestamp) >= ((1 / 12) * 0.5) then
                                    local mouseinfo = blockPlacer.clientManager:getBlockSelector():getMouseInfo(0)
                                    if mouseinfo and mouseinfo.placementPosition == mouseinfo.placementPosition then
                                        task_spawn(blockPlacer.placeBlock, blockPlacer, mouseinfo.placementPosition)
                                    end
                                end
                            end
                        elseif SwingSwordToggle.Enabled and toolType == 'sword' then
                            bedwars.SwordController:swingSwordAtMouse(0.39)
                        end
                    end

                    local currentCPS = getSafeCPS()
                    task_wait(1 / (currentCPS and currentCPS.GetRandomValue() or 7))
                until not AutoClicker.Enabled
            end)
        end

        local function StopAutoClick()
            if Thread then
                task.cancel(Thread)
                Thread = nil
            end
        end

        local MIN_HOLD_TIME = 0.12
        local ActivationScheduled = nil

        AutoClicker = vain.Categories.Combat:CreateModule({
            Name = 'AutoClicker',
            Tooltip = 'Automatically clicks at a configurable CPS rate',
            Function = function(callback)
                if callback then
                    AutoClicker:Clean(inputService.InputBegan:Connect(function(input)
                        if input.UserInputType == Enum.UserInputType.MouseButton1 then
                            ActivationScheduled = task.delay(MIN_HOLD_TIME, function()
                                ActivationScheduled = nil
                                if inputService:IsMouseButtonPressed(Enum.UserInputType.MouseButton1) then
                                    AutoClickAero()
                                end
                            end)
                        end
                    end))
                    AutoClicker:Clean(inputService.InputEnded:Connect(function(input)
                        if input.UserInputType == Enum.UserInputType.MouseButton1 then
                            if ActivationScheduled then
                                task.cancel(ActivationScheduled)
                                ActivationScheduled = nil
                            end
                            if Thread then
                                task.cancel(Thread)
                                Thread = nil
                            end
                        end
                    end))
                else
                    StopAutoClick()
                end
            end,
            Tooltip = 'Clicks for you'
        })

        PlaceBlocksToggle = AutoClicker:CreateToggle({
            Name = 'Place Blocks',
            Tooltip = 'Automatically places blocks while clicking',
            Default = false,
            Function = function(callback)
                task.defer(function()
                    if BlockCPS and BlockCPS.Object then BlockCPS.Object.Visible = callback end
                end)
            end
        })

        BlockCPS = AutoClicker:CreateTwoSlider({
            Name = 'Block CPS',
            Min = 1,
            Max = 20,
            DefaultMin = 12,
            DefaultMax = 12,
            Darker = true
        })

        SwingSwordToggle = AutoClicker:CreateToggle({
            Name = 'Swing Sword',
            Tooltip = 'Automatically swings the sword while clicking',
            Default = false,
            Function = function(callback)
                if SwordCPS.Object then SwordCPS.Object.Visible = callback end
            end
        })

        SwordCPS = AutoClicker:CreateTwoSlider({
            Name = 'Sword CPS',
            Min = 1,
            Max = 9,
            DefaultMin = 7,
            DefaultMax = 7,
            Darker = true
        })

        task.defer(function()
            if BlockCPS and BlockCPS.Object then
                BlockCPS.Object.Visible = PlaceBlocksToggle and PlaceBlocksToggle.Enabled
            end
            if SwordCPS and SwordCPS.Object then
                SwordCPS.Object.Visible = SwingSwordToggle and SwingSwordToggle.Enabled
            end
        end)
    end
end)  

run(function()
    local BowAssist
    local Targets
    local Sort
    local Shake
    local Speed
    local Angle
    local FOV
    local Blacklist
    local Mouse
    local ThirdPerson
    local Projectiles
    local AimPart
    local FOVCircle

    -- Draw an optional ring showing the Max angle cone, projected from the world
    -- angle onto the screen via the camera FOV and centred on the crosshair.
    local function makeFOVCircle(module)
        local circle = Drawing.new('Circle')
        circle.Thickness = 1
        circle.Filled = false
        circle.NumSides = 64
        circle.Color = Color3.fromRGB(255, 255, 255)
        circle.Visible = false
        module:Clean(function() circle:Remove() end)
        module:Clean(runService.RenderStepped:Connect(function()
            local show = FOVCircle and FOVCircle.Enabled
            circle.Visible = show or false
            if show then
                local vpY = gameCamera.ViewportSize.Y
                local halfAngle = math.rad(math.min(Angle.Value, 179) / 2)
                local camHalf = math.max(math.tan(math.rad(gameCamera.FieldOfView / 2)), 0.01)
                circle.Radius = math.min((vpY / 2) * math.tan(halfAngle) / camHalf, vpY)
                local m = inputService:GetMouseLocation()
                circle.Position = Vector2.new(m.X, m.Y)
            end
        end))
    end

    -- Resolve which point on the target to aim at. Auto uses the head up close
    -- (more damage, reliable at short range) and centre-mass at distance (a
    -- bigger, easier target to land a led shot on). Falls back to RootPart if a
    -- part is missing.
    local function aimPartPosition(ent)
    	local char = ent.Character
    	local head = char and char:FindFirstChild('Head')
    	local torso = char and (char:FindFirstChild('UpperTorso') or char:FindFirstChild('Torso'))
    	local mode = AimPart and AimPart.Value or 'Auto'
    	if mode == 'Head' then
    		return head and head.Position or ent.RootPart.Position
    	elseif mode == 'Torso' then
    		return torso and torso.Position or ent.RootPart.Position
    	end
    	local dist = (ent.RootPart.Position - entitylib.character.RootPart.Position).Magnitude
    	if dist <= 40 and head then
    		return head.Position
    	end
    	return torso and torso.Position or ent.RootPart.Position
    end

    local function ease(t)
    	return t < 0.5 and 4 * t * t * t or 1 - math.pow(-2 * t + 2, 3) / 2
    end
    
    local function findAim(localcframe, predicted, fps, started, offset)
    	local prog, rng = ease(math.min((tick() - started) / (1 / (Speed.Value * 0.5)), 1)), Random.new()
    	local speed = Speed.Value * prog
    
    	return localcframe:Lerp(CFrame.lookAt(localcframe.p, predicted + Vector3.new((rng:NextNumber() - 0.5) * Shake.Value * fps, offset + ((rng:NextNumber() - 0.5) * Shake.Value * fps), (rng:NextNumber() - 0.5) * Shake.Value * fps)), speed * fps), speed
    end
    
    local launchHook
    local lasttarget, started = nil, 0
    -- The held target is still good only while it is alive, present, a valid
    -- enemy, and inside our range. Re-checking this every call lets us drop a
    -- target the instant it leaves the FOV/range instead of staying locked on
    -- a stale one for up to a second (the old behaviour only re-scanned on a
    -- 1s timer or on death).
    local function stillValid(t)
    	if not t or not t.Parent or not t.RootPart or not t.Humanoid or t.Humanoid.Health <= 0 then
    		return false
    	end
    	if not isEnemy(t) then
    		return false
    	end
    	return (t.RootPart.Position - entitylib.character.RootPart.Position).Magnitude <= FOV.Value
    end
    local function getAttackData()
    	if not entitylib.isAlive then
    		return false
    	end
    	if Mouse.Enabled and not inputService:IsMouseButtonPressed(0) then
    		return false
    	end
    	if not store.hand.tool or not bedwars.ItemMeta[store.hand.tool.Name].projectileSource and store.hand.toolType ~= 'bow' then
    		return false
    	end
    	if Blacklist.Enabled and table.find(Projectiles.ListEnabled, store.hand.tool.Name == 'glue_trap' and 'gloop' or store.hand.tool.Name) then
    		return false
    	end

    	if (tick() - started) > 1 or not stillValid(lasttarget) then
    		local ent = entitylib.EntityMouse({
    			Origin = entitylib.character.RootPart.Position,
    			Range = FOV.Value,
    			Part = 'RootPart',
    			Wallcheck = Targets.Walls.Enabled,
    			Players = Targets.Players.Enabled,
    			NPCs = Targets.NPCs.Enabled,
    			Sort = sortmethods[Sort.Value],
    		})
    		if ent then
    			started = tick()
    		end
    		lasttarget = ent
    	end
    	return lasttarget
    end
    
    local rayCheck = RaycastParams.new()
    
    BowAssist = vain.Categories.Combat:CreateModule({
    	Name = 'Bow Assist',
    	Tooltip = 'Snaps bow aim onto the nearest valid target',
    	Function = function(callback)
    		if callback then
    			makeFOVCircle(BowAssist)
    			local predicted = nil
    			local lastpredicted = 0
    			local lastent, found, update = nil, 0, 0
    			-- Target velocity jitters frame-to-frame (knockback, jumps, stair
    			-- stepping), which makes the predicted lead wobble. Average the last
    			-- few samples for a steadier aim. Reset when the target changes.
    			local velSamples = {}
    			local VEL_SAMPLES = 4
    			local function pushVel(v)
    				table.insert(velSamples, v)
    				if #velSamples > VEL_SAMPLES then
    					table.remove(velSamples, 1)
    				end
    			end
    			local function smoothVel()
    				local n = #velSamples
    				if n == 0 then return nil end
    				local sum = Vector3.zero
    				for _, v in velSamples do sum += v end
    				return sum / n
    			end

    			launchHook = bedwars.ProjectileLaunchHook:Add('BowAssist', 10, function(nextLaunch, ...)
    				local res = nextLaunch(...)
    				local projmeta = select(2, ...)
    				if projmeta and tick() - update < 0.1 and lastent and lastent.RootPart then
    					local meta = projmeta:getProjectileMeta()
    					-- Real muzzle speed = base launchVelocity scaled by the charge
    					-- (velocityMultiplier). Gravity likewise scales by gravityMultiplier;
    					-- 35 is the most common Bedwars projectile gravity, used as fallback.
    					local speed = (meta.launchVelocity or 100) * (projmeta.velocityMultiplier or 1)
    					local gravity = (meta.gravitationalAcceleration or 35) * (projmeta.gravityMultiplier or 1)

    					-- Projectiles spawn from the bow/head, not the torso centre. Feeding
    					-- the real muzzle lets the solver return a correct aim direction
    					-- instead of relying on a downstream vertical fudge factor.
    					local char = lplr.Character
    					local head = char and char:FindFirstChild('Head')
    					local origin = head and head.Position or entitylib.character.RootPart.Position

    					-- Latency means the shot is processed on the server after `ping`
    					-- seconds, by which time the target has already moved. Advance the
    					-- target by that window first, then let SolveTrajectory lead the
    					-- remaining flight time. (Old code mis-modelled this by slowing the
    					-- arrow, which broke entirely at >1s ping.)
    					local lat = lplr:GetNetworkPing() or 0
    					local tvel = smoothVel() or lastent.RootPart.Velocity
    					local tpos = aimPartPosition(lastent) + tvel * lat

    					-- Keep the grounded raycast from hitting our own or the target's body.
    					rayCheck.FilterType = Enum.RaycastFilterType.Exclude
    					rayCheck.FilterDescendantsInstances = {char, lastent.RootPart.Parent}

    					predicted = prediction.SolveTrajectory(origin, speed, gravity, tpos, tvel, workspace.Gravity, entitylib.character.HipHeight, nil, rayCheck)
    					lastpredicted = tick()
    				else
    					predicted = nil
    				end
    				return res
    			end)
    
    			BowAssist:Clean(runService.PostSimulation:Connect(function(dt)
    				local ent = getAttackData()
    				if ent then
    					local delta = (ent.RootPart.Position - entitylib.character.RootPart.Position)
    					local localfacing = entitylib.character.RootPart.CFrame.LookVector * Vector3.new(1, 0, 1)
    					local angle = math.acos(localfacing:Dot((delta * Vector3.new(1, 0, 1)).Unit))
    					if angle >= (math.rad(Angle.Value) / 2) then
    						return
    					end
    					if ent ~= lastent then
    						found = tick()
    						table.clear(velSamples)
    					end
    					lastent = ent
    					update = tick()
    					pushVel(ent.RootPart.Velocity)
    					if tick() - lastpredicted < 0.1 then
    						targetinfo.Targets[ent] = tick() + 1
    						local aimpoint = predicted or aimPartPosition(ent)
    						-- Solver now returns a fully corrected intercept point (true muzzle
    						-- origin + charge-scaled speed), so no vertical fudge is needed.
    						local cframe, speed = findAim(gameCamera.CFrame, aimpoint, dt, found, 0)
    						-- In first person move the camera directly; in third person nudge
    						-- the mouse. The old check (Head.LocalTransparencyModifier == 1) was
    						-- an unreliable first-person test that often left the aim doing
    						-- nothing — use the shared isFirstPerson() helper instead.
    						if isFirstPerson() then
    							gameCamera.CFrame = cframe
    						elseif ThirdPerson.Enabled and inputService.MouseEnabled and mousemoverel then
    							local viewport = gameCamera:WorldToViewportPoint(aimpoint)
    							local pos = (Vector2.new(viewport.X, viewport.Y) - inputService:GetMouseLocation()) * (speed / 15)
    							mousemoverel(pos.X, pos.Y)
    						end
    					end
    				end
    			end))
    		else
    			if launchHook then
    				launchHook()
    				launchHook = nil
    			end
    		end
    	end,
        Tooltip = 'Smoothly aims your projectile trajectory to the target'
    })
    
    Targets = BowAssist:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
    	Players = true,
    	Walls = true,
    })
    local methods = {'Damage', 'Distance'}
    for i in sortmethods do
    	if not table.find(methods, i) then
    		table.insert(methods, i)
    	end
    end
    Sort = BowAssist:CreateDropdown({
    	Name = 'Target mode',
    	Tooltip = 'Selects how targets are prioritized and selected',
    	List = methods,
    	Default = 'Angle',
    	ItemTooltips = {
    		Distance = 'Targets the closest enemy by stud distance',
    		Health = 'Targets the enemy with the lowest remaining health',
    		Angle = 'Targets the enemy closest to your look direction',
    		Cursor = 'Targets the enemy nearest to your mouse cursor',
    		Damage = 'Targets the enemy who most recently took damage',
    		Threat = 'Targets the enemy judged to be the greatest combat threat',
    		Kit = 'Prioritizes dangerous kit users (Hannah, Spirit Assassin, etc.)',
    	},
    })
    AimPart = BowAssist:CreateDropdown({
    	Name = 'Aim Part',
    	Tooltip = 'Which point on the target to lead the shot onto',
    	List = {'Auto', 'Head', 'Torso'},
    	Default = 'Auto',
    	ItemTooltips = {
    		Auto = 'Head up close, centre-mass at range',
    		Head = 'Aims at the head — more damage, smaller target',
    		Torso = 'Aims at centre-mass — reliable and easy to land',
    	},
    })
    FOVCircle = BowAssist:CreateToggle({
    	Name = 'Show FOV',
    	Tooltip = 'Draws a ring on your crosshair showing the Max angle cone',
    	Default = false,
    })
    Speed = BowAssist:CreateSlider({
    	Name = 'Aim speed',
    	Min = 1,
    	Max = 20,
    	Default = 7,
    	Suffix = 'sp/s',
    	Tooltip = 'How fast you will aim per second',
    })
    Angle = BowAssist:CreateSlider({
    	Name = 'Max angle',
    	Tooltip = 'Maximum angle in degrees from your look direction to engage',
    	Min = 1,
    	Max = 360,
    	Default = 120,
    })
    Shake = BowAssist:CreateSlider({
    	Name = 'Shake',
    	Min = 1,
    	Max = 100,
    	Default = 5,
    	Tooltip = 'Jitters your screen, Simulating human aim',
    })
    FOV = BowAssist:CreateSlider({
    	Name = 'FOV',
    	Tooltip = 'Field-of-view cone in degrees for target detection',
    	Min = 1,
    	Max = 1000,
    	Default = 200,
    })
    Mouse = BowAssist:CreateToggle({
    	Name = 'Require mouse down',
    	Tooltip = 'Only activates while the left mouse button is held',
    	Default = inputService.KeyboardEnabled,
    })
    ThirdPerson = BowAssist:CreateToggle({
    	Name = 'Use mouse aim',
    	Tooltip = 'Aims using the mouse if ur on third person',
    	Default = true,
    })
    Blacklist = BowAssist:CreateToggle({
    	Name = 'Use blacklist',
    	Tooltip = 'Enables a block type blacklist for filtering targets',
    	Default = true,
    	Function = function(callback)
    		if Projectiles then
    			Projectiles.Object.Visible = callback
    		end
    	end,
    	Tooltip = 'Doesn\'t bow-assist if your holding one of the blacklisted projectiles',
    })
    Projectiles = BowAssist:CreateTextList({
    	Name = 'Blacklisted',
    	Tooltip = 'Projectile names that bypass bow-assist (one per line)',
    	Default = { 'fireball', 'telepearl', 'gloop' },
    	Darker = true,
    })
end)

run(function()
    local old

    vain.Categories.Combat:CreateModule({
        Name = 'No Click Delay',
        Tooltip = 'Enables the No Click Delay module',
        Function = function(callback)
            if callback then
                old = bedwars.SwordController.isClickingTooFast
                bedwars.SwordController.isClickingTooFast = function(self)
                    self.lastSwing = os.clock()
                    return false
                end
            else
                bedwars.SwordController.isClickingTooFast = old
            end
        end,
        Tooltip = 'Remove the CPS cap'
    })
end)

run(function()
    if canDebug then
    	run(function()
    		local BlockReach
    		local BlockRange
    		local BreakReach
    		local BreakRange
    		local SwordReach
    		local SwordRange
    
    		local old
    
    		Reach = vain.Categories.Combat:CreateModule({
    			Name = 'Reach',
    			Tooltip = 'Allows you to place, attack, and break further',
    			Function = function(callback)
    				bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE = callback and SwordReach.Enabled and SwordRange.Value + 2 or 14.4
    				if callback then
    					old = bedwars.BlockSelector.getMouseInfo
    					bedwars.BlockSelector.getMouseInfo = function(...)
    						local Self, Select, Args = ...
    						if not Args then
    							Args = {}
    						end
    						if Select == 0 then
    							Args.range = BlockReach.Enabled and BlockRange.Value or 24
    						elseif Select == 1 then
    							Args.range = BreakReach.Enabled and BreakRange.Value or 18
    						end
    						return old(Self, Select, Args)
    					end
    				else
    					bedwars.BlockSelector.getMouseInfo = old
    					old = nil
    				end
    			end,
    		})
    		SwordReach = Reach:CreateToggle({
    			Name = 'Sword Reach',
    			Tooltip = 'Extends sword attack reach server-side',
    			Default = true,
    			Function = function(callback)
    				bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE = Reach.Enabled and callback and SwordRange.Value + 2 or 14.4
    				pcall(function()
    					SwordRange.Object.Visible = callback
    				end)
    			end,
    		})
    		SwordRange = Reach:CreateSlider({
    			Name = 'Sword Range',
    			Tooltip = 'Sword reach extension in studs',
    			Min = 1,
    			Max = 18,
    			Default = 18,
    			Decimal = 5,
    			Darker = true,
    			Suffix = function(val)
    				return val <= 1 and 'stud' or 'studs'
    			end,
    			Function = function(val)
    				bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE = Reach.Enabled and SwordReach.Enabled and val or 14.4
    			end,
    		})
    		BlockReach = Reach:CreateToggle({
    			Name = 'Placement Reach',
    			Tooltip = 'Extends block placement reach in studs',
    			Function = function(callback)
    				BlockRange.Object.Visible = callback
    			end,
    		})
    		BlockRange = Reach:CreateSlider({
    			Name = 'Placement Range',
    			Tooltip = 'Adjusts the placement range value',
    			Min = 1,
    			Max = 60,
    			Default = 18,
    			Darker = true,
    			Suffix = function(val)
    				return val <= 1 and 'stud' or 'studs'
    			end,
    			Visible = false,
    		})
    		BreakReach = Reach:CreateToggle({
    			Name = 'Break Reach',
    			Tooltip = 'Extends block breaking reach in studs',
    			Function = function(callback)
    				BreakRange.Object.Visible = callback
    			end,
    		})
    		BreakRange = Reach:CreateSlider({
    			Name = 'Break Range',
    			Tooltip = 'Maximum distance in studs to break blocks',
    			Min = 1,
    			Max = 30,
    			Default = 30,
    			Decimal = 5,
    			Darker = true,
    			Suffix = function(val)
    				return val <= 1 and 'stud' or 'studs'
    			end,
    			Visible = false,
    		})
    		Reach:CreateButton({
    			Name = 'Reset to default reach',
    			Tooltip = 'Resets every range back to default',
    			Function = function()
    				BreakRange:SetValue(18)
    				BlockRange:SetValue(24)
    				SwordRange:SetValue(12.4)
    			end,
    		})
    	end)
    else
    	local Value
    	local rayParams = RaycastParams.new()
    	rayParams.RespectCanCollide = true
    
    	Reach = vain.Categories.Combat:CreateModule({
    		Name = 'Reach',
    		Tooltip = 'Extends your melee and placement ranges server-side',
    		Function = function(callback)
    			if callback then
    				Reach:Clean(vainEvents.CEAttacked.Event:Connect(function()
    					local doAttack
    					if not bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then
    						if
    							entitylib.isAlive
    							and store.hand.toolType == 'sword'
    							and bedwars.DaoController.chargingMaid == nil
    						then
    							local attackRange = Value.Value + 2
    							rayParams.FilterDescendantsInstances = { lplr.Character }
    
    							local unit = lplr:GetMouse().UnitRay
    							local localPos = entitylib.character.RootPart.Position
    							local rayRange = (attackRange or 14.4)
    							local ray = workspace:Raycast(unit.Origin, unit.Direction * 200, rayParams)
    							if ray and (localPos - ray.Instance.Position).Magnitude <= rayRange then
    								for _, ent in entitylib.List do
    									doAttack = ent.Targetable
    										and ray.Instance:IsDescendantOf(ent.Character)
    										and (localPos - ent.RootPart.Position).Magnitude <= rayRange
    									if doAttack then
    										break
    									end
    								end
    							end
    
    							local region = bedwars.SwordController:getTargetInRegion(attackRange or 3.8 * 3, 0)
    							if doAttack then
    								doAttack = region
    							end
    							if doAttack then
    								local selfpos = entitylib.character.RootPart.Position
    								local delta = (doAttack.RootPart.Position - selfpos)
    								local dir = CFrame.lookAt(selfpos, doAttack.RootPart.Position).LookVector
    								local pos = selfpos + dir * math.max(delta.Magnitude - 14.4, 0)
    
    								bedwars.Client:Get('SwordHit'):SendToServer({
    									weapon = store.hand.tool,
    									chargedAttack = {chargeRatio = 0},
    									entityInstance = doAttack.Character,
    									validate = {
    										raycast = {},
    										targetPosition = {value = doAttack.RootPart.Position},
    										selfPosition = {value = pos},
    									},
    								})
    							end
    						end
    					end
    				end))
    			end
    		end,
    	})
    	Value = Reach:CreateSlider({
    		Name = 'Range',
    		Tooltip = 'Maximum distance in studs',
    		Min = 0,
    		Max = 18,
    		Default = 18,
    		Suffix = function(val)
    			return val == 1 and 'stud' or 'studs'
    		end,
    	})
    end
end)

run(function()
    local SilentAura
    local Targets
    local Speed
    local Range
    local Angle
    local Mode
    local Area
    local LegitAura
    local Mouse
    local NoSwing
    local Limit
    local SilentAim
    local SwingTime
    local Perfect
    
    local Show
    local Targetcolor
    local Attackcolor
    
    local function getAttackData()
        if not entitylib.isAlive then
            return false
        end
        if Mouse.Enabled then
            if not inputService:IsMouseButtonPressed(0) and (tick() - bedwars.SwordController.lastSwing) > 0.3 then
                return false
            end
        end
        if LegitAura.Enabled and (tick() - bedwars.SwordController.lastSwing) > 0.3 then
            return false
        end
    
        if (lplr.Character:GetAttribute('StunnedUntilTime') or 0) - workspace:GetServerTimeNow() > 0 then
            return false
        end
        if bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then
            return false
        end
    
        local sword = Limit.Enabled and store.hand or store.tools.sword
        if not sword or not sword.tool then
            return false
        end
    
        local meta = bedwars.ItemMeta[sword.tool.Name]
        if Limit.Enabled then
            if store.hand.toolType ~= 'sword' or bedwars.DaoController.chargingMaid then
                return false
            end
        end
    
        return sword, meta
    end
    
    local cache = {}
    local function getAim(ent)
        if Area.Value == 'Closest' then
            if not cache[ent.Character] then
                cache[ent.Character] = ent.Character:GetChildren()
            end
            local localPosition, magnitude, part = inputService.GetMouseLocation(inputService), 9e9, nil
            for _, v in cache[ent.Character] do
                if v and v.Parent and v:IsA('BasePart') then
                    local position, vis = gameCamera.WorldToViewportPoint(gameCamera, v.Position)
    
                    if vis then
                        local mag = (localPosition - Vector2.new(position.x, position.y)).Magnitude
    
                        if mag < magnitude then
                            magnitude = mag
                            part = v
                        end
                    end
                end
            end
            if part then
                return part.Position
            end
        end
        return ent.RootPart.Position
    end
    
    local function ease(t)
        return t < 0.5 and 4 * t * t * t or 1 - math.pow(-2 * t + 2, 3) / 2
    end
    
    local function findAim(localcframe, ent, fps, started)
        local prog, rng = ease(math.min((tick() - started) / (1 / (Speed.Value * 0.5)), 1)), Random.new()
        local speed = Speed.Value * prog
        return localcframe:Lerp(CFrame.lookAt(localcframe.p, getAim(ent) + Vector3.new((rng:NextNumber() - 0.5) * 15 * fps, (rng:NextNumber() - 0.5) * 15 * fps, (rng:NextNumber() - 0.5) * 15 * fps)), speed * fps), speed
    end
    
    local box = Instance.new('BoxHandleAdornment')
    box.Adornee = nil
    box.AlwaysOnTop = true
    box.Size = Vector3.new(3, 5, 3)
    box.CFrame = CFrame.new(0, -0.5, 0)
    box.ZIndex = 0
    box.Parent = vain.gui
    
    SilentAura = vain.Categories.Combat:CreateModule({
        Name = 'Silent Aura',
        Tooltip = 'Attacks nearby enemies silently without visible swings',
        Function = function(callback)
            if callback then
                local lastent, lastfound = nil, 0
                local foundat = tick()
                local lastattacked = tick()
    
                SilentAura:Clean(runService.PostSimulation:Connect(function(dt)
                    if entitylib.isAlive and tick() - lastfound < 0.5 then
                        targetinfo.Targets[lastent] = tick() + 0.5
                        entitylib.character.Humanoid.AutoRotate = not SilentAim.Enabled
                        local cframe, speed = findAim(gameCamera.CFrame, lastent, dt, foundat)
                        if SilentAim.Enabled then
                            entitylib.character.RootPart.CFrame = entitylib.character.RootPart.CFrame:Lerp(CFrame.lookAt(entitylib.character.RootPart.Position, Vector3.new(lastent.RootPart.Position.X, entitylib.character.RootPart.Position.Y, lastent.RootPart.Position.Z)), (speed + 2) * dt)
                        else
                            gameCamera.CFrame = cframe
                        end
                    elseif entitylib.isAlive then
                        entitylib.character.Humanoid.AutoRotate = true
                    end
                end))
    
                local frames = 9e9
                repeat
                    task.wait()
                    local sword, meta = getAttackData()
                    if sword then
                        local localPosition = entitylib.character.RootPart.Position
                        local ent = entitylib.EntityPosition({
                            Origin = localPosition,
                            Range = bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE + Range.Value,
                            Wallcheck = Targets.Walls.Enabled or nil,
                            Part = 'RootPart',
                            Players = Targets.Players.Enabled,
                            NPCs = Targets.NPCs.Enabled,
                            Limit = 1,
                            Sort = sortmethods[Mode.Value or 'Distance'],
                        })
                        local Slider = tick() - lastattacked < 0.1 and Attackcolor or Targetcolor
                        box.Adornee = Show.Enabled and ent and ent.RootPart or nil
                        box.Transparency = 1 - Slider.Opacity
                        box.Color3 = Color3.fromHSV(Slider.Hue, Slider.Sat, Slider.Value)
                        if ent then
                            if not store.hand or store.hand.tool ~= sword.tool then
                                local hotbar = getHotbar(sword.tool)
                                if hotbar then
                                    hotbarSwitch(hotbar)
                                else
                                    continue
                                end
                            end
                            if frames > 50 then
                                frames = 0
                            end
                            frames += 1
    
                            local localfacing = (inputService.KeyboardEnabled and gameCamera or entitylib.character.RootPart).CFrame.LookVector * Vector3.new(1, 0, 1)
                            local delta, flat = (ent.RootPart.Position - localPosition), ((ent.RootPart.Position - localPosition) * Vector3.new(1, 0, 1))
                            local facingdot = flat.Magnitude > 0 and localfacing.Magnitude > 0 and (localfacing / localfacing.Magnitude):Dot(flat / flat.Magnitude) or 0
                            if facingdot < math.cos(math.rad(Angle.Value) / 2) then
                                continue
                            end
    
                            if not LegitAura.Enabled and (tick() - bedwars.SwordController.lastSwing) >= (Perfect.Enabled and (meta.sword.attackSpeed or 0.11) or math.max(SwingTime.Value, 0.11)) then
                                bedwars.SwordController:playSwordEffect(meta, false)
                                bedwars.SwordController.lastSwing = tick()
                            end
    
                            if lastent ~= ent or facingdot < -0.5 then
                                foundat = tick()
                            end
                            lastent, lastfound = ent, tick()
    
                            if delta.Magnitude > bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE then
                                continue
                            end
                            lastattacked = tick()
    
                            local dir = CFrame.lookAt(localPosition, ent.RootPart.Position).LookVector
                            local pos = localPosition + dir * math.max(delta.Magnitude - 14.4, 0)
                            bedwars.SwordController.lastAttack = workspace:GetServerTimeNow()
                            bedwars.Client:Get(remotes.AttackEntity):SendToServer({
                                weapon = sword.tool,
                                chargedAttack = {chargeRatio = 0},
                                entityInstance = ent.Character,
                                validate = {
                                    raycast = {
                                        cameraPosition = {value = pos},
                                        cursorDirection = {value = dir},
                                    },
                                    targetPosition = {
                                        value = ent.RootPart.Position,
                                    },
                                    selfPosition = {value = pos},
                                },
                            })
                        else
                            lastfound = 0
                            frames = 0
                        end
                    else
                        box.Adornee = nil
                        lastfound = 0
                        frames = 0
                    end
                until not SilentAura.Enabled
            else
                if entitylib.isAlive then
                    entitylib.character.Humanoid.AutoRotate = true
                end
                box.Adornee = nil
            end
        end,
        Tooltip = 'Automatically aims and attacks nearby target',
    })
    
    Targets = SilentAura:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        NPCs = true,
    })
    Speed = SilentAura:CreateSlider({
        Name = 'Aim speed',
        Min = 1,
        Max = 10,
        Default = 6,
        Decimal = 5,
        Tooltip = 'How fast the Aura is going to aim',
    })
    SwingTime = SilentAura:CreateSlider({
        Name = 'Swing time',
        Tooltip = 'Minimum seconds between swings',
        Darker = true,
        Visible = false,
        Min = 0,
        Max = 0.5,
        Default = 0.42,
        Decimal = 100,
    })
    Range = SilentAura:CreateSlider({
        Name = 'Extra swing distance',
        Tooltip = 'Where you will start swinging, not attacking',
        Min = 0,
        Max = 6,
        Suffix = function(val)
            return val <= 1 and 'stud' or 'studs'
        end,
