run(function()
    local Sprint
    local old
    
    Sprint = vain.Categories.Combat:CreateModule({
        Name = 'Sprint',
        Tooltip = 'Keeps you sprinting at all times automatically',
        Function = function(callback)
            if callback then
                if inputService.TouchEnabled then 
                    pcall(function() 
                        lplr.PlayerGui.MobileUI['4'].Visible = false 
                    end) 
                end
                old = bedwars.SprintController.stopSprinting
                bedwars.SprintController.stopSprinting = function(...)
                    local call = old(...)
                    bedwars.SprintController:startSprinting()
                    return call
                end
                Sprint:Clean(entitylib.Events.LocalAdded:Connect(function() 
                    task.delay(0.1, function() 
                        bedwars.SprintController:stopSprinting() 
                    end) 
                end))
                bedwars.SprintController:stopSprinting()
            else
                if inputService.TouchEnabled then 
                    pcall(function() 
                        lplr.PlayerGui.MobileUI['4'].Visible = true 
                    end) 
                end
                bedwars.SprintController.stopSprinting = old
                bedwars.SprintController:stopSprinting()
            end
        end,
        Tooltip = 'Sets your sprinting to true.'
    })
end)

run(function()
	local TriggerBot
	local SwordToggle
	local SwordCPS 
	local ProjectileToggle
	local ProjectileFirerate
	local ProjectileLegitSwitch
	local ProjectileDelayShoot
	local RequireMouse
	local TriggerDelay
	local DelayRandom
	local HitChance

	local rayparms = RaycastParams.new()
	rayparms.FilterType = Enum.RaycastFilterType.Exclude
	rayparms.RespectCanCollide = false
	rayparms.FilterDescendantsInstances = {lplr.Character}

	local lastCapture = 0
	local doAttack = false
	local lastShot = tick()
	local t = 0
	-- Humanization state for the sword path: when the crosshair first lands on a
	-- target we arm a randomized delay; the swing only fires once it elapses, then
	-- a hit-chance roll decides whether to actually swing this cycle.
	local triggerArmedAt = 0
	local pendingDelay = 0

	TriggerBot = vain.Categories.Combat:CreateModule({
		Name = 'TriggerBot',
		Tooltip = 'Automatically swings when hovering over a entity',
		Disabled = canEngine,
		Function = function(callback)
			if callback then
				lastCapture = 0
				doAttack = false
				triggerArmedAt = 0

				TriggerBot:Clean(lplr.CharacterAdded:Connect(function()
					rayparms.FilterDescendantsInstances = {lplr.Character}
				end))

				t = 0.016

				repeat
					if not entitylib.isAlive then
						t = 0.16
						task.wait(t)
						continue
					end

					if RequireMouse.Enabled and not inputService:IsMouseButtonPressed(0) then
						triggerArmedAt = 0
						t = 0.05
						task.wait(t)
						continue
					end

					if not bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then

						if SwordToggle.Enabled then
							if store.hand.toolType == 'sword' and bedwars.DaoController.chargingMaid == nil and not bedwars.SwordController.disableSwingState then
								local attackRange = bedwars.ItemMeta[store.hand.tool.Name].sword.attackRange
						
								local unit = lplr:GetMouse().UnitRay
								local localPos = entitylib.character.RootPart.Position
								local rayRange = (attackRange or 12.4)
								local ray = bedwars.QueryUtil:raycast(unit.Origin, unit.Direction * 200, rayparms)
								
								if ray and (localPos - ray.Instance.Position).Magnitude <= rayRange then
									for _, ent in entitylib.List do
										doAttack = ent.Targetable and ray.Instance:IsDescendantOf(ent.Character) and (localPos - ent.RootPart.Position).Magnitude <= rayRange
										if doAttack then
											break
										end
									end
								end
						
								doAttack = doAttack or bedwars.SwordController:getTargetInRegion(attackRange or 4.13 * 3, 0)
								
								if doAttack then
									-- Arm a randomized delay the moment the crosshair lands on a
									-- target; only swing once it elapses, then roll the hit chance.
									if triggerArmedAt == 0 then
										triggerArmedAt = tick()
										pendingDelay = (TriggerDelay.Value + math.random() * DelayRandom.Value) / 1000
									end
									if (tick() - triggerArmedAt) >= pendingDelay then
										triggerArmedAt = 0
										if math.random(1, 100) <= HitChance.Value then
											t = (1 / SwordCPS.GetRandomValue())
											bedwars.SwordController:swingSwordAtMouse()
										else
											t = 0.05
										end
									else
										t = 0.016
									end
								else
									triggerArmedAt = 0
									t = 0.028
								end

							elseif store.equippedKit == 'summoner' and store.hand.tool.Name:find('summoner_claw') then
								local unit = lplr:GetMouse().UnitRay
								local localPos = entitylib.character.RootPart.Position
								local rayRange = 14.4
								local ray = bedwars.QueryUtil:raycast(unit.Origin, unit.Direction * 200, rayparms)
								
								doAttack = false
								if ray and (localPos - ray.Instance.Position).Magnitude <= rayRange then
									for _, e in entitylib.List do
										if e.Targetable and ray.Instance:IsDescendantOf(e.Character) and (localPos - e.RootPart.Position).Magnitude <= rayRange then
											doAttack = true
											break
										end
									end
								end
								
								doAttack = doAttack or bedwars.SwordController:getTargetInRegion(4.8 * 3, 0)
								
								if doAttack then
									t = (1 / SwordCPS.GetRandomValue())
									bedwars.SummonerClawController:clawAttack(lplr, entitylib.character.RootPart.Position, gameCamera.CFrame.LookVector, store.hand.tool.Name or 'summoner_claw_1')
									bedwars.Client:Get(remotes.SummonerClawAttack):SendToServer({
										position = entitylib.character.RootPart.Position,
										direction = gameCamera.CFrame.LookVector,
										clientTime = workspace:GetServerTimeNow()
									})
								else
									t = 0.065
								end
							else
								t = 0.1
							end
						end
						if ProjectileToggle.Enabled then
							local toolName = store.hand.tool.Name:lower()
							local meta = bedwars.ItemMeta[toolName]

							if meta and meta.projectileSource then
								local ping = lplr:GetNetworkPing() or 0
								local fireDelay = 0.2 + ping + (ProjectileFirerate.Value or 0.2)

								if (tick() - lastShot) >= fireDelay then
									mouse1click()
									lastShot = tick()

									t = (ProjectileDelayShoot.Value or 0.1) + 0.015
									local itemType = nil
									local items = store.inventory.inventory.items
									for _, item in items do
										local _itemMeta = bedwars.ItemMeta[item.itemType]
										local proj = _itemMeta and _itemMeta.projectileSource
										if not proj then continue end
										if not proj.ammoItemTypes then continue end
										for _, inv in items do
											if table.find(proj.ammoItemTypes, inv.itemType) then
												itemType = item.itemType
												break
											end
										end
										if itemType then break end
									end
									if ProjectileLegitSwitch.Enabled then
										task.wait(t - 0.045)
										local holdingCrossbow = itemType and itemType:find('crossbow')
										local holdingBow = itemType and itemType:find('bow') and not holdingCrossbow

										if holdingCrossbow then
											pcall(function() bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_CROSSBOW_FIRE) end)
											bedwars.GameAnimationUtil:playAnimation(lplr, bedwars.AnimationType.CROSSBOW_FIRE)
										elseif holdingBow then
											pcall(function() bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_CROSSBOW_FIRE) end)
											bedwars.GameAnimationUtil:playAnimation(lplr, bedwars.AnimationType.BOW_FIRE)
										else
											local shootAnim = (bedwars.ItemMeta[toolName].thirdPerson) and (bedwars.ItemMeta[toolName].thirdPerson.shootAnimation)
											if shootAnim then
												bedwars.GameAnimationUtil:playAnimation(lplr, shootAnim)
											end
										end
									end
								else
									t = 0.03
								end
							else
								t = 0.12
							end
						end

					else
						t = 0.1
					end

					task.wait(t)
				until not TriggerBot.Enabled
			end
		end
	})

	SwordToggle = TriggerBot:CreateToggle({
		Name = 'Sword Toggle',
		Tooltip = 'enables the sword toggle',
		Default = true,
		Function = function(callback)
			if SwordCPS then SwordCPS.Object.Visible = callback end
		end
	})

	SwordCPS = TriggerBot:CreateTwoSlider({
		Name = "Sword CPS",
		Tooltip = 'swords cps',
		Min = 0,
		Max = 24,
		DefaultMax = 7,
		DefaultMin = 7,
		Darker = true,
		Visible = SwordToggle.Enabled
	})

	RequireMouse = TriggerBot:CreateToggle({
		Name = 'Require mouse down',
		Tooltip = 'Only triggers while holding the left mouse button',
		Default = false,
	})

	TriggerDelay = TriggerBot:CreateSlider({
		Name = 'Trigger Delay',
		Tooltip = 'Base delay after the crosshair lands on a target before swinging',
		Min = 0,
		Max = 500,
		Default = 0,
		Suffix = 'ms',
	})

	DelayRandom = TriggerBot:CreateSlider({
		Name = 'Delay Randomization',
		Tooltip = 'Adds up to this many extra ms of random delay to each swing',
		Min = 0,
		Max = 500,
		Default = 0,
		Suffix = 'ms',
	})

	HitChance = TriggerBot:CreateSlider({
		Name = 'Hit Chance',
		Tooltip = 'Chance to actually swing when a target is under the crosshair',
		Min = 1,
		Max = 100,
		Default = 100,
		Suffix = '%',
	})

	if not inputService.TouchEnabled then
		ProjectileToggle = TriggerBot:CreateToggle({
			Name = 'Projectile Toggle',
			Tooltip = 'enables the projectile toggle',
			Default = false,
			Function = function(callback)
				if ProjectileFirerate then ProjectileFirerate.Object.Visible = callback end
				if ProjectileDelayShoot then ProjectileDelayShoot.Object.Visible = callback end
				if ProjectileLegitSwitch then ProjectileLegitSwitch.Object.Visible = callback end
			end
		})

		ProjectileFirerate = TriggerBot:CreateSlider({
			Name = "Projectile Fire Rate",
			Tooltip = 'projectile fire rate',
			Min = 0,
			Max = 4,
			Default = 0.2,
			Decimal = 100,
			Darker = true,
			Visible = ProjectileToggle.Enabled
		})

		ProjectileDelayShoot = TriggerBot:CreateSlider({
			Name = "Projectile Delay Shoot",
			Tooltip = 'projectile delay in shooting',
			Min = 0,
			Max = 2,
			Default = 0.1,
			Decimal = 100,
			Darker = true,
			Visible = ProjectileToggle.Enabled
		})

		ProjectileLegitSwitch = TriggerBot:CreateToggle({
			Name = "Projectile Legit Switch",
			Tooltip = 'should switch to the projectile',
			Default = false,
			Darker = true,
			Visible = ProjectileToggle.Enabled
		})
	end
end)

run(function()
	local Velocity
	local Vertical
	local VerticalChance
	local Horizontal
	local HorizontalChance
	local Mode
	local DelayGround
	local DelayAir
	local Targetting
	local Chance

	local old = nil
	local rand = Random.new()

	Velocity = vain.Categories.Combat:CreateModule({
		Name = 'Velocity',
		Tooltip = 'allows you to edit ur velocity',
		Function = function(callback)
			if callback then
				old = bedwars.KnockbackUtil.applyKnockback
				Velocity:Clean(vainEvents.TakeKnockback.Event:Connect(function(root, mass, dir, knockback, ...)
					local args = {...}
					local clone = table.clone(knockback)

					local air, ground = false, false
					task.delay(DelayAir.Value / 1000, function()
						clone.horizontal = knockback.horizontal or 1
						air = true
					end)
					task.delay(DelayGround.Value / 1000, function()
						clone.vertical = knockback.vertical or 1
						ground = true
					end)
					repeat task.wait(0.1) until air
					repeat task.wait(0.05) until ground
					old(root, mass, dir, clone, unpack(args))
				end))

				bedwars.KnockbackUtil.applyKnockback = function(root, mass, dir, knockback, ...)
					local chance = rand:NextNumber(0, 100)
					chance = math.floor(chance)
					if Mode.Value == 'Normal' then
						if chance >= Chance.Value then return old(root, mass, dir, knockback, ...) end
					end
						
					local check = (not Targetting.Enabled) or entitylib.EntityPosition({
						Range = 20,
						Part = 'RootPart',
						Players = true
					})
		
					if check then
						knockback = knockback or {}
						if Mode.Value == 'Lag' then
							if chance < Chance.Value then
								return vainEvents.TakeKnockback:Fire(root, mass, dir, knockback, ...)
							end
						else
							local horiz = (knockback.horizontal or 1) * (Horizontal.Value / 100)
							local vert = (knockback.vertical or 1) * (Vertical.Value / 100)
							chance = rand:NextNumber(0, 100)
							chance = math.floor(chance)
							if Horizontal.Value == 0 and Vertical.Value == 0 and HorizontalChance.Value == 100 and VerticalChance.Value then return end
							if chance >= HorizontalChance.Value then  
								chance = rand:NextNumber(0, 100)
								chance = math.floor(chance)
								horiz = knockback.horizontal 
							end
							if chance >= VerticalChance.Value then  
								chance = rand:NextNumber(0, 100)
								chance = math.floor(chance)
								vert = knockback.vertical 
							end
							knockback.horizontal = horiz
							knockback.vertical = vert
						end
					end
						
					return old(root, mass, dir, knockback, ...)
				end
			else
				bedwars.KnockbackUtil.applyKnockback = old
				old = nil
			end
		end
	})
	Mode = Velocity:CreateDropdown({
		Name = "Mode",
		Tooltip = 'Selects the operating mode',
		List = {'Lag','Default'},
		ItemTooltips = {
			Lag = 'Applies velocity using packet-delay timing — works with FakeLag',
			Default = 'Directly multiplies horizontal and vertical knockback vectors',
		},
		Function = function(val)
			if val == 'Default' then
				if HorizontalChance then HorizontalChance.Object.Visible = true end
				if Horizontal then Horizontal.Object.Visible = true end
				if VerticalChance then VerticalChance.Object.Visible = true end
				if Vertical then Vertical.Object.Visible = true end
				if DelayGround then DelayGround.Object.Visible = false end
				if DelayAir then DelayAir.Object.Visible = false end
			elseif val == 'Lag' then
				if HorizontalChance then HorizontalChance.Object.Visible = false end
				if Horizontal then Horizontal.Object.Visible = false end
				if VerticalChance then VerticalChance.Object.Visible = false end
				if Vertical then Vertical.Object.Visible = false end
				if DelayGround then DelayGround.Object.Visible = true end
				if DelayAir then DelayAir.Object.Visible = true end
			else
				if HorizontalChance then HorizontalChance.Object.Visible = false end
				if Horizontal then Horizontal.Object.Visible = false end
				if VerticalChance then VerticalChance.Object.Visible = false end
				if Vertical then Vertical.Object.Visible = false end
				if DelayGround then DelayGround.Object.Visible = false end
				if DelayAir then DelayAir.Object.Visible = false end
				vain:CreateNotification('Velocity',`Storing packets... returned {val or Mode.Value} report ASAP`,16)
			end
		end
	})
	Vertical = Velocity:CreateSlider({
		Name = "Vertical",
		Tooltip = 'Vertical knockback component',
		Min = 0,
		Max = 100,
		Default = 100,
		Decimal = 10,
		Visible = (Mode.Value == 'Default')
	})
	VerticalChance = Velocity:CreateSlider({
		Name = "Vertical Chance",
		Tooltip = 'Probability (%) of applying the vertical component',
		Min = 0,
		Max = 100,
		Default = 100,
		Decimal = 100,
		Suffix = '%',
		Visible = (Mode.Value == 'Default')
	})
	Horizontal = Velocity:CreateSlider({
		Name = "Horizontal",
		Tooltip = 'Horizontal knockback component',
		Min = 0,
		Max = 100,
		Default = 100,
		Decimal = 10,
		Visible = (Mode.Value == 'Default')
	})
	HorizontalChance = Velocity:CreateSlider({
		Name = "Horizontal Chance",
		Tooltip = 'Probability (%) of applying the horizontal component',
		Min = 0,
		Max = 100,
		Default = 100,
		Decimal = 100,
		Suffix = '%',
		Visible = (Mode.Value == 'Default')
	})
	DelayGround = Velocity:CreateSlider({
		Name = "Delay Ground",
		Tooltip = 'Seconds before applying velocity while grounded',
		Min = 0,
		Max = 3000,
		Default = 1000,
		Suffix = 'ms',
		Decimal = 100,
		Visible = (Mode.Value == 'Lag')
	})
	DelayAir = Velocity:CreateSlider({
		Name = "Air Ground",
		Tooltip = 'Seconds before applying velocity while airborne',
		Min = 0,
		Max = 3000,
		Default = 1000,
		Suffix = 'ms',
		Decimal = 100,
		Visible = (Mode.Value == 'Lag')
	})
	Targetting = Velocity:CreateToggle({
		Name = 'Only when targetting',
		Tooltip = 'Only modifies velocity when a target is being attacked',
		Default = false
	})
	Chance = Velocity:CreateSlider({
		Name = "Chance",
		Tooltip = 'Probability (%) this action fires each cycle',
		Min = 0,
		Max = 100,
		Default = 100,
		Decimal = 100,
		Suffix = '%',
	})
end)

run(function()
    local VelocityPlus
    local Mode
    local Chance
    local TargetCheck
    local rand = Random.new()
    local old = nil
    
    local function rotateY(v, deg)
    	local r = math.rad(deg)
    	return Vector3.new(v.X * math.cos(r) - v.Z * math.sin(r), 0, v.X * math.sin(r) + v.Z * math.cos(r))
    end
    
    VelocityPlus = vain.Categories.Combat:CreateModule({
    	Name = 'Velocity Plus',
    	Tooltip = 'Modifies the knockback velocity you receive from hits',
    	Function = function(callback)
    		if callback then
    			old = bedwars.KnockbackUtil.applyKnockback
    			bedwars.KnockbackUtil.applyKnockback = function(root, mass, dir, knockback, ...)
    				if rand:NextNumber(0, 100) > Chance.Value then
    					return old(root, mass, dir, knockback, ...)
    				end
    				if
    					TargetCheck.Enabled
    					and not entitylib.EntityPosition({
    						Range = 22,
    						Part = 'RootPart',
    						Players = true,
    					})
    				then
    					return old(root, mass, dir, knockback, ...)
    				end
    
    				local velocity = (root.Position * Vector3.new(1, 0, 1)) - Vector3.new(dir.X, 0, dir.Z)
    				if velocity.Magnitude < 0.001 then
    					return old(root, mass, dir, knockback, ...)
    				end
    				velocity = velocity.Unit
    				local chosen = Mode.Value == 'Random' and ({ 'Left', 'Right', 'Pull' })[rand:NextInteger(1, 3)] or Mode.Value
    				local rdir = chosen == 'Pull' and -velocity or table.find({'Left', 'Right'}, chosen) and rotateY(velocity, chosen == 'Left' and 90 or 90) or velocity
    				return old(root, mass, Vector3.new(root.Position.X - rdir.X * 100, dir.Y, root.Position.Z - rdir.Z * 100), knockback, ...)
    			end
    		else
    			bedwars.KnockbackUtil.applyKnockback = old or bedwars.KnockbackUtil.applyKnockback
    			old = nil
    		end
    	end,
    	Tooltip = 'Redirects knockback you receive in a chosen direction.'
    })
    
    Mode = VelocityPlus:CreateDropdown({
    	Name = 'Direction',
    	List = {'Left', 'Right', 'Pull', 'Random'},
    	Default = 'Random',
    	Tooltip = 'Left/Right: deflect sideways 90dg\nPull: go past the attacker\nRandom: pick one each hit',
    	ItemTooltips = {
    		Left = 'Deflects your knockback 90° to the left',
    		Right = 'Deflects your knockback 90° to the right',
    		Pull = 'Sends you past the attacker instead of away from them',
    		Random = 'Randomly picks a direction each time you get hit',
    	},
    })
    Chance = VelocityPlus:CreateSlider({
    	Name = 'Chance',
    	Min = 0,
    	Max = 100,
    	Default = 100,
    	Suffix = '%',
    	Tooltip = 'Probability the redirect applies per knockback event',
    })
    TargetCheck = VelocityPlus:CreateToggle({
    	Name = 'Only when targeting',
    	Tooltip = 'Only redirects knockback when an enemy is within 22 studs',
    })
end)

