    Blatant
]]

run(function()
    local AntiFall
    local Mode
    local Material
    local Color
    local rayCheck = RaycastParams.new()
    rayCheck.RespectCanCollide = true
    
    local function getLowGround()
        local mag = math.huge
        for _, pos in bedwars.BlockController:getStore():getAllBlockPositions() do
            pos = pos * 3
            if pos.Y < mag and not getPlacedBlock(pos + Vector3.new(0, 3, 0)) then
                mag = pos.Y
            end
        end
        return mag
    end
    
    AntiFall = vain.Categories.Blatant:CreateModule({
        Name = 'Anti Fall',
        Tooltip = 'Prevents fall damage by placing a block beneath you',
        Function = function(callback)
            if callback then
                repeat task.wait() until store.matchState ~= 0 or (not AntiFall.Enabled)
                if not AntiFall.Enabled then return end
    
                local pos, debounce = getLowGround(), tick()
                if pos ~= math.huge then
                    AntiFallPart = Instance.new('Part')
                    AntiFallPart.Size = Vector3.new(10000, 1, 10000)
                    AntiFallPart.Transparency = 1 - Color.Opacity
                    AntiFallPart.Material = Enum.Material[Material.Value]
                    AntiFallPart.Color = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
                    AntiFallPart.Position = Vector3.new(0, pos - 2, 0)
                    AntiFallPart.CanCollide = Mode.Value == 'Collide'
                    AntiFallPart.Anchored = true
                    AntiFallPart.CanQuery = false
                    AntiFallPart.Parent = workspace
                    AntiFall:Clean(AntiFallPart)
                    AntiFall:Clean(AntiFallPart.Touched:Connect(function(touched)
                        if touched.Parent == lplr.Character and entitylib.isAlive and debounce < tick() then
                            debounce = tick() + 0.1
                            if Mode.Value == 'Normal' then
                                local top = getNearGround()
                                if top then
                                    local lastTeleport = lplr:GetAttribute('LastTeleported')
                                    local connection
                                    connection = runService.PreSimulation:Connect(function()
                                        if vain.Modules.Fly.Enabled or InfiniteFly.Enabled or vain.Modules['Long Jump'].Enabled then
                                            connection:Disconnect()
                                            AntiFallDirection = nil
                                            return
                                        end
    
                                        if entitylib.isAlive and lplr:GetAttribute('LastTeleported') == lastTeleport then
                                            local delta = ((top - entitylib.character.RootPart.Position) * Vector3.new(1, 0, 1))
                                            local root = entitylib.character.RootPart
                                            AntiFallDirection = delta.Unit == delta.Unit and delta.Unit or Vector3.zero
                                            root.Velocity *= Vector3.new(1, 0, 1)
                                            rayCheck.FilterDescendantsInstances = {gameCamera, lplr.Character}
                                            rayCheck.CollisionGroup = root.CollisionGroup
    
                                            local ray = workspace:Raycast(root.Position, AntiFallDirection, rayCheck)
                                            if ray then
                                                for _ = 1, 10 do
                                                    local dpos = roundPos(ray.Position + ray.Normal * 1.5) + Vector3.new(0, 3, 0)
                                                    if not getPlacedBlock(dpos) then
                                                        top = Vector3.new(top.X, pos.Y, top.Z)
                                                        break
                                                    end
                                                end
                                            end
    
                                            root.CFrame += Vector3.new(0, top.Y - root.Position.Y, 0)
                                            if not frictionTable.Speed then
                                                root.AssemblyLinearVelocity = (AntiFallDirection * getSpeed()) + Vector3.new(0, root.AssemblyLinearVelocity.Y, 0)
                                            end
    
                                            if delta.Magnitude < 1 then
                                                connection:Disconnect()
                                                AntiFallDirection = nil
                                            end
                                        else
                                            connection:Disconnect()
                                            AntiFallDirection = nil
                                        end
                                    end)
                                    AntiFall:Clean(connection)
                                end
                            elseif Mode.Value == 'Velocity' then
                                entitylib.character.RootPart.Velocity = Vector3.new(entitylib.character.RootPart.Velocity.X, 100, entitylib.character.RootPart.Velocity.Z)
                            end
                        end
                    end))
                end
            else
                AntiFallDirection = nil
            end
        end,
        Tooltip = 'Help\'s you with your Parkinson\'s\nPrevents you from falling into the void.'
    })
    Mode = AntiFall:CreateDropdown({
        Name = 'Move Mode',
        Tooltip = 'Selects the move mode option',
        List = {'Normal', 'Collide', 'Velocity'},
        ItemTooltips = {
            Normal = 'Moves using standard walkspeed character movement',
            Collide = 'Moves using physics collision to stay on the platform',
            Velocity = 'Moves by directly setting character velocity each frame',
        },
        Function = function(val)
            if AntiFallPart then
                AntiFallPart.CanCollide = val == 'Collide'
            end
        end,
    Tooltip = 'Normal - Smoothly moves you towards the nearest safe point\nVelocity - Launches you upward after touching\nCollide - Allows you to walk on the part'
    })
    local materials = {'ForceField'}
    for _, v in Enum.Material:GetEnumItems() do
        if v.Name ~= 'ForceField' then
            table.insert(materials, v.Name)
        end
    end
    Material = AntiFall:CreateDropdown({
        Name = 'Material',
        Tooltip = 'Selects the material used for placed blocks',
        List = materials,
        Function = function(val)
            if AntiFallPart then
                AntiFallPart.Material = Enum.Material[val]
            end
        end
    })
    Color = AntiFall:CreateColorSlider({
        Name = 'Color',
        DefaultOpacity = 0.5,
        Function = function(h, s, v, o)
            if AntiFallPart then
                AntiFallPart.Color = Color3.fromHSV(h, s, v)
                AntiFallPart.Transparency = 1 - o
            end
        end
    })
end)

run(function()
    local AutoDodge
    local Targets
    local Melee
    local Range
    
    local oldroot, clone, hip = nil, nil, 2.5
    local rayParams = RaycastParams.new()
    rayParams.FilterType = Enum.RaycastFilterType.Include
    rayParams.RespectCanCollide = true
    
    local function doClone()
        if store.rootpart then return end
        if entitylib.isAlive and entitylib.character.Humanoid.Health > 0 then
            if oldroot and oldroot.Parent then
                return true
            end
    
            hip = entitylib.character.Humanoid.HipHeight
            oldroot = entitylib.character.HumanoidRootPart
            if not lplr.Character.Parent then return false end
            lplr.Character.Parent = replicatedStorage
            clone = oldroot:Clone()
            clone.Parent = lplr.Character
            oldroot.Transparency = 1
            oldroot.Parent = workspace
            store.rootpart = oldroot
            lplr.Character.PrimaryPart = clone
            lplr.Character.Parent = workspace
            bedwars.QueryUtil:setQueryIgnored(clone, true)
            bedwars.QueryUtil:setQueryIgnored(oldroot, true)
            return true
        end
        return false
    end
    
    local function revertClone()
        if oldroot and oldroot.Parent and entitylib.isAlive then 
            lplr.Character.Parent = replicatedStorage
            oldroot.Parent = lplr.Character
            if clone then
                oldroot.CFrame = clone.CFrame
                oldroot.Velocity = clone.Velocity
                clone:Destroy()
                clone = nil
            end
            lplr.Character.PrimaryPart = oldroot
            lplr.Character.Parent = workspace
            oldroot.CanCollide = true
            entitylib.character.Humanoid.HipHeight = hip or 2.6
            oldroot.Transparency = 1
            oldroot = nil
            store.rootpart = nil
            return true
        end
        return false
    end
    
    AutoDodge = vain.Categories.Blatant:CreateModule({
    	Name = 'Auto Dodge',
    	Tooltip = 'Dodges melee and projectiles "blatantly"',
    	Function = function(call)
    		if call then
    			repeat
    				task.wait()
    			until store.matchState ~= 0 and store.map or not AutoDodge.Enabled
    			if not AutoDodge.Enabled then
    				return
    			end
    
    			rayParams.FilterDescendantsInstances = {store.map}
    			local lowestpoint = 9e9
    			local Dodge = 0
    			for _, v in store.blocks do
    				local point = (v.Position.Y - (v.Size.Y / 2)) - 50
    				if point < lowestpoint then
    					lowestpoint = point
    				end
    			end
    
                AutoDodge:Clean(runService.PostSimulation:Connect(function()
                    if oldroot and oldroot.Parent then
                        local newpoint, pos = lowestpoint, CFrame.new(clone.CFrame.X, lowestpoint - 6, clone.CFrame.Z)
                        if Dodge then
                            newpoint = workspace:Raycast(pos.Position, Vector3.new(0, 1000, 0), rayParams)
                            if newpoint then
                                newpoint = CFrame.new(clone.CFrame.X, newpoint.Position.Y - 6, clone.CFrame.Z) * CFrame.Angles(math.rad(90), 0, 0)
                            end
                        end
                        oldroot.Velocity = Vector3.zero
                        oldroot.CFrame = Dodge and (newpoint or pos) or (clone.CFrame + Vector3.new(0, 1, 0)) * CFrame.Angles(math.rad(90), 0, 0)
                    end
                end))
    
                local last = true
                repeat
                    if entitylib.isAlive then
                        if oldroot then
                            local ownership = isnetworkowner(oldroot)
                            if not ownership and ownership ~= last then
                                notif('AutoDodge', 'Network ownership disowned', 7, 'alert')
                            end
                            last = ownership
                            if not ownership then
                                Dodge = false
                                revertClone()
                                task.wait()
                                continue
                            end
                        end
    
                        if Melee.Enabled and entitylib.EntityPosition({
                            Range = Range.Value,
                            Players = Targets.Players.Enabled,
                            NPCs = Targets.NPCs.Enabled,
                            Wallcheck = Targets.Walls.Enabled or nil,
                            Sort = sortmethods.Distance,
                            Part = 'RootPart',
                        }) and doClone() then
                            Dodge = false
                            task.wait(0.2)
                            Dodge = true
                            task.wait(0.4)
                        else
                            Dodge = false
                            revertClone()
                        end
                    end
                    task.wait()
                until not AutoDodge.Enabled
    		else
    			revertClone()
    		end
    	end,
    })
    
    Targets = AutoDodge:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
    	Players = true,
    	NPCs = false,
    })
    Melee = AutoDodge:CreateToggle({
    	Name = 'Melee',
    	Tooltip = 'Dodges melee attacks',
    	Default = true,
    	Function = function(call)
    		pcall(function()
    			Range.Object.Visible = call
    		end)
    	end,
    })
    Range = AutoDodge:CreateSlider({
    	Name = 'Melee Range',
    	Tooltip = 'Maximum melee hit distance in studs',
    	Min = 1,
    	Max = 30,
    	Default = 30,
    	Decimal = 5,
    	Darker = true,
    })
    AutoDodge:CreateToggle({
    	Name = 'Projectiles',
    	Tooltip = 'Dodges projectiles',
    	Default = true,
    })
end)

run(function()
	local KaidaKillaura	
	local Targets
	local AttackRange
	local UpdateRate
	local MouseDown
	local GUICheck
	local ShowAnimation
	local AutoAbility
	local AbilityDistance
	local SwingDuringAbility
	local lastAttackTime = 0
	local lastAbilityTime = 0
	local attackCooldown = 0.55
	local abilityCooldown = 22
	local isChargingAbility = false
	manualCharging = false
	local currentTarget = nil
	local AutoStopAbility
	local SummonerKitController = nil
	local function getSummonerController()
		if SummonerKitController then return SummonerKitController end
		pcall(function()
			SummonerKitController = bedwars.KnitClient.Controllers.SummonerKitController
		end)
		return SummonerKitController
	end

	local function isActuallyCharging()
		if isChargingAbility then return true end
		if manualCharging then return true end
		local result = false
		pcall(function()
			local btns = lplr.PlayerGui
				:FindFirstChild("ActionBarScreenGui")
				and lplr.PlayerGui.ActionBarScreenGui:FindFirstChild("ActionBar")
				and lplr.PlayerGui.ActionBarScreenGui.ActionBar:FindFirstChild("AbilityButtons")
			if btns and btns:FindFirstChild("summoner_finish_charging") then
				result = true
			end
		end)
		return result
	end

	local function getSpellLevel()
		local level = 1
		pcall(function()
			local util = require(game:GetService("ReplicatedStorage").TS.games.bedwars.kit.kits.summoner['summoner-kit-util'])
			local result = util.summoner_getPlayerSpellLevel(lplr)
			if result then level = result end
		end)
		return level
	end

	local function getCastTime(level)
		local castTime = 2
		pcall(function()
			local util = require(game:GetService("ReplicatedStorage").TS.games.bedwars.kit.kits.summoner['summoner-kit-util'])
			local result = util.summoner_getTotalCastTimeRequired(level)
			if result then castTime = result end
		end)
		return castTime
	end

	local function fireUseAbility(abilityName)
		pcall(function()
			game:GetService("ReplicatedStorage")
				:WaitForChild("events-@easy-games/game-core:shared/game-core-networking@getEvents.Events")
				:WaitForChild("useAbility"):FireServer(abilityName)
		end)
	end

	local function doAutoAbility()
		if isChargingAbility then return end
		isChargingAbility = true

		pcall(function()
			local remote = game:GetService("ReplicatedStorage")
				:WaitForChild("events-@easy-games/game-core:shared/game-core-networking@getEvents.Events")
				:WaitForChild("useAbility")

			remote:FireServer(unpack({"summoner_start_charging"}))

			if AutoStopAbility.Enabled then
				task.wait(0.5)
				remote:FireServer(unpack({"summoner_finish_charging"}))
			else
				local level = getSpellLevel()
				local castTime = getCastTime(level)
				task.wait(math.max(castTime, 0.5))
				if isChargingAbility then
					remote:FireServer(unpack({"summoner_finish_charging"}))
					if currentTarget and currentTarget.RootPart then
						local myPos = entitylib.character.RootPart.Position
						local shootDir = CFrame.lookAt(myPos, currentTarget.RootPart.Position).LookVector
						local localPosition = myPos + shootDir * math.max((myPos - currentTarget.RootPart.Position).Magnitude - 16, 0)
						bedwars.Client:Get(remotes.SummonerClawAttack):SendToServer({
							position = localPosition,
							direction = shootDir,
							clientTime = workspace:GetServerTimeNow()
						})
					end
				end
			end
		end)

		lastAbilityTime = tick()
		isChargingAbility = false
	end

	local function getPlayerClawLevel()
		local handItem = lplr.Character and lplr.Character:FindFirstChild('HandInvItem')
		if handItem and handItem.Value then
			local itemType = handItem.Value.Name
			if itemType == 'summoner_claw_1' then return 1 end
			if itemType == 'summoner_claw_2' then return 2 end
			if itemType == 'summoner_claw_3' then return 3 end
			if itemType == 'summoner_claw_4' then return 4 end
		end
		if store and store.inventory and store.inventory.hotbar then
			for _, v in pairs(store.inventory.hotbar) do
				if v.item then
					local itemType = v.item.itemType
					if itemType == 'summoner_claw_1' then return 1 end
					if itemType == 'summoner_claw_2' then return 2 end
					if itemType == 'summoner_claw_3' then return 3 end
					if itemType == 'summoner_claw_4' then return 4 end
				end
			end
		end
		return 1
	end

	KaidaKillaura = vain.Categories.Kits:CreateModule({
		Name = 'AutoKaida',
		Tooltip = 'Automates the Kaida kit flame breath ability',
		Function = function(callback)
			if callback then
				lastAttackTime = 0
				lastAbilityTime = 0
				isChargingAbility = false
				manualCharging = false   
				pcall(function()
					local abilityButtons = lplr.PlayerGui
						:WaitForChild("ActionBarScreenGui", 10)
						:WaitForChild("ActionBar", 10)
						:WaitForChild("AbilityButtons", 10)

					KaidaKillaura:Clean(abilityButtons.ChildRemoved:Connect(function(child)
						if child.Name == "summoner_start_charging" then
							manualCharging = true
						end
						if child.Name == "summoner_finish_charging" then
							manualCharging = false
						end
					end))

					KaidaKillaura:Clean(abilityButtons.ChildAdded:Connect(function(child)
						if child.Name == "summoner_start_charging" then
							manualCharging = false
						end
					end))

					if abilityButtons:FindFirstChild("summoner_finish_charging") then
						manualCharging = true
					end
				end)

				repeat
					if not entitylib.isAlive then
						task.wait(0.1)
						continue
					end

					if GUICheck.Enabled then
						if bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then
							task.wait(0.1)
							continue
						end
					end

					local handItem = lplr.Character:FindFirstChild('HandInvItem')
					local hasClaw = handItem and handItem.Value and handItem.Value.Name:find('summoner_claw') ~= nil

					if MouseDown.Enabled then
						if not inputService:IsMouseButtonPressed(Enum.UserInputType.MouseButton1) then
							task.wait(1.2)
							continue
						end
					end

					local plr = nil
					do
						local bestDot = -math.huge
						local camCF = workspace.CurrentCamera.CFrame
						local myPos = entitylib.character.RootPart.Position
						for _, ent in ipairs(entitylib.List) do
							local validType = (Targets.Players.Enabled and ent.Player) or (Targets.NPCs.Enabled and ent.NPC)
							if validType and ent.Targetable and ent.RootPart and ent.Health > 0 then
								local dist = (myPos - ent.RootPart.Position).Magnitude
								if dist <= AttackRange.Value then
									local toEnt = (ent.RootPart.Position - camCF.Position).Unit
									local dot = camCF.LookVector:Dot(toEnt)
									if dot <= 0 then continue end
									if dot > bestDot then
										bestDot = dot
										plr = ent
									end
								end
							end
						end
					end

					if plr and plr.Health > 0 then
						local localPosition = entitylib.character.RootPart.Position
						local targetDistance = (localPosition - plr.RootPart.Position).Magnitude
						local now = tick()

						if AutoAbility.Enabled and targetDistance <= AbilityDistance.Value * 1.25 then
							if not isChargingAbility and (now - lastAbilityTime) >= abilityCooldown then
								currentTarget = plr
								task.spawn(doAutoAbility)
							end
						end

						if not SwingDuringAbility.Enabled and isChargingAbility then
							task.wait(0.05)
							continue
						end

						if hasClaw then
							local charging = isActuallyCharging()

							if not SwingDuringAbility.Enabled and charging then
								task.wait(0.05)
								continue
							end

							if (now - lastAttackTime) >= attackCooldown and targetDistance <= AttackRange.Value then
								local shootDir = CFrame.lookAt(localPosition, plr.RootPart.Position).LookVector
								localPosition += shootDir * math.max((localPosition - plr.RootPart.Position).Magnitude - 16, 0)
								lastAttackTime = now

								if ShowAnimation.Enabled then
									task.spawn(function()
										pcall(function()
											local clawLevel = getPlayerClawLevel()
											bedwars.AnimationUtil:playAnimation(lplr, bedwars.GameAnimationUtil:getAssetId(bedwars.AnimationType.SUMMONER_CHARACTER_SWIPE), {
												looped = false
											})
											local clawModel = replicatedStorage.Assets.Misc.Kaida.Summoner_DragonClaw:Clone()
											local clawColors = {
												Color3.fromRGB(75, 75, 75),
												Color3.fromRGB(255, 255, 255),
												Color3.fromRGB(43, 229, 229),
												Color3.fromRGB(49, 229, 94)
											}
											local nailMesh = clawModel:FindFirstChild("dragon_claw_nail_mesh")
											if nailMesh and nailMesh:IsA("MeshPart") then
												nailMesh.Color = clawColors[clawLevel] or clawColors[1]
											end
											if bedwars.KnightClient and bedwars.KnightClient.Controllers.SummonerKitSkinController then
												if bedwars.KnightClient.Controllers.SummonerKitSkinController:isPrismaticSkin(lplr) then
													bedwars.KnightClient.Controllers.SummonerKitSkinController:applyClawRGB(clawModel)
												end
											end
											clawModel.Parent = workspace
											local camera = workspace.CurrentCamera
											if camera and (camera.CFrame.Position - entitylib.character.RootPart.Position).Magnitude < 1 then
												for _, part in clawModel:GetDescendants() do
													if part:IsA('MeshPart') then
														part.Transparency = 0.6
													end
												end
											end
											local rootPart = entitylib.character.RootPart
											local Unit = Vector3.new(shootDir.X, 0, shootDir.Z).Unit
											local startPos = rootPart.Position + Unit:Cross(Vector3.new(0, 1, 0)).Unit * -1 * 5 + Unit * 6
											local direction = (startPos + shootDir * 13 - startPos).Unit
											local cframe = CFrame.new(startPos, startPos + direction)
											clawModel:PivotTo(cframe)
											clawModel.PrimaryPart.Anchored = true
											local portalConn = nil
											if clawModel:FindFirstChild("Portal1") then
												portalConn = runService.Heartbeat:Connect(function()
													if not clawModel or not clawModel.Parent then
														portalConn:Disconnect()
														portalConn = nil
														return
													end
													local foreArmCF = clawModel.RootPart.root.fore_arm.TransformedWorldCFrame
													if clawModel.Portal1 then
														clawModel.Portal1:PivotTo(foreArmCF)
													end
													if clawModel.Portal2 then
														clawModel.Portal2:PivotTo(foreArmCF * CFrame.Angles(math.pi, 0, 0))
													end
												end)
											end
											if clawModel:FindFirstChild('AnimationController') then
												local animator = clawModel.AnimationController:FindFirstChildOfClass('Animator')
												if animator then
													bedwars.AnimationUtil:playAnimation(animator, bedwars.GameAnimationUtil:getAssetId(bedwars.AnimationType.SUMMONER_CLAW_ATTACK), {
														looped = false,
														speed = 1
													})
												end
											end
											pcall(function()
												local sounds = {
													bedwars.SoundList.SUMMONER_CLAW_ATTACK_1,
													bedwars.SoundList.SUMMONER_CLAW_ATTACK_2,
													bedwars.SoundList.SUMMONER_CLAW_ATTACK_3,
													bedwars.SoundList.SUMMONER_CLAW_ATTACK_4
												}
												bedwars.SoundManager:playSound(sounds[math.random(1, #sounds)], {
													position = rootPart.Position
												})
											end)
											task.wait(0.5)
											if portalConn then
												portalConn:Disconnect()
												portalConn = nil
											end
											clawModel:Destroy()
										end)
									end)
								end

								bedwars.Client:Get(remotes.SummonerClawAttack):SendToServer({
									position = localPosition,
									direction = shootDir,
									clientTime = workspace:GetServerTimeNow()
								})
							end
						end
					else
						if isChargingAbility then
							isChargingAbility = false
							fireUseAbility("summoner_finish_charging")
						end
					end

					task.wait(1 / UpdateRate.Value)
				until not KaidaKillaura.Enabled

				isChargingAbility = false
			end
		end,
		Tooltip = 'Auto attacks with Summoner claw'
	})

	Targets = KaidaKillaura:CreateTargets({
		Tooltip = 'Configure which types of targets to include',
		Players = true,
		NPCs = true,
		Walls = true
	})

	AttackRange = KaidaKillaura:CreateSlider({
		Name = 'Attack Range',
		Tooltip = 'Distance at which the hit packet is sent',
		Min = 1,
		Max = 32,
		Default = 22,
		Suffix = function(val)
			return val == 1 and 'stud' or 'studs'
		end
	})

	UpdateRate = KaidaKillaura:CreateSlider({
		Name = 'Update Rate',
		Tooltip = 'How often to scan for targets (seconds)',
		Min = 1,
		Max = 120,
		Default = 60,
		Suffix = 'hz'
	})

	MouseDown = KaidaKillaura:CreateToggle({
		Name = 'Require Mouse Down',
		Tooltip = 'Only attacks while holding left click'
	})

	GUICheck = KaidaKillaura:CreateToggle({
		Name = 'GUI Check',
		Tooltip = 'Pauses the module when a GUI menu is open',
	})

	ShowAnimation = KaidaKillaura:CreateToggle({
		Name = 'Show Animation',
		Tooltip = 'Plays the attack animation during killaura hits',
		Default = true
	})

	SwingDuringAbility = KaidaKillaura:CreateToggle({
		Name = 'Swing During Ability',
		Default = true,
		Tooltip = 'Continue claw attacks while charging ability'
	})

	AutoAbility = KaidaKillaura:CreateToggle({
		Name = 'Auto Ability',
		Default = false,
		Tooltip = 'Automatically uses ability when enemy is within distance',
		Function = function(callback)
			if not callback then
				isChargingAbility = false
			end
			AbilityDistance.Object.Visible = callback
			AutoStopAbility.Object.Visible = callback
		end
	})

	AbilityDistance = KaidaKillaura:CreateSlider({
		Name = 'Ability Distance',
		Min = 3,
		Max = 15,
		Default = 6,
		Visible = false,
		Tooltip = 'Distance to trigger ability',
		Suffix = function(val)
			return val == 1 and 'stud' or 'studs'
		end
	})

	AutoStopAbility = KaidaKillaura:CreateToggle({
		Name = 'Auto Stop Ability',
		Default = true,
		Visible = false,
		Tooltip = 'Cancels ability early if target leaves range mid-cast'
	})

	task.defer(function()
		if AbilityDistance and AbilityDistance.Object then
			AbilityDistance.Object.Visible = false   
		end
	end)
end)

run(function()
    local DamageBoost
    local stack
    
    DamageBoost = vain.Categories.Blatant:CreateModule({
    	Name = 'Damage Boost',
    	Tooltip = 'Boosts the damage you deal to enemies',
    	Function = function(callback)
    		if callback then
    			DamageBoost:Clean(vainEvents.EntityDamageEvent.Event:Connect(function(damageTable)
    				if entitylib.isAlive and tick() > (stack or 0) and damageTable.entityInstance == lplr.Character and not LongJump.Enabled then
    					local horizontal = (damageTable.knockbackMultiplier and damageTable.knockbackMultiplier.horizontal or 0)
    					knockbackSpeed = bedwars.KnockbackUtil.calculateKnockbackVelocity(Vector3.one, 1, {
    						vertical = 0,
    						horizontal = horizontal,
    					}).Magnitude * (0.9 + lplr:GetNetworkPing())
                        stack = tick() + (knockbackSpeed / 45)
                        knockbackBoost = tick() + (horizontal / 3.5)
    				end
    			end))
    		end
    	end,
        Tooltip = 'Makes you go slightly faster when damaged'
    })
end)

run(function()
    -- ══════════════════════════════════════════════════════════════════════════
    --  CHEAT DETECTOR  (flags players landing hits from beyond legit reach)
    -- ══════════════════════════════════════════════════════════════════════════
    -- Every damage event is replicated to us via EntityDamageEventZap with the
    -- attacker's position (fromPosition), the attacker (fromEntity) and the victim
    -- (entityInstance). A legit sword hit can only land within the game's own
    -- RAYCAST_SWORD_CHARACTER_DISTANCE constant (14.4 studs, from
    -- bedwars.CombatConstant). If someone repeatedly lands MELEE hits from farther
    -- than that (+ a small tolerance for body size / interpolation), they're almost
    -- certainly using reach. We count violations per player and alert once a player
    -- crosses the flag threshold, so a single laggy frame doesn't false-positive.
    local CheatDetector, Tolerance, FlagThreshold, ResetOnMatch
    local flags = {}   -- [player] = violation count
    local alerted = {} -- [player] = true once we've announced them

    -- exact legit reach from the game constant, with a fallback to the literal.
    local function legitReach()
        local ok, c = pcall(function() return bedwars.CombatConstant.RAYCAST_SWORD_CHARACTER_DISTANCE end)
        if ok and type(c) == 'number' and c > 0 then
            -- if OUR reach module inflated the constant, ignore that and use 14.4
            return c < 20 and c or 14.4
        end
        return 14.4
    end

    local function rootPos(char)
        if typeof(char) ~= 'Instance' then return nil end
        local hrp = char:FindFirstChild('HumanoidRootPart') or (char:IsA('Model') and char.PrimaryPart)
        return hrp and hrp.Position
    end

    local function onDamage(damageTable)
        if not (CheatDetector and CheatDetector.Enabled) then return end
        local attackerChar = damageTable.fromEntity
        local victimChar = damageTable.entityInstance
        if typeof(attackerChar) ~= 'Instance' or typeof(victimChar) ~= 'Instance' then return end

        local attacker = playersService:GetPlayerFromCharacter(attackerChar)
        if not attacker or attacker == lplr then return end -- only detect OTHER players

        -- attacker's claimed position at hit time (falls back to their root)
        local fp = damageTable.fromPosition
        local fromPos = fp and Vector3.new(fp.X, fp.Y, fp.Z) or rootPos(attackerChar)
        local victimPos = rootPos(victimChar)
        if not (fromPos and victimPos) then return end

        -- MELEE only: a real sword hit has the attacker's character as the source.
        -- Projectiles/explosions come from a projectile instance, not a player
        -- character adjacent to the victim, so requiring a player fromEntity
        -- filters most non-melee damage. We also skip absurd distances (>60) which
        -- are clearly projectile/void/fall damage, not a reach attempt.
        local dist = (victimPos - fromPos).Magnitude
        if dist > 60 then return end

        local limit = legitReach() + (Tolerance and Tolerance.Value or 2)
        if dist > limit then
            flags[attacker] = (flags[attacker] or 0) + 1
            if not alerted[attacker] and flags[attacker] >= (FlagThreshold and FlagThreshold.Value or 3) then
                alerted[attacker] = true
                vain:CreateNotification('Cheat Detector',
                    ('%s likely REACH — hit from %.1f studs (legit %.1f)'):format(
                        attacker.Name, dist, legitReach()),
                    8, 'alert')
            end
        end
    end

    CheatDetector = vain.Categories.Utility:CreateModule({
        Name = 'Cheat Detector',
        Tooltip = 'Flags players who land melee hits from beyond the game\'s legit sword reach (RAYCAST_SWORD_CHARACTER_DISTANCE = 14.4 studs). Counts violations and alerts once a player crosses the flag threshold, so lag spikes do not false-positive.',
        Function = function(callback)
            if callback then
                table.clear(flags)
                table.clear(alerted)
                CheatDetector:Clean(vainEvents.EntityDamageEvent.Event:Connect(onDamage))
                if ResetOnMatch and ResetOnMatch.Enabled then
                    CheatDetector:Clean(vainEvents.MatchEndEvent.Event:Connect(function()
                        table.clear(flags)
                        table.clear(alerted)
                    end))
                end
            else
                table.clear(flags)
                table.clear(alerted)
            end
        end
    })
    Tolerance = CheatDetector:CreateSlider({
        Name = 'Reach Tolerance',
        Min = 0, Max = 6, Default = 2, Decimal = 10,
        Suffix = function() return 'studs' end,
        Tooltip = 'Extra studs allowed on top of the exact 14.4 legit reach before a hit is flagged (accounts for body size / interpolation). Lower = stricter/more precise.'
    })
    FlagThreshold = CheatDetector:CreateSlider({
        Name = 'Flag Threshold',
        Min = 1, Max = 15, Default = 3,
        Suffix = function(v) return v == 1 and 'hit' or 'hits' end,
        Tooltip = 'How many over-reach hits before a player is called out (higher = fewer false positives).'
    })
    ResetOnMatch = CheatDetector:CreateToggle({
        Name = 'Reset Each Match',
        Default = true,
        Tooltip = 'Clear the violation counts when a match ends.'
    })
end)

run(function()
    local FastBreak
    local Time
    local BedCheck
    local Blacklist
    local blocks
    local string_lower = string.lower
    local string_find = string.find
    local task_wait = task.wait
    local currentBlock = nil
    local oldHitBlock = nil
    local bedCache = {}
    local blacklistCache = {}
    local lastCacheClean = 0
    local cacheCleanInterval = 5 
    
    local function isBed(block)
        if not block then return false end
        local cached = bedCache[block]
        if cached ~= nil then return cached end
        
        local result = false
        pcall(function()
            if collectionService:HasTag(block, 'bed') or (block.Parent and collectionService:HasTag(block.Parent, 'bed')) then
                result = true
            elseif string_find(string_lower(block.Name), 'bed', 1, true) then
                result = true
            end
        end)
        
        bedCache[block] = result
        return result
    end
    
    local cachedBlacklistLower = {}
    local function updateBlacklistCache()
        if not blocks or not blocks.ListEnabled then return end
        
        cachedBlacklistLower = {}
        for _, v in pairs(blocks.ListEnabled) do
            table.insert(cachedBlacklistLower, string_lower(v))
        end
    end
    
    local function isBlacklisted(block)
        if not block or #cachedBlacklistLower == 0 then return false end
        local cached = blacklistCache[block]
        if cached ~= nil then return cached end
        
        local name = string_lower(block.Name)
        local result = false
        for i = 1, #cachedBlacklistLower do
            if string_find(name, cachedBlacklistLower[i], 1, true) then
                result = true
                break
            end
        end
        
        blacklistCache[block] = result
        return result
    end
    
    local function shouldSkip(block)
        if not block then return false end
        if BedCheck and BedCheck.Enabled and isBed(block) then return true end
        if Blacklist and Blacklist.Enabled and isBlacklisted(block) then return true end
        return false
    end
    
    local lastBreakUpdate = 0
    local breakUpdateCooldown = 0.05
    local pendingUpdate = false
    
    local function updateBreakSpeed()
        if not FastBreak or not FastBreak.Enabled then return end
        local now = tick()
        if now - lastBreakUpdate < breakUpdateCooldown then
            pendingUpdate = true
            return
        end
        lastBreakUpdate = now
        pendingUpdate = false
        
        pcall(function()
            local cooldown = (shouldSkip(currentBlock)) and 0.3 or Time.Value
            bedwars.BlockBreakController.blockBreaker:setCooldown(cooldown)
        end)
    end
    
    FastBreak = vain.Categories.Blatant:CreateModule({
        Name = 'FastBreak',
        Tooltip = 'Speeds up block breaking beyond the normal cap',
        Function = function(callback)
            if callback then
                oldHitBlock = bedwars.BlockBreaker.hitBlock
				local lastHotbarSlot = nil

				-- The game updated hitBlock's signature to (self, maid) -- there is no
				-- longer a raycastparams argument (it used to be the 3rd). Passing the
				-- old (self, maid, raycastparams) meant raycastparams was nil, so
				-- getMouseInfo({ray = nil}) resolved no block and the passthrough was
				-- wrong -> FastBreak silently stopped mining. Match the new signature
				-- with (...) so we forward EXACTLY what we receive, and resolve the
				-- looked-at block via the default mouse ray (no ray arg needed).
				bedwars.BlockBreaker.hitBlock = function(self, ...)
					local block = nil
					pcall(function()
						local blockInfo = self.clientManager:getBlockSelector():getMouseInfo(1)
						if blockInfo and blockInfo.target and blockInfo.target.blockInstance then
							block = blockInfo.target.blockInstance
						end
					end)

					local currentSlot = store.inventory and store.inventory.hotbarSlot
					local slotChanged = currentSlot ~= lastHotbarSlot
					if slotChanged then
						lastHotbarSlot = currentSlot
					end

					if block ~= currentBlock or slotChanged then
						currentBlock = block
						updateBreakSpeed()
					end
					return oldHitBlock and oldHitBlock(self, ...)
				end
                
                updateBlacklistCache()
                
                task.spawn(function()
                    while FastBreak.Enabled do
                        if tick() - lastCacheClean > cacheCleanInterval then
                            lastCacheClean = tick()
                            bedCache = {}
                            blacklistCache = {}
                        end
                        if pendingUpdate then updateBreakSpeed() end
                        task_wait(0.5) 
                    end
                end)
			else
				pcall(function() bedwars.BlockBreakController.blockBreaker:setCooldown(0.3) end)
				if oldHitBlock then
					bedwars.BlockBreaker.hitBlock = oldHitBlock
					oldHitBlock = nil
				end
				currentBlock = nil
				lastHotbarSlot = nil
				bedCache, blacklistCache, cachedBlacklistLower = {}, {}, {}
			end
        end,
        Tooltip = 'Decreases block hit cooldown'
    })
    
    Time = FastBreak:CreateSlider({
        Name = 'Break speed',
        Tooltip = 'How fast blocks are broken (higher = faster)',
        Min = 0, Max = 0.3, Default = 0.25, Decimal = 100, Suffix = 'seconds',
        Function = function() updateBreakSpeed() end
    })
    
    BedCheck = FastBreak:CreateToggle({
        Name = 'Bed Check',
        Default = false,
        Tooltip = 'Use normal break speed when breaking beds',
        Function = function() bedCache = {}; updateBreakSpeed() end
    })
    
    Blacklist = FastBreak:CreateToggle({
        Name = 'Blacklist Blocks',
        Default = false,
        Tooltip = 'Use normal break speed on blacklisted blocks',
        Function = function(v)
            if blocks then blocks.Object.Visible = v end
            blacklistCache = {}
            if v then updateBlacklistCache() end
            updateBreakSpeed()
        end
    })
    
    blocks = FastBreak:CreateTextList({
        Name = 'Blacklisted Blocks',
        Tooltip = 'Block names that FastBreak will not mine (one per line)',
        Placeholder = 'bed',
        Visible = false,
        Function = function()
            updateBlacklistCache()
            blacklistCache = {}
            updateBreakSpeed()
        end
    })
end)

run(function()
    local Value
    local VerticalValue
    local WallCheck
    local PopBalloons
    local TP
    local AutoDisable
    local rayCheck = RaycastParams.new()
    rayCheck.RespectCanCollide = true
    local up, down, old = 0, 0
    
    Fly = vain.Categories.Blatant:CreateModule({
        Name = 'Fly',
        Tooltip = 'Lets you fly freely around the map',
        Function = function(callback)
            frictionTable.Fly = callback or nil
            updateVelocity()
            if callback then
                up, down, old = 0, 0, bedwars.BalloonController.deflateBalloon
                bedwars.BalloonController.deflateBalloon = function() end
                local tpTick, tpToggle, oldy = tick(), true
    
                if lplr.Character and (lplr.Character:GetAttribute('InflatedBalloons') or 0) == 0 and getItem('balloon') then
                    bedwars.BalloonController:inflateBalloon()
                end
                Fly:Clean(vainEvents.AttributeChanged.Event:Connect(function(changed)
                    if changed == 'InflatedBalloons' and (lplr.Character:GetAttribute('InflatedBalloons') or 0) == 0 and getItem('balloon') then
                        bedwars.BalloonController:inflateBalloon()
                    end
                end))
                Fly:Clean(runService.PreSimulation:Connect(function(dt)
                    if entitylib.isAlive and not InfiniteFly.Enabled and isnetworkowner(entitylib.character.RootPart) then
                        local flyAllowed = (lplr.Character:GetAttribute('InflatedBalloons') and lplr.Character:GetAttribute('InflatedBalloons') > 0) or store.matchState == 2
                        local mass = (1.5 + (flyAllowed and 6 or 0) * (tick() % 0.4 < 0.2 and -1 or 1)) + ((up + down) * VerticalValue.Value)
                        local root, moveDirection = entitylib.character.RootPart, entitylib.character.Humanoid.MoveDirection
                        local velo = getSpeed()
                        local destination = (moveDirection * math.max(Value.Value - velo, 0) * dt)
                        rayCheck.FilterDescendantsInstances = {lplr.Character, gameCamera, AntiFallPart}
                        rayCheck.CollisionGroup = root.CollisionGroup
    
                        if WallCheck.Enabled then
                            local ray = workspace:Raycast(root.Position, destination, rayCheck)
                            if ray then
                                destination = ((ray.Position + ray.Normal) - root.Position)
                            end
                        end
    
                        if not flyAllowed then
                            if tpToggle then
                                local airleft = (tick() - entitylib.character.AirTime)
                                if airleft > 2 then
                                    if not oldy then
                                        local ray = workspace:Raycast(root.Position, Vector3.new(0, -1000, 0), rayCheck)
                                        if ray and TP.Enabled then
                                            tpToggle = false
                                            oldy = root.Position.Y
                                            tpTick = tick() + 0.11
                                            root.CFrame = CFrame.lookAlong(Vector3.new(root.Position.X, ray.Position.Y + entitylib.character.HipHeight, root.Position.Z), root.CFrame.LookVector)
                                        end
                                    end
                                end
                            else
                                if oldy then
                                    if tpTick < tick() then
                                        local newpos = Vector3.new(root.Position.X, oldy, root.Position.Z)
                                        root.CFrame = CFrame.lookAlong(newpos, root.CFrame.LookVector)
                                        tpToggle = true
                                        oldy = nil
                                    else
                                        mass = 0
                                    end
                                end
                            end
                        end
    
                        root.CFrame += destination
                        root.AssemblyLinearVelocity = (moveDirection * velo) + Vector3.new(0, mass, 0)
                    end
                end))
                Fly:Clean(inputService.InputBegan:Connect(function(input)
                    if not inputService:GetFocusedTextBox() then
                        if input.KeyCode == Enum.KeyCode.Space or input.KeyCode == Enum.KeyCode.ButtonA then
                            up = 1
                        elseif input.KeyCode == Enum.KeyCode.LeftShift or input.KeyCode == Enum.KeyCode.ButtonL2 then
                            down = -1
                        end
                    end
                end))
                Fly:Clean(inputService.InputEnded:Connect(function(input)
                    if input.KeyCode == Enum.KeyCode.Space or input.KeyCode == Enum.KeyCode.ButtonA then
                        up = 0
                    elseif input.KeyCode == Enum.KeyCode.LeftShift or input.KeyCode == Enum.KeyCode.ButtonL2 then
                        down = 0
                    end
                end))
                if inputService.TouchEnabled then
                    pcall(function()
                        local jumpButton = lplr.PlayerGui.TouchGui.TouchControlFrame.JumpButton
                        Fly:Clean(jumpButton:GetPropertyChangedSignal('ImageRectOffset'):Connect(function()
                            up = jumpButton.ImageRectOffset.X == 146 and 1 or 0
                        end))
                    end)
                end
                -- Turn Fly off automatically on death so you don't have to remember
                -- to re-toggle, and so a respawn never starts mid-air with it on.
                Fly:Clean(lplr.CharacterRemoving:Connect(function()
                    if AutoDisable.Enabled and Fly.Enabled then
                        Fly:Toggle()
                    end
                end))
            else
                bedwars.BalloonController.deflateBalloon = old
                if PopBalloons.Enabled and entitylib.isAlive and (lplr.Character:GetAttribute('InflatedBalloons') or 0) > 0 then
                    for _ = 1, 3 do
                        bedwars.BalloonController:deflateBalloon()
                    end
                end
            end
        end,
        ExtraText = function()
            return 'Heatseeker'
        end,
        Tooltip = 'Makes you go zoom.'
    })
    Value = Fly:CreateSlider({
        Name = 'Speed',
        Tooltip = 'Movement speed multiplier',
        Min = 1,
        Max = 23,
        Default = 23,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    VerticalValue = Fly:CreateSlider({
        Name = 'Vertical Speed',
        Tooltip = 'Upward/downward speed in fly mode',
        Min = 1,
        Max = 150,
        Default = 50,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    WallCheck = Fly:CreateToggle({
        Name = 'Wall Check',
        Tooltip = 'Only targets enemies with a clear line of sight',
        Default = true
    })
    PopBalloons = Fly:CreateToggle({
        Name = 'Pop Balloons',
        Tooltip = 'Automatically pops balloons when flying nearby',
        Default = true
    })
    TP = Fly:CreateToggle({
        Name = 'TP Down',
        Tooltip = 'Teleports down to ground level when fly is active',
        Default = true
    })
    AutoDisable = Fly:CreateToggle({
        Name = 'Auto Disable',
        Tooltip = 'Automatically turns Fly off when you die',
        Default = false
    })
end)

run(function()
    local Mode
    local Expand
    local AutoToggle
    local Visible
    local VisibleColor
    local Targets
    local objects, set = {}, {}
    local hitboxesActive = false
    local autoToggleConnection = nil
    local autoToggleFrameCounter = 0

    local vector3new = Vector3.new
    local vector3one = Vector3.one

    local colorList = {
        Red = Color3.fromRGB(255, 0, 0),
        Blue = Color3.fromRGB(0, 100, 255),
        Green = Color3.fromRGB(0, 255, 0),
        Yellow = Color3.fromRGB(255, 255, 0),
        Orange = Color3.fromRGB(255, 140, 0),
        Purple = Color3.fromRGB(180, 0, 255),
        White = Color3.fromRGB(255, 255, 255),
        Cyan = Color3.fromRGB(0, 255, 255),
        Pink = Color3.fromRGB(255, 50, 150),
        Black = Color3.fromRGB(0, 0, 0)
    }

    local function shouldCreateHitbox(ent)
        if not ent.Targetable then return false end
        if ent.Player and Targets and Targets.Players and Targets.Players.Enabled then return true end
        if not ent.Player and Targets and Targets.NPCs and Targets.NPCs.Enabled then return true end
        return false
    end

    local _wallRayParams = RaycastParams.new()
    _wallRayParams.FilterType = Enum.RaycastFilterType.Exclude
    local function isTargetBehindWall(ent)
        if not Targets or not Targets.Walls or not Targets.Walls.Enabled then return false end
        if not ent.RootPart then return false end
        local origin = entitylib.character.RootPart.Position
        local target = ent.RootPart.Position
        local direction = target - origin
        _wallRayParams.FilterDescendantsInstances = {entitylib.character, ent.Character}
        local result = workspace:Raycast(origin, direction, _wallRayParams)
        if result then
            local hitDist = (result.Position - origin).Magnitude
            local targetDist = direction.Magnitude
            if hitDist < targetDist - 0.5 then return true end
        end
        return false
    end

    local cachedExpandSize = vector3new(3, 6, 3)
    local lastExpandValue = 0
    local function updateExpandSize(val)
        if val ~= lastExpandValue then
            lastExpandValue = val
            cachedExpandSize = vector3new(3, 6, 3) + vector3one * (val / 5)
        end
    end

    local function createHitbox(ent)
        if not shouldCreateHitbox(ent) then return end
        if isTargetBehindWall(ent) then return end
        if objects[ent] then return end
        local hitbox = Instance.new('Part')
        hitbox.Size = cachedExpandSize
        hitbox.Position = ent.RootPart.Position
        hitbox.CanCollide = false
        hitbox.Massless = true
        hitbox.Transparency = Visible and Visible.Enabled and 0.5 or 1
        if Visible and Visible.Enabled and VisibleColor then
            hitbox.Color = colorList[VisibleColor.Value] or colorList.Red
        end
        hitbox.Parent = ent.Character
        local weld = Instance.new('Motor6D')
        weld.Part0 = hitbox
        weld.Part1 = ent.RootPart
        weld.Parent = hitbox
        objects[ent] = hitbox
    end

    local function clearHitboxes()
        for _, part in pairs(objects) do part:Destroy() end
        table.clear(objects)
    end

    local function refreshAllHitboxes()
        clearHitboxes()
        local entityList = entitylib.List
        for i = 1, #entityList do
            createHitbox(entityList[i])
        end
    end

    local function handleAutoToggle()
        if not AutoToggle or not AutoToggle.Enabled then return end
        if not HitBoxes.Enabled or Mode.Value ~= 'Player' then return end
        local holdingSword = isSword()
        if holdingSword and not hitboxesActive then
            hitboxesActive = true
            refreshAllHitboxes()
        elseif not holdingSword and hitboxesActive then
            hitboxesActive = false
            clearHitboxes()
        end
    end

    HitBoxes = vain.Categories.Blatant:CreateModule({
        Name = 'HitBoxes',
        Tooltip = 'Expands enemy hitboxes to make them easier to hit',
        Function = function(callback)
            if callback then
                updateExpandSize(Expand.Value)
                if Mode.Value == 'Sword' then
                    debug.setconstant(bedwars.SwordController.swingSwordInRegion, 6, (Expand.Value / 3))
                    set = true
                else
                    HitBoxes:Clean(entitylib.Events.EntityAdded:Connect(function(ent)
                        if AutoToggle and AutoToggle.Enabled then
                            if hitboxesActive then createHitbox(ent) end
                        else
                            createHitbox(ent)
                        end
                    end))
                    HitBoxes:Clean(entitylib.Events.EntityRemoving:Connect(function(ent)
                        local obj = objects[ent]
                        if obj then obj:Destroy() objects[ent] = nil end
                    end))
                    if AutoToggle and AutoToggle.Enabled then
                        handleAutoToggle()
                    else
                        refreshAllHitboxes()
                    end
                    local hitboxThrottleCounter = 0
                    HitBoxes:Clean(runService.Heartbeat:Connect(function()
                        if not Targets or not Targets.Walls or not Targets.Walls.Enabled then return end
                        hitboxThrottleCounter = hitboxThrottleCounter + 1
                        if hitboxThrottleCounter % 20 ~= 0 then return end
                        for ent, part in pairs(objects) do
                            if isTargetBehindWall(ent) then
                                part:Destroy()
                                objects[ent] = nil
                            end
                        end
                        local entityList = entitylib.List
                        for i = 1, #entityList do
                            local ent = entityList[i]
                            if not objects[ent] then
                                if AutoToggle and AutoToggle.Enabled then
                                    if hitboxesActive then createHitbox(ent) end
                                else
                                    createHitbox(ent)
                                end
                            end
                        end
                    end))
                end
            else
                hitboxesActive = false
                if set then
                    debug.setconstant(bedwars.SwordController.swingSwordInRegion, 6, 3.8)
                    set = nil
                end
                clearHitboxes()
            end
        end,
        Tooltip = 'Expands attack hitbox'
    })

    Targets = HitBoxes:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        Walls = false,
        NPCs = false,
        Function = function()
            if HitBoxes.Enabled and Mode.Value == 'Player' then
                if AutoToggle and AutoToggle.Enabled then
                    if hitboxesActive then refreshAllHitboxes() end
                else
                    refreshAllHitboxes()
                end
            end
        end
    })

    Mode = HitBoxes:CreateDropdown({
        Name = 'Mode',
        Tooltip = 'Selects the operating mode',
        List = {'Sword', 'Player'},
        ItemTooltips = {
            Sword = 'Expands the range around you — makes it easier to hit enemies with your sword',
            Player = "Expands each player's hitbox model — targets are larger and easier to click",
        },
        Function = function(val)
            local isPlayer = val == 'Player'
            if AutoToggle then AutoToggle.Object.Visible = isPlayer end
            if Visible then Visible.Object.Visible = isPlayer end
            if VisibleColor then VisibleColor.Object.Visible = isPlayer and Visible.Enabled end
            if HitBoxes.Enabled then HitBoxes:Toggle() HitBoxes:Toggle() end
        end,
        Tooltip = 'Sword - Increases the range around you to hit entities\nPlayer - Increases the players hitbox'
    })

    Expand = HitBoxes:CreateSlider({
        Name = 'Expand amount',
        Tooltip = 'How many studs to expand hitboxes in each direction',
        Min = 0,
        Max = 50,
        Default = 14.4,
        Decimal = 10,
        Function = function(val)
            updateExpandSize(val)
            if HitBoxes.Enabled then
                if Mode.Value == 'Sword' then
                    debug.setconstant(bedwars.SwordController.swingSwordInRegion, 6, (val / 3))
                else
                    for _, part in pairs(objects) do part.Size = cachedExpandSize end
                end
            end
        end,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })

    AutoToggle = HitBoxes:CreateToggle({
        Name = 'Auto Toggle',
        Default = false,
        Tooltip = 'Automatically enables hitbox when holding a sword',
        Function = function(callback)
            if callback then
                if autoToggleConnection then autoToggleConnection:Disconnect() end
                hitboxesActive = false
                autoToggleFrameCounter = 0
                autoToggleConnection = runService.Heartbeat:Connect(function()
                    autoToggleFrameCounter = autoToggleFrameCounter + 1
                    if autoToggleFrameCounter % 5 == 0 then
                        handleAutoToggle()
                    end
                end)
                HitBoxes:Clean(autoToggleConnection)
                handleAutoToggle()
            else
                if autoToggleConnection then
                    autoToggleConnection:Disconnect()
                    autoToggleConnection = nil
                end
                hitboxesActive = false
                if HitBoxes.Enabled and Mode.Value == 'Player' then
                    refreshAllHitboxes()
                end
            end
        end
    })

    Visible = HitBoxes:CreateToggle({
        Name = 'Visible',
        Default = false,
        Tooltip = 'Makes the hitbox visible on screen',
        Function = function(callback)
            if VisibleColor then VisibleColor.Object.Visible = callback end
            if HitBoxes.Enabled and Mode.Value == 'Player' then
                local transparency = callback and 0.5 or 1
                local col = callback and VisibleColor and (colorList[VisibleColor.Value] or colorList.Red) or nil
                for _, part in pairs(objects) do
                    part.Transparency = transparency
                    if col then part.Color = col end
                end
            end
        end
    })

    VisibleColor = HitBoxes:CreateDropdown({
        Name = 'Hitbox Color',
        List = {'Red', 'Blue', 'Green', 'Yellow', 'Orange', 'Purple', 'White', 'Cyan', 'Pink', 'Black'},
        Default = 'Red',
        Visible = false,
        ItemTooltips = {
            Red = 'Renders hitboxes in red',
            Blue = 'Renders hitboxes in blue',
            Green = 'Renders hitboxes in green',
            Yellow = 'Renders hitboxes in yellow',
            Orange = 'Renders hitboxes in orange',
            Purple = 'Renders hitboxes in purple',
            White = 'Renders hitboxes in white',
            Cyan = 'Renders hitboxes in cyan',
            Pink = 'Renders hitboxes in pink',
            Black = 'Renders hitboxes in black',
        },
        Tooltip = 'Color of the visible hitbox',
        Function = function(val)
            if HitBoxes.Enabled and Mode.Value == 'Player' and Visible.Enabled then
                local col = colorList[val] or colorList.Red
                for _, part in pairs(objects) do part.Color = col end
            end
        end
    })

    task.spawn(function()
        repeat task.wait() until Mode and Mode.Value
        local isPlayer = Mode.Value == 'Player'
        AutoToggle.Object.Visible = isPlayer
        Visible.Object.Visible = isPlayer
    end)

    task.defer(function()
        if VisibleColor and VisibleColor.Object then
            VisibleColor.Object.Visible = false
        end
    end)
end)

run(function()
    vain.Categories.Blatant:CreateModule({
        Name = 'Keep Sprint',
        Tooltip = 'Enables the Keep Sprint module',
        Function = function(callback)
            debug.setconstant(bedwars.SprintController.startSprinting, 5, callback and 'blockSprinting' or 'blockSprint')
            bedwars.SprintController:stopSprinting()
        end,
        Tooltip = 'Lets you sprint with a speed potion.'
    })
end)

run(function()
    local Killaura
    local Continue
    local Targets
    local Mode
    local Sort
    local SwingRange
    local AttackRange
    local AirChance
    local SwingTime
    local Hitreg
    local Dynamic
    local Sync = {}
    local UpdateRate
    local Attackable
    local AngleSlider
    local MaxTargets
    local SwitchDelay
    local Mouse
    local Swing
    local GUI
    local BoxSwingColor
    local BoxAttackColor
    local ParticleTexture
    local ParticleColor1
    local ParticleColor2
    local ParticleSize
    local Face
    local Animation
    local AnimationMode
    local AnimationSpeed
    local AnimationTween
    local Limit
    local LegitAura
    local Particles, Boxes = {}, {}
    local anims, AnimDelay, AnimTween, armC0 = vain.Libraries.auraanims, tick()
    local AttackRemote = {FireServer = function(self, ...) end}
    local projectileRemote = {InvokeServer = function(self, ...) end}
    task.spawn(function()
        AttackRemote = bedwars.Client:Get(remotes.AttackEntity).instance
    end)
    task.spawn(function()
    	projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
    end)
    
    local FastHits
    local Legit
    local FireRate
    local Whitelist
    local FireRates = {}
    
    local function getAmmo(check)
    	for _, item in store.inventory.inventory.items do
    		if check.ammoItemTypes and table.find(check.ammoItemTypes, item.itemType) then
    			return item.itemType
    		end
    	end
    	return nil
    end
    local function getProjectiles()
    	local items = {}
    	for _, item in store.inventory.inventory.items do
    		local proj = bedwars.ItemMeta[item.itemType].projectileSource
    		local ammo = proj and getAmmo(proj)
    		if ammo and table.find(Whitelist.ListEnabled, ammo) then
    			table.insert(items, {
    				item,
    				ammo,
    				proj.projectileType(ammo),
    				proj,
    			})
    		end
    	end
    	return items
    end
    local function getHitreg(distance)
        local hitreg = math.max(Hitreg.Value + 1, 36)
        if Dynamic.Enabled then
            local limit = hitreg < 14.4 and Hitreg or 14.4
            local window = AttackRange.Value - limit
            if window < 1 then
                window = 1
            end
            local scale: number = (distance - limit) / window
            if scale < 0 then
                scale = 0
            elseif scale > 1 then
                scale = 1
            end
            hitreg = hitreg + (limit - hitreg) * scale
        end
        return hitreg
    end
    local function getAttackData()
        if Mouse.Enabled then
            if not inputService:IsMouseButtonPressed(0) then return false end
        end
    
        if Attackable.Enabled then
            if not entitylib.isAlive then return false end
            if (lplr.Character:GetAttribute('StunnedUntilTime') or 0) > workspace:GetServerTimeNow() then return false end
            if lplr.Character:FindFirstChild('elk') then return false end
            for _, v in bedwars.StatusEffectUtil:getAllActive(lplr.Character) do
                if v.statusEffect == 'frozen' then
                    return false
                end
            end -- lowkey just pasted this from my potionstatus, i remember a better way to do this but im too lazy to figure it out
        end
    
        if GUI.Enabled then
            if bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then return false end
        end
    
        local sword = Limit.Enabled and store.hand or store.tools.sword
        if not sword or not sword.tool then return false end
    
        local meta = bedwars.ItemMeta[sword.tool.Name]
        if Limit.Enabled then
            if store.hand.toolType ~= 'sword' or bedwars.DaoController.chargingMaid then return false end
        end
    
        if LegitAura.Enabled then
            if (tick() - bedwars.SwordController.lastSwing) > 0.2 then return false end
        end
    
        return sword, meta
    end
    
    Killaura = vain.Categories.Blatant:CreateModule({
        Name = 'Killaura',
        Tooltip = 'Automatically attacks all nearby enemies within range',
        Function = function(callback)
            if callback then
                if Animation.Enabled then
                    local fake = {
                        Controllers = {
                            ViewmodelController = {
                                isVisible = function()
                                    return not Attacking
                                end,
                                playAnimation = function(...)
                                    if not Attacking then
                                        bedwars.ViewmodelController:playAnimation(select(2, ...))
                                    end
                                end
                            }
                        }
                    }
                    debug.setupvalue(oldSwing or bedwars.SwordController.playSwordEffect, 7, fake)
                    debug.setupvalue(bedwars.ScytheController.playLocalAnimation, 3, fake)
    
                    task.spawn(function()
                        local started = false
                        repeat
                            if Attacking then
                                if not armC0 then
                                    armC0 = gameCamera.Viewmodel.RightHand.RightWrist.C0
                                end
                                local first = not started
                                started = true
    
                                if AnimationMode.Value == 'Random' then
                                    anims.Random = {{CFrame = CFrame.Angles(math.rad(math.random(1, 360)), math.rad(math.random(1, 360)), math.rad(math.random(1, 360))), Time = 0.12}}
                                end
    
                                for _, v in anims[AnimationMode.Value] do
                                    AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(first and (AnimationTween.Enabled and 0.001 or 0.1) or v.Time / AnimationSpeed.Value, Enum.EasingStyle.Linear), {
                                        C0 = armC0 * v.CFrame
                                    })
                                    AnimTween:Play()
                                    AnimTween.Completed:Wait()
                                    first = false
                                    if (not Killaura.Enabled) or (not Attacking) then break end
                                end
                            elseif started then
                                started = false
                                AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
                                    C0 = armC0
                                })
                                AnimTween:Play()
                            end
    
                            if not started then
                                task.wait(1 / UpdateRate.Value)
                            end
                        until (not Killaura.Enabled) or (not Animation.Enabled)
                    end)
                end
    
                local swingCooldown, switchCooldown, lastSwing, targetIndex = tick(), tick(), 0, 0
                local lastShot, projectileIndex = tick(), 0
                local lastHit = 0
                local singleTarget = nil
                repeat
                    local attacked, sword, meta = {}, getAttackData()
                    Attacking = false
                    store.KillauraTarget = nil
                    if sword then
                        local plrs = entitylib.AllPosition({
                            Range = SwingRange.Value,
                            Wallcheck = Targets.Walls.Enabled or nil,
                            Part = 'RootPart',
                            Players = Targets.Players.Enabled,
                            NPCs = Targets.NPCs.Enabled,
                            Limit = Mode.Value == 'Single' and 8 or MaxTargets.Value,
                            Sort = sortmethods[Sort.Value]
                        })
    
                        if #plrs > 0 then
                            switchItem(sword.tool, 0)
                            local selfpos = entitylib.character.RootPart.Position
                            local localfacing = entitylib.character.RootPart.CFrame.LookVector * Vector3.new(1, 0, 1)
                            -- Single mode locks onto one target: keep the current one while
                            -- it stays a valid, in-angle candidate (AllPosition already drops
                            -- it once dead or out of range), otherwise lock the best in-angle
                            -- target. This makes the 'hits them exclusively until they die or
                            -- leave range' behaviour real instead of re-picking every tick.
                            if Mode.Value == 'Single' then
                                local function inAngle(v)
                                    local d = (v.RootPart.Position - selfpos) * Vector3.new(1, 0, 1)
                                    return d.Magnitude < 0.001 or math.acos(math.clamp(localfacing:Dot(d.Unit), -1, 1)) <= (math.rad(AngleSlider.Value) / 2)
                                end
                                local chosen
                                if singleTarget then
                                    for _, v in plrs do
                                        if v == singleTarget then
                                            if inAngle(v) then chosen = v end
                                            break
                                        end
                                    end
                                end
                                if not chosen then
                                    for _, v in plrs do
                                        if inAngle(v) then chosen = v break end
                                    end
                                end
                                singleTarget = chosen
                                plrs = chosen and {chosen} or {}
                            end
                            if tick() > switchCooldown and Mode.Value == 'Switch' then
    							switchCooldown = tick() + SwitchDelay.Value
    							targetIndex += 1
    						end
                            if not plrs[targetIndex] then
                                targetIndex = 1
                            end
                            for i, v in plrs do
                                if Mode.Value == 'Switch' and i ~= targetIndex then
    								continue
    							end
                                local delta = (v.RootPart.Position - selfpos)
                                local angle = math.acos(localfacing:Dot((delta * Vector3.new(1, 0, 1)).Unit))
                                if angle > (math.rad(AngleSlider.Value) / 2) then continue end
    
                                table.insert(attacked, {
                                    Entity = v,
                                    Check = delta.Magnitude > AttackRange.Value and BoxSwingColor or BoxAttackColor
                                })
                                targetinfo.Targets[v] = tick() + 1
    
                                if not Attacking then
                                    Attacking = true
                                    store.KillauraTarget = v
                                    if not Swing.Enabled and AnimDelay < tick() and not LegitAura.Enabled then
                                        AnimDelay = tick() + math.max(SwingTime.Value, 0.11)
                                        lastSwing = tick()
                                        bedwars.SwordController:playSwordEffect(meta, false)
                                        if meta.displayName:find(' Scythe') then
                                            bedwars.ScytheController:playLocalAnimation()
                                        end
    
                                        if vain.ThreadFix then
                                            setthreadidentity(8)
                                        end
                                    end
                                end
    
                                if delta.Magnitude > AttackRange.Value then continue end
    
                                local actualRoot = v.Character.PrimaryPart
                                if actualRoot and (not Sync.Enabled or (tick() - swingCooldown >= SwingTime.Value)) and (v.Humanoid.FloorMaterial ~= Enum.Material.Air or math.random(1, 100) < AirChance.Value) then
                                    local current, delay = tick(), 10 / math.max(Hitreg.Value, 1)
                                    if Hitreg.Value >= 36 or (current - lastHit) >= delay then
                                        lastHit += delay
                                        if current - lastHit > delay then
                                            lastHit = current
                                        end
    
                                        local dir = CFrame.lookAt(selfpos, actualRoot.Position).LookVector
                                        local pos = selfpos + dir * math.max(delta.Magnitude - 14.4, 0)
                                        bedwars.SwordController.lastAttack = workspace:GetServerTimeNow()
                                        store.attackReach = (delta.Magnitude * 100) // 1 / 100
                                        store.attackReachUpdate = tick() + 1
                                        swingCooldown = tick()
    
                                        AttackRemote:FireServer({
                                            weapon = sword.tool,
                                            chargedAttack = {chargeRatio = 0},
                                            entityInstance = v.Character,
                                            validate = {
                                                raycast = {
                                                    cameraPosition = {value = pos},
                                                    cursorDirection = {value = dir}
                                                },
                                                targetPosition = {value = actualRoot.Position + (CFrame.lookAt(actualRoot.Position, selfpos).LookVector * math.max((selfpos - actualRoot.Position).Magnitude / 10, 0))},
                                                selfPosition = {value = pos}
                                            }
                                        })
    
                                        if FastHits.Enabled and tick() > lastShot and not entitylib.Wallcheck(entitylib.character.RootPart.Position, actualRoot.Position, {gameCamera, lplr.Character, v.Character}) then
                                            local projectiles = getProjectiles()
                                            if #projectiles > 0 then
                                                projectileIndex += 1
                                                if not projectiles[projectileIndex] then
                                                    projectileIndex = 1
                                                end
                                                
                                                local item, ammo, projectile, itemMeta = unpack(projectiles[projectileIndex])
                                                if tick() > (FireRates[item.itemType] or 0) then
                                                    local projmeta = bedwars.ProjectileMeta[projectile]
                                                    local projSpeed, gravity = projmeta.launchVelocity, projmeta.gravitationalAcceleration or 196.2
                                                    local oldhotbar, oldtool = store.inventory.hotbarSlot, store.hand.tool
                                                    local hotbar = getHotbar(item.tool)
                                                    if hotbar then
                                                        switchItem(item.tool)
                                                        if Legit.Enabled then
                                                            hotbarSwitch(hotbar)
                                                        end
                                                    end
                                                    
                                                    local calc = prediction.SolveTrajectory(selfpos, projSpeed, gravity, v.RootPart.Position, v.RootPart.Velocity, workspace.Gravity, v.HipHeight, v.Jumping and 42.6 or nil, nil, nil, lplr:GetNetworkPing())
                                                    if calc then
                                                        local sdir, id = CFrame.lookAt(selfpos, calc).LookVector, httpService:GenerateGUID(true)
                                                        local shootPosition = (CFrame.new(selfpos, calc) * CFrame.new(Vector3.new(-bedwars.BowConstantsTable.RelX, -bedwars.BowConstantsTable.RelY, -bedwars.BowConstantsTable.RelZ))).Position
                                                    
                                                        bedwars.ProjectileController:createLocalProjectile(itemMeta, ammo, projectile, shootPosition, id, sdir * projSpeed, {drawDurationSeconds = 1})
                                                        local res = projectileRemote:InvokeServer(
                                                            item.tool,
                                                            ammo,
                                                            projectile,
                                                            shootPosition,
                                                            pos,
                                                            sdir * projSpeed,
                                                            id,
                                                            { 
                                                                drawDurationSeconds = 1, 
                                                                shotId = httpService:GenerateGUID(false) 
                                                            },
                                                            workspace:GetServerTimeNow() - 0.045
                                                        )
                                                        if res then
                                                            res.Parent = replicatedStorage
                                                            FireRates[item.itemType] = tick() + itemMeta.fireDelaySec
                                                            local shoot = itemMeta.launchSound
                                                            shoot = shoot and shoot[math.random(1, #shoot)] or nil
                                                            if shoot then
                                                                bedwars.SoundManager:playSound(shoot)
                                                            end
                                                        end
                                                        lastShot = tick() + (lplr:GetNetworkPing() + FireRate.Value)
                                                    end
                                                    task.spawn(function()
                                                        if Legit.Enabled then
                                                            hotbarSwitch(oldhotbar)
                                                            if oldtool then
                                                                switchItem(oldtool.tool)
                                                            end
                                                        end
                                                    end)
                                                end
                                            end
                                        end
    
                                        if Mode.Value ~= 'Multi' then
                                            break
                                        end
                                    end
                                end
                            end
                        else
                            if (tick() - lastSwing) < Continue:GetRandomValue() and not Swing.Enabled and not LegitAura.Enabled and AnimDelay < tick() then
                                AnimDelay = tick() + math.max(SwingTime.Value, 0.11)
                                if vain.ThreadFix then
    								setthreadidentity(8)
    							end
                                
    							pcall(function()
    								bedwars.SwordController:playSwordEffect(meta, false)
                                    if meta.displayName:find(' Scythe') then
                                        bedwars.ScytheController:playLocalAnimation()
                                    end
    							end)
                            end
                        end
                    end
    
                    for i, v in Boxes do
                        v.Adornee = attacked[i] and attacked[i].Entity.RootPart or nil
                        if v.Adornee then
                            v.Color3 = Color3.fromHSV(attacked[i].Check.Hue, attacked[i].Check.Sat, attacked[i].Check.Value)
                            v.Transparency = 1 - attacked[i].Check.Opacity
                        end
                    end
    
                    for i, v in Particles do
                        v.Position = attacked[i] and attacked[i].Entity.RootPart.Position or Vector3.new(9e9, 9e9, 9e9)
                        v.Parent = attacked[i] and gameCamera or nil
                    end
    
                    if Face.Enabled and attacked[1] then
                        local vec = attacked[1].Entity.RootPart.Position * Vector3.new(1, 0, 1)
                        entitylib.character.RootPart.CFrame = CFrame.lookAt(entitylib.character.RootPart.Position, Vector3.new(vec.X, entitylib.character.RootPart.Position.Y + 0.001, vec.Z))
                    end
    
                    task.wait(1 / UpdateRate.Value)
                until not Killaura.Enabled
            else
                store.KillauraTarget = nil
                for _, v in Boxes do
                    v.Adornee = nil
                end
                for _, v in Particles do
                    v.Parent = nil
                end
                if inputService.TouchEnabled then
                    pcall(function()
                        lplr.PlayerGui.MobileUI['2'].Visible = true
                    end)
                end
                debug.setupvalue(oldSwing or bedwars.SwordController.playSwordEffect, 7, bedwars.Knit)
                debug.setupvalue(bedwars.ScytheController.playLocalAnimation, 3, bedwars.Knit)
                Attacking = false
                if armC0 then
                    AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
                        C0 = armC0
                    })
                    AnimTween:Play()
                end
            end
        end,
        Tooltip = 'Attack players around you\nwithout aiming at them.'
    })
    Targets = Killaura:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        NPCs = true
    })
    Continue = Killaura:CreateTwoSlider({
    	Name = 'Continue Swinging',
    	Min = 0,
    	Max = 2,
    	Decimal = 100,
    	DefaultMin = 0,
    	DefaultMax = 0.1,
    	Suffix = 'seconds',
    	Tooltip = 'Continues to swing ur sword'
    })
    local methods = {'Damage', 'Distance'}
    for i in sortmethods do
        if not table.find(methods, i) then
            table.insert(methods, i)
        end
    end
    SwingRange = Killaura:CreateSlider({
        Name = 'Swing range',
        Tooltip = 'Distance at which the swing animation begins',
        Min = 1,
        Max = 28,
        Default = 28,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    AttackRange = Killaura:CreateSlider({
        Name = 'Attack range',
        Tooltip = 'Distance at which the hit packet is sent',
        Min = 1,
        Max = 28,
        Default = 28,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    AngleSlider = Killaura:CreateSlider({
        Name = 'Max angle',
        Tooltip = 'Maximum angle in degrees from your look direction to engage',
        Min = 1,
        Max = 360,
        Default = 360
    })
    AirChance = Killaura:CreateSlider({
        Name = 'Air Hit Chance',
        Tooltip = 'Probability (%) of landing hits while airborne',
        Min = 0,
    	Max = 100,
    	Default = 100,
    	Suffix = '%'
    })
    SwingTime = Killaura:CreateSlider({
        Name = 'Swing time',
        Tooltip = 'Minimum seconds between swings',
        Min = 0,
        Max = 2,
        Decimal = 100,
        Default = 0.11,
        Suffix = 'seconds'
    })
    --[[Sync = Killaura:CreateToggle({
        Name = 'Sync with hitreg',
        Darker = true,
        Tooltip = 'Syncs the swing time with hitreg'
    })]]
    Hitreg = Killaura:CreateSlider({
        Name = 'Hitreg',
        Tooltip = 'Hit registration timing offset in seconds',
        Min = 1,
        Max = 36,
        Default = 36,
        Suffix = 'reg'
    })
    UpdateRate = Killaura:CreateSlider({
        Name = 'Update rate',
        Tooltip = 'How often to scan for targets (seconds)',
        Min = 1,
        Max = 120,
        Default = 60,
        Suffix = 'hz'
    })
    FastHits = Killaura:CreateToggle({
    	Name = 'Fast Hits',
    	Tooltip = 'Deals more damage quicker using projectiles',
    	Default = false,
    	Function = function(callback)
            pcall(function()
                Legit.Object.Visible = callback
                FireRate.Object.Visible = callback
                Whitelist.Object.Visible = callback
            end)
    	end
    })
    Whitelist = Killaura:CreateTextList({
        Name = 'Projectiles',
        Default = {'arrow', 'snowball'},
        Darker = true,
        Visible = false,
        Tooltip = 'Projectiles to use for fasthits'
    })
    Legit = Killaura:CreateToggle({
    	Name = 'Legit Switch',
    	Tooltip = 'Switches to a more legit-looking mode automatically',
    	Darker = true,
    	Visible = false
    })
    FireRate = Killaura:CreateSlider({
    	Name = 'Fire rate',
    	Tooltip = 'Shots per second for projectile weapons',
    	Suffix = 'seconds',
    	Min = 0,
    	Max = 2,
    	Decimal = 100,
    	Darker = true,
    	Visible = false,
    	Default = 0.05
    })
    MaxTargets = Killaura:CreateSlider({
        Name = 'Max targets',
        Tooltip = 'Maximum number of enemies to attack simultaneously',
        Min = 1,
        Max = 5,
        Default = 5
    })
    SwitchDelay = Killaura:CreateSlider({
        Name = 'Switch Delay',
        Tooltip = 'How long to stay on each target before rotating (Switch mode)',
        Min = 0.1,
        Max = 3,
        Default = 0.7,
        Decimal = 100,
        Suffix = 'sec',
    })
    Mode = Killaura:CreateDropdown({
    	Name = 'Attack Mode',
    	List = {'Single', 'Multi', 'Switch'},
    	Tooltip = 'Single - Attacks one person at a time\nMulti - Attack multiple people at once\nSwitch - Switch between targets',
    	Default = 'Switch',
    	ItemTooltips = {
    		Single = 'Locks onto one target and hits them exclusively until they die or leave range',
    		Multi = 'Splits attacks across all targets in range simultaneously',
    		Switch = 'Cycles between targets in range each tick for balanced pressure',
    	},
    	Function = function(val)
    		pcall(function()
    			MaxTargets.Object.Visible = val ~= 'Single'
    			if SwitchDelay then SwitchDelay.Object.Visible = val == 'Switch' end
    		end)
    	end,
    })
    Sort = Killaura:CreateDropdown({
        Name = 'Target Mode',
        Tooltip = 'Selects how targets are prioritized and selected',
        List = methods,
        ItemTooltips = {
            Distance = 'Targets the closest enemy by stud distance',
            Health = 'Targets the enemy with the lowest remaining health',
            Angle = 'Targets the enemy closest to your look direction',
            Cursor = 'Targets the enemy nearest to your mouse cursor',
            Damage = 'Targets the enemy who most recently took damage',
            Threat = 'Targets the enemy judged to be the greatest combat threat',
            Kit = 'Prioritizes dangerous kit users (Hannah, Spirit Assassin, etc.)',
        },
    })
    Dynamic = Killaura:CreateToggle({
        Name = 'Dynamic hits',
        Tooltip = 'Calculates ur hitreg depending on ur distance'
    })
    Mouse = Killaura:CreateToggle({Name = 'Require mouse down', Tooltip = 'Only activates while the left mouse button is held'})
    Swing = Killaura:CreateToggle({Name = 'No Swing', Tooltip = 'Sends hit packets without playing the swing animation'})
    GUI = Killaura:CreateToggle({Name = 'GUI check', Tooltip = 'Pauses the module when a GUI menu is open'})
    Killaura:CreateToggle({
        Name = 'Show target',
        Tooltip = 'Renders a visual indicator on the current target',
        Function = function(callback)
            BoxSwingColor.Object.Visible = callback
            BoxAttackColor.Object.Visible = callback
            if callback then
                for i = 1, 10 do
                    local box = Instance.new('BoxHandleAdornment')
                    box.Adornee = nil
                    box.AlwaysOnTop = true
                    box.Size = Vector3.new(3, 5, 3)
                    box.CFrame = CFrame.new(0, -0.5, 0)
                    box.ZIndex = 0
                    box.Parent = vain.gui
                    Boxes[i] = box
                end
            else
                for _, v in Boxes do
                    v:Destroy()
                end
                table.clear(Boxes)
            end
        end
    })
    BoxSwingColor = Killaura:CreateColorSlider({
        Name = 'Target Color',
        Darker = true,
        DefaultHue = 0.6,
        DefaultOpacity = 0.5,
        Visible = false
    })
    BoxAttackColor = Killaura:CreateColorSlider({
        Name = 'Attack Color',
        Darker = true,
        DefaultOpacity = 0.5,
        Visible = false
    })
    Killaura:CreateToggle({
        Name = 'Target particles',
        Tooltip = 'Shows particles on the currently targeted enemy',
        Function = function(callback)
            ParticleTexture.Object.Visible = callback
            ParticleColor1.Object.Visible = callback
            ParticleColor2.Object.Visible = callback
            ParticleSize.Object.Visible = callback
            if callback then
                for i = 1, 10 do
                    local part = Instance.new('Part')
                    part.Size = Vector3.new(2, 4, 2)
                    part.Anchored = true
                    part.CanCollide = false
                    part.Transparency = 1
                    part.CanQuery = false
                    part.Parent = Killaura.Enabled and gameCamera or nil
                    local particles = Instance.new('ParticleEmitter')
                    particles.Brightness = 1.5
                    particles.Size = NumberSequence.new(ParticleSize.Value)
                    particles.Shape = Enum.ParticleEmitterShape.Sphere
                    particles.Texture = ParticleTexture.Value
                    particles.Transparency = NumberSequence.new(0)
                    particles.Lifetime = NumberRange.new(0.4)
                    particles.Speed = NumberRange.new(16)
                    particles.Rate = 128
                    particles.Drag = 16
                    particles.ShapePartial = 1
                    particles.Color = ColorSequence.new({
                        ColorSequenceKeypoint.new(0, Color3.fromHSV(ParticleColor1.Hue, ParticleColor1.Sat, ParticleColor1.Value)),
                        ColorSequenceKeypoint.new(1, Color3.fromHSV(ParticleColor2.Hue, ParticleColor2.Sat, ParticleColor2.Value))
                    })
                    particles.Parent = part
                    Particles[i] = part
                end
            else
                for _, v in Particles do
                    v:Destroy()
                end
                table.clear(Particles)
            end
        end
    })
    ParticleTexture = Killaura:CreateTextBox({
        Name = 'Texture',
        Tooltip = 'Roblox asset ID for the particle effect texture',
        Default = 'rbxassetid://14736249347',
        Function = function()
            for _, v in Particles do
                v.ParticleEmitter.Texture = ParticleTexture.Value
            end
        end,
        Darker = true,
        Visible = false
    })
    ParticleColor1 = Killaura:CreateColorSlider({
        Name = 'Color Begin',
        Function = function(hue, sat, val)
            for _, v in Particles do
                v.ParticleEmitter.Color = ColorSequence.new({
                    ColorSequenceKeypoint.new(0, Color3.fromHSV(hue, sat, val)),
                    ColorSequenceKeypoint.new(1, Color3.fromHSV(ParticleColor2.Hue, ParticleColor2.Sat, ParticleColor2.Value))
                })
            end
        end,
        Darker = true,
        Visible = false
    })
    ParticleColor2 = Killaura:CreateColorSlider({
        Name = 'Color End',
        Function = function(hue, sat, val)
            for _, v in Particles do
                v.ParticleEmitter.Color = ColorSequence.new({
                    ColorSequenceKeypoint.new(0, Color3.fromHSV(ParticleColor1.Hue, ParticleColor1.Sat, ParticleColor1.Value)),
                    ColorSequenceKeypoint.new(1, Color3.fromHSV(hue, sat, val))
                })
            end
        end,
        Darker = true,
        Visible = false
    })
    ParticleSize = Killaura:CreateSlider({
        Name = 'Size',
        Tooltip = 'Display size of this element',
        Min = 0,
        Max = 1,
        Default = 0.2,
        Decimal = 100,
        Function = function(val)
            for _, v in Particles do
                v.ParticleEmitter.Size = NumberSequence.new(val)
            end
        end,
        Darker = true,
        Visible = false
    })
    Face = Killaura:CreateToggle({Name = 'Face target', Tooltip = 'Rotates your character to face the target during animation'})
    Animation = Killaura:CreateToggle({
        Name = 'Custom Animation',
        Tooltip = 'Plays a custom ability animation instead of the default',
        Function = function(callback)
            AnimationMode.Object.Visible = callback
            AnimationTween.Object.Visible = callback
            AnimationSpeed.Object.Visible = callback
            if Killaura.Enabled then
                Killaura:Toggle()
                Killaura:Toggle()
            end
        end
    })
    local animnames = {}
    for i in anims do
        table.insert(animnames, i)
    end
    AnimationMode = Killaura:CreateDropdown({
        Name = 'Animation Mode',
        Tooltip = 'Selects the animation style to use',
        List = animnames,
        Darker = true,
        Visible = false
    })
    AnimationSpeed = Killaura:CreateSlider({
        Name = 'Animation Speed',
        Tooltip = 'Adjusts the animation speed value',
        Min = 0,
        Max = 2,
        Default = 1,
        Decimal = 10,
        Darker = true,
        Visible = false
    })
    AnimationTween = Killaura:CreateToggle({
        Name = 'No Tween',
        Tooltip = 'Skips smooth interpolation for instant hitbox updates',
        Darker = true,
        Visible = false
    })
    Attackable = Killaura:CreateToggle({
        Name = 'Attackable check',
        Tooltip = 'Checks if your in a state where you can attack'
    })
    Limit = Killaura:CreateToggle({
        Name = 'Limit to items',
        Tooltip = 'Only attacks when the sword is held'
    })
    LegitAura = Killaura:CreateToggle({
        Name = 'Swing only',
        Tooltip = 'Only attacks while swinging manually'
    })
end)

run(function()
    local Value
    local CameraDir
    local start
    local JumpTick, JumpSpeed, Direction = tick(), 0
    local projectileRemote = {InvokeServer = function() end}
    task.spawn(function()
        projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
    end)
    
    local function launchProjectile(item, pos, proj, speed, dir)
        if not pos then return end
    
        pos = pos - dir * 0.1
        local shootPosition = (CFrame.lookAlong(pos, Vector3.new(0, -speed, 0)) * CFrame.new(Vector3.new(-bedwars.BowConstantsTable.RelX, -bedwars.BowConstantsTable.RelY, -bedwars.BowConstantsTable.RelZ)))
        switchItem(item.tool, 0)
        task.wait(0.1)
        bedwars.ProjectileController:createLocalProjectile(bedwars.ProjectileMeta[proj], proj, proj, shootPosition.Position, '', shootPosition.LookVector * speed, {drawDurationSeconds = 1})
        if projectileRemote:InvokeServer(item.tool, proj, proj, shootPosition.Position, pos, shootPosition.LookVector * speed, httpService:GenerateGUID(true), {drawDurationSeconds = 1}, workspace:GetServerTimeNow() - 0.045) then
            local shoot = bedwars.ItemMeta[item.itemType].projectileSource.launchSound
            shoot = shoot and shoot[math.random(1, #shoot)] or nil
            if shoot then
                bedwars.SoundManager:playSound(shoot)
            end
        end
    end
    
    local LongJumpMethods = {
        cannon = function(_, pos, dir)
            pos = pos - Vector3.new(0, (entitylib.character.HipHeight + (entitylib.character.RootPart.Size.Y / 2)) - 3, 0)
            local rounded = Vector3.new(math.round(pos.X / 3) * 3, math.round(pos.Y / 3) * 3, math.round(pos.Z / 3) * 3)
            bedwars.placeBlock(rounded, 'cannon', false)
    
            task.delay(0, function()
                local block, blockpos = getPlacedBlock(rounded)
                if block and block.Name == 'cannon' and (entitylib.character.RootPart.Position - block.Position).Magnitude < 20 then
                    local breaktype = bedwars.ItemMeta[block.Name].block.breakType
                    local tool = store.tools[breaktype]
                    if tool then
                        switchItem(tool.tool)
                    end
    
                    bedwars.Client:Get(remotes.CannonAim):SendToServer({
                        cannonBlockPos = blockpos,
                        lookVector = dir
                    })
    
                    local broken = 0.1
                    if bedwars.BlockController:calculateBlockDamage(lplr, {blockPosition = blockpos}) < block:GetAttribute('Health') then
                        broken = 0.4
                        bedwars.breakBlock(block, true, true)
                    end
    
                    task.delay(broken, function()
                        for _ = 1, 3 do
                            local call = bedwars.Client:Get(remotes.CannonLaunch):CallServer({cannonBlockPos = blockpos})
                            if call then
                                bedwars.breakBlock(block, true, true)
                                JumpSpeed = 5.25 * Value.Value
                                JumpTick = tick() + 2.3
                                Direction = Vector3.new(dir.X, 0, dir.Z).Unit
                                break
                            end
                            task.wait(0.1)
                        end
                    end)
                end
            end)
        end,
        cat = function(_, _, dir)
            LongJump:Clean(vainEvents.CatPounce.Event:Connect(function()
                JumpSpeed = 4 * Value.Value
                JumpTick = tick() + 2.5
                Direction = Vector3.new(dir.X, 0, dir.Z).Unit
                entitylib.character.RootPart.Velocity = Vector3.zero
            end))
    
            if not bedwars.AbilityController:canUseAbility('CAT_POUNCE') then
                repeat task.wait() until bedwars.AbilityController:canUseAbility('CAT_POUNCE') or not LongJump.Enabled
            end
    
            if bedwars.AbilityController:canUseAbility('CAT_POUNCE') and LongJump.Enabled then
                bedwars.AbilityController:useAbility('CAT_POUNCE')
            end
        end,
        fireball = function(item, pos, dir)
            launchProjectile(item, pos, 'fireball', 60, dir)
        end,
        grappling_hook = function(item, pos, dir)
            launchProjectile(item, pos, 'grappling_hook_projectile', 140, dir)
        end,
        jade_hammer = function(item, _, dir)
            if not bedwars.AbilityController:canUseAbility(item.itemType..'_jump') then
                repeat task.wait() until bedwars.AbilityController:canUseAbility(item.itemType..'_jump') or not LongJump.Enabled
            end
    
            if bedwars.AbilityController:canUseAbility(item.itemType..'_jump') and LongJump.Enabled then
                bedwars.AbilityController:useAbility(item.itemType..'_jump')
                JumpSpeed = 1.4 * Value.Value
                JumpTick = tick() + 2.5
                Direction = Vector3.new(dir.X, 0, dir.Z).Unit
            end
        end,
        tnt = function(item, pos, dir)
            pos = pos - Vector3.new(0, (entitylib.character.HipHeight + (entitylib.character.RootPart.Size.Y / 2)) - 3, 0)
            local rounded = Vector3.new(math.round(pos.X / 3) * 3, math.round(pos.Y / 3) * 3, math.round(pos.Z / 3) * 3)
            start = Vector3.new(rounded.X, start.Y, rounded.Z) + (dir * (item.itemType == 'pirate_gunpowder_barrel' and 2.6 or 0.2))
            bedwars.placeBlock(rounded, item.itemType, false)
        end,
        wood_dao = function(item, pos, dir)
            if (lplr.Character:GetAttribute('CanDashNext') or 0) > workspace:GetServerTimeNow() or not bedwars.AbilityController:canUseAbility('dash') then
                repeat task.wait() until (lplr.Character:GetAttribute('CanDashNext') or 0) < workspace:GetServerTimeNow() and bedwars.AbilityController:canUseAbility('dash') or not LongJump.Enabled
            end
    
            if LongJump.Enabled then
                bedwars.SwordController.lastAttack = workspace:GetServerTimeNow()
                switchItem(item.tool, 0.1)
                replicatedStorage['events-@easy-games/game-core:shared/game-core-networking@getEvents.Events'].useAbility:FireServer('dash', {
                    direction = dir,
                    origin = pos,
                    weapon = item.itemType
                })
                JumpSpeed = 4.5 * Value.Value
                JumpTick = tick() + 2.4
                Direction = Vector3.new(dir.X, 0, dir.Z).Unit
            end
        end
    }
    for _, v in {'stone_dao', 'iron_dao', 'diamond_dao', 'emerald_dao'} do
        LongJumpMethods[v] = LongJumpMethods.wood_dao
    end
    LongJumpMethods.void_axe = LongJumpMethods.jade_hammer
    LongJumpMethods.siege_tnt = LongJumpMethods.tnt
    LongJumpMethods.pirate_gunpowder_barrel = LongJumpMethods.tnt
    
    LongJump = vain.Categories.Blatant:CreateModule({
        Name = 'Long Jump',
        Tooltip = 'Increases jump distance by boosting horizontal velocity',
        Function = function(callback)
            frictionTable.LongJump = callback or nil
            updateVelocity()
            if callback then
                LongJump:Clean(vainEvents.EntityDamageEvent.Event:Connect(function(damageTable)
                    if damageTable.entityInstance == lplr.Character and damageTable.fromEntity == lplr.Character and (not damageTable.knockbackMultiplier or not damageTable.knockbackMultiplier.disabled) then
                        local knockbackBoost = bedwars.KnockbackUtil.calculateKnockbackVelocity(Vector3.one, 1, {
                            vertical = 0,
                            horizontal = (damageTable.knockbackMultiplier and damageTable.knockbackMultiplier.horizontal or 1)
                        }).Magnitude * 1.1
    
                        if knockbackBoost >= JumpSpeed then
                            local pos = damageTable.fromPosition and Vector3.new(damageTable.fromPosition.X, damageTable.fromPosition.Y, damageTable.fromPosition.Z) or damageTable.fromEntity and damageTable.fromEntity.PrimaryPart.Position
                            if not pos then return end
                            local vec = (entitylib.character.RootPart.Position - pos)
                            JumpSpeed = knockbackBoost
                            JumpTick = tick() + 2.5
                            Direction = Vector3.new(vec.X, 0, vec.Z).Unit
                        end
                    end
                end))
                LongJump:Clean(vainEvents.GrapplingHookFunctions.Event:Connect(function(dataTable)
                    if dataTable.hookFunction == 'PLAYER_IN_TRANSIT' then
                        local vec = entitylib.character.RootPart.CFrame.LookVector
                        JumpSpeed = 2.5 * Value.Value
                        JumpTick = tick() + 2.5
                        Direction = Vector3.new(vec.X, 0, vec.Z).Unit
                    end
                end))
    
                start = entitylib.isAlive and entitylib.character.RootPart.Position or nil
                LongJump:Clean(runService.PreSimulation:Connect(function(dt)
                    local root = entitylib.isAlive and entitylib.character.RootPart or nil
    
                    if root and isnetworkowner(root) then
                        if JumpTick > tick() then
                            root.AssemblyLinearVelocity = Direction * (getSpeed() + ((JumpTick - tick()) > 1.1 and JumpSpeed or 0)) + Vector3.new(0, root.AssemblyLinearVelocity.Y, 0)
                            if entitylib.character.Humanoid.FloorMaterial == Enum.Material.Air and not start then
                                root.AssemblyLinearVelocity += Vector3.new(0, dt * (workspace.Gravity - 23), 0)
                            else
                                root.AssemblyLinearVelocity = Vector3.new(root.AssemblyLinearVelocity.X, 15, root.AssemblyLinearVelocity.Z)
                            end
                            start = nil
                        else
                            if start then
                                root.CFrame = CFrame.lookAlong(start, root.CFrame.LookVector)
                            end
                            root.AssemblyLinearVelocity = Vector3.zero
                            JumpSpeed = 0
                        end
                    else
                        start = nil
                    end
                end))
    
                if store.hand and LongJumpMethods[store.hand.tool.Name] then
                    task.spawn(LongJumpMethods[store.hand.tool.Name], getItem(store.hand.tool.Name), start, (CameraDir.Enabled and gameCamera or entitylib.character.RootPart).CFrame.LookVector)
                    return
                end
    
                for i, v in LongJumpMethods do
                    local item = getItem(i)
                    if item or store.equippedKit == i then
                        task.spawn(v, item, start, (CameraDir.Enabled and gameCamera or entitylib.character.RootPart).CFrame.LookVector)
                        break
                    end
                end
            else
                JumpTick = tick()
                Direction = nil
                JumpSpeed = 0
            end
        end,
        ExtraText = function()
            return 'Heatseeker'
        end,
        Tooltip = 'Lets you jump farther'
    })
    Value = LongJump:CreateSlider({
        Name = 'Speed',
        Tooltip = 'Movement speed multiplier',
        Min = 1,
        Max = 37,
        Default = 37,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    CameraDir = LongJump:CreateToggle({
        Name = 'Camera Direction',
        Tooltip = 'Launches in the direction the camera is facing',
    })
end)

run(function()
    local MouseTP
    local Movement
    local Mode
    
    local rayParams = RaycastParams.new()
    rayParams.RespectCanCollide = true
    rayParams.FilterType = Enum.RaycastFilterType.Include
    
    local MouseTPs = {
    	Items = function(position)
    		local item = getItem('telepearl') or getItem('fireball')
    		local localPosition = entitylib.character.RootPart.Position
    		if item then
    			if item.itemType == 'telepearl' then
    				local meta = bedwars.ProjectileMeta.telepearl
    				local calc = prediction.SolveTrajectory(localPosition, meta.launchVelocity, meta.gravitationalAcceleration, position, Vector3.zero, workspace.Gravity, 0, 0)
    				if calc then
    					position = calc
    				end
    
    				local shootPosition = (CFrame.new(localPosition, position) * CFrame.new(Vector3.new(-bedwars.BowConstantsTable.RelX, -bedwars.BowConstantsTable.RelY, -bedwars.BowConstantsTable.RelZ))).Position
    				switchItem(item.tool)
    				bedwars.Client:Get(remotes.FireProjectile):CallServerAsync(
    					item.tool,
    					'telepearl',
    					'telepearl',
    					shootPosition,
    					localPosition,
    					CFrame.lookAt(localPosition, position).LookVector * meta.launchVelocity,
    					httpService:GenerateGUID(true),
    					{
    						drawDurationSeconds = 1,
    						shotId = httpService:GenerateGUID(false),
    					},
    					workspace:GetServerTimeNow() - 0.045
    				)
    				:andThen(function(result)
    					if result then
    						bedwars.SoundManager:playSound('rbxassetid://6866223756')
    					end
    				end)
    				return true
    			elseif item.itemType == 'fireball' and (localPosition - Vector3.new(position.X, localPosition.Y, position.Z)).Magnitude <= 200 then
    				local root = entitylib.character.RootPart
    				local ray = workspace:Raycast(localPosition, Vector3.new(0, -1000, 0), rayParams)
    				if ray then
    					localPosition = ray.Position + Vector3.new(0, entitylib.character.HipHeight or 2, 0)
    					root.Velocity = Vector3.zero
    					root.CFrame = CFrame.new(localPosition)
    
    					MouseTP:Clean(vainEvents.EntityDamageEvent.Event:Connect(function(damageTable)
    						if damageTable.entityInstance == lplr.Character and damageTable.fromEntity == lplr.Character and (not damageTable.knockbackMultiplier or not damageTable.knockbackMultiplier.disabled) then
    							local knockbackBoost = bedwars.KnockbackUtil.calculateKnockbackVelocity(Vector3.one, 1, {
    								vertical = 0,
    								horizontal = (damageTable.knockbackMultiplier and damageTable.knockbackMultiplier.horizontal or 1)
    							}).Magnitude * 1.1
    
    							if knockbackBoost >= 38 then
    								repeat
    									task.wait()
    								until (root.Position - position).Magnitude <= 1
    							end
    						end
    					end))
    
    					local shootPosition = (CFrame.new(localPosition, position) * CFrame.new(Vector3.new(-bedwars.BowConstantsTable.RelX, -bedwars.BowConstantsTable.RelY, -bedwars.BowConstantsTable.RelZ))).Position
    					switchItem(item.tool)
    					bedwars.Client:Get(remotes.FireProjectile):CallServerAsync(
    						item.tool,
    						'fireball',
    						'fireball',
    						shootPosition,
    						localPosition,
    						Vector3.new(0, -68, 0),
    						httpService:GenerateGUID(true),
    						{
    							drawDurationSeconds = 1,
    							shotId = httpService:GenerateGUID(false),
    						},
    						workspace:GetServerTimeNow() - 0.045
    					)
    					:andThen(function(result)
    						if result then
    							bedwars.SoundManager:playSound('rbxassetid://7192289445')
    						end
    					end)
    					task.wait(2.5)
    					return true
    				end
    			end
    		end
    		return false
    	end,
    	Kits = function() end
    }
    
    MouseTP = vain.Categories.Blatant:CreateModule({
    	Name = 'Mouse TP',
    	Tooltip = 'Teleports you to wherever your mouse is pointing',
    	Function = function(callback)
    		if callback then
    			local position = nil
    			if Mode.Value == 'Mouse' then
    				rayParams.FilterDescendantsInstances = { workspace:WaitForChild('Map', 9e9) }
    				local ray = cloneref(lplr:GetMouse()).UnitRay
    				ray = workspace:Raycast(ray.Origin, ray.Direction * 10000, rayParams)
    				position = ray and ray.Position + Vector3.new(0, entitylib.character.HipHeight or 2, 0)
    			elseif Mode.Value == 'Player' then
    				local ent = entitylib.EntityMouse({
    					Range = math.huge,
    					Part = 'RootPart',
    					Players = true,
    				})
    				position = ent and ent.RootPart.Position
    			end
    
    			if position then
    				if Movement.Value == 'All' then
    					if not MouseTPs.Kits(position) and not MouseTPs.Items(position) then
    						notif('MouseTP', 'Couldn\'t find an item or a kit to teleport with', 5)
    					end
    				elseif not MouseTPs[Movement.Value](position) then
    					notif('MouseTP', `Couldn\'t find {Movement.Value:lower()} to teleport with`, 5)
    				end
    			else
    				notif('MouseTP', 'No position found.', 5)
    			end
    			if MouseTP.Enabled then
    				MouseTP:Toggle()
    			end
    		end
    	end,
        Tooltip = 'Teleports to a selected position'
    })
    
    Mode = MouseTP:CreateDropdown({
    	Name = 'Mode',
    	List = {'Mouse', 'Player'},
    	Tooltip = 'Where you\'re going to teleport to',
    	ItemTooltips = {
    		Mouse = 'Teleports to wherever your mouse cursor is pointing',
    		Player = 'Teleports directly to a selected player',
    	},
    })
    Movement = MouseTP:CreateDropdown({
    	Name = 'Movement',
    	List = {'All', 'Kits', 'Items'},
    	Tooltip = 'All - Uses Kits & Items to teleport',
    	ItemTooltips = {
    		All = 'Uses both kit abilities and inventory items to perform the teleport',
    		Kits = 'Only uses the equipped kit ability to teleport',
    		Items = 'Only uses inventory items (e.g. pearls) to teleport',
    	},
    })
end)

run(function()
    local old
    
    vain.Categories.Blatant:CreateModule({
        Name = 'No Slow',
        Tooltip = 'Prevents slowness effects from items and abilities',
        Function = function(callback)
            local modifier = bedwars.SprintController:getMovementStatusModifier()
            if callback then
                old = modifier.addModifier
                modifier.addModifier = function(self, tab)
                    if tab.moveSpeedMultiplier then
                        tab.moveSpeedMultiplier = math.max(tab.moveSpeedMultiplier, 1)
                    end
                    return old(self, tab)
                end
    
                for i in modifier.modifiers do
                    if (i.moveSpeedMultiplier or 1) < 1 then
                        modifier:removeModifier(i)
                    end
                end
            else
                modifier.addModifier = old
                old = nil
            end
        end,
        Tooltip = 'Prevents slowing down when using items.'
    })
end)

run(function()
    local OwlAura
    local Targets
    local Range
    
    local function getProjectileMeta()
        local meta = table.clone(bedwars.ProjectileMeta.owl_projectile)
        return meta
    end
    
    OwlAura = vain.Categories.Blatant:CreateModule({
        Name = 'Owl Aura',
        Tooltip = 'Automatically uses the Owl kit passive on nearby enemies',
        Function = function(callback)
            if callback then
                local owls = collection('Owl', OwlAura, function(self, obj)
                    task.delay(1, function()
                        if obj and obj.Parent and obj:GetAttribute('Owner') == lplr.UserId then
                            table.insert(self, obj)
                        end
                    end)
                end)
                repeat
                    if store.equippedKit ~= 'owl' then
                        task.wait(3)
                        continue
                    end
    
                    if entitylib.isAlive then
                        local owl = owls[1]
                        if owl then
                            local origin = owl.Part.Position
                            local plr = entitylib.EntityPosition({
                                Origin = origin,
                                Range = Range.Value,
                                Part = 'RootPart',
                                Players = Targets.Players.Enabled,
                                NPCs = Targets.NPCs.Enabled,
                                Wallcheck = Targets.Walls.Enabled,
                                Sort = sortmethods.Health,
                            })
    
                            if plr then
                                local meta = getProjectileMeta()
                                local calc = prediction.SolveTrajectory(origin, meta.launchVelocity, meta.gravitationalAcceleration, plr.RootPart.Position, plr.RootPart.Velocity, workspace.Gravity, plr.HipHeight, plr.Jumping and 42.6 or nil)
                                if calc then
                                    local dir = CFrame.lookAt(origin, calc).LookVector * meta.launchVelocity
                                    bedwars.Client:Get('OwlAiming'):SendToServer({
                                        owl = owl.Part,
                                        starting = true,
                                    })
                                    bedwars.Client:Get('OwlFireProjectile'):SendToServer({
                                        ProjectileRefId = vain.Libraries.string:GenerateString(8),
                                        direction = dir,
                                        fromPosition = origin,
                                        initialVelocity = dir,
                                    })
                                    task.wait(lplr:GetNetworkPing())
                                end
                            end
                        end
                    end
                    task.wait(0.1)
                until not OwlAura.Enabled
            else
                bedwars.Client:Get('OwlAiming'):SendToServer({
                    starting = false,
                })
            end
        end,
        Tooltip = 'Automatically shoots projectiles with whisper kit'
    })
    
    Targets = OwlAura:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        Wallcheck = true,
    })
    Range = OwlAura:CreateSlider({
        Name = 'Range',
        Tooltip = 'Maximum distance in studs',
        Min = 1,
        Max = 50,
        Suffix = function(val)
            return val <= 0 and 'stud' or 'studs'
        end,
        Default = 50,
    })
end)

run(function()
    local PlayerAttach
    local Range
    local Targets
    
    local rayCheck = RaycastParams.new()
    rayCheck.FilterType = Enum.RaycastFilterType.Exclude
    
    PlayerAttach = vain.Categories.Blatant:CreateModule({
        Name = 'Player Attach',
        Tooltip = 'Attachs you to the nearest target',
        Function = function(call)
            if call then
                repeat
                    if entitylib.isAlive then
                        local plr = entitylib.AllPosition({
                            Range = Range.Value,
                            Wallcheck = Targets.Walls.Enabled or nil,
                            Part = 'RootPart',
                            Players = Targets.Players.Enabled,
                            NPCs = Targets.NPCs.Enabled,
                            Limit = 1,
                            Sort = function(a, b)
                                return a.Entity.Health < b.Entity.Health
                            end
                        })[1]
                        if plr then
                            rayCheck.FilterDescendantsInstances = {plr.RootPart.Parent, lplr.Character}
    
                            entitylib.character.RootPart.AssemblyLinearVelocity = Vector3.new(0, entitylib.character.RootPart.Size.Y / 2 + entitylib.character.Humanoid.HipHeight + 0.25 * 3, 0)
                            entitylib.character.RootPart.CFrame = plr.RootPart.CFrame + (not workspace:Raycast(plr.RootPart.Position, plr.RootPart.CFrame.LookVector, rayCheck) and (plr.RootPart.CFrame.LookVector * 1.4) or Vector3.zero)
                        end
                    end
                    task.wait()
                until not PlayerAttach.Enabled
            end
        end
    })
    
    Targets = PlayerAttach:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        NPCs = true
    })
    
    Range = PlayerAttach:CreateSlider({
        Name = 'Range',
        Tooltip = 'Maximum distance in studs',
        Min = 1,
        Max = 35,
        Default = 23,
        Suffix = function(val)
            return val <= 1 and 'stud' or 'studs'
        end
    })
end)

run(function()
	local TargetPart
	local Targets
	local FOV
	local Range
	local OtherProjectiles
	local Blacklist
	local SortMethod
	local HitChance
	local AeroPAChargePercent
	local RandomHeadPercent
	local RandomTorsoPercent
	local CustomPrediction
	local HorizontalMultiplier
	local VerticalMultiplier
	local DesirePAWorkMode
	local DesirePAHideCursor
	local DesirePACursorViewMode
	local DesirePACursorLimitBow
	local DesirePACursorShowGUI
	local cursorRenderConnection
	local lastGUIState = false
	local rayCheck = RaycastParams.new()
	local old
	local math_sqrt = math.sqrt
	local math_rad = math.rad
	local math_cos = math.cos
	local math_clamp = math.clamp
	local math_min = math.min
	local math_max = math.max
	local lockedRandomPart = nil
	local wasHovering = false
	local PAFOVCircle
	local ProjectileAimbot
	local paFOVCircleDrawing = nil
	local AutoCharge
	local paFOVCircleConnection = nil
	local function runPAFOVCircle(call)
		if paFOVCircleConnection then
			paFOVCircleConnection:Disconnect()
			paFOVCircleConnection = nil
		end
		if paFOVCircleDrawing then
			paFOVCircleDrawing:Remove()
			paFOVCircleDrawing = nil
		end
		if call then
			paFOVCircleDrawing = Drawing.new('Circle')
			paFOVCircleDrawing.Visible = false
			paFOVCircleDrawing.Thickness = 1
			paFOVCircleDrawing.Color = Color3.fromRGB(255, 255, 255)
			paFOVCircleDrawing.Filled = false
			paFOVCircleDrawing.NumSides = 64
			paFOVCircleConnection = runService.RenderStepped:Connect(function()
				if paFOVCircleDrawing and FOV and FOV.Value then
					local shouldShow = false
					if PAFOVCircle and PAFOVCircle.Enabled and ProjectileAimbot and ProjectileAimbot.Enabled then
						local tool = store.hand and store.hand.tool
						local itemType = tool and tool.Name or ""
						local itemMeta = bedwars.ItemMeta and bedwars.ItemMeta[itemType]
						if itemMeta and itemMeta.projectileSource then
							local src = itemMeta.projectileSource
							local isArrow = src.ammoItemTypes and table.find(src.ammoItemTypes, 'arrow')
							local isHeadhunter = itemType:find('headhunter')
							if isArrow or isHeadhunter then
								shouldShow = true
							elseif OtherProjectiles and OtherProjectiles.Enabled then
								local projectileType = src.projectileType and (type(src.projectileType) == 'function' and src.projectileType('arrow') or src.projectileType) or ""
								local blacklisted = false
								for _, black in ipairs(Blacklist and Blacklist.ListEnabled or {}) do
									if tostring(projectileType):find(black) then
										blacklisted = true
										break
									end
								end
								if not blacklisted then
									shouldShow = true
								end
							end
						end
					end
					paFOVCircleDrawing.Visible = shouldShow
					local mousePos = inputService:GetMouseLocation()
					paFOVCircleDrawing.Position = Vector2.new(mousePos.X, mousePos.Y)
					paFOVCircleDrawing.Radius = FOV.Value
				end
			end)
		end
	end

	local function hasBowEquipped()
		if not store.hand or not store.hand.toolType then return false end
		return store.hand.toolType == 'bow' or store.hand.toolType == 'crossbow'
	end

	local function shouldHideCursor()
		if not DesirePAHideCursor or not DesirePAHideCursor.Enabled then return false end
		if DesirePACursorShowGUI and DesirePACursorShowGUI.Enabled and isGUIOpen() then return false end
		if DesirePACursorLimitBow and DesirePACursorLimitBow.Enabled and not hasBowEquipped() then return false end
		local inFirstPerson = isFirstPerson()
		if DesirePACursorViewMode then
			if DesirePACursorViewMode.Value == 'First Person' then return inFirstPerson
			elseif DesirePACursorViewMode.Value == 'Third Person' then return not inFirstPerson
			end
		end
		return true
	end

	local function updateCursor()
		pcall(function() inputService.MouseIconEnabled = not shouldHideCursor() end)
	end

	local function checkGUIState()
		local currentGUIState = isGUIOpen()
		if lastGUIState ~= currentGUIState then
			updateCursor()
			lastGUIState = currentGUIState
		end
	end

	local function shouldPAWork()
		if not DesirePAWorkMode then return true end
		local inFirstPerson = isFirstPerson()
		if DesirePAWorkMode.Value == 'First Person' then return inFirstPerson
		elseif DesirePAWorkMode.Value == 'Third Person' then return not inFirstPerson
		end
		return true
	end

	local function isBlacklisted(projectileName)
		if not OtherProjectiles.Enabled then
			local isTurret = projectileName:find('turret') ~= nil or projectileName:find('vulcan') ~= nil
			return not projectileName:find('arrow') and not isTurret
		end
		for _, black in ipairs(Blacklist.ListEnabled) do
			if projectileName:find(black) then
				return true
			end
		end
		return false
	end

    local function getValidTargets(originPos, maxDist, maxAngle, sortMethod)
        local valid = {}
        local fovThreshold = math_cos(math_rad(maxAngle) / 2)
        local rangeSq = maxDist * maxDist

        for _, ent in ipairs(entitylib.List) do
            if not Targets.Players.Enabled and ent.Player then continue end
            if (not Targets.NPCs or not Targets.NPCs.Enabled) and ent.NPC then continue end
            if not ent.Targetable then continue end
			if ent.Player and getAccountTier(ent.Player) >= 1 and getAccountTier(lplr) == 0 then continue end
            if not ent.Character or not ent.RootPart or not ent.RootPart.Parent then continue end

            local delta = ent.RootPart.Position - originPos
            local distSq = delta.X*delta.X + delta.Y*delta.Y + delta.Z*delta.Z
            if distSq > rangeSq then continue end

            if maxAngle < 360 then
                local facing = gameCamera.CFrame.LookVector
                if delta.Magnitude > 0.001 then
                    local dot = facing:Dot(delta.Unit)
                    if dot < fovThreshold then continue end
                end
            end

            if Targets.Walls.Enabled then
                local ray = workspace:Raycast(originPos, delta, rayCheck)
                if ray then continue end
            end

            if sortMethod == "Cursor" then
                local mousePos = inputService:GetMouseLocation()
                local screenPos, onScreen = gameCamera:WorldToScreenPoint(ent.RootPart.Position)
                if not onScreen then continue end
                local screenDist = (Vector2.new(screenPos.X, screenPos.Y) - mousePos).Magnitude
                if screenDist > FOV.Value then continue end
            end

            table.insert(valid, {Entity = ent})
        end

        if #valid == 0 then return {} end

        local sortFunc = sortmethods[sortMethod] or sortmethods.Distance
        table.sort(valid, sortFunc)
        local unwrapped = {}
        for _, v in ipairs(valid) do
            table.insert(unwrapped, v.Entity)
        end
        return unwrapped
    end

	local function pickRandomPart(character)
		local roll = math.random(1, 100)
		if roll <= RandomHeadPercent.Value then
			return character:FindFirstChild('Head') or character:FindFirstChild('HumanoidRootPart')
		else
			return character:FindFirstChild('HumanoidRootPart')
		end
	end

	local function getClosestPart(character, mousePos)
		local parts = {
			'HumanoidRootPart', 'Head', 'LeftHand', 'RightHand',
			'LeftLowerArm', 'RightLowerArm', 'LeftUpperArm', 'RightUpperArm',
			'LeftFoot', 'RightFoot', 'LeftLowerLeg', 'RightLowerLeg',
			'LeftUpperLeg', 'RightUpperLeg', 'LowerTorso', 'UpperTorso'
		}
		local camera = gameCamera
		local rayOrigin = camera.CFrame.Position
		local rayDir = camera:ScreenPointToRay(mousePos.X, mousePos.Y, 0).Direction
		local bestAngle = math.huge
		local bestPart = nil

		for _, partName in ipairs(parts) do
			local part = character:FindFirstChild(partName)
			if part then
				local dirToPart = (part.Position - rayOrigin).Unit
				local angle = math.acos(math_clamp(rayDir:Dot(dirToPart), -1, 1))
				if angle < bestAngle then
					bestAngle = angle
					bestPart = part
				end
			end
		end
		return bestPart or character:FindFirstChild('HumanoidRootPart')
	end

	ProjectileAimbot = vain.Categories.Blatant:CreateModule({
		Name = 'ProjectileAimbot',
		Function = function(callback)
			if callback then
					if PAFOVCircle then
						runPAFOVCircle(PAFOVCircle.Enabled)
					end
					if DesirePAHideCursor and DesirePAHideCursor.Enabled and not cursorRenderConnection then
						cursorRenderConnection = runService.RenderStepped:Connect(function()
							checkGUIState()
							updateCursor()
						end)
					end

					old = bedwars.ProjectileController.calculateImportantLaunchValues
					bedwars.ProjectileController.calculateImportantLaunchValues = function(...)
					local self, projmeta, worldmeta, origin, shootpos = ...
					local originPos = entitylib.isAlive and (shootpos or (entitylib.character and entitylib.character.RootPart and entitylib.character.RootPart.Position)) or Vector3.zero
					if not wasHovering then lockedRandomPart = nil end
					wasHovering = true
					local entityPart = (TargetPart.Value == 'Head') and 'Head' or 'RootPart'
					local plr = entitylib.EntityMouse({
						Part = entityPart,
						Range = FOV.Value,
						Players = Targets.Players.Enabled,
						NPCs = (Targets.NPCs and Targets.NPCs.Enabled) or false,
						Wallcheck = Targets.Walls.Enabled,
						Origin = originPos
					})

					if not plr then
						wasHovering = false
						local s, r = pcall(old, ...)
						return s and r or nil
					end

					if not getgenv().AeroLocalPaid and plr.Player and getgenv().isAeroPaid and getgenv().isAeroPaid(plr.Player) then
						wasHovering = false
						return old(...)
					end

					if not shouldPAWork() then
						wasHovering = false
						return old(...)
					end

					local targetBodyPart = nil
					if TargetPart.Value == 'Dynamic' then
						local tool = store.hand and store.hand.tool
						local itemType = tostring(tool and tool.Name or ""):lower()
						local isHH = itemType:find("headhunter")
						targetBodyPart = isHH and (plr.Character:FindFirstChild("Head") or plr.RootPart) or plr.RootPart
					elseif TargetPart.Value == 'RootPart' then
						targetBodyPart = plr.RootPart
					elseif TargetPart.Value == 'Head' then
						targetBodyPart = plr.Head or plr.RootPart
					elseif TargetPart.Value == 'Closest' then
						local mousePos = inputService:GetMouseLocation()
						targetBodyPart = getClosestPart(plr.Character, mousePos)
					elseif TargetPart.Value == 'Randomize' then
						if not lockedRandomPart or not lockedRandomPart.Parent then
							lockedRandomPart = pickRandomPart(plr.Character)
						end
						targetBodyPart = lockedRandomPart
					else
						targetBodyPart = plr.RootPart
					end

					if not targetBodyPart then
						wasHovering = false
						return old(...)
					end

					local dist = (targetBodyPart.Position - originPos).Magnitude
					if dist > Range.Value then
						wasHovering = false
						return old(...)
					end

					local pos = shootpos or self:getLaunchPosition(origin)
					if not pos then
						wasHovering = false
						return old(...)
					end

					local projectileName = projmeta.projectile or ""
					if isBlacklisted(projectileName) then
						wasHovering = false
						return old(...)
					end

					local meta = projmeta:getProjectileMeta()
					local lifetime = (worldmeta and meta.predictionLifetimeSec or meta.lifetimeSec or 3)
					local gravity = (meta.gravitationalAcceleration or 196.2) * projmeta.gravityMultiplier
					local projSpeed = (meta.launchVelocity or 100)
					local offsetpos = pos + (projmeta.projectile == 'owl_projectile' and Vector3.zero or projmeta.fromPositionOffset)
					local balloons = plr.Character and plr.Character:GetAttribute('InflatedBalloons')
					local playerGravity = workspace.Gravity
					if balloons and balloons > 0 then
						playerGravity = workspace.Gravity * (1 - (balloons >= 4 and 1.2 or balloons >= 3 and 1 or 0.975))
					end
					if plr.Character and plr.Character.PrimaryPart and plr.Character.PrimaryPart:FindFirstChild('rbxassetid://8200754399') then
						playerGravity = 6
					end
					if plr.Player and plr.Player:GetAttribute('IsOwlTarget') then
						for _, owl in ipairs(collectionService:GetTagged('Owl')) do
							if owl:GetAttribute('Target') == plr.Player.UserId and owl:GetAttribute('Status') == 2 then
								playerGravity = 0
								break
							end
						end
					end

					-- AssemblyLinearVelocity is the live physics velocity; the legacy
					-- .Velocity field is less reliable for moving targets.
					local targetVelocity = targetBodyPart.AssemblyLinearVelocity
					if targetVelocity == nil or targetVelocity.Magnitude < 0.01 then
						targetVelocity = targetBodyPart.Velocity
					end
					if CustomPrediction and CustomPrediction.Enabled then
						local hMult = (HorizontalMultiplier and HorizontalMultiplier.Value or 100) / 100
						local vMult = (VerticalMultiplier and VerticalMultiplier.Value or 100) / 100
						targetVelocity = Vector3.new(
							targetVelocity.X * hMult,
							targetVelocity.Y * vMult,
							targetVelocity.Z * hMult
						)
					end

					local targetPos = targetBodyPart.Position

					local bowRelX = bedwars.BowConstantsTable.RelX or 0
					local bowRelY = bedwars.BowConstantsTable.RelY or 0
					local bowRelZ = bedwars.BowConstantsTable.RelZ or 0
					local newlook = CFrame.new(offsetpos, targetPos) *
						CFrame.new(projmeta.projectile == 'owl_projectile' and Vector3.zero or
							Vector3.new(bowRelX, bowRelY, bowRelZ))

					local calc = prediction.SolveTrajectory(
						newlook.p, projSpeed, gravity,
						targetPos,
						projmeta.projectile == 'telepearl' and Vector3.zero or targetVelocity,
						playerGravity, plr.HipHeight, plr.Jumping and 42.6 or nil, rayCheck
					)

					if calc then
						if targetinfo and targetinfo.Targets then
							targetinfo.Targets[plr] = tick() + 1
						end

						local customDrawDuration = 5
						if AutoCharge.Enabled then
							if projmeta.projectile:find('arrow') then
								customDrawDuration = 0.58 * (AeroPAChargePercent.Value / 100)
							elseif projmeta.projectile:find('frosty_snowball') then
								local tool = store.hand and store.hand.tool
								if tool and tool.Name:find('frost_staff') then
									local cd = (tool.Name:find('frost_staff_3') and 0.16) or
											(tool.Name:find('frost_staff_2') and 0.18) or 0.2
									customDrawDuration = cd * (AeroPAChargePercent.Value / 100)
								end
							end
						else
							    customDrawDuration = 0.05
						end

						local aimDir = CFrame.new(newlook.Position, calc).LookVector
						-- Hit Chance: on a failed roll, deflect the aim by a small random
						-- angle. Rotating the direction (not offsetting a point) makes the
						-- linear miss grow with distance to the target automatically.
						if HitChance and HitChance.Value < 100 and math.random(1, 100) > HitChance.Value then
							local maxMissDeg = 4 * (1 - HitChance.Value / 100)
							local missAngle = math.rad((math.random() * 0.5 + 0.5) * maxMissDeg)
							local up = math.abs(aimDir.Y) < 0.99 and Vector3.yAxis or Vector3.xAxis
							local perp = aimDir:Cross(up).Unit
							local spin = math.random() * math.pi * 2
							local axis = (perp * math.cos(spin) + aimDir:Cross(perp).Unit * math.sin(spin)).Unit
							aimDir = CFrame.fromAxisAngle(axis, missAngle) * aimDir
						end

						wasHovering = false
						return {
							initialVelocity = aimDir * projSpeed,
							positionFrom = offsetpos,
							deltaT = lifetime,
							gravitationalAcceleration = gravity,
							drawDurationSeconds = customDrawDuration
						}
					end

					wasHovering = false
					return old(...)
				end
			else
				bedwars.ProjectileController.calculateImportantLaunchValues = old
				wasHovering = false
				lockedRandomPart = nil
				if cursorRenderConnection then
					cursorRenderConnection:Disconnect()
					cursorRenderConnection = nil
				end
				runPAFOVCircle(false)
				pcall(function() inputService.MouseIconEnabled = true end)
				task.defer(function()
					pcall(function() inputService.MouseIconEnabled = true end)
					pcall(function() game:GetService('UserInputService').MouseIconEnabled = true end)
				end)
			end
		end,
		Tooltip = 'Silently adjusts your aim towards the enemy'
	})

	Targets = ProjectileAimbot:CreateTargets({
		Players = true,
		NPCs = true,
		Walls = true
	})

	TargetPart = ProjectileAimbot:CreateDropdown({
		Name = 'Part',
		List = {'Dynamic', 'RootPart', 'Head', 'Closest', 'Randomize'},
		Default = 'RootPart',
		Tooltip = 'Select which body part to aim at',
		Function = function()
			lockedRandomPart = nil
			wasHovering = false
		end
	})

	SortMethod = ProjectileAimbot:CreateDropdown({
		Name = 'Sort Method',
		List = {'Distance', 'Damage', 'Threat', 'Kit', 'Health', 'Angle', 'Cursor', 'Forest'},
		Default = 'Distance',
		Tooltip = 'Prioritize targets when multiple are in range'
	})

	DesirePAWorkMode = ProjectileAimbot:CreateDropdown({
		Name = 'PA Work Mode',
		List = {'First Person', 'Third Person', 'Both'},
		Default = 'Both',
		Tooltip = 'Which perspective the aimbot works in'
	})

	Range = ProjectileAimbot:CreateSlider({
		Name = 'Range',
		Min = 10,
		Max = 500,
		Default = 100,
		Tooltip = 'Maximum distance (in studs) for targeting'
	})



	FOV = ProjectileAimbot:CreateSlider({
		Name = 'FOV',
		Min = 1,
		Max = 1000,
		Default = 1000
	})

	HitChance = ProjectileAimbot:CreateSlider({
		Name = 'Hit Chance',
		Min = 0,
		Max = 100,
		Default = 100,
		Suffix = '%',
		Tooltip = 'Chance for each shot to actually hit. Failed shots are deflected by a small angle that scales with distance, so they look like natural misses.'
	})

	PAFOVCircle = ProjectileAimbot:CreateToggle({
		Name = 'FOV Circle',
		Tooltip = 'Shows a circle representing your FOV on screen',
		Function = function(call)
			runPAFOVCircle(call)
		end
	})

	RandomHeadPercent = ProjectileAimbot:CreateSlider({
		Name = 'Head Chance',
		Min = 0,
		Max = 100,
		Default = 50,
		Darker = true,
		Tooltip = 'Chance to aim at head when Part is set to Randomize',
		Visible = false
	})

	RandomTorsoPercent = ProjectileAimbot:CreateSlider({
		Name = 'Torso Chance',
		Min = 0,
		Max = 100,
		Default = 50,
		Darker = true,
		Tooltip = 'Chance to aim at torso when Part is set to Randomize',
		Visible = false
	})

	local function updateRandomizeVisibility()
		local vis = (TargetPart.Value == 'Randomize')
		RandomHeadPercent.Object.Visible = vis
		RandomTorsoPercent.Object.Visible = vis
	end
	if TargetPart.AddHook then
		TargetPart:AddHook(updateRandomizeVisibility)
	end
	updateRandomizeVisibility()

	DesirePAHideCursor = ProjectileAimbot:CreateToggle({
		Name = 'Hide Cursor',
		Default = false,
		Tooltip = 'Hides the cursor while aiming',
		Function = function(callback)
			if DesirePACursorViewMode then DesirePACursorViewMode.Object.Visible = callback end
			if DesirePACursorLimitBow then DesirePACursorLimitBow.Object.Visible = callback end
			if DesirePACursorShowGUI then DesirePACursorShowGUI.Object.Visible = callback end
			if callback and ProjectileAimbot.Enabled then
				if not cursorRenderConnection then
					cursorRenderConnection = runService.RenderStepped:Connect(function()
						checkGUIState()
						updateCursor()
					end)
				end
				updateCursor()
			else
				if cursorRenderConnection then
					cursorRenderConnection:Disconnect()
					cursorRenderConnection = nil
				end
				pcall(function() inputService.MouseIconEnabled = true end)
				task.defer(function()
					pcall(function() inputService.MouseIconEnabled = true end)
