run(function()
    local TerraAimbot
    local Range
    local Mode
    
    local old
    
    TerraAimbot = vain.Categories.Blatant:CreateModule({
        Name = 'Terra Aimbot',
        Function = function(callback)
            if callback then
                old = bedwars.BlockKickerKitController.getKickBlockProjectileOriginPosition
                bedwars.BlockKickerKitController.getKickBlockProjectileOriginPosition = function(...)
                    local origin, dir = select(2, ...)
                    local plr = entitylib['Entity'.. Mode.Value]({
                        Part = 'RootPart',
                        Range = Range.Value,
                        Origin = origin,
                        Players = true,
                        Wallcheck = true
                    })
    
                    if plr then
                        local calc = prediction.SolveTrajectory(origin, 100, 20, plr.RootPart.Position, plr.RootPart.Velocity, workspace.Gravity, plr.HipHeight, plr.Jumping and 42.6 or nil)
    
                        if calc then
                            for i, v in debug.getstack(2) do
                                if v == dir then
                                    debug.setstack(2, i, CFrame.lookAt(origin, calc).LookVector)
                                end
                            end
                        end
                    end
    
                    return old(...)
                end
            end
        end,
        Tooltip = 'Silently adjusts where terra blocks are heading towards.'
    })
    
    Mode = TerraAimbot:CreateDropdown({
        Name = 'Mode',
        List = {'Position', 'Mouse'},
        Default = 'Mouse'
    })
    Range = TerraAimbot:CreateSlider({
        Name = 'Range',
        Min = 1,
        Max = 1000,
        Default = 1000,
        Suffix = function(val)
            return val <= 1 and 'studs' or 'stud'
        end
    })
end)

run(function()
    local VulcanAimbot
    local Targets
    local Range
    local Sort
    
    VulcanAimbot = vain.Categories.Blatant:CreateModule({
        Name = 'Vulcan Aimbot',
        Function = function(callback)
            if callback then
                repeat
                    if entitylib.isAlive then
                        local turret = bedwars.Store:getState().Game.selectedTurret
                        if turret then
                            local origin = turret.Rotate.Position
                            local ent = entitylib.EntityMouse({
                                Range = Range.Value,
                                Origin = origin,
                                Wallcheck = Targets.Walls.Enabled or nil,
                                Part = 'RootPart',
                                Players = Targets.Players.Enabled,
                                NPCs = Targets.NPCs.Enabled,
                                Sort = sortmethods[Sort.Value]
                            })
                            if ent then
                                local pos = prediction.SolveTrajectory(origin, 320, 10, ent.RootPart.Position, ent.RootPart.Velocity, workspace.Gravity, ent.HipHeight, nil, store.airRay)
                                if pos then
                                    local delta = pos - origin
    
                                    -- mathing
                                    bedwars.TurretCameraController.angleX = math.atan2(-delta.X, -delta.Z)
                                    bedwars.TurretCameraController.angleY = math.clamp(math.atan2(delta.Y, math.sqrt(delta.X^2 + delta.Z^2)), -0.8, 0.8)
                                end
                            end
                        end
                    end
                    task.wait(0.1)
                until not VulcanAimbot.Enabled
            end
        end,
        Tooltip = 'Automatically aims ur camera toward opponents.'
    })
    
    Targets = VulcanAimbot:CreateTargets({Walls = true, Players = true})
    local methods = {'Distance', 'Damage'}
    for i in sortmethods do
        if not table.find(methods, i) then
            table.insert(methods, i)
        end
    end
    Sort = VulcanAimbot:CreateDropdown({
        Name = 'Target mode',
        List = methods,
        Default = methods[1]
    })
    Range = VulcanAimbot:CreateSlider({
        Name = 'Range',
        Min = 1,
        Max = 1000,
        Default = 500
    })
end)
run(function()
    local ProjectileAura
    local FireRate
    local Targets
    local Range
    local Sort
    local List
    local rayCheck = RaycastParams.new()
    rayCheck.FilterType = Enum.RaycastFilterType.Include
    local projectileRemote = { InvokeServer = function(self, ...) end }
    local projectileCooldown = 0
    local FireDelays = {}
    task.spawn(function()
    	projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
    end)
    
    local function getAmmo(check)
    	for _, item in store.inventory.inventory.items do
    		if check.ammoItemTypes and table.find(check.ammoItemTypes, item.itemType) then
    			return item.itemType
    		end
    	end
    	return nil
    end
    local function getProjectiles()
    	local items = {}
    	for _, item in store.inventory.inventory.items do
    		local proj = bedwars.ItemMeta[item.itemType].projectileSource
    		local ammo = proj and getAmmo(proj)
    		if ammo and table.find(List.ListEnabled, ammo) then
    			table.insert(items, {
    				item,
    				ammo,
    				proj.projectileType(ammo),
    				proj,
    			})
    		end
    	end
    	return items
    end
    
    ProjectileAura = vain.Categories.Blatant:CreateModule({
    	Name = 'Projectile Aura',
    	Tooltip = 'Auto-fires projectile weapons at nearby enemies',
    	Function = function(callback)
    		if callback then
    			repeat
    				if (workspace:GetServerTimeNow() - bedwars.SwordController.lastAttack) > 0.5 then
    					local ent = entitylib.EntityPosition({
    						Part = 'RootPart',
    						Range = Range.Value,
    						Sort = sortmethods[Sort.Value],
    						Players = Targets.Players.Enabled,
    						NPCs = Targets.NPCs.Enabled,
    						Wallcheck = Targets.Walls.Enabled,
    					})
    
    					if ent then
    						local pos = entitylib.character.RootPart.Position
    						for _, data in getProjectiles() do
    							local item, ammo, projectile, itemMeta = unpack(data)
    							if (FireDelays[item.itemType] or 0) < tick() then
    								rayCheck.FilterDescendantsInstances = { workspace.Map }
    								local meta = bedwars.ProjectileMeta[projectile]
    								local projSpeed, gravity = meta.launchVelocity, meta.gravitationalAcceleration or 196.2
    								local calc = prediction.SolveTrajectory(pos, projSpeed, gravity, ent.RootPart.Position + (ent.Humanoid.MoveDirection or Vector3.zero), ent.RootPart.Velocity, workspace.Gravity, ent.HipHeight + 2, ent.Jumping and 42.6 or nil, rayCheck)
    								if calc then
    									targetinfo.Targets[ent] = tick() + 1
    									local switched = switchItem(item.tool)
    
    									local v = ent.RootPart.AssemblyLinearVelocity
    									local s = v:Lerp(ent.RootPart.AssemblyLinearVelocity, 0.5)
    									pos = entitylib.character.RootPart.Position
    									local ps = math.min(lplr:GetNetworkPing(), 0.5)
    									local tpos = ent.RootPart.Position
    									if ps > 0.06 then
    										tpos = tpos + (v * ps)
    									end
    									calc = prediction.SolveTrajectory(pos, projSpeed, gravity, tpos, s, workspace.Gravity, ent.HipHeight + 2, ent.Jumping and 42.6 or nil, rayCheck)
    									if not calc then
                                            task.wait()
    										continue
    									end
    									task.spawn(function()
    										local dir, id =
    											CFrame.lookAt(pos, calc).LookVector, httpService:GenerateGUID(true)
    										local shootPosition = (CFrame.new(pos, calc) * CFrame.new(Vector3.new(-bedwars.BowConstantsTable.RelX, -bedwars.BowConstantsTable.RelY, -bedwars.BowConstantsTable.RelZ))).Position
    										projectileCooldown = 9e9
    										local _, res = pcall(function() return projectileRemote:InvokeServer(
    											item.tool,
    											ammo,
    											projectile,
    											shootPosition,
    											pos,
    											dir * projSpeed,
    											id,
    											{ 
                                                    drawDurationSeconds = 1, 
                                                    shotId = httpService:GenerateGUID(false) 
                                                },
    											workspace:GetServerTimeNow() - 0.045
    										) end)
    										projectileCooldown = tick()
    										if not res then
    											FireDelays[item.itemType] = tick()
    										else
    											--res.Parent = replicatedStorage
    											local shoot = itemMeta.launchSound
    											shoot = shoot and shoot[math.random(1, #shoot)] or nil
    											if shoot then
    												bedwars.SoundManager:playSound(shoot)
    											end
    										end
    									end)
    
    									FireDelays[item.itemType] = tick() + itemMeta.fireDelaySec
    									if switched then
    										repeat task.wait() until tick() > projectileCooldown
    										if FireRate.Value > 0 then
    											task.wait(FireRate.Value)
    										end
    									end
    								end
    							end
    						end
    					end
    				end
    				task.wait(0.012)
    			until not ProjectileAura.Enabled
    		end
    	end,
    	Tooltip = 'Shoots people around you',
    })
    Targets = ProjectileAura:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
    	Players = true,
    	Walls = true,
    })
    local methods = {'Damage', 'Distance'}
    for i in sortmethods do
    	if not table.find(methods, i) then
    		table.insert(methods, i)
    	end
    end
    Sort = ProjectileAura:CreateDropdown({
    	Name = 'Target Mode',
    	Tooltip = 'Selects how targets are prioritized and selected',
    	List = methods,
    	Default = 'Distance',
    	ItemTooltips = {
    		Distance = 'Targets the closest enemy by stud distance',
    		Health = 'Targets the enemy with the lowest remaining health',
    		Angle = 'Targets the enemy closest to your look direction',
    		Cursor = 'Targets the enemy nearest to your mouse cursor',
    		Damage = 'Targets the enemy who most recently took damage',
    		Threat = 'Targets the enemy judged to be the greatest combat threat',
    		Kit = 'Prioritizes dangerous kit users (Hannah, Spirit Assassin, etc.)',
    	}
    })
    List = ProjectileAura:CreateTextList({
    	Name = 'Projectiles',
    	Tooltip = 'Projectile types the aura fires (one per line)',
    	Default = {'arrow', 'snowball'},
    })
    FireRate = ProjectileAura:CreateSlider({
    	Name = 'Fire Rate',
    	Tooltip = 'Shots per second for projectile weapons',
    	Min = 0,
    	Max = 2,
    	Default = 0.02,
    	Decimal = 100,
    	Suffix = 'seconds'
    })
    Range = ProjectileAura:CreateSlider({
    	Name = 'Range',
    	Tooltip = 'Maximum distance in studs',
    	Min = 1,
    	Max = 50,
    	Default = 50,
    	Suffix = function(val)
    		return val == 1 and 'stud' or 'studs'
    	end,
    })
end)

run(function()
    local Mode
    local Value
    local WallCheck
    local AutoJump
    local AlwaysJump
    local rayCheck = RaycastParams.new()
    rayCheck.RespectCanCollide = true
    
    Speed = vain.Categories.Blatant:CreateModule({
        Name = 'Speed',
        Tooltip = 'Increases your movement speed beyond the server cap',
        Function = function(callback)
            frictionTable.Speed = callback or nil
            updateVelocity()
            pcall(function()
                debug.setconstant(bedwars.WindWalkerController.updateSpeed, 7, callback and 'constantSpeedMultiplier' or 'moveSpeedMultiplier')
            end)
    
            if callback then
                Speed:Clean(runService.PreSimulation:Connect(function(dt)
                    bedwars.StatefulEntityKnockbackController.lastImpulseTime = callback and math.huge or time()
                    if entitylib.isAlive then
                        if not (Fly and Fly.Enabled) and not (LongJump and LongJump.Enabled) then
                            bedwars.SprintController:setSpeed(Mode.Value == 'CFrame' and 20 or Value.Value)
                            if Mode.Value == 'CFrame' then
                                local state = entitylib.character.Humanoid:GetState()
                                if state == Enum.HumanoidStateType.Climbing then return end
            
                                local root, velo = entitylib.character.RootPart, getSpeed()
                                local moveDirection = AntiFallDirection or entitylib.character.Humanoid.MoveDirection
                                local destination = (moveDirection * math.max(Value.Value - velo, 0) * dt)
            
                                if WallCheck.Enabled then
                                    rayCheck.FilterDescendantsInstances = {lplr.Character, gameCamera}
                                    rayCheck.CollisionGroup = root.CollisionGroup
                                    local ray = workspace:Raycast(root.Position, destination, rayCheck)
                                    if ray then
                                        destination = ((ray.Position + ray.Normal) - root.Position)
                                    end
                                end
            
                                root.CFrame += destination
                                root.AssemblyLinearVelocity = (moveDirection * velo) + Vector3.new(0, root.AssemblyLinearVelocity.Y, 0)
                                if AutoJump.Enabled and (state == Enum.HumanoidStateType.Running or state == Enum.HumanoidStateType.Landed) and moveDirection ~= Vector3.zero and (Attacking or AlwaysJump.Enabled) then
                                    entitylib.character.Humanoid:ChangeState(Enum.HumanoidStateType.Jumping)
                                end
                            end
                        end
                    end
                end))
            else
                bedwars.SprintController:setSpeed(bedwars.SprintController:isSprinting() and 20 or 14)
            end
        end,
        ExtraText = function()
            return 'Heatseeker'
        end,
        Tooltip = 'Increases your movement with various methods.'
    })
    Mode = Speed:CreateDropdown({
        Name = 'Method',
        Tooltip = 'Selects the implementation method',
        List = {'Bedwars', 'CFrame'},
        Default = 'CFrame',
        ItemTooltips = {
            Bedwars = "Uses the game's own walk speed API — more compatible but capped",
            CFrame = 'Moves the character CFrame directly each frame — faster and uncapped',
        }
    })
    Value = Speed:CreateSlider({
        Name = 'Speed',
        Tooltip = 'Movement speed multiplier',
        Min = 1,
        Max = 23,
        Default = 23,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    WallCheck = Speed:CreateToggle({
        Name = 'Wall Check',
        Tooltip = 'Only targets enemies with a clear line of sight',
        Default = true
    })
    AutoJump = Speed:CreateToggle({
        Name = 'AutoJump',
        Tooltip = 'Automatically jumps when you land, enabling continuous bunny-hop movement',
        Function = function(callback)
            AlwaysJump.Object.Visible = callback
        end
    })
    AlwaysJump = Speed:CreateToggle({
        Name = 'Always Jump',
        Tooltip = 'Continuously jumps even while airborne — requires AutoJump to be enabled',
        Visible = false,
        Darker = true
    })
end)

