run(function()
    local ItemESP
    local Distance
    local Transparency
    local Scale
    local WhitelistOnly
    local Whitelist = { ListEnabled = {}, Object = nil }

    local Folder = Instance.new('Folder')
    Folder.Parent = vain.gui

    local Reference, Strings, Sizes = {}, {}, {}

    local function Added(ent)
    	local Name = bedwars.ItemMeta[ent.Name] and bedwars.ItemMeta[ent.Name].displayName or ent.Name
    	if WhitelistOnly.Enabled and not table.find(Whitelist.ListEnabled, Name:lower()) then
    		return
    	end

    	Strings[ent] = Name .. '%s'
    	if Distance.Enabled then
    		Strings[ent] = '<font color="rgb(85, 255, 85)">[</font><font color="rgb(255, 255, 255)">%s</font><font color="rgb(85, 255, 85)">]</font> '.. Strings[ent]
    	end

    	local nametag = Instance.new('TextLabel')
    	nametag.TextSize = 14 * Scale.Value
    	nametag.Font = Enum.Font.Arial
    	local size = getfontsize(removeTags(ent.Name), nametag.TextSize, nametag.FontFace, Vector2.new(100000, 100000))
    	nametag.Name = ent.Name
    	nametag.Size = UDim2.fromOffset(size.X + 8, size.Y + 7)
    	nametag.AnchorPoint = Vector2.new(0.5, 1)
    	nametag.BackgroundColor3 = Color3.new()
    	nametag.BackgroundTransparency = 0.5
    	nametag.BorderSizePixel = 0
    	nametag.Visible = false
    	nametag.Text = string.format(Strings[ent], 'nan', ent:GetAttribute('Amount') >= 2 and ' x' .. tostring(ent:GetAttribute('Amount')) or '')
    	nametag.TextColor3 = Color3.new(1, 1, 1)
    	nametag.RichText = true
    	nametag.Parent = Folder
    	Reference[ent] = nametag
    end
    local function Updated(ent)
    	if Reference[ent] then
    		Reference[ent].TextSize = 14 * Scale.Value
    		Reference[ent].BackgroundTransparency = Transparency.Value
    	end
    end
    local function Removing(ent)
    	if Reference[ent] then
    		Reference[ent]:Destroy()
    		Reference[ent] = nil
    	end
    end

    ItemESP = vain.Categories.Render:CreateModule({
    	Name = 'Item ESP',
    	Tooltip = 'Highlights dropped items on the ground',
    	Function = function(call)
    		if call then
    			ItemESP:Clean(collectionService:GetInstanceAddedSignal('ItemDrop'):Connect(Added))
    			ItemESP:Clean(collectionService:GetInstanceRemovedSignal('ItemDrop'):Connect(Removing))
    			ItemESP:Clean(runService.PreRender:Connect(function()
    				for ent, nametag in Reference do
    					local headPos, headVis = gameCamera:WorldToViewportPoint(ent.Position + Vector3.new(0, 1, 0))
    					nametag.Visible = headVis
    					if not headVis then
    						continue
    					end

    					if Distance.Enabled then
    						local mag = entitylib.isAlive and math.floor((entitylib.character.RootPart.Position - ent.Position).Magnitude) or 0
    						if Sizes[ent] ~= mag then
    							nametag.Text = string.format(Strings[ent], mag, ent:GetAttribute('Amount') >= 2 and ' x' .. tostring(ent:GetAttribute('Amount')) or '')
    							local size = getfontsize(removeTags(nametag.Text), nametag.TextSize, nametag.FontFace, Vector2.new(100000, 100000))
    							nametag.Size = UDim2.fromOffset(size.X + 8, size.Y + 7)
    							Sizes[ent] = mag
    						end
    					end
    					nametag.Position = UDim2.fromOffset(headPos.X, headPos.Y)
    				end
    			end))

    			for _, v in collectionService:GetTagged('ItemDrop') do
    				Added(v)
    			end
    		else
    			for i in Reference do
    				Removing(i)
    			end
    		end
    	end,
    	Tooltip = 'Renders tags dropped items'
    })
    Distance = ItemESP:CreateToggle({
    	Name = 'Distance',
    	Tooltip = 'Shows the distance of the item',
    })
    ItemESP:CreateToggle({
    	Name = 'Group items',
    	Tooltip = 'Group items into easier to read tags',
    })
    Transparency = ItemESP:CreateSlider({
    	Name = 'Transparency',
    	Tooltip = 'Opacity of the rendered element (0 = fully opaque)',
    	Function = function()
    		if ItemESP.Enabled then
    			for ent in Reference do
    				Updated(ent)
    			end
    		end
    	end,
    	Default = 0.5,
    	Min = 0,
    	Max = 1,
    	Decimal = 100,
    })
    Scale = ItemESP:CreateSlider({
    	Name = 'Scale',
    	Tooltip = 'Scale multiplier for this ESP element',
    	Default = 1,
    	Min = 0.1,
    	Max = 1.5,
    	Decimal = 10,
    	Function = function()
    		if ItemESP.Enabled then
    			for ent in Reference do
    				Updated(ent)
    			end
    		end
    	end,
    })
    WhitelistOnly = ItemESP:CreateToggle({
    	Name = 'Whitelist Only',
    	Tooltip = 'Only renders whitelisted items',
    	Function = function(call)
    		if Whitelist.Object then
    			Whitelist.Object.Visible = call

    			if ItemESP.Enabled then
    				ItemESP:Toggle()
    				ItemESP:Toggle()
    			end
    		end
    	end,
    })
    Whitelist = ItemESP:CreateTextList({
    	Name = 'Allowed items',
    	Tooltip = 'Only highlight items in this list (one per line)',
    	Visible = false,
    	Darker = true,
    	Function = function()
    		if ItemESP.Enabled then
    			ItemESP:Toggle()
    			ItemESP:Toggle()
    		end
    	end,
    })
end)

run(function()
    local KitDisplay

    local function getKitMeta(player)
    	local kit = player:GetAttribute('PlayingAsKits') or player:GetAttribute('PlayingAsKit') or 'none'
    	return bedwars.BedwarsKitMeta[kit] or bedwars.BedwarsKitMeta.none or {renderImage = ''}
    end

    local function getPlayerFromDraft(render, name)
    	local id = render and render:match('id=(%d+)')
    	if id then
    		local player = playersService:GetPlayerByUserId(tonumber(id))
    		if player then
    			return player
    		end
    	end

    	for _, v in playersService:GetPlayers() do
    		if render and render:find('id=' .. v.UserId, 1, true) then
    			return v
    		end

    		if name and (v.Name == name or v.DisplayName == name or v:GetAttribute('DisguiseDisplayName') == name) then
    			return v
    		end

    		local displayName
    		pcall(function()
    			displayName = bedwars.StreamerModeController:getDisplayName(v)
    		end)
    		if name and displayName == name then
    			return v
    		end
    	end
    	return nil
    end

    local waitForChild = function(start, ...)
    	local parent = start
    	for _, v in {...} do
    		parent = parent and parent:WaitForChild(v, 5)
    		if not parent then
    			break
    		end
    	end
    	return parent
    end

    local function getPlayerName(card)
    	local textbar = card and card:FindFirstChild('TextBackgroundBar')
    	local label = textbar and textbar:FindFirstChild('PlayerName') or card and card:FindFirstChild('PlayerName', true)
    	return label and label.Text or ''
    end

    local function getDraftCard(container)
    	if not container then
    		return
    	end
    	return container.Name == 'MatchDraftPlayerCard' and container or container:FindFirstChild('MatchDraftPlayerCard', true)
    end

    local function callback5v5(v, plr)
    	if not v then
    		return
    	end
    	local render = v:FindFirstChild('PlayerRender', true)
    	local player = plr or getPlayerFromDraft(render and render.Image or '', getPlayerName(v))

    	if player then
    		local kitImage = getKitMeta(player)
    		local roact = v:FindFirstChild('KitImage')

    		if not roact then
    			roact = Instance.new('ImageLabel', v)
    			roact.BackgroundTransparency = 1
    			roact.AnchorPoint = Vector2.new(1, 0.5)
    			roact.Position = UDim2.fromScale(1.05, 0.5)
    			roact.Name = 'KitImage'
    			roact.Size = UDim2.fromScale(1.5, 1.5)
    			roact.ZIndex = 1
    			roact.ImageTransparency = 0.4
    			roact.SliceCenter = Rect.new(0, 0, 0, 0)
    			roact.SliceScale = 1
    			roact.ScaleType = Enum.ScaleType.Crop

    			KitDisplay:Clean(roact)

    			local ratio = Instance.new('UIAspectRatioConstraint', roact)
    			ratio.Name = '1'
    			ratio.AspectRatio = 1
    			ratio.AspectType = Enum.AspectType.FitWithinMaxSize
    			ratio.DominantAxis = Enum.DominantAxis.Width
    		end

    		roact.Image = kitImage.renderImage
    		roact.Position = UDim2.fromScale(1.05, 0)
    		tweenService:Create(roact, TweenInfo.new(0.2, Enum.EasingStyle.Cubic, Enum.EasingDirection.Out), {Position = UDim2.fromScale(1.05, 0.4)}):Play()

    		local function update()
    			roact.Image = getKitMeta(player).renderImage
    		end

    		-- Re-bind the kit listener to whichever player the card currently shows.
    		-- Draft cards are reused as the list reorders, so a card can switch to a
    		-- new player; without this the kit image stays stuck on the old player.
    		local kitConn
    		local function bindKit()
    			if kitConn then kitConn:Disconnect() end
    			kitConn = player:GetAttributeChangedSignal('PlayingAsKits'):Connect(update)
    			KitDisplay:Clean(kitConn)
    			update()
    		end
    		bindKit()

    		if render then
    			KitDisplay:Clean(render:GetPropertyChangedSignal('Image'):Connect(function()
    				local newplayer = getPlayerFromDraft(render.Image, getPlayerName(v))
    				if newplayer and newplayer ~= player then
    					player = newplayer
    					bindKit()
    				end
    			end))
    		end
    	end
    end

    local function callbacksquad(v)
    	if not v then
    		return
    	end
    	local render = v:FindFirstChild('PlayerRender', true)
    	local player = render and getPlayerFromDraft(render.Image, '') or nil

    	if player then
    		local kitImage = getKitMeta(player)
    		local Roact = v:FindFirstChild('Kitcvrender')

    		if not Roact then
    			local base = v:FindFirstChild('3') or v:WaitForChild('3', 5)
    			if not base then
    				return
    			end
    			Roact = base:Clone()
    			Roact.Parent = v
    			Roact.Name = 'Kitcvrender'
    			KitDisplay:Clean(Roact)
    		end

    		Roact.Image = kitImage.renderImage

    		local function update()
    			Roact.Image = getKitMeta(player).renderImage
    		end

    		-- Keep the kit listener bound to whichever player this card now shows.
    		local kitConn
    		local function bindKit()
    			if kitConn then kitConn:Disconnect() end
    			kitConn = player:GetAttributeChangedSignal('PlayingAsKits'):Connect(update)
    			KitDisplay:Clean(kitConn)
    			update()
    		end
    		bindKit()

    		KitDisplay:Clean(render:GetPropertyChangedSignal('Image'):Connect(function()
    			local newplayer = getPlayerFromDraft(render.Image, '')
    			if newplayer and newplayer ~= player then
    				player = newplayer
    				bindKit()
    			end
    		end))
    	end
    end

    local function setup5v5(DraftApp)
    	local Background = DraftApp:FindFirstChild('DraftAppBackground')
    	local BodyContainer = Background and Background:FindFirstChild('1') and Background['1']:FindFirstChild('BodyContainer')
    	local hooked = false

    	for i = 1, 2 do
    		local dtc = BodyContainer and BodyContainer:FindFirstChild('Team' .. i .. 'Column')
    		if dtc then
    			hooked = true
    			KitDisplay:Clean(dtc.ChildAdded:Connect(function(child)
    				task.delay(0.2, function()
    					if KitDisplay.Enabled then
    						callback5v5(getDraftCard(child))
    					end
    				end)
    			end))

    			for _, v in dtc:GetChildren() do
    				if v:IsA('Frame') then
    					callback5v5(getDraftCard(v))
    				end
    			end
    		end
    	end

    	if not hooked then
    		for _, label in DraftApp:GetDescendants() do
    			if label:IsA('TextLabel') and label.Name == 'PlayerName' then
    				local container = label.Parent
    				for _ = 1, 3 do
    					container = container and container.Parent
    				end
    				if container then
    					callback5v5(getDraftCard(container))
    				end
    			end
    		end

    		KitDisplay:Clean(DraftApp.DescendantAdded:Connect(function(child)
    			if child:IsA('TextLabel') and child.Name == 'PlayerName' then
    				task.delay(0.2, function()
    					local container = child.Parent
    					for _ = 1, 3 do
    						container = container and container.Parent
    					end
    					if KitDisplay.Enabled and container then
    						callback5v5(getDraftCard(container))
    					end
    				end)
    			end
    		end))
    	end

    	return hooked
    end

    local function setupSquad(DraftApp)
    	local Background = DraftApp:FindFirstChild('DraftAppBackground')
    	local BodyContainer = Background and Background:FindFirstChild('1') and Background['1']:FindFirstChild('BodyContainer')
    	local TeamsColumn = BodyContainer and BodyContainer:FindFirstChild('TeamsColumn')
    	if not TeamsColumn then
    		return
    	end

    	for _, v: Instance in TeamsColumn:GetChildren() do
    		if v:IsA('Frame') then
    			local plrframe = waitForChild(v, '1', '2', '4')
    			if plrframe then
    				for _, plr in plrframe:GetChildren() do
    					callbacksquad(plr)
    				end

    				-- Apply directly to the newly added card instead of restarting the
    				-- whole module (the old code toggled itself off/on, which combined
    				-- with the infinite WaitForChild below would hang/flicker it).
    				KitDisplay:Clean(plrframe.ChildAdded:Connect(function(plr)
    					task.delay(0.2, function()
    						if KitDisplay.Enabled then
    							callbacksquad(plr)
    						end
    					end)
    				end))
    			end
    		end
    	end
    end

    local function runSetup(DraftApp)
    	if not DraftApp or not KitDisplay.Enabled then return end
    	-- 5v5 first; if it found no team columns it hooks PlayerName labels itself.
    	setup5v5(DraftApp)
    	setupSquad(DraftApp)
    end

    KitDisplay = vain.Categories.Render:CreateModule({
    	Name = 'Kit Display',
    	Tooltip = 'Enables the Kit Display module',
    	Function = function(call)
    		if call then
    			-- The draft UI (MatchDraftApp) is created at the start of every kit
    			-- phase and removed after, so a one-shot wait misses later rounds.
    			-- Set up on whatever's there now, and again each time it reappears.
    			local existing = lplr.PlayerGui:FindFirstChild('MatchDraftApp')
    			if existing then
    				runSetup(existing)
    			end
    			KitDisplay:Clean(lplr.PlayerGui.ChildAdded:Connect(function(child)
    				if child.Name == 'MatchDraftApp' and KitDisplay.Enabled then
    					task.wait(0.2)
    					runSetup(child)
    				end
    			end))
    		end
    	end,
    	Tooltip = 'Allows you to see the other opponent kits'
    })
end)

run(function()
    local NameTags
    local Targets
    local Color
    local Background
    local DisplayName
    local Health
    local Distance
    local Equipment
    local Rank
    local Enchant
    local DrawingToggle
    local Scale
    local FontOption
    local Teammates
    local DistanceCheck
    local DistanceLimit
    local Strings, Sizes, Reference = {}, {}, {}
    local Folder = Instance.new('Folder')
    Folder.Parent = vain.gui
    local methodused

    local Added = {
    	Normal = function(ent)
    		if not Targets.Players.Enabled and ent.Player then
    			return
    		end
    		if not Targets.NPCs.Enabled and ent.NPC then
    			return
    		end
    		if Teammates.Enabled and not ent.Targetable and not ent.Friend then
    			return
    		end

    		local nametag = Instance.new('TextLabel')
    		Strings[ent] = ent.Player
    				and whitelist:tag(ent.Player, true, true) .. (DisplayName.Enabled and ent.Player.DisplayName or ent.Player.Name)
    			or ent.Character.Name

    		if Health.Enabled then
    			local healthColor = Color3.fromHSV(math.clamp(ent.Health / ent.MaxHealth, 0, 1) / 2.5, 0.89, 0.75)
    			Strings[ent] = Strings[ent]
    				.. ' <font color="rgb('
    				.. tostring(math.floor(healthColor.R * 255))
    				.. ','
    				.. tostring(math.floor(healthColor.G * 255))
    				.. ','
    				.. tostring(math.floor(healthColor.B * 255))
    				.. ')">'
    				.. math.round(ent.Health)
    				.. '</font>'
    		end

    		if Distance.Enabled then
    			Strings[ent] = '<font color="rgb(85, 255, 85)">[</font><font color="rgb(255, 255, 255)">%s</font><font color="rgb(85, 255, 85)">]</font> '
    				.. Strings[ent]
    		end

    		if Equipment.Enabled then
    			for i, v in {'Hand', 'Helmet', 'Chestplate', 'Boots', 'Kit'} do
    				local Icon = Instance.new('ImageLabel')
    				Icon.Name = v
    				Icon.Size = UDim2.fromOffset(30, 30)
    				Icon.Position = UDim2.fromOffset(-60 + (i * 30), -30)
    				Icon.BackgroundTransparency = 1
    				Icon.Image = ''
    				Icon.Parent = nametag
    			end
    		end

    		nametag.TextSize = 14 * Scale.Value
    		nametag.FontFace = FontOption.Value
    		local size =
    			getfontsize(removeTags(Strings[ent]), nametag.TextSize, nametag.FontFace, Vector2.new(100000, 100000))
    		nametag.Name = ent.Player and ent.Player.Name or ent.Character.Name
    		nametag.Size = UDim2.fromOffset(size.X + 8, size.Y + 7)
    		nametag.AnchorPoint = Vector2.new(0.5, 1)
    		nametag.BackgroundColor3 = Color3.new()
    		nametag.BackgroundTransparency = Background.Value
    		nametag.BorderSizePixel = 0
    		nametag.Visible = false
    		nametag.Text = Strings[ent]
    		nametag.TextColor3 = entitylib.getEntityColor(ent) or Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
    		nametag.RichText = true
    		nametag.Parent = Folder
    		task.spawn(function()
    			if Rank.Enabled and ent.Player then
    				local Icon = Instance.new('ImageLabel')
    				Icon.Name = 'RankIcon'
    				Icon.Size = UDim2.fromOffset(30, 30)
    				Icon.Position = UDim2.fromOffset(size.X + 10, -4)
    				Icon.BackgroundTransparency = 1
    				Icon.Image = store.rank[ent.Player]:async() and bedwars.RankMeta[store.rank[ent.Player]:async()].image
    					or ''
    				Icon.Parent = nametag
    			end
    		end)
    		task.spawn(function()
    			if Enchant.Enabled and ent.Player then
    				local Icon = Instance.new('ImageLabel')
    				Icon.Name = 'EnchantIcon'
    				Icon.Size = UDim2.fromOffset(30, 30)
    				Icon.Position = UDim2.fromOffset(-30, -4)
    				Icon.BackgroundTransparency = 1
    				Icon.Image = store.enchants[ent.Player]:async() or ''
    				Icon.Parent = nametag
    			end
    		end)
    		Reference[ent] = nametag
    	end,
    	Drawing = function(ent)
    		if not Targets.Players.Enabled and ent.Player then
    			return
    		end
    		if not Targets.NPCs.Enabled and ent.NPC then
    			return
    		end
    		if Teammates.Enabled and not ent.Targetable and not ent.Friend then
    			return
    		end

    		local nametag = {}
    		nametag.BG = Drawing.new('Square')
    		nametag.BG.Filled = true
    		nametag.BG.Transparency = 1 - Background.Value
    		nametag.BG.Color = Color3.new()
    		nametag.BG.ZIndex = 1
    		nametag.Text = Drawing.new('Text')
    		nametag.Text.Size = 15 * Scale.Value
    		nametag.Text.Font = 0
    		nametag.Text.ZIndex = 2
    		Strings[ent] = ent.Player
    				and whitelist:tag(ent.Player, true) .. (DisplayName.Enabled and ent.Player.DisplayName or ent.Player.Name)
    			or ent.Character.Name

    		if Health.Enabled then
    			Strings[ent] = Strings[ent] .. ' ' .. math.round(ent.Health)
    		end

    		if Distance.Enabled then
    			Strings[ent] = '[%s] ' .. Strings[ent]
    		end

    		nametag.Text.Text = Strings[ent]
    		nametag.Text.Color = entitylib.getEntityColor(ent) or Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
    		nametag.BG.Size = Vector2.new(nametag.Text.TextBounds.X + 8, nametag.Text.TextBounds.Y + 7)
    		Reference[ent] = nametag
    	end,
    }

    local Removed = {
    	Normal = function(ent)
    		local v = Reference[ent]
    		if v then
    			Reference[ent] = nil
    			Strings[ent] = nil
    			Sizes[ent] = nil
    			v:Destroy()
    		end
    	end,
    	Drawing = function(ent)
    		local v = Reference[ent]
    		if v then
    			Reference[ent] = nil
    			Strings[ent] = nil
    			Sizes[ent] = nil
    			for _, obj in v do
    				pcall(function()
    					obj.Visible = false
    					obj:Remove()
    				end)
    			end
    		end
    	end,
    }


    local Updated = {
    	Normal = function(ent)
    		local nametag = Reference[ent]
    		if nametag then
    			Sizes[ent] = nil
    			Strings[ent] = ent.Player
    					and whitelist:tag(ent.Player, true, true) .. (DisplayName.Enabled and ent.Player.DisplayName or ent.Player.Name)
    				or ent.Character.Name

    			if Health.Enabled then
    				local healthColor = Color3.fromHSV(math.clamp(ent.Health / ent.MaxHealth, 0, 1) / 2.5, 0.89, 0.75)
    				Strings[ent] = Strings[ent]
    					.. ' <font color="rgb('
    					.. tostring(math.floor(healthColor.R * 255))
    					.. ','
    					.. tostring(math.floor(healthColor.G * 255))
    					.. ','
    					.. tostring(math.floor(healthColor.B * 255))
    					.. ')">'
    					.. math.round(ent.Health)
    					.. '</font>'
    			end

    			if Distance.Enabled then
    				Strings[ent] = '<font color="rgb(85, 255, 85)">[</font><font color="rgb(255, 255, 255)">%s</font><font color="rgb(85, 255, 85)">]</font> '
    					.. Strings[ent]
    			end

    			if Equipment.Enabled and store.inventories[ent.Player] then
    				local kit = ent.Player:GetAttribute('PlayingAsKit')
    				local inventory = store.inventories[ent.Player]
    				nametag.Hand.Image = bedwars.getIcon(inventory.hand or {itemType = ''}, true)
    				nametag.Helmet.Image = bedwars.getIcon(inventory.armor[4] or {itemType = ''}, true)
    				nametag.Chestplate.Image = bedwars.getIcon(inventory.armor[5] or {itemType = ''}, true)
    				nametag.Boots.Image = bedwars.getIcon(inventory.armor[6] or {itemType = ''}, true)
    				nametag.Kit.Image = kit and bedwars.BedwarsKitMeta[kit].renderImage or ''
    			end

    			if Enchant.Enabled and nametag:FindFirstChild('EnchantIcon') then
    				nametag.EnchantIcon.Image = store.enchants[ent.Player]:async() or ''
    			end

    			local size = getfontsize(removeTags(Strings[ent]), nametag.TextSize, nametag.FontFace, Vector2.new(100000, 100000))
    			nametag.Size = UDim2.fromOffset(size.X + 8, size.Y + 7)
    			nametag.Text = Strings[ent]
    			-- Keep the RankIcon anchored to the text's right edge (the tag width can
    			-- change as health/distance update). Loot now lives in its own row below,
    			-- so it never pushes the rank icon.
    			local rankIcon = nametag:FindFirstChild('RankIcon')
    			if rankIcon then
    				rankIcon.Position = UDim2.fromOffset(size.X + 10, -4)
    			end
    		end
    	end,
    	Drawing = function(ent)
    		local nametag = Reference[ent]
    		if nametag then
    			if vain.ThreadFix then
    				setthreadidentity(8)
    			end
    			Sizes[ent] = nil
    			Strings[ent] = ent.Player
    					and whitelist:tag(ent.Player, true) .. (DisplayName.Enabled and ent.Player.DisplayName or ent.Player.Name)
    				or ent.Character.Name

    			if Health.Enabled then
    				Strings[ent] = Strings[ent] .. ' ' .. math.round(ent.Health)
    			end

    			if Distance.Enabled then
    				Strings[ent] = '[%s] ' .. Strings[ent]
    				nametag.Text.Text = entitylib.isAlive and string.format(Strings[ent], math.floor((entitylib.character.RootPart.Position - ent.RootPart.Position).Magnitude)) or Strings[ent]
    			else
    				nametag.Text.Text = Strings[ent]
    			end

    			nametag.BG.Size = Vector2.new(nametag.Text.TextBounds.X + 8, nametag.Text.TextBounds.Y + 7)
    			nametag.Text.Color = entitylib.getEntityColor(ent) or Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
    		end
    	end,
    }

    local ColorFunc = {
    	Normal = function(hue, sat, val)
    		local color = Color3.fromHSV(hue, sat, val)
    		for i, v in Reference do
    			v.TextColor3 = entitylib.getEntityColor(i) or color
    		end
    	end,
    	Drawing = function(hue, sat, val)
    		local color = Color3.fromHSV(hue, sat, val)
    		for i, v in Reference do
    			v.Text.Color = entitylib.getEntityColor(i) or color
    		end
    	end,
    }

    local Loop = {
    	Normal = function()
    		local alive = entitylib.isAlive
    		local localPosition = alive and entitylib.character.RootPart.Position
    		for ent, nametag in Reference do
    			local distance
    			if alive and (DistanceCheck.Enabled or Distance.Enabled) then
    				distance = (localPosition - ent.RootPart.Position).Magnitude
    			end

    			if DistanceCheck.Enabled then
    				distance = distance or math.huge
    				if distance < DistanceLimit.ValueMin or distance > DistanceLimit.ValueMax then
    					nametag.Visible = false
    					continue
    				end
    			end

    			local headPos, headVis = gameCamera:WorldToViewportPoint(ent.RootPart.Position + Vector3.new(0, ent.HipHeight + 1, 0))
    			nametag.Visible = headVis
    			if not headVis then
    				continue
    			end

    			if Distance.Enabled then
    				local mag = alive and math.floor(distance) or 0
    				if Sizes[ent] ~= mag then
    					nametag.Text = string.format(Strings[ent], mag)
    					local ize = getfontsize(
    						removeTags(nametag.Text),
    						nametag.TextSize,
    						nametag.FontFace,
    						Vector2.new(100000, 100000)
    					)
    					nametag.Size = UDim2.fromOffset(ize.X + 8, ize.Y + 7)
    					Sizes[ent] = mag
    				end
    			end
    			nametag.Position = UDim2.fromOffset(headPos.X, headPos.Y)
    		end
    	end,
    	Drawing = function()
    		local alive = entitylib.isAlive
    		local localPosition = alive and entitylib.character.RootPart.Position
    		for ent, nametag in Reference do
    			local distance
    			if alive and (DistanceCheck.Enabled or Distance.Enabled) then
    				distance = (localPosition - ent.RootPart.Position).Magnitude
    			end

    			if DistanceCheck.Enabled then
    				distance = distance or math.huge
    				if distance < DistanceLimit.ValueMin or distance > DistanceLimit.ValueMax then
    					nametag.Text.Visible = false
    					nametag.BG.Visible = false
    					continue
    				end
    			end

    			local headPos, headVis = gameCamera:WorldToViewportPoint(ent.RootPart.Position + Vector3.new(0, ent.HipHeight + 1, 0))
    			nametag.Text.Visible = headVis
    			nametag.BG.Visible = headVis
    			if not headVis then
    				continue
    			end

    			if Distance.Enabled then
    				local mag = alive and math.floor(distance) or 0
    				if Sizes[ent] ~= mag then
    					nametag.Text.Text = string.format(Strings[ent], mag)
    					nametag.BG.Size = Vector2.new(nametag.Text.TextBounds.X + 8, nametag.Text.TextBounds.Y + 7)
    					Sizes[ent] = mag
    				end
    			end
    			nametag.BG.Position = Vector2.new(headPos.X - (nametag.BG.Size.X / 2), headPos.Y - nametag.BG.Size.Y)
    			nametag.Text.Position = nametag.BG.Position + Vector2.new(4, 3)
    		end
    	end,
    }

    NameTags = vain.Categories.Render:CreateModule({
    	Name = 'Name Tags',
    	Tooltip = 'Renders custom nametags above players with extra info',
    	Function = function(callback)
    		if callback then
    			methodused = DrawingToggle.Enabled and 'Drawing' or 'Normal'
    			if Removed[methodused] then
    				NameTags:Clean(entitylib.Events.EntityRemoved:Connect(Removed[methodused]))
    			end
    			if Added[methodused] then
    				for _, v in entitylib.List do
    					if Reference[v] then
    						Removed[methodused](v)
    					end
    					Added[methodused](v)
    				end
    				NameTags:Clean(entitylib.Events.EntityAdded:Connect(function(ent)
    					if Reference[ent] then
    						Removed[methodused](ent)
    					end
    					Added[methodused](ent)
    				end))
    			end
    			if Updated[methodused] then
    				NameTags:Clean(entitylib.Events.EntityUpdated:Connect(Updated[methodused]))
    				for _, v in entitylib.List do
    					Updated[methodused](v)
    				end
    			end
    			if ColorFunc[methodused] then
    				NameTags:Clean(vain.Categories.Friends.ColorUpdate.Event:Connect(function()
    					ColorFunc[methodused](Color.Hue, Color.Sat, Color.Value)
    				end))
    			end
    			if Loop[methodused] then
    				NameTags:Clean(runService.RenderStepped:Connect(Loop[methodused]))
    			end
    		else
    			if Removed[methodused] then
    				for i in Reference do
    					Removed[methodused](i)
    				end
    			end
    		end
    	end,
    	Tooltip = 'Renders nametags on entities through walls.'
    })
    Targets = NameTags:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
    	Players = true,
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    FontOption = NameTags:CreateFont({
    	Name = 'Font',
    	Blacklist = 'Arial',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    Color = NameTags:CreateColorSlider({
    	Name = 'Player Color',
    	Function = function(hue, sat, val)
    		if NameTags.Enabled and ColorFunc[methodused] then
    			ColorFunc[methodused](hue, sat, val)
    		end
    	end,
    })
    Scale = NameTags:CreateSlider({
    	Name = 'Scale',
    	Tooltip = 'Scale multiplier for this ESP element',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    	Default = 1,
    	Min = 0.1,
    	Max = 1.5,
    	Decimal = 10,
    })
    Background = NameTags:CreateSlider({
    	Name = 'Transparency',
    	Tooltip = 'Opacity of the rendered element (0 = fully opaque)',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    	Default = 0.5,
    	Min = 0,
    	Max = 1,
    	Decimal = 10,
    })
    Health = NameTags:CreateToggle({
    	Name = 'Health',
    	Tooltip = 'Health threshold that triggers this action',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    Distance = NameTags:CreateToggle({
    	Name = 'Distance',
    	Tooltip = 'Maximum distance in studs',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    Rank = NameTags:CreateToggle({
    	Name = 'Rank',
    	Tooltip = "Displays player's rank",
    })
    Enchant = NameTags:CreateToggle({
    	Name = 'Enchant',
    	Tooltip = "Displays player's enchant",
    	Default = true,
    })
    Equipment = NameTags:CreateToggle({
    	Name = 'Equipment',
    	Tooltip = 'Shows equipped items on the nametag',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    DisplayName = NameTags:CreateToggle({
    	Name = 'Use Displayname',
    	Tooltip = 'Shows the player\'s display name instead of their username',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    	Default = true,
    })
    Teammates = NameTags:CreateToggle({
    	Name = 'Priority Only',
    	Tooltip = 'Only renders for players in your priority/target list',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    	Default = true,
    })
    DrawingToggle = NameTags:CreateToggle({
    	Name = 'Drawing',
    	Tooltip = 'Uses the Drawing API instead of Roblox billboards',
    	Function = function()
    		if NameTags.Enabled then
    			NameTags:Toggle()
    			NameTags:Toggle()
    		end
    	end,
    })
    DistanceCheck = NameTags:CreateToggle({
    	Name = 'Distance Check',
    	Tooltip = 'Only renders this element within a set distance',
    	Function = function(callback)
    		DistanceLimit.Object.Visible = callback
    	end,
    })
    DistanceLimit = NameTags:CreateTwoSlider({
    	Name = 'Player Distance',
    	Min = 0,
    	Max = 256,
    	DefaultMin = 0,
    	DefaultMax = 64,
    	Darker = true,
    	Visible = false,
    })
end)

-- ══════════════════════════════════════════════════════════════════════════════
--  LOOT DISPLAY  (own module: shows each player's carried resources on a billboard)
-- ══════════════════════════════════════════════════════════════════════════════
-- Split out of Name Tags so its options don't clutter that module. Renders its
-- own BillboardGui per player so the two never fight over the same instance --
-- offset a little higher than the head, and Name Tags sits at the head, so the
-- rows stack cleanly instead of overlapping.
run(function()
    local LootDisplay, Highlight, TargetClass, ClassDropdown, SizeSlider, HideTeam
    local LootShow = {}       -- resource key -> "Show X" toggle
    local LootThresholds = {} -- resource key -> threshold slider

    -- key   = display / toggle key
    -- item  = exact inventory itemType to tally (nil when using `match`)
    -- match = a prefix; ANY itemType starting with it is summed into this key
    --         (used for blocks: all wool_* colours count as one)
    -- icon  = itemType whose ItemMeta.image is shown (defaults to `item`)
    -- off   = true -> Show toggle defaults OFF
    local LOOT_RES = {
        { key = 'iron',      item = 'iron',          color = Color3.fromRGB(210, 210, 210) },
        { key = 'gold',      item = 'gold',          color = Color3.fromRGB(255, 215, 90)  },
        { key = 'emerald',   item = 'emerald',       color = Color3.fromRGB(80, 235, 120)  },
        { key = 'diamond',   item = 'diamond',       color = Color3.fromRGB(120, 225, 255) },
        { key = 'telepearl', item = 'telepearl',     color = Color3.fromRGB(200, 120, 255) },
        { key = 'vitality',  item = 'vitality_star', color = Color3.fromRGB(140, 235, 140) },
        { key = 'crit',      item = 'crit_star',     color = Color3.fromRGB(255, 220, 90)  },
        { key = 'bee',       item = 'bee',           color = Color3.fromRGB(255, 210, 60)  },
        { key = 'arrow',     item = 'arrow',         color = Color3.fromRGB(230, 230, 230) },
        { key = 'block',     match = 'wool_', icon = 'wool_white', off = true, color = Color3.fromRGB(235, 235, 235) },
        { key = 'tesla',     match = 'tesla', icon = 'tesla', iconAlt = 'tesla_trap', off = true, color = Color3.fromRGB(120, 220, 255) },
    }
    -- exact itemType -> key
    local ITEM_TO_KEY = {}
    for _, r in LOOT_RES do if r.item then ITEM_TO_KEY[r.item] = r.key end end

    local iconCache = {}
    -- realItem = the concrete itemType actually seen in inventory (best source).
    local function lootIcon(r, realItem)
        local id = realItem or r.icon or r.item or r.match
        if iconCache[id] ~= nil then return iconCache[id] end
        local img = ''
        -- try candidates in order via getIcon (same resolver Storage ESP uses)
        -- then ItemMeta.image, so an item whose exact key differs still gets an icon.
        for _, cand in { realItem, r.icon, r.item, r.iconAlt } do
            if cand and img == '' then
                pcall(function()
                    if bedwars.getIcon then img = bedwars.getIcon({ itemType = cand }, true) or '' end
                    if img == '' then
                        local meta = bedwars.ItemMeta and bedwars.ItemMeta[cand]
                        if meta and meta.image then img = meta.image end
                    end
                end)
            end
        end
        iconCache[id] = img
        return img
    end

    -- returns counts[key] and seen[key] = the concrete itemType actually carried
    -- (so the icon can be resolved from the real item, not a guessed key).
    local function tally(plr)
        local counts, seen = {}, {}
        for _, r in LOOT_RES do counts[r.key] = 0 end
        local inv = plr and store.inventories[plr]
        if inv and type(inv.items) == 'table' then
            for _, v in inv.items do
                if v and v.itemType then
                    local amt = tonumber(v.amount) or 0
                    local key = ITEM_TO_KEY[v.itemType]
                    if not key then
                        for _, r in LOOT_RES do
                            if r.match and v.itemType:sub(1, #r.match) == r.match then key = r.key break end
                        end
                    end
                    if key then
                        counts[key] = counts[key] + amt
                        seen[key] = seen[key] or v.itemType
                    end
                end
            end
        end
        return counts, seen
    end
    local function resShown(key)
        local t = LootShow[key]
        return (t == nil) or t.Enabled
    end

    -- ── Kit class ─────────────────────────────────────────────────────────────
    -- getBedwarsClassMeta(classId).display -> "Movement"/"Fighter"/... . Resolve
    -- the module once and cache class display names so we can filter by class.
    local classMetaFn
    local function getClassMeta()
        if classMetaFn ~= nil then return classMetaFn or nil end
        local ok, mod = pcall(function()
            return require(replicatedStorage.TS.games.bedwars.kit.class['bedwars-class-meta']).getBedwarsClassMeta
        end)
        classMetaFn = (ok and mod) or false
        return classMetaFn or nil
    end
    local classNameCache = {}
    local function classDisplay(classId)
        if classId == nil or classId == 0 then return nil end
        if classNameCache[classId] ~= nil then return classNameCache[classId] or nil end
        local name
        local fn = getClassMeta()
        if fn then
            pcall(function()
                local meta = fn(classId)
                if meta and meta.display then name = tostring(meta.display) end
            end)
        end
        classNameCache[classId] = name or false
        return name
    end
    -- the class name of the kit a player is currently using. The game uses BOTH
    -- 'PlayingAsKits' (plural) and 'PlayingAsKit' depending on version -- check
    -- both (this is why only "Any" worked before: the plural attr was ignored).
    local function playerClassName(plr)
        if not plr then return nil end
        local kit = plr:GetAttribute('PlayingAsKits') or plr:GetAttribute('PlayingAsKit')
        if not kit or kit == 'none' then return nil end
        local meta = bedwars.BedwarsKitMeta and bedwars.BedwarsKitMeta[kit]
        return meta and classDisplay(meta.kitClass)
    end
    -- discover every class display name across all kits (for the dropdown)
    local function allClassNames()
        local set, list = {}, { 'Any' }
        pcall(function()
            for _, meta in pairs(bedwars.BedwarsKitMeta or {}) do
                if type(meta) == 'table' then
                    local n = classDisplay(meta.kitClass)
                    if n and not set[n] then set[n] = true; list[#list + 1] = n end
                end
            end
        end)
        table.sort(list, function(a, b)
            if a == 'Any' then return true end
            if b == 'Any' then return false end
            return a < b
        end)
        return list
    end

    local function isHighlighted(counts)
        if not (Highlight and Highlight.Enabled) then return false end
        for _, r in LOOT_RES do
            -- only resources whose "Show X" toggle is on count toward the highlight
            if resShown(r.key) then
                local s = LootThresholds[r.key]
                if s and (counts[r.key] or 0) >= (s.Value or math.huge) then return true end
            end
        end
        return false
    end

    local Reference = {} -- entity -> BillboardGui
    local Folder = Instance.new('Folder')
    Folder.Parent = vain.gui

    local highlights = {} -- entity -> Highlight instance (threshold glow)
    local function clearGlow(ent)
        local hl = highlights[ent]
        if hl then hl:Destroy() highlights[ent] = nil end
    end
    local function clear(ent)
        local bb = Reference[ent]
        if bb then bb:Destroy() Reference[ent] = nil end
        clearGlow(ent)
    end
    local function clearAll()
        for ent in Reference do clear(ent) end
        for ent in highlights do clearGlow(ent) end
        Folder:ClearAllChildren()
    end

    -- Apply/remove a real Roblox Highlight glow on the character when they cross a
    -- loot threshold (much clearer than tinting numbers).
    local function setGlow(ent, on)
        if on then
            local hl = highlights[ent]
            if not hl or not hl.Parent then
                hl = Instance.new('Highlight')
                hl.Name = 'VainLootGlow'
                hl.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
                hl.FillColor = Color3.fromRGB(255, 70, 70)
                hl.OutlineColor = Color3.fromRGB(255, 70, 70)
                hl.FillTransparency = 0.6
                hl.OutlineTransparency = 0
                hl.Adornee = ent.Character
                hl.Parent = ent.Character
                highlights[ent] = hl
            elseif hl.Adornee ~= ent.Character then
                hl.Adornee = ent.Character
            end
        else
            clearGlow(ent)
        end
    end

    -- (re)build the row for one entity
    local function refresh(ent)
        if not (LootDisplay and LootDisplay.Enabled) then return end
        local plr = ent.Player
        local adornee = ent.Character and (ent.Character.PrimaryPart or ent.Character:FindFirstChild('HumanoidRootPart'))
        if not (plr and adornee) then clear(ent) return end

        -- Hide teammates: only show loot on ENEMIES. isEnemy(ent) uses the same
        -- Targetable flag the rest of the cheat uses to tell enemies from teammates,
        -- so a player on your team (Targetable == false) is skipped when this is on.
        if (not HideTeam or HideTeam.Enabled) and plr ~= lplr and not isEnemy(ent) then
            clear(ent) return
        end

        -- Target Kit Class: when on, only show players whose kit is in the chosen
        -- class ("Any" = no filter). Players whose class is unknown are hidden.
        if TargetClass and TargetClass.Enabled and ClassDropdown and ClassDropdown.Value ~= 'Any' then
            if playerClassName(plr) ~= ClassDropdown.Value then clear(ent) return end
        end

        local counts, seen = tally(plr)

        local bb = Reference[ent]
        if not bb then
            bb = Instance.new('BillboardGui')
            bb.Name = 'LootDisplay'
            bb.AlwaysOnTop = true
            bb.Size = UDim2.fromOffset(640, 40) -- big so it stays legible far away
            -- BELOW the head/nametag. A larger world offset keeps clear separation
            -- from the nametag even at distance.
            bb.StudsOffsetWorldSpace = Vector3.new(0, -3.2, 0)
            bb.ClipsDescendants = false
            -- rounded dark plate so the row reads against any background at range
            local plate = Instance.new('Frame')
            plate.Name = 'Plate'
            plate.AnchorPoint = Vector2.new(0.5, 0.5)
            plate.Position = UDim2.fromScale(0.5, 0.5)
            plate.AutomaticSize = Enum.AutomaticSize.X
            plate.Size = UDim2.fromOffset(0, 38)
            plate.BackgroundColor3 = Color3.fromRGB(12, 12, 16)
            plate.BackgroundTransparency = 0.25
            plate.BorderSizePixel = 0
            local pc = Instance.new('UICorner') pc.CornerRadius = UDim.new(0, 8) pc.Parent = plate
            local ps = Instance.new('UIStroke') ps.Color = Color3.fromRGB(0, 0, 0) ps.Thickness = 2 ps.Transparency = 0.3 ps.Parent = plate
            local pad = Instance.new('UIPadding')
            pad.PaddingLeft = UDim.new(0, 10) pad.PaddingRight = UDim.new(0, 10)
            pad.Parent = plate
            local row = Instance.new('Frame')
            row.Name = 'Row'
            row.BackgroundTransparency = 1
            row.AutomaticSize = Enum.AutomaticSize.X
            row.Size = UDim2.fromOffset(0, 38)
            local layout = Instance.new('UIListLayout')
            layout.FillDirection = Enum.FillDirection.Horizontal
            layout.HorizontalAlignment = Enum.HorizontalAlignment.Center
            layout.VerticalAlignment = Enum.VerticalAlignment.Center
            layout.Padding = UDim.new(0, 10)
            layout.Parent = row
            row.Parent = plate
            plate.Parent = bb
            bb.Parent = Folder
            Reference[ent] = bb
        end
        bb.Adornee = adornee
        -- size multiplier from the slider (100 = base). Scale every element off it.
        local scale = (SizeSlider and SizeSlider.Value or 100) / 100
        local H = math.floor(34 * scale)         -- cell/plate height
        local ICON = math.floor(30 * scale)      -- icon px
        local TXT = math.max(8, math.floor(22 * scale)) -- text px
        bb.Size = UDim2.fromOffset(math.floor(640 * scale), math.floor(40 * scale))
        local plate = bb.Plate
        plate.Size = UDim2.fromOffset(0, H + 4)
        local row = plate.Row
        row.Size = UDim2.fromOffset(0, H + 4)
        for _, c in row:GetChildren() do
            if not c:IsA('UIListLayout') then c:Destroy() end
        end

        -- threshold -> glow the whole character with a real Roblox Highlight
        setGlow(ent, isHighlighted(counts))
        local any = false
        for i, r in LOOT_RES do
            local n = counts[r.key]
            if n > 0 and resShown(r.key) then
                any = true
                local cell = Instance.new('Frame')
                cell.BackgroundTransparency = 1
                cell.AutomaticSize = Enum.AutomaticSize.X
                cell.Size = UDim2.fromOffset(0, H)
                cell.LayoutOrder = i
                local cl = Instance.new('UIListLayout')
                cl.FillDirection = Enum.FillDirection.Horizontal
                cl.VerticalAlignment = Enum.VerticalAlignment.Center
                cl.Padding = UDim.new(0, math.floor(3 * scale))
                cl.Parent = cell
                local icon = Instance.new('ImageLabel')
                icon.BackgroundTransparency = 1
                icon.Size = UDim2.fromOffset(ICON, ICON)
                icon.LayoutOrder = 1
                icon.Image = lootIcon(r, seen[r.key])
                icon.Parent = cell
                local amt = Instance.new('TextLabel')
                amt.BackgroundTransparency = 1
                amt.AutomaticSize = Enum.AutomaticSize.X
                amt.Size = UDim2.fromOffset(0, H)
                amt.LayoutOrder = 2
                amt.Text = tostring(n)
                amt.TextColor3 = Color3.new(1, 1, 1)
                amt.TextStrokeColor3 = Color3.new(0, 0, 0)
                amt.TextStrokeTransparency = 0
                amt.TextSize = TXT
                amt.Font = Enum.Font.GothamBold
                amt.TextXAlignment = Enum.TextXAlignment.Left
                amt.Parent = cell
                cell.Parent = row
            end
        end
        bb.Enabled = any
    end

    LootDisplay = vain.Categories.Render:CreateModule({
        Name = 'Loot Display',
        Tooltip = 'Shows each player\'s carried resources on a large plate under their name (visible from a distance). Toggle which resources appear + highlight when a threshold is crossed.',
        Function = function(callback)
            if callback then
                for _, ent in entitylib.List do refresh(ent) end
                LootDisplay:Clean(entitylib.Events.EntityAdded:Connect(refresh))
                LootDisplay:Clean(entitylib.Events.EntityUpdated:Connect(refresh))
                LootDisplay:Clean(entitylib.Events.EntityRemoved:Connect(clear))
                LootDisplay:Clean(clearAll)
                -- resources change without firing EntityUpdated, so poll inventories
                task.spawn(function()
                    while LootDisplay.Enabled do
                        for _, ent in entitylib.List do
                            if ent.Player and bedwars.getInventory then
                                pcall(function()
                                    store.inventories[ent.Player] = bedwars.getInventory(ent.Player)
                                end)
                                pcall(refresh, ent)
                            end
                        end
                        task.wait(0.5)
                    end
                end)
            else
                clearAll()
            end
        end,
    })
    local function rebuild()
        for _, ent in entitylib.List do pcall(refresh, ent) end
    end
    SizeSlider = LootDisplay:CreateSlider({
        Name = 'Size',
        Tooltip = 'Scale of the loot plate (100 = default).',
        Min = 30, Max = 200, Default = 65, Suffix = '%',
        Function = rebuild,
    })
    HideTeam = LootDisplay:CreateToggle({
        Name = 'Hide Teammates', Default = true,
        Tooltip = 'Only show loot on enemies. Off = also show your own teammates\' loot.',
        Function = rebuild,
    })
    LootShow.iron = LootDisplay:CreateToggle({ Name = 'Show Iron', Default = true, Function = rebuild })
    LootShow.gold = LootDisplay:CreateToggle({ Name = 'Show Gold', Default = true, Function = rebuild })
    LootShow.emerald = LootDisplay:CreateToggle({ Name = 'Show Emeralds', Default = true, Function = rebuild })
    LootShow.diamond = LootDisplay:CreateToggle({ Name = 'Show Diamonds', Default = true, Function = rebuild })
    LootShow.telepearl = LootDisplay:CreateToggle({ Name = 'Show Telepearls', Default = true, Function = rebuild })
    LootShow.vitality = LootDisplay:CreateToggle({ Name = 'Show Vitality Stars', Default = true, Function = rebuild })
    LootShow.crit = LootDisplay:CreateToggle({ Name = 'Show Crit Stars', Default = true, Function = rebuild })
    LootShow.bee = LootDisplay:CreateToggle({ Name = 'Show Bees', Default = true, Function = rebuild })
    LootShow.arrow = LootDisplay:CreateToggle({ Name = 'Show Arrows', Default = true, Function = rebuild })
    LootShow.block = LootDisplay:CreateToggle({ Name = 'Show Blocks', Default = false, Function = rebuild })
    LootShow.tesla = LootDisplay:CreateToggle({ Name = 'Show Teslas', Default = false, Function = rebuild })
    Highlight = LootDisplay:CreateToggle({
        Name = 'Highlight On Threshold',
        Tooltip = 'Glows a player red (character Highlight) once they carry at least the threshold amount of any resource below.',
        Default = false,
        Function = function(callback)
            for _, r in LOOT_RES do
                local s = LootThresholds[r.key]
                if s then s.Object.Visible = callback end
            end
            rebuild()
        end,
    })
    LootThresholds.iron = LootDisplay:CreateSlider({ Name = 'Iron Threshold', Min = 1, Max = 128, Default = 32, Suffix = 'iron', Visible = false })
    LootThresholds.gold = LootDisplay:CreateSlider({ Name = 'Gold Threshold', Min = 1, Max = 128, Default = 16, Suffix = 'gold', Visible = false })
    LootThresholds.emerald = LootDisplay:CreateSlider({ Name = 'Emerald Threshold', Min = 1, Max = 64, Default = 4, Suffix = 'emerald', Visible = false })
    LootThresholds.diamond = LootDisplay:CreateSlider({ Name = 'Diamond Threshold', Min = 1, Max = 64, Default = 5, Suffix = 'diamond', Visible = false })
    LootThresholds.telepearl = LootDisplay:CreateSlider({ Name = 'Telepearl Threshold', Min = 1, Max = 16, Default = 1, Suffix = 'telepearl', Visible = false })
    LootThresholds.vitality = LootDisplay:CreateSlider({ Name = 'Vitality Star Threshold', Min = 1, Max = 16, Default = 1, Suffix = 'star', Visible = false })
    LootThresholds.crit = LootDisplay:CreateSlider({ Name = 'Crit Star Threshold', Min = 1, Max = 16, Default = 1, Suffix = 'star', Visible = false })
    LootThresholds.bee = LootDisplay:CreateSlider({ Name = 'Bee Threshold', Min = 1, Max = 16, Default = 3, Suffix = 'bee', Visible = false })
    LootThresholds.arrow = LootDisplay:CreateSlider({ Name = 'Arrow Threshold', Min = 1, Max = 64, Default = 8, Suffix = 'arrow', Visible = false })
    LootThresholds.block = LootDisplay:CreateSlider({ Name = 'Block Threshold', Min = 1, Max = 128, Default = 32, Suffix = 'block', Visible = false })
    LootThresholds.tesla = LootDisplay:CreateSlider({ Name = 'Tesla Threshold', Min = 1, Max = 8, Default = 1, Suffix = 'tesla', Visible = false })

    -- ── Target Kit Class filter ───────────────────────────────────────────────
    TargetClass = LootDisplay:CreateToggle({
        Name = 'Target Kit Class',
        Tooltip = 'Only show loot for players using a kit of the class picked below.',
        Default = false,
        Function = function(callback)
            if ClassDropdown then ClassDropdown.Object.Visible = callback end
            rebuild()
        end,
    })
    ClassDropdown = LootDisplay:CreateDropdown({
        Name = 'Kit Class',
        List = { 'Any' },
        Default = 'Any',
        Tooltip = 'Which kit class to show loot for.',
        Visible = false,
        Function = rebuild,
    })
    -- populate the class list once the kit meta is available
    task.spawn(function()
        for _ = 1, 20 do
            local names = allClassNames()
            if #names > 1 then
                pcall(function() ClassDropdown:Change(names) end)
                break
            end
            task.wait(1)
        end
    end)
end)

run(function()
    local BulletTracers
    local Material
    local Lifetime
    local Curve
    local Opacity
    local Thickness
    local Color
    local Fade

    local rayCheck = RaycastParams.new()
    rayCheck.FilterType = Enum.RaycastFilterType.Exclude

    BulletTracers = vain.Categories.Render:CreateModule({
    	Name = 'Projectile Tracers',
    	Tooltip = 'Draws tracers on all projectiles in flight',
    	Function = function(callback)
    		if callback then
    			BulletTracers:Clean(workspace.ChildAdded:Connect(function(projectile)
    				task.delay(0, function()
    					rayCheck.FilterDescendantsInstances = {projectile, lplr.Character}
    					if projectile:GetAttribute('ProjectileShooter') ~= lplr.UserId then
    						return
    					end
    					local origin = projectile:GetPivot().Position
    					local velocity = projectile.PrimaryPart and projectile.PrimaryPart.Velocity or Vector3.zero
    					local velocityMagnitude = velocity.Magnitude
    					if velocityMagnitude <= 0 then
    						return
    					end
    					local velocityUnit = velocity / velocityMagnitude
    					local gravity = bedwars.ProjectileMeta[projectile.Name].gravitationalAcceleration
    					local ray = workspace:Raycast(origin, velocityUnit * 2000, rayCheck)
    					local endpoint = ray and ray.Position or (origin + velocityUnit * 2000)
    					local travelTime = (endpoint - origin).Magnitude / velocityMagnitude

    					prediction.SpawnArcTracer(
    						origin,
    						velocityUnit,
    						velocityMagnitude,
    						gravity,
    						travelTime,
    						Curve.Value,
    						{
    							Color = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value),
    							Transparency = Opacity.Value,
    							Thick = Thickness.Value,
    							Material = Enum.Material[Material.Value],
    							Lifetime = Lifetime.Value,
    							Fade = Fade.Enabled,
    						}
    					)
    				end)
    			end))
    		end
    	end,
    	Tooltip = 'Replacement tracers for projectiles'
    })

    local materials = {'SmoothPlastic'}
    for _, v in Enum.Material:GetEnumItems() do
    	if v.Name ~= 'SmoothPlastic' then
    		table.insert(materials, v.Name)
    	end
    end
    Material = BulletTracers:CreateDropdown({
    	Name = 'Material',
    	Tooltip = 'Selects the material used for placed blocks',
    	List = materials
    })
    Color = BulletTracers:CreateColorSlider({
    	Name = 'Tracer Color',
    	DefaultOpacity = 0.5
    })
    Thickness = BulletTracers:CreateSlider({
    	Name = 'Thickness',
    	Tooltip = 'Line thickness for drawn elements',
    	Min = 0.01,
    	Max = 1,
    	Default = 0.1,
    	Decimal = 100
    })
    Curve = BulletTracers:CreateSlider({
    	Name = 'Curveness',
    	Min = 1,
    	Max = 100,
    	Default = 40,
    	Tooltip = 'How curve the projectile is gonna be\n(More curve = more lag)'
    })
    Opacity = BulletTracers:CreateSlider({
    	Name = 'Opacity',
    	Tooltip = 'Opacity of the drawn element',
    	Min = 0,
    	Max = 1,
    	Default = 0,
    	Decimal = 100
    })
    Lifetime = BulletTracers:CreateSlider({
    	Name = 'Lifetime',
    	Tooltip = 'How long in seconds the visual effect persists',
    	Min = 0,
    	Max = 5,
    	Decimal = 100,
    	Default = 2,
    	Suffix = 'secs'
    })
    Fade = BulletTracers:CreateToggle({
    	Name = 'Fade',
    	Tooltip = 'Fades the tracer out over its lifetime',
    	Default = true
    })
end)

run(function()
    local SkinChanger
    local Skin, SkinType
    
    local ModelOffsets = setmetatable({
        bow_default = CFrame.Angles(0, math.rad(90), math.rad(-90)) * CFrame.new(-0.4, 0, 0),
        bow_max = CFrame.Angles(math.rad(-38), math.rad(90), math.rad(-45)) * CFrame.new(1.5, 0, 0),
        bow_headhunter = CFrame.Angles(math.rad(-90), math.rad(-90), 0) * CFrame.new(-2, 1, 0),
        sword = CFrame.Angles(math.rad(-95), math.rad(-90), 0) * CFrame.new(0, 2, 0),
        hammer = CFrame.Angles(math.rad(-90), math.rad(90), 0),
    }, {
        __index = function()
            return CFrame.Angles(math.rad(-90), 0, 0)
        end,
    })
    
    local Names, Saved = {}, {}
    
    local function Added(Item, Parent)
        if not Skin.Value or not Item then
            return
        end
        local Meta = bedwars.ItemMeta[Item.Name]
        if Meta then
            local Type = 'none'
            if Meta.block then
                Type = 'block'
            elseif Meta.projectileSource then
                if Item.Name:find('bow') then
                    Type = `bow_{Item.Name:find('cross') and 'max' or 'default'}`
                elseif Item.Name:find('headhunter') then
                    if Type:find('victorious') then
                        Type = 'bow_headhunter'
                    else
                        Type = 'bow_max'
                    end
                end
            elseif Meta.sword then
                Type = 'sword'
            else
                Type = Item.Name
            end
    
            for _, skin in Names[Skin.Value] do
                if not skin:find(Item.Name) then
                    continue
                end
                if SkinType.Value ~= 'All' and not skin:find(SkinType.Value:lower()) then
                    continue
                end
                local ItemSkin = replicatedStorage.Items:FindFirstChild(skin)
    
                if ItemSkin then
                    local Model = Instance.new('Model', Item)
                    ItemSkin = ItemSkin.Handle:Clone()
                    ItemSkin.Parent = Model
                    table.insert(Saved, Model)
                    SkinChanger:Clean(Model)
                    for _, v in Model:GetDescendants() do
                        pcall(function()
                            v.Anchored = false
                        end)
                        pcall(function()
                            v.CanCollide = false
                        end)
                    end
                    Model:PivotTo(Parent.RightHand.CFrame * ModelOffsets[Type])
    
                    local Weld = Instance.new('WeldConstraint', Model)
                    Weld.Part0 = Parent.RightHand
                    Weld.Part1 = Model.Handle
                    if Item:FindFirstChild('Handle') then
                        Item.Handle:Destroy()
                    end
    
                    Item:SetAttribute('ItemSkin', skin)
                    break
                end
            end
        end
    end
    
    SkinChanger = vain.Categories.Render:CreateModule({
        Name = 'Skin Changer',
        Tooltip = 'Changes ur item skins with others',
        Disabled = not getgenv().canDebug,
        Function = function(callback)
            if callback then
                repeat
                    task.wait()
                until store.map or not SkinChanger.Enabled
                if not SkinChanger.Enabled then return end
                
                SkinChanger:Clean(vainEvents.InventoryHeldChanged.Event:Connect(function(Tool)
                    for _, v in Saved do
                        pcall(function()
                            v:Destroy()
                        end)
                    end
                    if Tool then
                        for _, parent in { lplr.Character, gameCamera.Viewmodel } do
                            local Model = parent:WaitForChild(Tool.Name, 5)
                            if Model then
                                task.delay(0, Added, Model, parent)
                            end
                        end
                    end
                end))
                SkinChanger:Clean(store.map.Blocks.ChildAdded:Connect(function(v)
                    task.defer(function()
                        local Meta = bedwars.ItemMeta[v.Name]
                        if Meta then
                            for _, SkinName in Names[Skin.Value] do
                                if not SkinName:find(v.Name) then
                                    continue
                                end
                                if SkinType.Value ~= 'All' and not SkinName:find(SkinType.Value:lower()) then
                                    continue
                                end
                                local ItemSkin = replicatedStorage.Assets.Blocks:FindFirstChild(SkinName)
                                if ItemSkin then
                                    ItemSkin = ItemSkin:Clone()
                                    ItemSkin.Parent = workspace
                                    local OldTransparencies = {}
                                    for _, v2 in v:QueryDescendants('BasePart') do
                                        OldTransparencies[v2] = v2.Transparency
                                        v2.Transparency = 1
                                    end
                                    task.spawn(pcall, function()
                                        v:WaitForChild('TeamLight', 5):Destroy()
                                    end)
    
                                    for _, v2 in ItemSkin:GetDescendants() do
                                        pcall(function()
                                            v2.CanCollide = false
                                            v2.CanQuery = false
                                            v2.CanTouch = false
                                        end)
                                    end
    
                                    v:SetAttribute('ItemSkin', SkinName)
    
                                    local Base = v:FindFirstChild('Barrel') or v:FindFirstChild('Bottom') or v
    
                                    local Connection = runService.PreRender:Connect(function()
                                        if not Base or not Base.Parent then
                                            return
                                        end
                                        ItemSkin:PivotTo(Base.CFrame)
                                    end)
    
                                    local callback = function()
                                        if v and v.Parent then
                                            for i, v in OldTransparencies do
                                                i.Transparency = v
                                            end
                                        end
                                    end
                                    SkinChanger:Clean(ItemSkin)
                                    SkinChanger:Clean(Connection)
                                    SkinChanger:Clean(callback)
                                    v.Destroying:Once(function()
                                        if Connection then
                                            Connection:Disconnect()
                                        end
                                        if ItemSkin and ItemSkin.Parent then
                                            ItemSkin:Destroy()
                                        end
                                    end)
                                end
                            end
                        end
                    end)
                end))
            end
        end,
    })
    
    local list = {}
    for _, v in bedwars.BedwarsKitSkin do
        if v.itemSkins then
            if Names[v.name] then
                for _, v2 in v.itemSkins do
                    table.insert(Names[v.name], v2)
                end
            else
                table.insert(list, v.name)
                Names[v.name] = v.itemSkins
            end
        end
    end
    table.sort(list, function(a, b)
        return a < b
    end)
    Skin = SkinChanger:CreateDropdown({
        Name = 'Item Skin',
        Tooltip = 'Selects the cosmetic skin for this item',
        List = list,
    })
    SkinType = SkinChanger:CreateDropdown({
        Name = 'Skin Type',
        Tooltip = 'Selects the skin category',
        List = { 'All', 'Gold', 'Platinum', 'Diamond', 'Emerald', 'Nightmare', 'Void' },
        Default = 'All',
        ItemTooltips = {
            All = 'Show all available skins regardless of tier',
            Gold = 'Show only Gold-tier skins',
            Platinum = 'Show only Platinum-tier skins',
            Diamond = 'Show only Diamond-tier skins',
            Emerald = 'Show only Emerald-tier skins',
            Nightmare = 'Show only Nightmare-tier skins',
            Void = 'Show only Void-tier skins',
        },
    })
end)

run(function()
    local StorageESP
    local List
    local Background
    local Color
    local ShowAmount
    local ShowAll
    local ShowOwnTeam
    local ResourceAlert, DetectOwnTeam, EmeraldThreshold, DiamondThreshold
    local Reference = {}
    local Connections = {}
    local alertState = {} -- adornee -> { emerald = bool, diamond = bool } (debounce)
    local Folder = Instance.new('Folder')
    Folder.Parent = vain.gui

    -- Nearest team-spawn id for a WORLD POSITION. workspace.MapCFrames holds a
    -- '<id>_spawn' part per team. Returns the id as a string, or nil.
    -- NOTE: we deliberately do NOT try to match this against the store's team id or
    -- the player's Team attribute -- those live in a DIFFERENT namespace (the store
    -- team id can be an arbitrary string like "4", while spawns are named "1"/"2"),
    -- so they never line up. Instead we compare a chest's nearest spawn to OUR OWN
    -- character's nearest spawn (same primitive), which is namespace-proof.
    local function nearestSpawnId(pos)
        if not pos then return nil end
        local mapcf = workspace:FindFirstChild('MapCFrames')
        if not mapcf then return nil end
        local best, bestDist
        for _, spawnpart in mapcf:GetChildren() do
            local id = spawnpart.Name:match('^(%w+)_spawn$')
            if id then
                local sok, spos = pcall(function()
                    return (spawnpart:IsA('BasePart') and spawnpart.Position) or spawnpart.Value.Position
                end)
                if sok and spos then
                    local d = (spos - pos).Magnitude
                    if not bestDist or d < bestDist then
                        bestDist = d
                        best = tostring(id)
                    end
                end
            end
        end
        return best
    end

    local function chestTeam(adornee)
        local ok, pos = pcall(function() return adornee:GetPivot().Position end)
        if not ok then return nil end
        return nearestSpawnId(pos)
    end

    -- MY team's spawn id = the spawn nearest to my own character (or my bed as a
    -- fallback when I'm dead / not spawned). Cached briefly since it never changes
    -- mid-match. This is compared against a chest's nearestSpawnId -> same namespace.
    local myTeamCache, myTeamCacheAt = nil, 0
    local function myTeamId()
        if myTeamCache ~= nil and (tick() - myTeamCacheAt) < 5 then return myTeamCache end
        local pos
        local char = lplr.Character
        local hrp = char and char:FindFirstChild('HumanoidRootPart')
        if hrp then pos = hrp.Position end
        local id = pos and nearestSpawnId(pos) or nil
        if id then myTeamCache, myTeamCacheAt = id, tick() end
        return id
    end

    -- Is this chest on MY team? Compare the chest's nearest spawn to mine.
    local function isOwnTeam(chestSpawnId)
        if chestSpawnId == nil then return false end
        local mine = myTeamId()
        if mine == nil then return false end
        return tostring(chestSpawnId) == tostring(mine)
    end

    -- Describe a chest's team for the alert: "your team" if it's yours, otherwise
    -- the team's colour name (e.g. "the Blue team") rather than a numeric id.
    local function teamDescriptor(teamId)
        if teamId == nil then return 'a team chest' end
        if isOwnTeam(teamId) then return 'YOUR team\'s chest' end
        local name
        pcall(function()
            local teams = bedwars.Store:getState().Game.teams
            if type(teams) == 'table' then
                for _, t in teams do
                    if t.id == teamId then name = t.name and tostring(t.name); break end
                end
            end
        end)
        if name then return 'the ' .. name .. ' team\'s chest' end
        return 'a team chest'
    end

    -- Fire a one-shot notification when a chest's emerald/diamond count first
    -- crosses its threshold. Skips your own team unless Detect Own Team is on.
    local function checkResourceAlert(adornee, counts)
        if not (ResourceAlert and ResourceAlert.Enabled and adornee) then return end
        local team = chestTeam(adornee)
        if team ~= nil and not (DetectOwnTeam and DetectOwnTeam.Enabled) then
            if isOwnTeam(team) then return end
        end
        local st = alertState[adornee]
        if not st then st = {}; alertState[adornee] = st end
        local function one(res, threshold)
            local n = counts[res] or 0
            local thr = threshold and threshold.Value or math.huge
            local over = n >= thr
            -- Fire when the count first crosses the threshold, and again whenever it
            -- climbs to a NEW high while still over (so a growing stockpile keeps you
            -- informed). st[res] stores the last-notified amount; reset when it drops
            -- back under the threshold so a fresh crossing alerts again.
            local last = st[res] or 0
            if over and n > last then
                st[res] = n
                notif('Storage ESP', ('%d %s in %s'):format(n, res, teamDescriptor(team)), 8, 'warning')
            elseif not over then
                st[res] = 0 -- back under threshold -> re-arm
            end
        end
        one('emerald', EmeraldThreshold)
        one('diamond', DiamondThreshold)
    end

    local function nearStorageItem(item)
    	for _, v in List.ListEnabled do
    		if item:find(v) then
    			return v
    		end
    	end
    	return nil
    end

    local function refreshAdornee(v)
    	local chest = v.Adornee:FindFirstChild('ChestFolderValue')
    	chest = chest and chest.Value or nil
    	if not chest then
    		v.Enabled = false
    		return
    	end

    	-- Only show loot on ENEMY chests. Your own team's chest is hidden unless
    	-- "Show Own Team" is on. (Same team-id-vs-attribute string fix as the alert:
    	-- chestTeam is a number, the Team attribute is a string.)
    	if not (ShowOwnTeam and ShowOwnTeam.Enabled) and isOwnTeam(chestTeam(v.Adornee)) then
    		v.Enabled = false
    		return
    	end

    	local chestitems = chest and chest:GetChildren() or {}
    	for _, obj in v.Frame:GetChildren() do
    		if obj:IsA('ImageLabel') and obj.Name ~= 'Blur' then
    			obj:Destroy()
    		end
    	end

    	v.Enabled = false
    	-- Tally the TOTAL quantity of each matching item type in the chest (sum of
    	-- each stack's Amount attribute, defaulting to 1), so we can show how MUCH
    	-- loot is stored, not just that a type is present.
    	local counts = {}
    	local order = {}
    	-- Separately tally emerald/diamond for the resource alert, independent of the
    	-- display filter (the alert must work even if those aren't shown).
    	local resCounts = { emerald = 0, diamond = 0 }
    	for _, item in chestitems do
    		if resCounts[item.Name] ~= nil then
    			resCounts[item.Name] = resCounts[item.Name] + (tonumber(item:GetAttribute('Amount')) or 1)
    		end
    		-- Always surface emerald/diamond on the billboard while Resource Alert is
    		-- on, so you can watch the amount live even if they aren't whitelisted.
    		local alertRes = (ResourceAlert and ResourceAlert.Enabled)
    			and (item.Name == 'emerald' or item.Name == 'diamond')
    		if alertRes or (ShowAll and ShowAll.Enabled) or table.find(List.ListEnabled, item.Name) or nearStorageItem(item.Name) then
    			if counts[item.Name] == nil then order[#order + 1] = item.Name end
    			local amt = tonumber(item:GetAttribute('Amount')) or 1
    			counts[item.Name] = (counts[item.Name] or 0) + amt
    		end
    	end
    	-- run the alert non-fatally AFTER the display so a failure here can never
    	-- block the count from refreshing
    	pcall(checkResourceAlert, v.Adornee, resCounts)
    	for _, name in order do
    		v.Enabled = true
    		local blockimage = Instance.new('ImageLabel')
    		blockimage.Size = UDim2.fromOffset(32, 32)
    		blockimage.BackgroundTransparency = 1
    		blockimage.Image = bedwars.getIcon({ itemType = name }, true)
    		blockimage.Parent = v.Frame
    		local total = counts[name]
    		if total > 1 and (not ShowAmount or ShowAmount.Enabled) then
    			local amounttext = Instance.new('TextLabel')
    			amounttext.Name = 'Amount'
    			amounttext.Size = UDim2.fromScale(1, 1)
    			amounttext.BackgroundTransparency = 1
    			amounttext.Text = tostring(total)
    			amounttext.TextColor3 = Color3.new(1, 1, 1)
    			amounttext.TextSize = 16
    			amounttext.TextStrokeTransparency = 0.3
    			amounttext.Font = Enum.Font.Arial
    			amounttext.Parent = blockimage
    		end
    	end
    	table.clear(chestitems)
    end

    local function Removing(v)
    	alertState[v] = nil
    	local billboard = Reference[v]
    	if billboard then
    		billboard:Destroy()
    		Reference[v] = nil
    	end

    	local connections = Connections[v]
    	if connections then
    		for _, connection in connections do
    			connection:Disconnect()
    		end
    		table.clear(connections)
    		Connections[v] = nil
    	end
    end

    local function Clear()
    	local references = table.clone(Reference)
    	for v in references do
    		Removing(v)
    	end
    	table.clear(references)
    	Folder:ClearAllChildren()
    end

    local function Added(v)
    	local chest = v:WaitForChild('ChestFolderValue', 3)
    	if not (chest and StorageESP.Enabled and v:HasTag('chest')) then
    		return
    	end
    	if Reference[v] then
    		Removing(v)
    	end
    	chest = chest.Value
    	if not chest then
    		return
    	end
    	local billboard = Instance.new('BillboardGui')
    	billboard.Parent = Folder
    	billboard.Name = 'chest'
    	billboard.StudsOffsetWorldSpace = Vector3.new(0, 3, 0)
    	billboard.Size = UDim2.fromOffset(36, 36)
    	billboard.AlwaysOnTop = true
    	billboard.ClipsDescendants = false
    	billboard.Adornee = v
    	local blur = addBlur(billboard)
    	blur.Visible = Background.Enabled
    	local frame = Instance.new('Frame')
    	frame.Size = UDim2.fromScale(1, 1)
    	frame.BackgroundColor3 = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
    	frame.BackgroundTransparency = 1 - (Background.Enabled and Color.Opacity or 0)
    	frame.Parent = billboard
    	local layout = Instance.new('UIListLayout')
    	layout.FillDirection = Enum.FillDirection.Horizontal
    	layout.Padding = UDim.new(0, 4)
    	layout.VerticalAlignment = Enum.VerticalAlignment.Center
    	layout.HorizontalAlignment = Enum.HorizontalAlignment.Center
    	local layoutConnection = layout:GetPropertyChangedSignal('AbsoluteContentSize'):Connect(function()
    		billboard.Size = UDim2.fromOffset(math.max(layout.AbsoluteContentSize.X + 4, 36), 36)
    	end)
    	layout.Parent = frame
    	local corner = Instance.new('UICorner')
    	corner.CornerRadius = UDim.new(0, 4)
    	corner.Parent = frame
    	Reference[v] = billboard
    	Connections[v] = {
    		layoutConnection,
    		chest.ChildAdded:Connect(function(item)
    			-- also refresh for emerald/diamond so the resource alert stays live
    			-- even when those aren't in the display filter
    			local isRes = item.Name == 'emerald' or item.Name == 'diamond'
    			if isRes or (ShowAll and ShowAll.Enabled) or table.find(List.ListEnabled, item.Name) or nearStorageItem(item.Name) then
    				refreshAdornee(billboard)
    			end
    		end),
    		chest.ChildRemoved:Connect(function(item)
    			local isRes = item.Name == 'emerald' or item.Name == 'diamond'
    			if isRes or (ShowAll and ShowAll.Enabled) or table.find(List.ListEnabled, item.Name) or nearStorageItem(item.Name) then
    				refreshAdornee(billboard)
    			end
    		end),
    	}
    	task.spawn(refreshAdornee, billboard)
    end

    StorageESP = vain.Categories.Render:CreateModule({
    	Name = 'Storage ESP',
    	Tooltip = 'Enables the Storage ESP module',
    	Function = function(callback)
    		if callback then
    			StorageESP:Clean(collectionService:GetInstanceAddedSignal('chest'):Connect(Added))
    			StorageESP:Clean(collectionService:GetInstanceRemovedSignal('chest'):Connect(Removing))
    			StorageESP:Clean(Clear)
    			for _, v in collectionService:GetTagged('chest') do
    				task.spawn(Added, v)
    			end
    			-- Chest contents also change via an item's Amount ATTRIBUTE (not just
    			-- child add/remove), which fires no ChildAdded/Removed -> the display
    			-- and the resource alert would lag. Poll every chest on a short timer
    			-- so counts stay fresh.
    			task.spawn(function()
    				while StorageESP.Enabled do
    					for _, billboard in Reference do
    						task.spawn(refreshAdornee, billboard)
    					end
    					task.wait(0.4)
    				end
    			end)
    		else
    			Clear()
    		end
    	end,
    	Tooltip = 'Displays items in chests'
    })
    List = StorageESP:CreateTextList({
    	Name = 'Item',
    	Tooltip = 'Items to search for inside storage chests (one per line)',
    	Function = function()
    		for _, v in Reference do
    			task.spawn(refreshAdornee, v)
    		end
    	end,
    })
    Background = StorageESP:CreateToggle({
    	Name = 'Background',
    	Tooltip = 'Renders a background box behind this ESP element',
    	Function = function(callback)
    		if Color and Color.Object then
    			Color.Object.Visible = callback
    		end
    		for _, v in Reference do
    			v.Frame.BackgroundTransparency = 1 - (callback and Color.Opacity or 0)
    			v.Blur.Visible = callback
    		end
    	end,
    	Default = true,
    })
    Color = StorageESP:CreateColorSlider({
    	Name = 'Background Color',
    	DefaultValue = 0,
    	DefaultOpacity = 0.5,
    	Function = function(hue, sat, val, opacity)
    		for _, v in Reference do
    			v.Frame.BackgroundColor3 = Color3.fromHSV(hue, sat, val)
    			v.Frame.BackgroundTransparency = 1 - opacity
    		end
    	end,
    	Darker = true,
    })
    ShowAmount = StorageESP:CreateToggle({
    	Name = 'Show Amount',
    	Tooltip = 'Show the total quantity of each stored item on its icon (not just that it is present)',
    	Default = true,
    	Function = function()
    		for _, v in Reference do
    			task.spawn(refreshAdornee, v)
    		end
    	end,
    })
    ShowAll = StorageESP:CreateToggle({
    	Name = 'Show All Items',
    	Tooltip = 'Show EVERY item stored in the chest, ignoring the item whitelist above',
    	Default = false,
    	Function = function()
    		for _, v in Reference do
    			task.spawn(refreshAdornee, v)
    		end
    	end,
    })
    ShowOwnTeam = StorageESP:CreateToggle({
    	Name = 'Show Own Team',
    	Tooltip = "Also show loot on your OWN team's chest. Off (default) = enemy chests only.",
    	Default = false,
    	Function = function()
    		for _, v in Reference do
    			task.spawn(refreshAdornee, v)
    		end
    	end,
    })
    ResourceAlert = StorageESP:CreateToggle({
    	Name = 'Resource Alert',
    	Tooltip = 'Notifies you when a team chest holds at least the threshold amount of emeralds or diamonds.',
    	Default = false,
    	Function = function(callback)
    		DetectOwnTeam.Object.Visible = callback
    		EmeraldThreshold.Object.Visible = callback
    		DiamondThreshold.Object.Visible = callback
    		if not callback then table.clear(alertState) end
    		-- re-scan existing chests so an already-full chest alerts immediately
    		if callback then
    			for _, v in Reference do task.spawn(refreshAdornee, v) end
    		end
    	end,
    })
    DetectOwnTeam = StorageESP:CreateToggle({
    	Name = 'Detect Own Team',
    	Tooltip = 'Also alert for your OWN team\'s chest (off = only enemy team chests).',
    	Default = false,
    	Visible = false,
    })
    EmeraldThreshold = StorageESP:CreateSlider({
    	Name = 'Emerald Alert', Min = 1, Max = 64, Default = 5, Suffix = 'emerald', Visible = false,
    })
    DiamondThreshold = StorageESP:CreateSlider({
    	Name = 'Diamond Alert', Min = 1, Max = 64, Default = 5, Suffix = 'diamond', Visible = false,
    })
end)

