run(function()
    local AntiSuffocate
    
    AntiSuffocate = vain.Categories.Utility:CreateModule({
    	Name = 'Anti Suffocate',
    	Tooltip = 'Prevents suffocation damage inside blocks',
    	Function = function(call)
    		if call then
    			repeat
    				if entitylib.isAlive then
    					if
    						getPlacedBlock(entitylib.character.RootPart.Position)
    						and (
    							getPlacedBlock(entitylib.character.RootPart.Position + Vector3.new(0, 2, 0))
    							and getPlacedBlock(entitylib.character.RootPart.Position - Vector3.new(0, 2, 0))
    						)
    					then
    						entitylib.character.RootPart.CFrame += Vector3.new(0, 0.5, 0)
    						if entitylib.character.RootPart.AssemblyLinearVelocity.Y < -1 then
    							entitylib.character.RootPart.AssemblyLinearVelocity = Vector3.zero
    						end
    					end
    				end
    				task.wait()
    			until not AntiSuffocate.Enabled
    		end
    	end,
    	Tooltip = 'Prevents you from suffocating in blocks',
    })
end)

run(function()
    local AutoBalloon
    
    AutoBalloon = vain.Categories.Utility:CreateModule({
        Name = 'Auto Balloon',
        Tooltip = 'Automatically deploys balloons when in range',
        Function = function(callback)
            if callback then
                repeat task.wait() until store.matchState ~= 0 or (not AutoBalloon.Enabled)
                if not AutoBalloon.Enabled then return end
    
                local lowestpoint = math.huge
                for _, v in store.blocks do
                    local point = (v.Position.Y - (v.Size.Y / 2)) - 50
                    if point < lowestpoint then 
                        lowestpoint = point 
                    end
                end
    
                repeat
                    if entitylib.isAlive then
                        if entitylib.character.RootPart.Position.Y < lowestpoint and (lplr.Character:GetAttribute('InflatedBalloons') or 0) < 3 then
                            local balloon = getItem('balloon')
                            if balloon then
                                for _ = 1, 3 do 
                                    bedwars.BalloonController:inflateBalloon() 
                                end
                            end
                            task.wait(0.1)
                        end
                    end
                    task.wait(0.1)
                until not AutoBalloon.Enabled
            end
        end,
        Tooltip = 'Inflates when you fall into the void'
    })
end)

run(function()
    local AutoKit
    local Legit
    local Toggles = {}
    
    local function kitCollection(id, func, range, specific)
        local objs = type(id) == 'table' and id or collection(id, AutoKit)
        repeat
            if entitylib.isAlive then
                local localPosition = entitylib.character.RootPart.Position
                for _, v in objs do
                    if InfiniteFly.Enabled or not AutoKit.Enabled then break end
                    local part = not v:IsA('Model') and v or v.PrimaryPart
                    if part and (part.Position - localPosition).Magnitude <= (not Legit.Enabled and specific and math.huge or range) then
                        func(v)
                    end
                end
            end
            task.wait(0.1)
        until not AutoKit.Enabled
    end
    
    local AutoKitFunctions = {
        battery = function()
            repeat
                if entitylib.isAlive then
                    local localPosition = entitylib.character.RootPart.Position
                    for i, v in bedwars.BatteryEffectsController.liveBatteries do
                        if (v.position - localPosition).Magnitude <= 10 then
                            local BatteryInfo = bedwars.BatteryEffectsController:getBatteryInfo(i)
                            if not BatteryInfo or BatteryInfo.activateTime >= workspace:GetServerTimeNow() or BatteryInfo.consumeTime + 0.1 >= workspace:GetServerTimeNow() then continue end
                            BatteryInfo.consumeTime = workspace:GetServerTimeNow()
                            bedwars.Client:Get(remotes.ConsumeBattery):SendToServer({batteryId = i})
                        end
                    end
                end
                task.wait(0.1)
            until not AutoKit.Enabled
        end,
        beekeeper = function()
            kitCollection('bee', function(v)
                bedwars.Client:Get(remotes.BeePickup):SendToServer({beeId = v:GetAttribute('BeeId')})
            end, 18, false)
        end,
        bigman = function()
            kitCollection('treeOrb', function(v)
                if bedwars.Client:Get(remotes.ConsumeTreeOrb):CallServer({treeOrbSecret = v:GetAttribute('TreeOrbSecret')}) then
                    v:Destroy()
                end
            end, 12, false)
        end,
        block_kicker = function()
            local old = bedwars.BlockKickerKitController.getKickBlockProjectileOriginPosition
            bedwars.BlockKickerKitController.getKickBlockProjectileOriginPosition = function(...)
                local origin, dir = select(2, ...)
                local plr = entitylib.EntityMouse({
                    Part = 'RootPart',
                    Range = 1000,
                    Origin = origin,
                    Players = true,
                    Wallcheck = true
                })
    
                if plr then
                    local calc = prediction.SolveTrajectory(origin, 100, 20, plr.RootPart.Position, plr.RootPart.Velocity, workspace.Gravity, plr.HipHeight, plr.Jumping and 42.6 or nil)
    
                    if calc then
                        for i, v in debug.getstack(2) do
                            if v == dir then
                                debug.setstack(2, i, CFrame.lookAt(origin, calc).LookVector)
                            end
                        end
                    end
                end
    
                return old(...)
            end
    
            AutoKit:Clean(function()
                bedwars.BlockKickerKitController.getKickBlockProjectileOriginPosition = old
            end)
        end,
        cat = function()
            local old = bedwars.CatController.leap
            bedwars.CatController.leap = function(...)
                vainEvents.CatPounce:Fire()
                return old(...)
            end
    
            AutoKit:Clean(function()
                bedwars.CatController.leap = old
            end)
        end,
        davey = function()
            local old = bedwars.CannonHandController.launchSelf
            bedwars.CannonHandController.launchSelf = function(...)
                local res = {old(...)}
                local self, block = ...
    
                if block:GetAttribute('PlacedByUserId') == lplr.UserId and (block.Position - entitylib.character.RootPart.Position).Magnitude < 30 then
                    task.spawn(bedwars.breakBlock, block, false, nil, true)
                end
    
                return unpack(res)
            end
    
            AutoKit:Clean(function()
                bedwars.CannonHandController.launchSelf = old
            end)
        end,
        dragon_slayer = function()
            kitCollection('KaliyahPunchInteraction', function(v)
                bedwars.DragonSlayerController:deleteEmblem(v)
                bedwars.DragonSlayerController:playPunchAnimation(Vector3.zero)
                bedwars.Client:Get(remotes.KaliyahPunch):SendToServer({
                    target = v
                })
            end, 18, true)
        end,
        farmer_cletus = function()
            kitCollection('HarvestableCrop', function(v)
                if bedwars.Client:Get(remotes.HarvestCrop):CallServer({position = bedwars.BlockController:getBlockPosition(v.Position)}) then
                    bedwars.GameAnimationUtil:playAnimation(lplr.Character, bedwars.AnimationType.PUNCH)
                    bedwars.SoundManager:playSound(bedwars.SoundList.CROP_HARVEST)
                end
            end, 10, false)
        end,
        fisherman = function()
            local old = bedwars.FishingMinigameController.startMinigame
            bedwars.FishingMinigameController.startMinigame = function(_, _, result)
                result({win = true})
            end
    
            AutoKit:Clean(function()
                bedwars.FishingMinigameController.startMinigame = old
            end)
        end,
        gingerbread_man = function()
            local old = bedwars.LaunchPadController.attemptLaunch
            bedwars.LaunchPadController.attemptLaunch = function(...)
                local res = {old(...)}
                local self, block = ...
    
                if (workspace:GetServerTimeNow() - self.lastLaunch) < 0.4 then
                    if block:GetAttribute('PlacedByUserId') == lplr.UserId and (block.Position - entitylib.character.RootPart.Position).Magnitude < 30 then
                        task.spawn(bedwars.breakBlock, block, false, nil, true)
                    end
                end
    
                return unpack(res)
            end
    
            AutoKit:Clean(function()
                bedwars.LaunchPadController.attemptLaunch = old
            end)
        end,
        hannah = function()
            kitCollection('HannahExecuteInteraction', function(v)
                local billboard = bedwars.Client:Get(remotes.HannahKill):CallServer({
                    user = lplr,
                    victimEntity = v
                }) and v:FindFirstChild('Hannah Execution Icon')
    
                if billboard then
                    billboard:Destroy()
                end
            end, 30, true)
        end,
        jailor = function()
            kitCollection('jailor_soul', function(v)
                bedwars.JailorController:collectEntity(lplr, v, 'JailorSoul')
            end, 20, false)
        end,
        grim_reaper = function()
            kitCollection(bedwars.GrimReaperController.soulsByPosition, function(v)
                if entitylib.isAlive and lplr.Character:GetAttribute('Health') <= (lplr.Character:GetAttribute('MaxHealth') / 4) and (not lplr.Character:GetAttribute('GrimReaperChannel')) then
                    bedwars.Client:Get(remotes.ConsumeSoul):CallServer({
                        secret = v:GetAttribute('GrimReaperSoulSecret')
                    })
                end
            end, 120, false)
        end,
        melody = function()
            repeat
                local mag, hp, ent = 30, math.huge
                if entitylib.isAlive then
                    local localPosition = entitylib.character.RootPart.Position
                    for _, v in entitylib.List do
                        if v.Player and v.Player:GetAttribute('Team') == lplr:GetAttribute('Team') then
                            local newmag = (localPosition - v.RootPart.Position).Magnitude
                            if newmag <= mag and v.Health < hp and v.Health < v.MaxHealth then
                                mag, hp, ent = newmag, v.Health, v
                            end
                        end
                    end
                end
    
                if ent and getItem('guitar') then
                    bedwars.Client:Get(remotes.GuitarHeal):SendToServer({
                        healTarget = ent.Character
                    })
                end
    
                task.wait(0.1)
            until not AutoKit.Enabled
        end,
        metal_detector = function()
            kitCollection('hidden-metal', function(v)
                bedwars.Client:Get(remotes.PickupMetal):SendToServer({
                    id = v:GetAttribute('Id')
                })
            end, 20, false)
        end,
        miner = function()
            kitCollection('petrified-player', function(v)
                bedwars.Client:Get(remotes.MinerDig):SendToServer({
                    petrifyId = v:GetAttribute('PetrifyId')
                })
            end, 6, true)
        end,
        pinata = function()
            kitCollection(lplr.Name..':pinata', function(v)
                if getItem('candy') then
                    bedwars.Client:Get(remotes.DepositPinata):CallServer(v)
                end
            end, 6, true)
        end,
        spirit_assassin = function()
            kitCollection('EvelynnSoul', function(v)
                bedwars.SpiritAssassinController:useSpirit(lplr, v)
            end, 120, true)
        end,
        star_collector = function()
            kitCollection('stars', function(v)
                bedwars.StarCollectorController:collectEntity(lplr, v, v.Name)
            end, 20, false)
        end,
        summoner = function()
            repeat
                local plr = entitylib.EntityPosition({
                    Range = 31,
                    Part = 'RootPart',
                    Players = true,
                    Sort = sortmethods.Health
                })
    
                if plr and (not Legit.Enabled or (lplr.Character:GetAttribute('Health') or 0) > 0) then
                    local localPosition = entitylib.character.RootPart.Position
                    local shootDir = CFrame.lookAt(localPosition, plr.RootPart.Position).LookVector
                    localPosition += shootDir * math.max((localPosition - plr.RootPart.Position).Magnitude - 16, 0)
    
                    bedwars.Client:Get(remotes.SummonerClawAttack):SendToServer({
                        position = localPosition,
                        direction = shootDir,
                        clientTime = workspace:GetServerTimeNow()
                    })
                end
    
                task.wait(0.1)
            until not AutoKit.Enabled
        end,
        void_dragon = function()
            local oldflap = bedwars.VoidDragonController.flapWings
            local flapped
    
            bedwars.VoidDragonController.flapWings = function(self)
                if not flapped and bedwars.Client:Get(remotes.DragonFly):CallServer() then
                    local modifier = bedwars.SprintController:getMovementStatusModifier():addModifier({
                        blockSprint = true,
                        constantSpeedMultiplier = 2
                    })
                    self.SpeedMaid:GiveTask(modifier)
                    self.SpeedMaid:GiveTask(function()
                        flapped = false
                    end)
                    flapped = true
                end
            end
    
            AutoKit:Clean(function()
                bedwars.VoidDragonController.flapWings = oldflap
            end)
    
            repeat
                if bedwars.VoidDragonController.inDragonForm then
                    local plr = entitylib.EntityPosition({
                        Range = 30,
                        Part = 'RootPart',
                        Players = true
                    })
    
                    if plr then
                        bedwars.Client:Get(remotes.DragonBreath):SendToServer({
                            player = lplr,
                            targetPoint = plr.RootPart.Position
                        })
                    end
                end
                task.wait(0.1)
            until not AutoKit.Enabled
        end,
        warlock = function()
            local lastTarget
            repeat
                if store.hand.tool and store.hand.tool.Name == 'warlock_staff' then
                    local plr = entitylib.EntityPosition({
                        Range = 30,
                        Part = 'RootPart',
                        Players = true,
                        NPCs = true
                    })
    
                    if plr and plr.Character ~= lastTarget then
                        if not bedwars.Client:Get(remotes.WarlockTarget):CallServer({
                            target = plr.Character
                        }) then
                            plr = nil
                        end
                    end
    
                    lastTarget = plr and plr.Character
                else
                    lastTarget = nil
                end
    
                task.wait(0.1)
            until not AutoKit.Enabled
        end,
        wizard = function()
            repeat
                local ability = lplr:GetAttribute('WizardAbility')
                if ability and bedwars.AbilityController:canUseAbility(ability) then
                    local plr = entitylib.EntityPosition({
                        Range = 50,
                        Part = 'RootPart',
                        Players = true,
                        Sort = sortmethods.Health
                    })
    
                    if plr then
                        bedwars.AbilityController:useAbility(ability, newproxy(true), {target = plr.RootPart.Position})
                    end
                end
    
                task.wait(0.1)
            until not AutoKit.Enabled
        end
    }
    
    AutoKit = vain.Categories.Utility:CreateModule({
        Name = 'Auto Kit',
        Tooltip = 'Enables the Auto Kit module',
        Function = function(callback)
            if callback then
                repeat task.wait() until store.equippedKit ~= '' and store.matchState ~= 0 or (not AutoKit.Enabled)
                if AutoKit.Enabled and AutoKitFunctions[store.equippedKit] and Toggles[store.equippedKit].Enabled then
                    AutoKitFunctions[store.equippedKit]()
                end
            end
        end,
        Tooltip = 'Automatically uses kit abilities.'
    })
    Legit = AutoKit:CreateToggle({Name = 'Legit Range', Tooltip = 'Restricts range to a value indistinguishable from vanilla'})
    local sortTable = {}
    for i in AutoKitFunctions do
        table.insert(sortTable, i)
    end
    table.sort(sortTable, function(a, b)
        return bedwars.BedwarsKitMeta[a].name < bedwars.BedwarsKitMeta[b].name
    end)
    for _, v in sortTable do
        Toggles[v] = AutoKit:CreateToggle({
        	Tooltip = "Automatically activates this kit's ability when the kit is equipped",
            Name = bedwars.BedwarsKitMeta[v].name,
            Default = true
        })
    end
end)

run(function()
    local AutoLasso
    local Targets
    local Range
    local FOV
    local AimPart
    local PredictionMode
    local projectileRemote = {InvokeServer = function() end}
    local nextAllowedShot = 0
    local rayCheck = RaycastParams.new()
    local COOLDOWN_SECONDS = 10.5

    task.spawn(function()
        projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
    end)

    local function getLassoSlot()
        for i, v in store.inventory.hotbar do
            if v.item and v.item.itemType == "lasso" then
                return i - 1, v.item
            end
        end
        return nil, nil
    end

    local function getLassoProjectileMeta()
        local meta = bedwars.ProjectileMeta and bedwars.ProjectileMeta["lasso"]
        if meta then
            return meta.launchVelocity or 100, meta.gravitationalAcceleration or 196.2
        end
        return 100, 196.2
    end

    local function shootLasso(targetEnt)
        if not targetEnt or not targetEnt.RootPart then return false end

        local now = tick()
        if now < nextAllowedShot then return false end

        local lassoSlot, lassoItem = getLassoSlot()
        if not lassoSlot or not lassoItem then return false end

        local selfpos = entitylib.character.RootPart.Position
        local targetPart = targetEnt.RootPart

        if AimPart.Value == "Head" and targetEnt.Head then
            targetPart = targetEnt.Head
        elseif AimPart.Value == "Torso" then
            local torso = targetEnt.Character:FindFirstChild("UpperTorso") or targetEnt.Character:FindFirstChild("Torso")
            if torso then targetPart = torso end
        end

        local projSpeed, gravity = getLassoProjectileMeta()
        local targetPos = targetPart.Position
        local targetVel = targetPart.Velocity

        local aimPos = targetPos
        if PredictionMode.Value == "On" then
            local calc = prediction.SolveTrajectory(
                selfpos, projSpeed, gravity,
                targetPos, targetVel,
                workspace.Gravity, targetEnt.HipHeight,
                targetEnt.Jumping and 42.6 or nil,
                rayCheck
            )
            local targetRoot = plr.RootPart
						if targetRoot then
							local targetRootVel = targetRoot.AssemblyLinearVelocity or targetRoot.Velocity or Vector3.zero
							local targetMovingUp = targetRootVel.Y > 3
							local heightDiff = aimTarget.Y - newlook.p.Y
							if targetMovingUp then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(targetRootVel.Y * 0.08, 0.5, 3.5), 0)
							elseif heightDiff < -8 then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(math.abs(heightDiff) * 0.04, 0.3, 2.5), 0)
							end
						end
						if calc then aimPos = calc end
        end

        local dir = CFrame.lookAt(selfpos, aimPos).LookVector * projSpeed
        local originalSlot = store.inventory.hotbarSlot

        if originalSlot ~= lassoSlot then
            hotbarSwitch(lassoSlot)
            task.wait(0.05)
        end

        local success = pcall(function()
            projectileRemote:InvokeServer(
                lassoItem.tool,
                "lasso", "lasso",
                selfpos, selfpos, dir,
                httpService:GenerateGUID(true),
                {drawDurationSeconds = 1, shotId = httpService:GenerateGUID(false)},
                workspace:GetServerTimeNow() - 0.045
            )
        end)

        if originalSlot ~= lassoSlot then
            hotbarSwitch(originalSlot)
        end

        if success then
            nextAllowedShot = now + COOLDOWN_SECONDS
            targetinfo.Targets[targetEnt] = now + 1
            return true
        end
        return false
    end

    AutoLasso = vain.Categories.Kits:CreateModule({
        Name = 'AutoLasso',
        Tooltip = 'Automatically uses the lasso on nearby enemies',
        Function = function(callback)
            if callback then
                repeat
                    if entitylib.isAlive then
                        local target = entitylib.EntityPosition({
                            Range = Range.Value,
                            Part = 'RootPart',
                            Wallcheck = Targets.Walls.Enabled,
                            Players = Targets.Players.Enabled,
                            NPCs = Targets.NPCs.Enabled,
                            Sort = sortmethods.Distance
                        })

                        if target then
							if getAccountTier(target.Player) >= 1 and getAccountTier(lplr) == 0 then continue end
                            local selfpos = entitylib.character.RootPart.Position
                            local localFacing = (ViewMode.Value == 'Third Person' and gameCamera.CFrame.LookVector or entitylib.character.RootPart.CFrame.LookVector) * Vector3.new(1, 0, 1)
                            local delta = (target.RootPart.Position - selfpos) * Vector3.new(1, 0, 1)
                            if delta.Magnitude > 0.001 then
                                local angle = math.acos(math.clamp(localfacing:Dot(delta.Unit), -1, 1))
                                if angle <= math.rad(FOV.Value) / 2 then
                                    shootLasso(target)
                                end
                            end
                        end
                    end
                    task.wait(0.05)
                until not AutoLasso.Enabled
            else
                nextAllowedShot = 0
            end
        end,
        Tooltip = 'Switches to lasso, shoots once, then switches back. 10.5 second cooldown.'
    })

    Targets = AutoLasso:CreateTargets({
    	Tooltip = 'Configure which types of targets to include',
        Players = true,
        NPCs = true,
        Walls = false
    })

    Range = AutoLasso:CreateSlider({
        Name = 'Range',
        Tooltip = 'Maximum distance in studs',
        Min = 5,
        Max = 80,
        Default = 50,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })

    FOV = AutoLasso:CreateSlider({
        Name = 'FOV',
        Tooltip = 'Field-of-view cone in degrees for target detection',
        Min = 1,
        Max = 360,
        Default = 90
    })

    AimPart = AutoLasso:CreateDropdown({
        Name = 'Aim Part',
        Tooltip = 'Which body part on the target to aim at',
        List = {'RootPart', 'Head', 'Torso'},
        Default = 'RootPart',
        ItemTooltips = {
            RootPart = 'Aims at the center of the player\'s body (HumanoidRootPart)',
            Head = 'Aims at the head — higher damage potential but smaller hitbox',
            Torso = 'Aims at the upper torso',
        }
    })

    PredictionMode = AutoLasso:CreateDropdown({
        Name = 'Prediction',
        List = {'Off', 'On'},
        Default = 'On',
        Tooltip = 'Predict target movement for better accuracy',
        ItemTooltips = {
            Off = "Aims directly at the target's current position",
            On = 'Leads the shot based on target velocity for better hit rate',
        }
    })
end)

run(function()
	local AutoPearl
	local LimitItems
	local HandCheck
	local Cooldown
	local FallSpeed
	local ReactDelay

	local rayCheck = RaycastParams.new()
	rayCheck.RespectCanCollide = true

	local scanParams = RaycastParams.new()
	scanParams.RespectCanCollide = true
	scanParams.FilterType = Enum.RaycastFilterType.Exclude
	
	local projectileRemote = {InvokeServer = function() end}
	task.spawn(function()
		projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
	end)

	local function isHoldingPearl()
		if not entitylib.isAlive then return false end
		local hand = store.inventory and store.inventory.inventory and store.inventory.inventory.hand
		return hand and hand.itemType == 'telepearl'
	end

	local function getPearlHotbarSlot()
		for i, v in store.inventory.hotbar do
			if v.item and v.item.itemType == 'telepearl' then
				return i - 1, v.item
			end
		end
		return nil, nil
	end

	local function throwPearl(pos, spot, pearlTool)
		local meta = bedwars.ProjectileMeta.telepearl
		local offsets = {
			Vector3.new(0, 0, 0),
			Vector3.new(0, 0.5, 0),
		}

		local calc, usedSpot
		for _, offset in offsets do
			local trySpot = spot + offset
			calc = prediction.SolveTrajectory(
				pos,
				meta.launchVelocity,
				meta.gravitationalAcceleration,
				trySpot,
				Vector3.zero,
				workspace.Gravity,
				0, 0, nil, false,
				lplr:GetNetworkPing()
			)
			local targetRoot = plr.RootPart
						if targetRoot then
							local targetRootVel = targetRoot.AssemblyLinearVelocity or targetRoot.Velocity or Vector3.zero
							local targetMovingUp = targetRootVel.Y > 3
							local heightDiff = aimTarget.Y - newlook.p.Y
							if targetMovingUp then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(targetRootVel.Y * 0.08, 0.5, 3.5), 0)
							elseif heightDiff < -4 then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(math.abs(heightDiff) * 0.07, 0.5, 4.5), 0)
							end
						end
						if calc then
				usedSpot = trySpot
				break
			end
		end

		if not calc then return false end

		local dir = CFrame.lookAt(pos, calc).LookVector * meta.launchVelocity
		projectileRemote:InvokeServer(
			pearlTool,
			'telepearl', 'telepearl',
			pos, pos, dir,
			httpService:GenerateGUID(true),
			{drawDurationSeconds = 1, shotId = httpService:GenerateGUID(false)},
			workspace:GetServerTimeNow() - 0.045
		)
		return true
	end

	local function isValidLandingSpot(pos, scanP)
		local headCheck = workspace:Raycast(pos + Vector3.new(0, 0.1, 0), Vector3.new(0, 3, 0), scanP)
		if headCheck then return false end
		local groundCheck = workspace:Raycast(pos + Vector3.new(0, 0.5, 0), Vector3.new(0, -2, 0), scanP)
		return groundCheck ~= nil
	end

	local function findBestLandingSpot(origin)
		local char = lplr.Character
		if not char then return nil end

		scanParams.FilterDescendantsInstances = {char, gameCamera}

		local meta = bedwars.ProjectileMeta.telepearl
		local candidates = {}

		local distances = {4, 6, 8, 10, 12, 16, 20, 24, 30}
		local angleSteps = 32

		for _, dist in distances do
			for step = 0, angleSteps - 1 do
				local angle = (step / angleSteps) * math.pi * 2
				local offsetX = math.cos(angle) * dist
				local offsetZ = math.sin(angle) * dist

				local checkOrigin = Vector3.new(
					origin.X + offsetX,
					origin.Y + 50,
					origin.Z + offsetZ
				)

				local downRay = workspace:Raycast(checkOrigin, Vector3.new(0, -120, 0), scanParams)
				if downRay then
					local hitPos = downRay.Position
					local normal = downRay.Normal
					local block = downRay.Instance

					if normal.Y > 0.7 and block and block:IsA("BasePart") then
						local blockTop = block.Position.Y + (block.Size.Y / 2)
						local landingSpot = Vector3.new(hitPos.X, blockTop + 0.1, hitPos.Z)

						if isValidLandingSpot(landingSpot, scanParams) then
							local calc = prediction.SolveTrajectory(
								origin,
								meta.launchVelocity,
								meta.gravitationalAcceleration,
								landingSpot,
								Vector3.zero,
								workspace.Gravity,
								0, 0, nil, false,
								lplr:GetNetworkPing()
							)

							local targetRoot = plr.RootPart
						if targetRoot then
							local targetRootVel = targetRoot.AssemblyLinearVelocity or targetRoot.Velocity or Vector3.zero
							local targetMovingUp = targetRootVel.Y > 3
							local heightDiff = aimTarget.Y - newlook.p.Y
							if targetMovingUp then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(targetRootVel.Y * 0.08, 0.5, 3.5), 0)
							elseif heightDiff < -8 then
								aimTarget = aimTarget + Vector3.new(0, math.clamp(math.abs(heightDiff) * 0.04, 0.3, 2.5), 0)
							end
						end
						if calc then
								local dist2d = Vector2.new(origin.X - landingSpot.X, origin.Z - landingSpot.Z).Magnitude
								local heightDiff = landingSpot.Y - origin.Y
								table.insert(candidates, {
									spot = landingSpot,
									dist = dist2d,
									heightDiff = heightDiff,
									calc = calc
								})
							end
						end
					end
				end
			end
		end

		if #candidates == 0 then return nil end
		table.sort(candidates, function(a, b)
			local aAbove = a.heightDiff >= -10
			local bAbove = b.heightDiff >= -10
			if aAbove ~= bAbove then return aAbove end
			return a.dist < b.dist
		end)

		return candidates[1].spot
	end

	local function doPearl(pos, spot, pearl)
		local pearlSlot, pearlItem = getPearlHotbarSlot()
		if not pearlSlot or not pearlItem then return end

		if LimitItems.Enabled then
			if not isHoldingPearl() then return end
			throwPearl(pos, spot, pearlItem.tool)
			return
		end

		local originalSlot = store.inventory.hotbarSlot

		if isHoldingPearl() then
			throwPearl(pos, spot, pearlItem.tool)
		else
			hotbarSwitch(pearlSlot)
			task.wait(0.08)
			throwPearl(pos, spot, pearlItem.tool)
			task.wait(0.05)
			hotbarSwitch(originalSlot)
		end
	end

	AutoPearl = vain.Categories.Utility:CreateModule({
		Name = 'AutoPearl',
		Tooltip = 'Automatically pearls to safety when falling into the void',
		Function = function(callback)
			if callback then
				local lastThrowTime = 0
				local pearlTriggered = false
				local pearlCountAtFallStart = nil
				local manualThrowTime = nil
				local fallInVoidStart = nil
				local lastScanTime = 0

				local voidRayParams = RaycastParams.new()
				voidRayParams.FilterType = Enum.RaycastFilterType.Blacklist
				voidRayParams.FilterDescendantsInstances = {lplr.Character, gameCamera}

				repeat
					if entitylib.isAlive then
						local root = entitylib.character.RootPart
						local pearl = getItem('telepearl')
						local currentTime = tick()

						local velY = root.AssemblyLinearVelocity.Y
						local falling = velY < -FallSpeed.Value
						local isJumping = velY > 5
						local noGroundBelow = not workspace:Raycast(root.Position, Vector3.new(0, -120, 0), voidRayParams)

						if not falling then
							pearlCountAtFallStart = nil
							manualThrowTime = nil
						elseif falling and pearlCountAtFallStart == nil then
							pearlCountAtFallStart = pearl and pearl.amount or 0
						end

						local currentPearlCount = pearl and pearl.amount or 0
						if pearlCountAtFallStart ~= nil and currentPearlCount < pearlCountAtFallStart and not pearlTriggered then
							manualThrowTime = currentTime
							pearlCountAtFallStart = currentPearlCount
						end

						local blockedByManual = manualThrowTime and (currentTime - manualThrowTime) < 3

						if falling and noGroundBelow then
							if not fallInVoidStart then
								fallInVoidStart = currentTime
							end
						else
							fallInVoidStart = nil
						end
						local fallInVoidDuration = fallInVoidStart and (currentTime - fallInVoidStart) or 0

						if pearl and falling and noGroundBelow and not isJumping and not blockedByManual and fallInVoidDuration >= ReactDelay.Value and not (HandCheck.Enabled and isHoldingPearl()) then
							if not pearlTriggered and (currentTime - lastThrowTime) >= Cooldown.Value then
								pearlTriggered = true
								lastThrowTime = currentTime
								if currentTime - lastScanTime >= 0.5 then
									lastScanTime = currentTime
									local ground = findBestLandingSpot(root.Position)
									if ground then
										task.spawn(doPearl, root.Position, ground, pearl)
									end
								end
							end
						else
							pearlTriggered = false
						end
					else
						pearlTriggered = false
					end
					task.wait(0.05)
				until not AutoPearl.Enabled
			end
		end,
		Tooltip = 'automatically pearls to safety when falling into void'
	})

	LimitItems = AutoPearl:CreateToggle({
		Name = 'Limit to Pearl',
		Default = false,
		Tooltip = 'only pearls when already holding pearl, no switching'
	})

	HandCheck = AutoPearl:CreateToggle({
		Name = 'Hand Check',
		Default = false,
		Tooltip = 'disables auto pearl while holding a pearl'
	})

	Cooldown = AutoPearl:CreateSlider({
		Name = 'Throw Cooldown',
		Tooltip = 'Minimum time between automatic pearl throws',
		Min = 0,
		Max = 10,
		Default = 3,
		Decimal = 10,
		Suffix = 'sec',
	})

	FallSpeed = AutoPearl:CreateSlider({
		Name = 'Fall Sensitivity',
		Tooltip = 'Downward speed that counts as falling — lower triggers sooner',
		Min = 10,
		Max = 150,
		Default = 60,
		Suffix = 'sp/s',
	})

	ReactDelay = AutoPearl:CreateSlider({
		Name = 'React Delay',
		Tooltip = 'How long you must be falling over the void before it pearls',
		Min = 0,
		Max = 3,
		Default = 0.6,
		Decimal = 100,
		Suffix = 'sec',
	})
end)

run(function()
    local AutoPlay
    local Random
    
    local function isEveryoneDead()
        return #bedwars.Store:getState().Party.members <= 0
    end
    
    local function joinQueue()
        if not bedwars.Store:getState().Game.customMatch and bedwars.Store:getState().Party.leader.userId == lplr.UserId and bedwars.Store:getState().Party.queueState == 0 then
            if Random.Enabled then
                local listofmodes = {}
                for i, v in bedwars.QueueMeta do
                    if not v.disabled and not v.voiceChatOnly and not v.rankCategory then 
                        table.insert(listofmodes, i) 
                    end
                end
                bedwars.QueueController:joinQueue(listofmodes[math.random(1, #listofmodes)])
            else
                bedwars.QueueController:joinQueue(store.queueType)
            end
        end
    end
    
    AutoPlay = vain.Categories.Utility:CreateModule({
        Name = 'Auto Play',
        Tooltip = 'Enables the Auto Play module',
        Function = function(callback)
            if callback then
                AutoPlay:Clean(vainEvents.EntityDeathEvent.Event:Connect(function(deathTable)
                    if deathTable.finalKill and deathTable.entityInstance == lplr.Character and isEveryoneDead() and store.matchState ~= 2 then
                        joinQueue()
                    end
                end))
                AutoPlay:Clean(vainEvents.MatchEndEvent.Event:Connect(joinQueue))
            end
        end,
        Tooltip = 'Automatically queues after the match ends.'
    })
    Random = AutoPlay:CreateToggle({
        Name = 'Random',
        Tooltip = 'Chooses a random mode'
    })
end)

run(function()
    local AutoRelease
    local Percentage
    local Delay
    
    local launchHook, last = nil, 0
    local charge = 0
    
    AutoRelease = vain.Categories.Utility:CreateModule({
    	Name = 'Auto Release',
    	Tooltip = 'Automatically releases a charged bow at the optimal moment',
    	Function = function(call)
    		if call then
    			launchHook = bedwars.ProjectileLaunchHook:Add('AutoRelease', 20, function(nextLaunch, ...)
    				local projmeta = select(2, ...)
    				if projmeta and typeof(projmeta) == 'table' then
    					charge = (projmeta.velocityMultiplier / 1) * 100
    					last = os.clock() + 0.1
    				end
    
    				return nextLaunch(...)
    			end)
    
    			repeat
    				if last > os.clock() and charge >= Percentage.Value then
    					task.wait(Delay.Value)
    					mouse1click()
    					task.wait(0.2)
    				end
    				task.wait()
    			until not AutoRelease.Enabled
    		else
    			if launchHook then
    				launchHook()
    				launchHook = nil
    			end
    		end
    	end,
        Tooltip = 'Automatically releases ur projectile source when\nat certain charging percentage'
    })
    
    Percentage = AutoRelease:CreateSlider({
    	Name = 'Percentage',
    	Tooltip = 'Threshold percentage that triggers the action',
    	Min = 0,
    	Max = 100,
    	Suffix = '%',
    	Default = 100,
    })
    Delay = AutoRelease:CreateSlider({
    	Name = 'Release delay',
    	Tooltip = 'Seconds before releasing a fully charged bow',
    	Min = 0,
    	Max = 5,
    	Default = 0.5,
    	Decimal = 10,
    	Suffix = function(val)
    		return val <= 1 and 'sec' or 'secs'
    	end,
    })
end)

run(function()
	local shooting, old = false
	local AutoShootInterval
	local AutoShootSwitchSpeed
	local AutoShootRange
	local AutoShootFOV
	local AutoShootWaitDelay
	local lastAutoShootTime = 0
	local autoShootEnabled = false
	local KillauraTargetCheck
	local FirstPersonCheck
	_G.autoShootLock = _G.autoShootLock or false
	local cachedBows = {}
	local cachedSwordSlot = nil
	local cachedHasArrows = false
	local lastInventoryUpdate = 0
	local INVENTORY_CACHE_TIME = 0.5
	local lastTargetCheck = 0
	local lastTargetResult = false
	local TARGET_CHECK_INTERVAL = 0.15
	local math_acos = math.acos
	local math_rad = math.rad
	local tick = tick
	
	local function updateInventoryCache()
		local now = tick()
		if now - lastInventoryUpdate < INVENTORY_CACHE_TIME then
			return
		end
		lastInventoryUpdate = now
		
		local arrowItem = getItem('arrow')
		cachedHasArrows = arrowItem and arrowItem.amount > 0
		
		table.clear(cachedBows)
		cachedSwordSlot = nil
		
		local hotbar = store.inventory.hotbar
		for i = 1, #hotbar do
			local v = hotbar[i]
			if v.item and v.item.itemType then
				local itemMeta = bedwars.ItemMeta[v.item.itemType]
				if itemMeta then
					if itemMeta.projectileSource then
						local projectileSource = itemMeta.projectileSource
						if projectileSource.ammoItemTypes and table.find(projectileSource.ammoItemTypes, 'arrow') then
							table.insert(cachedBows, i - 1)
						end
					end
					if itemMeta.sword and not cachedSwordSlot then
						cachedSwordSlot = i - 1
					end
				end
			end
		end
	end
	
	local function hasArrows()
		updateInventoryCache()
		return cachedHasArrows
	end
	
	local function getBows()
		updateInventoryCache()
		return cachedBows
	end
	
	local function getSwordSlot()
		updateInventoryCache()
		return cachedSwordSlot
	end
	
	local function hasValidTarget()
		if store.KillauraTarget ~= nil then
			return true
		end
		if KillauraTargetCheck.Enabled then
			return false
		end
		
		local now = tick()
		if now - lastTargetCheck < TARGET_CHECK_INTERVAL then
			return lastTargetResult
		end
		lastTargetCheck = now
		
		if not entitylib.isAlive then 
			lastTargetResult = false
			return false 
		end
		
		local myPos = entitylib.character.RootPart.Position
		local myLook = entitylib.character.RootPart.CFrame.LookVector
		local rangeSquared = AutoShootRange.Value * AutoShootRange.Value
		local fovRad = math_rad(AutoShootFOV.Value)
		local myTeam = lplr:GetAttribute('Team')
		
		for _, entity in entitylib.List do
			if entity.Player == lplr then continue end
			if not entity.Character then continue end
			
			local rootPart = entity.RootPart
			if not rootPart then continue end
			
			if entity.Player then
				if myTeam == entity.Player:GetAttribute('Team') then
					continue
				end
			else
				if not entity.Targetable then
					continue
				end
			end
			
			local pos = rootPart.Position
			local dx = pos.X - myPos.X
			local dy = pos.Y - myPos.Y
			local dz = pos.Z - myPos.Z
			local distanceSquared = dx * dx + dy * dy + dz * dz
			
			if distanceSquared > rangeSquared then continue end
			
			local distance = math.sqrt(distanceSquared)
			if distance < 0.01 then 
				lastTargetResult = true
				return true 
			end
			
			local toTargetX = dx / distance
			local toTargetY = dy / distance
			local toTargetZ = dz / distance
			local dot = myLook.X * toTargetX + myLook.Y * toTargetY + myLook.Z * toTargetZ
			local angle = math_acos(math.max(-1, math.min(1, dot)))
			
			if angle <= fovRad then
				lastTargetResult = true
				return true
			end
		end
		
		lastTargetResult = false
		return false
	end
	
	local AutoShoot = vain.Categories.Utility:CreateModule({
		Name = 'AutoShoot',
		Tooltip = 'Automatically fires ranged weapons at nearby enemies',
		Function = function(callback)
			if callback then
				autoShootEnabled = true
				
				lastInventoryUpdate = 0
				updateInventoryCache()
				
				old = bedwars.ProjectileController.createLocalProjectile
				bedwars.ProjectileController.createLocalProjectile = function(...)
					local source, data, proj = ...
					if source and proj and (proj == 'arrow' or bedwars.ProjectileMeta[proj] and bedwars.ProjectileMeta[proj].combat) and not _G.autoShootLock then
						task.spawn(function()
							if not hasArrows() then
								return
							end
							
							if FirstPersonCheck.Enabled and not isFirstPerson() then
								return
							end
							
							if KillauraTargetCheck.Enabled then
								if not store.KillauraTarget then
									return
								end
							else
								if not hasValidTarget() then
									return
								end
							end
							
							local bows = getBows()
							if #bows > 0 then
								_G.autoShootLock = true
								task.wait(AutoShootWaitDelay.Value)
								local selected = store.inventory.hotbarSlot
								for i = 1, #bows do
									local v = bows[i]
									if hotbarSwitch(v) then
										task.wait(0.05)
										leftClick()
										task.wait(0.05)
									end
								end
								hotbarSwitch(selected)
								_G.autoShootLock = false
							end
						end)
					end
					return old(...)
				end
				
				task.spawn(function()
					repeat
						task.wait(0.15) 
						if autoShootEnabled and not _G.autoShootLock then
							if not hasArrows() then
								continue
							end
							
							if FirstPersonCheck.Enabled and not isFirstPerson() then
								continue
							end
							
							local hasTarget = false
							if KillauraTargetCheck.Enabled then
								hasTarget = store.KillauraTarget ~= nil
							else
								hasTarget = hasValidTarget()
							end
							
							if not hasTarget then
								continue
							end
							
							local currentTime = tick()
							if (currentTime - lastAutoShootTime) >= AutoShootInterval.Value then
								local bows = getBows()
								
								if #bows > 0 then
									_G.autoShootLock = true
									lastAutoShootTime = currentTime
									local originalSlot = store.inventory.hotbarSlot
									
									for i = 1, #bows do
										local bowSlot = bows[i]
										if hotbarSwitch(bowSlot) then
											task.wait(AutoShootSwitchSpeed.Value)
											leftClick()
											task.wait(0.05)
										end
									end
									
									local swordSlot = getSwordSlot()
									if swordSlot then
										hotbarSwitch(swordSlot)
									else
										hotbarSwitch(originalSlot)
									end
									
									_G.autoShootLock = false
								end
							end
						end
					until not autoShootEnabled
				end)
			else
				autoShootEnabled = false
				if old then
					bedwars.ProjectileController.createLocalProjectile = old
				end
				_G.autoShootLock = false
				
				table.clear(cachedBows)
				cachedSwordSlot = nil
				cachedHasArrows = false
				lastInventoryUpdate = 0
			end
		end,
		Tooltip = 'Automatically switches to bows and shoots them'
	})
	
	AutoShootInterval = AutoShoot:CreateSlider({
		Name = 'Shoot Interval',
		Min = 0.1,
		Max = 3,
		Default = 0.5,
		Decimal = 10,
		Suffix = function(val)
			return val == 1 and 'second' or 'seconds'
		end,
		Tooltip = 'How often to auto-shoot bows'
	})
	
	AutoShootSwitchSpeed = AutoShoot:CreateSlider({
		Name = 'Switch Delay',
		Min = 0,
		Max = 0.2,
		Default = 0.05,
		Decimal = 100,
		Suffix = 's',
		Tooltip = 'Delay between switching and shooting (lower = faster)'
	})
	
	AutoShootWaitDelay = AutoShoot:CreateSlider({
		Name = 'Wait Delay',
		Min = 0,
		Max = 1,
		Default = 0,
		Decimal = 100,
		Suffix = 's',
		Tooltip = 'Delay before shooting (helps prevent ghosting)'
	})
	
	AutoShootRange = AutoShoot:CreateSlider({
		Name = 'Range',
		Min = 1,
		Max = 30,
		Default = 20,
		Suffix = function(val)
			return val == 1 and 'stud' or 'studs'
		end,
		Tooltip = 'Maximum range to auto-shoot'
	})
	
	AutoShootFOV = AutoShoot:CreateSlider({
		Name = 'FOV',
		Min = 1,
		Max = 180,
		Default = 90,
		Tooltip = 'Field of view for target detection (1-180 degrees)'
	})
	
	KillauraTargetCheck = AutoShoot:CreateToggle({
		Name = 'Require Killaura Target',
		Default = false,
		Tooltip = 'Only auto-shoot when Killaura has a target (overrides Range/FOV)'
	})
	
	FirstPersonCheck = AutoShoot:CreateToggle({
		Name = 'First Person Only',
		Default = false,
		Tooltip = 'Only works in first person mode'
	})
	
	vain:Clean(vainEvents.InventoryChanged.Event:Connect(function()
		lastInventoryUpdate = 0
	end))
end)

run(function()
    local AutoToxic
    local GG
    local Toggles, Lists, said, dead = {}, {}, {}
    
    local function sendMessage(name, obj, default)
        local tab = Lists[name].ListEnabled
        local custommsg = #tab > 0 and tab[math.random(1, #tab)] or default
        if not custommsg then return end
        if #tab > 1 and custommsg == said[name] then
            repeat 
                task.wait() 
                custommsg = tab[math.random(1, #tab)] 
            until custommsg ~= said[name]
        end
        said[name] = custommsg
    
        custommsg = custommsg and custommsg:gsub('<obj>', obj or '') or ''
        if textChatService.ChatVersion == Enum.ChatVersion.TextChatService then
            textChatService.ChatInputBarConfiguration.TargetTextChannel:SendAsync(custommsg)
        else
            replicatedStorage.DefaultChatSystemChatEvents.SayMessageRequest:FireServer(custommsg, 'All')
        end
    end
    
    AutoToxic = vain.Categories.Utility:CreateModule({
        Name = 'Auto Toxic',
        Tooltip = 'Automatically sends configured chat messages',
        Function = function(callback)
            if callback then
                AutoToxic:Clean(vainEvents.BedwarsBedBreak.Event:Connect(function(bedTable)
                    if Toggles.BedDestroyed.Enabled and bedTable.brokenBedTeam.id == lplr:GetAttribute('Team') then
                        sendMessage('BedDestroyed', (bedTable.player.DisplayName or bedTable.player.Name), 'how dare you >:( | <obj>')
                    elseif Toggles.Bed.Enabled and bedTable.player.UserId == lplr.UserId then
                        local team = bedwars.QueueMeta[store.queueType].teams[tonumber(bedTable.brokenBedTeam.id)]
                        sendMessage('Bed', team and team.displayName:lower() or 'white', 'nice bed lul | <obj>')
                    end
                end))
                AutoToxic:Clean(vainEvents.EntityDeathEvent.Event:Connect(function(deathTable)
                    if deathTable.finalKill then
                        local killer = playersService:GetPlayerFromCharacter(deathTable.fromEntity)
                        local killed = playersService:GetPlayerFromCharacter(deathTable.entityInstance)
                        if not killed or not killer then return end
                        if killed == lplr then
                            if (not dead) and killer ~= lplr and Toggles.Death.Enabled then
                                dead = true
                                sendMessage('Death', (killer.DisplayName or killer.Name), 'my gaming chair subscription expired :( | <obj>')
                            end
                        elseif killer == lplr and Toggles.Kill.Enabled then
                            sendMessage('Kill', (killed.DisplayName or killed.Name), 'vxp on top | <obj>')
                        end
                    end
                end))
                AutoToxic:Clean(vainEvents.MatchEndEvent.Event:Connect(function(winstuff)
                    if GG.Enabled then
                        if textChatService.ChatVersion == Enum.ChatVersion.TextChatService then
                            textChatService.ChatInputBarConfiguration.TargetTextChannel:SendAsync('gg')
                        else
                            replicatedStorage.DefaultChatSystemChatEvents.SayMessageRequest:FireServer('gg', 'All')
                        end
                    end
                    
                    local myTeam = bedwars.Store:getState().Game.myTeam
                    if myTeam and myTeam.id == winstuff.winningTeamId or lplr.Neutral then
                        if Toggles.Win.Enabled then 
                            sendMessage('Win', nil, 'yall garbage') 
                        end
                    end
                end))
            end
        end,
        Tooltip = 'Says a message after a certain action'
    })
    GG = AutoToxic:CreateToggle({
        Name = 'AutoGG',
        Tooltip = 'Automatically types GG in chat after the match ends',
        Default = true
    })
    local toxicTooltips = {
        Kill = 'Sends a random chat message when you score a final kill on an enemy',
        Death = 'Sends a random chat message when you are eliminated from the game',
        Bed = "Sends a random chat message when you destroy an enemy team's bed",
        BedDestroyed = 'Sends a random chat message when your own bed is destroyed by an enemy',
        Win = 'Sends a random chat message when your team wins the match',
    }
    for _, v in {'Kill', 'Death', 'Bed', 'BedDestroyed', 'Win'} do
        Toggles[v] = AutoToxic:CreateToggle({
        	Tooltip = toxicTooltips[v],
            Name = v..' ',
            Function = function(callback)
                if Lists[v] then
                    Lists[v].Object.Visible = callback
                end
            end
        })
        Lists[v] = AutoToxic:CreateTextList({
            Name = v,
            Tooltip = 'Messages to send for this category (one per line)',
            Darker = true,
            Visible = false
        })
    end
end)

