                            setfflag('TargetTimeDelayFacctorTenths', '20')
                            task.wait(0.05 * Tick.Value)
                        else
                            setfflag('TargetTimeDelayFacctorTenths', tostring(math.floor(20 + (Latency:GetRandomValue() / 20))))
                            task.wait(1)
