    local function getBlock()
        local clone = table.clone(store.inventory.inventory.items)
        table.sort(clone, function(a, b)
            return a.amount < b.amount
        end)
    
        for _, item in clone do
            local block = bedwars.ItemMeta[item.itemType].block
            if block and not block.seeThrough then
                return item
            end
        end
    end
    
    local function getCustomItem(v)
        if v == 'diamond_sword' then
            local sword = store.tools.sword
            v = sword and sword.itemType or 'wood_sword'
        elseif v == 'diamond_pickaxe' then
            local pickaxe = store.tools.stone
            v = pickaxe and pickaxe.itemType or 'wood_pickaxe'
        elseif v == 'diamond_axe' then
            local axe = store.tools.wood
            v = axe and axe.itemType or 'wood_axe'
        elseif v == 'wood_bow' then
            local bow = getBow()
            v = bow and bow.itemType or 'wood_bow'
        elseif v == 'wool_white' then
            local block = getBlock()
            v = block and block.itemType or 'wool_white'
        end
    
        return v
    end
    
    local function findItemInTable(tab, item)
        for slot, v in tab do
            if item.itemType == getCustomItem(v) then
                return tonumber(slot)
            end
        end
    end
    
    local function findInHotbar(item)
        for i, v in store.inventory.hotbar do
            if v.item and v.item.itemType == item.itemType then
                return i - 1, v.item
            end
        end
    end
    
    local function findInInventory(item)
        for _, v in store.inventory.inventory.items do
            if v.itemType == item.itemType then
                return v
            end
        end
    end
    
    local function dispatch(...)
        bedwars.Store:dispatch(...)
        vainEvents.InventoryChanged.Event:Wait()
    end
    
    local function sortCallback()
        if Active then return end
        Active = true
        local items = (List.Hotbars[List.Selected] and List.Hotbars[List.Selected].Hotbar or {})
    
        for _, v in store.inventory.inventory.items do
            local slot = findItemInTable(items, v)
            if slot then
                local olditem = store.inventory.hotbar[slot]
                if olditem.item and olditem.item.itemType == v.itemType then continue end
                if olditem.item then
                    dispatch({
                        type = 'InventoryRemoveFromHotbar',
                        slot = slot - 1
                    })
                end
    
                local newslot = findInHotbar(v)
                if newslot then
                    dispatch({
                        type = 'InventoryRemoveFromHotbar',
                        slot = newslot
                    })
                    if olditem.item then
                        dispatch({
                            type = 'InventoryAddToHotbar',
                            item = findInInventory(olditem.item),
                            slot = newslot
                        })
                    end
                end
    
                dispatch({
                    type = 'InventoryAddToHotbar',
                    item = findInInventory(v),
                    slot = slot - 1
                })
            elseif Clear.Enabled then
                local newslot = findInHotbar(v)
                if newslot then
                    dispatch({
                        type = 'InventoryRemoveFromHotbar',
                        slot = newslot
                    })
                end
            end
        end
    
        Active = false
    end
    
    AutoHotbar = vain.Categories.Inventory:CreateModule({
        Name = 'Auto Hotbar',
        Tooltip = 'Enables the Auto Hotbar module',
        Function = function(callback)
            if callback then
                task.spawn(sortCallback)
                if Mode.Value == 'On Key' then
                    AutoHotbar:Toggle()
                    return
                end
    
                AutoHotbar:Clean(vainEvents.InventoryAmountChanged.Event:Connect(sortCallback))
            end
        end,
        Tooltip = 'Automatically arranges hotbar to your liking.'
    })
    Mode = AutoHotbar:CreateDropdown({
        Name = 'Activation',
        Tooltip = 'Selects what triggers this module to activate',
        List = {'Toggle', 'On Key'},
        ItemTooltips = {
            Toggle = 'Rearranges the hotbar automatically whenever the module is enabled',
            ['On Key'] = 'Rearranges the hotbar only while the configured keybind is held',
        },
        Function = function()
            if AutoHotbar.Enabled then
                AutoHotbar:Toggle()
                AutoHotbar:Toggle()
            end
        end
    })
    Clear = AutoHotbar:CreateToggle({Name = 'Clear Hotbar', Tooltip = 'Clears relevant hotbar slots before item switch'})
    List = AutoHotbar:CreateHotbarList({})
end)

run(function()
    local AutoSteal
    local Range
    local Delay
    local GUI
    
    local Start = 0
    
    AutoSteal = vain.Categories.Inventory:CreateModule({
    	Name = 'Auto Steal',
    	Tooltip = 'Automatically steals resources from nearby players',
    	Function = function(call)
    		if call then
    			repeat
    				task.wait()
    			until store.matchState ~= 0 or not AutoSteal.Enabled
    			if not AutoSteal.Enabled then
    				return
    			end
    
    			local crates, items = collection('team-crate', AutoSteal, function(tab, obj)
                    task.delay(0, function()
                        if obj:GetAttribute('Team') ~= lplr:GetAttribute('Team') then
                            table.insert(tab, obj)
                        end
                    end)
                end), {}
    			repeat
    				if entitylib.isAlive then
    					local localPosition = entitylib.character.RootPart.Position
    					if (tick() - Start) >= Delay.Value and (not GUI.Enabled or bedwars.AppController:isAppOpen('ChestApp')) then
    						for _, v in crates do
    							if (localPosition - v.Position).Magnitude <= Range.Value then
    								local folder = v.ChestFolderValue.Value
    								bedwars.Client:GetNamespace('Inventory'):Get('SetObservedChest'):SendToServer(folder)
    								for _, v2 in folder:GetChildren() do
    									if v2:IsA('Accessory') then
    										task.spawn(function()
    											if bedwars.Client:GetNamespace('Inventory'):Get('ChestGetItem'):CallServer(folder, v2) then
    												table.insert(items, v2.Name)
    											end
    										end)
    									end
    								end
    								bedwars.Client:GetNamespace('Inventory'):Get('SetObservedChest'):SendToServer(nil)
    							end
    						end
    
    						if #items > 0 then
    							for _, v in collectionService:GetTagged('personal-chest') do
    								if (localPosition - v.Position).Magnitude <= Range.Value then
    									for _, v2 in items do
    										local i = getItem(v2)
    										if i then
    											task.spawn(function()
    												if bedwars.Client:GetNamespace('Inventory'):Get('ChestGiveItem'):CallServer(
                                                        replicatedStorage.Inventories[lplr.Name .. '_personal'],
                                                        i.tool
                                                    ) then
    													table.remove(items, table.find(items, v2))
    												end
    											end)
    										end
    									end
    									break
    								end
    							end
    						end
    
    						Start = tick()
    					end
    				end
    				task.wait(0.1)
    			until not AutoSteal.Enabled
    		end
    	end,
    	Tooltip = "Automatically steals loot from other team's chest, And personal chesting it",
    })
    
    Range = AutoSteal:CreateSlider({
    	Name = 'Range',
    	Tooltip = 'Maximum distance in studs',
    	Min = 1,
    	Max = 18,
    	Suffix = function(val)
    		return val <= 1 and 'stud' or 'studs'
    	end,
    	Default = 18,
    })
    Delay = AutoSteal:CreateSlider({
    	Name = 'Delay',
    	Tooltip = 'Seconds between consecutive actions',
    	Min = 0,
    	Max = 1,
    	Decimal = 100,
    	Suffix = 'seconds',
    	Default = 0,
    })
    GUI = AutoSteal:CreateToggle({
    	Name = 'GUI Check',
    	Tooltip = 'Pauses the module when a GUI menu is open',
    })
end)

run(function()
    local Value
    local oldclickhold, oldshowprogress
    
    local FastConsume = vain.Categories.Inventory:CreateModule({
        Name = 'Fast Consume',
        Tooltip = 'Speeds up item consumption (eating, drinking)',
        Function = function(callback)
            if callback then
                oldclickhold = bedwars.ClickHold.startClick
                oldshowprogress = bedwars.ClickHold.showProgress
                bedwars.ClickHold.startClick = function(self)
                    self.startedClickTime = tick()
                    local handle = self:showProgress()
                    local clicktime = self.startedClickTime
                    bedwars.RuntimeLib.Promise.defer(function()
                        task.wait(self.durationSeconds * (Value.Value / 40))
                        if handle == self.handle and clicktime == self.startedClickTime and self.closeOnComplete then
                            self:hideProgress()
                            if self.onComplete then self.onComplete() end
                            if self.onPartialComplete then self.onPartialComplete(1) end
                            self.startedClickTime = -1
                        end
                    end)
                end
    
                bedwars.ClickHold.showProgress = function(self)
                    local roact = debug.getupvalue(oldshowprogress, 1)
                    local countdown = roact.mount(roact.createElement('ScreenGui', {}, { roact.createElement('Frame', {
                        [roact.Ref] = self.wrapperRef,
                        Size = UDim2.new(),
                        Position = UDim2.fromScale(0.5, 0.55),
                        AnchorPoint = Vector2.new(0.5, 0),
                        BackgroundColor3 = Color3.fromRGB(0, 0, 0),
                        BackgroundTransparency = 0.8
                    }, { roact.createElement('Frame', {
                        [roact.Ref] = self.progressRef,
                        Size = UDim2.fromScale(0, 1),
                        BackgroundColor3 = Color3.new(1, 1, 1),
                        BackgroundTransparency = 0.5
                    }) }) }), lplr:FindFirstChild('PlayerGui'))
    
                    self.handle = countdown
                    local sizetween = tweenService:Create(self.wrapperRef:getValue(), TweenInfo.new(0.1), {
                        Size = UDim2.fromScale(0.11, 0.005)
                    })
                    local countdowntween = tweenService:Create(self.progressRef:getValue(), TweenInfo.new(self.durationSeconds * (Value.Value / 100), Enum.EasingStyle.Linear), {
                        Size = UDim2.fromScale(1, 1)
                    })
    
                    sizetween:Play()
                    countdowntween:Play()
                    table.insert(self.tweens, countdowntween)
                    table.insert(self.tweens, sizetween)
                    
                    return countdown
                end
            else
                bedwars.ClickHold.startClick = oldclickhold
                bedwars.ClickHold.showProgress = oldshowprogress
                oldclickhold = nil
                oldshowprogress = nil
            end
        end,
        Tooltip = 'Use/Consume items quicker.'
    })
    Value = FastConsume:CreateSlider({
        Name = 'Multiplier',
        Tooltip = 'Speed multiplier applied to this action',
        Min = 0,
        Max = 100
    })
end)

run(function()
    local FastDrop
    
    FastDrop = vain.Categories.Inventory:CreateModule({
        Name = 'Fast Drop',
        Tooltip = 'Enables the Fast Drop module',
        Function = function(callback)
            if callback then
                repeat
                    if entitylib.isAlive and (not store.inventory.opened) and (inputService:IsKeyDown(Enum.KeyCode.H) or inputService:IsKeyDown(Enum.KeyCode.Backspace)) and inputService:GetFocusedTextBox() == nil then
                        task.spawn(bedwars.ItemDropController.dropItemInHand)
                        task.wait()
                    else
                        task.wait(0.1)
                    end
                until not FastDrop.Enabled
            end
        end,
        Tooltip = 'Drops items fast when you hold Q'
    })
end)

--[[
    Minigames
]]

run(function()
    local BedPlates
    local Background
    local Color
    local LayerCounter
    local LayerColor
    local LayerNotify
    local ObsidianOnly
    local Reference = {}
    local prevLayers = {} -- [bedAdornee] = { [blockName] = count } from the last scan
    local Folder = Instance.new('Folder')
    Folder.Parent = vain.gui

    local function isObsidian(name)
        return tostring(name):lower():find('obsidian', 1, true) ~= nil
    end
    
    local function getBlockLayerHealth(block)
    	local meta = bedwars.ItemMeta[block]
    	return meta and meta.block and meta.block.health or 0
    end
    
    local function getLayerColor()
    	return LayerColor and Color3.fromHSV(LayerColor.Hue, LayerColor.Sat, LayerColor.Value) or Color3.new(1, 1, 1)
    end
    
    local function scanSide(self, start, tab)
    	for _, side in sides do
    		local layers = {}
    		for i = 1, 15 do
    			local block = getPlacedBlock(start + (side * i))
    			if not block or block == self or block.Name == 'bed' then
    				break
    			end
    			if not block:GetAttribute('NoBreak') then
    				layers[block.Name] = (layers[block.Name] or 0) + 1
    			end
    		end
    
    		for block, amount in layers do
    			tab[block] = math.max(tab[block] or 0, amount)
    		end
    	end
    end
    
    local function refreshAdornee(v)
    	for _, obj in v.Frame:GetChildren() do
    		if obj:IsA('ImageLabel') and obj.Name ~= 'Blur' then
    			obj:Destroy()
    		end
    	end
    
    	local start = v.Adornee.Position
    	local layers = {}
    	local alreadygot = {}
    	scanSide(v.Adornee, start, layers)
    	scanSide(v.Adornee, start + Vector3.new(0, 0, 3), layers)

    	-- Notify when a NEW layer is added (a block type's count went up vs the last
    	-- scan of this bed). ObsidianOnly restricts the alert to obsidian layers.
    	-- Skip the FIRST scan of a bed (prevLayers[bed] == nil) so pre-existing
    	-- layers don't all fire as "new" the moment you enable the module.
    	if LayerNotify and LayerNotify.Enabled and prevLayers[v.Adornee] then
    		local prev = prevLayers[v.Adornee]
    		for block, amount in layers do
    			local before = prev[block] or 0
    			if amount > before then
    				local obs = isObsidian(block)
    				if (not (ObsidianOnly and ObsidianOnly.Enabled)) or obs then
    					local added = amount - before
    					local nice = tostring(block):gsub('_', ' ')
    					vain:CreateNotification('Bed Plates',
    						('+%d %s layer%s (%d total)'):format(added, nice, added == 1 and '' or 's', amount),
    						3, obs and 'alert' or nil)
    				end
    			end
    		end
    	end
    	prevLayers[v.Adornee] = layers

    	for block, amount in layers do
    		table.insert(alreadygot, {block, amount})
    	end
    	table.sort(alreadygot, function(a, b)
    		local healthA, healthB = getBlockLayerHealth(a[1]), getBlockLayerHealth(b[1])
    		return healthA == healthB and a[1] < b[1] or healthA > healthB
    	end)
    	v.Enabled = #alreadygot > 0
    
    	for _, blockData in alreadygot do
    		local block, amount = blockData[1], blockData[2]
    		local blockimage = Instance.new('ImageLabel')
    		blockimage.Size = UDim2.fromOffset(32, 32)
    		blockimage.BackgroundTransparency = 1
    		blockimage.Image = bedwars.getIcon({ itemType = block }, true)
    		blockimage.Parent = v.Frame
    		if amount > 1 and (not LayerCounter or LayerCounter.Enabled) then
    			local amounttext = Instance.new('TextLabel')
    			amounttext.Name = 'Amount'
    			amounttext.Size = UDim2.fromScale(1, 1)
    			amounttext.BackgroundTransparency = 1
    			amounttext.Text = tostring(amount)
    			amounttext.TextColor3 = getLayerColor()
    			amounttext.TextSize = 16
    			amounttext.TextStrokeTransparency = 0.3
    			amounttext.Font = Enum.Font.Arial
    			amounttext.Parent = blockimage
    		end
    	end
    end
    
    local function refreshAll()
    	for _, v in Reference do
    		refreshAdornee(v)
    	end
    end
    
    local function updateLayerTextColor()
    	local textColor = getLayerColor()
    	for _, v in Reference do
    		for _, obj in v.Frame:GetDescendants() do
    			if obj:IsA('TextLabel') and obj.Name == 'Amount' then
    				obj.TextColor3 = textColor
    			end
    		end
    	end
    end
    
    local function Added(v)
    	local billboard = Instance.new('BillboardGui')
    	billboard.Parent = Folder
    	billboard.Name = 'bed'
    	billboard.StudsOffsetWorldSpace = Vector3.new(0, 3, 0)
    	billboard.Size = UDim2.fromOffset(36, 36)
    	billboard.AlwaysOnTop = true
    	billboard.ClipsDescendants = false
    	billboard.Adornee = v
    	local blur = addBlur(billboard)
    	blur.Visible = Background.Enabled
    	local frame = Instance.new('Frame')
    	frame.Size = UDim2.fromScale(1, 1)
    	frame.BackgroundColor3 = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
    	frame.BackgroundTransparency = 1 - (Background.Enabled and Color.Opacity or 0)
    	frame.Parent = billboard
    	local layout = Instance.new('UIListLayout')
    	layout.FillDirection = Enum.FillDirection.Horizontal
    	layout.Padding = UDim.new(0, 4)
    	layout.VerticalAlignment = Enum.VerticalAlignment.Center
    	layout.HorizontalAlignment = Enum.HorizontalAlignment.Center
    	layout:GetPropertyChangedSignal('AbsoluteContentSize'):Connect(function()
    		billboard.Size = UDim2.fromOffset(math.max(layout.AbsoluteContentSize.X + 4, 36), 36)
    	end)
    	layout.Parent = frame
    	local corner = Instance.new('UICorner')
    	corner.CornerRadius = UDim.new(0, 4)
    	corner.Parent = frame
    	Reference[v] = billboard
    	refreshAdornee(billboard)
    end
    
    local function refreshNear(data)
    	data = data.blockRef.blockPosition * 3
    	for i, v in Reference do
    		if (data - i.Position).Magnitude <= 30 then
    			refreshAdornee(v)
    		end
    	end
    end
    
    BedPlates = vain.Categories.Minigames:CreateModule({
    	Name = 'Bed Plates',
    	Tooltip = 'Displays the number of protection layers on your bed',
    	Function = function(callback)
    		if callback then
    			for _, v in collectionService:GetTagged('bed') do
    				task.spawn(Added, v)
    			end
    			BedPlates:Clean(vainEvents.PlaceBlockEvent.Event:Connect(refreshNear))
    			BedPlates:Clean(vainEvents.BreakBlockEvent.Event:Connect(refreshNear))
    			BedPlates:Clean(collectionService:GetInstanceAddedSignal('bed'):Connect(Added))
    			BedPlates:Clean(collectionService:GetInstanceRemovedSignal('bed'):Connect(function(v)
    				if Reference[v] then
    					Reference[v]:Destroy()
    					Reference[v]:ClearAllChildren()
    					Reference[v] = nil
    				end
    				prevLayers[v] = nil
    			end))
    		else
    			table.clear(Reference)
    			table.clear(prevLayers)
    			Folder:ClearAllChildren()
    		end
    	end,
    	Tooltip = 'Displays blocks over the bed',
    })
    Background = BedPlates:CreateToggle({
    	Name = 'Background',
    	Tooltip = 'Renders a background box behind this ESP element',
    	Function = function(callback)
    		if Color and Color.Object then
    			Color.Object.Visible = callback
    		end
    		for _, v in Reference do
    			v.Frame.BackgroundTransparency = 1 - (callback and Color.Opacity or 0)
    			v.Blur.Visible = callback
    		end
    	end,
    	Default = true,
    })
    Color = BedPlates:CreateColorSlider({
    	Name = 'Background Color',
    	DefaultValue = 0,
    	DefaultOpacity = 0.5,
    	Function = function(hue, sat, val, opacity)
    		for _, v in Reference do
    			v.Frame.BackgroundColor3 = Color3.fromHSV(hue, sat, val)
    			v.Frame.BackgroundTransparency = 1 - opacity
    		end
    	end,
    	Darker = true,
    })
    LayerCounter = BedPlates:CreateToggle({
    	Name = 'Layer Counter',
    	Tooltip = 'Shows the number of protection layers on your bed',
    	Function = function(callback)
    		if LayerColor and LayerColor.Object then
    			LayerColor.Object.Visible = callback
    		end
    		refreshAll()
    	end,
    	Default = true,
    })
    LayerColor = BedPlates:CreateColorSlider({
    	Name = 'Counter Text Color',
    	DefaultSat = 0,
    	DefaultValue = 1,
    	Function = function()
    		updateLayerTextColor()
    	end,
    	Visible = LayerCounter.Enabled,
    })
    LayerNotify = BedPlates:CreateToggle({
    	Name = 'Notify New Layer',
    	Tooltip = 'Notifies you when a new layer of blocks is added to a bed',
    	Default = false,
    })
    ObsidianOnly = BedPlates:CreateToggle({
    	Name = 'Obsidian Only',
    	Tooltip = 'Only notify when the added layer is obsidian (requires Notify New Layer)',
    	Default = false,
    })
end)

run(function()
    local Breaker
    local Mode
    local Range
    local Angle
    local AutoTool
    local BreakSpeed
    local UpdateRate
    local Custom
    local Bed
    local Tesla
    local Hive
    local LuckyBlock
    local IronOre
    local Effect
    local CustomHealth = {}
    local Animation
    local SelfBreak
    local InstantBreak
    local LimitItem
    local customlist, parts = {}, {}
    
    local function customHealthbar(self, blockRef, health, maxHealth, changeHealth, block)
        if block:GetAttribute('NoHealthbar') then return end
        if not self.healthbarPart or not self.healthbarBlockRef or self.healthbarBlockRef.blockPosition ~= blockRef.blockPosition then
            self.healthbarMaid:DoCleaning()
            self.healthbarBlockRef = blockRef
            local create = bedwars.Roact.createElement
            local percent = math.clamp(health / maxHealth, 0, 1)
            local cleanCheck = true
            local part = Instance.new('Part')
            part.Size = Vector3.one
            part.CFrame = CFrame.new(bedwars.BlockController:getWorldPosition(blockRef.blockPosition))
            part.Transparency = 1
            part.Anchored = true
            part.CanCollide = false
            part.Parent = workspace
            self.healthbarPart = part
            bedwars.QueryUtil:setQueryIgnored(self.healthbarPart, true)
    
            local mounted = bedwars.Roact.mount(create('BillboardGui', {
                Size = UDim2.fromOffset(249, 102),
                StudsOffset = Vector3.new(0, 2.5, 0),
                Adornee = part,
                MaxDistance = 40,
                AlwaysOnTop = true
            }, {
                create('Frame', {
                    Size = UDim2.fromOffset(160, 50),
                    Position = UDim2.fromOffset(44, 32),
                    BackgroundColor3 = Color3.new(),
                    BackgroundTransparency = 0.5
                }, {
                    create('UICorner', {CornerRadius = UDim.new(0, 5)}),
                    create('ImageLabel', {
                        Size = UDim2.new(1, 89, 1, 52),
                        Position = UDim2.fromOffset(-48, -31),
                        BackgroundTransparency = 1,
                        Image = getcustomasset('vain/assets/new/blur.png'),
                        ScaleType = Enum.ScaleType.Slice,
                        SliceCenter = Rect.new(52, 31, 261, 502)
                    }),
                    create('TextLabel', {
                        Size = UDim2.fromOffset(145, 14),
                        Position = UDim2.fromOffset(13, 12),
                        BackgroundTransparency = 1,
                        Text = bedwars.ItemMeta[block.Name].displayName or block.Name,
                        TextXAlignment = Enum.TextXAlignment.Left,
                        TextYAlignment = Enum.TextYAlignment.Top,
                        TextColor3 = Color3.new(),
                        TextScaled = true,
                        Font = Enum.Font.Arial
                    }),
                    create('TextLabel', {
                        Size = UDim2.fromOffset(145, 14),
                        Position = UDim2.fromOffset(12, 11),
                        BackgroundTransparency = 1,
                        Text = bedwars.ItemMeta[block.Name].displayName or block.Name,
                        TextXAlignment = Enum.TextXAlignment.Left,
                        TextYAlignment = Enum.TextYAlignment.Top,
                        TextColor3 = color.Dark(uipallet.Text, 0.16),
                        TextScaled = true,
                        Font = Enum.Font.Arial
                    }),
                    create('Frame', {
                        Size = UDim2.fromOffset(138, 4),
                        Position = UDim2.fromOffset(12, 32),
                        BackgroundColor3 = uipallet.Main
                    }, {
                        create('UICorner', {CornerRadius = UDim.new(1, 0)}),
                        create('Frame', {
                            [bedwars.Roact.Ref] = self.healthbarProgressRef,
                            Size = UDim2.fromScale(percent, 1),
                            BackgroundColor3 = Color3.fromHSV(math.clamp(percent / 2.5, 0, 1), 0.89, 0.75)
                        }, {create('UICorner', {CornerRadius = UDim.new(1, 0)})})
                    })
                })
            }), part)
    
            self.healthbarMaid:GiveTask(function()
                cleanCheck = false
                self.healthbarBlockRef = nil
                bedwars.Roact.unmount(mounted)
                if self.healthbarPart then
                    self.healthbarPart:Destroy()
                end
                self.healthbarPart = nil
            end)
    
            bedwars.RuntimeLib.Promise.delay(5):andThen(function()
                if cleanCheck then
                    self.healthbarMaid:DoCleaning()
                end
            end)
        end
    
        local newpercent = math.clamp((health - changeHealth) / maxHealth, 0, 1)
        tweenService:Create(self.healthbarProgressRef:getValue(), TweenInfo.new(0.3), {
            Size = UDim2.fromScale(newpercent, 1), BackgroundColor3 = Color3.fromHSV(math.clamp(newpercent / 2.5, 0, 1), 0.89, 0.75)
        }):Play()
    end
    
    local hit = 0
    
    local function attemptBreak(tab, localPosition)
        if not tab then return end
        for _, v in tab do
            if (v.Position - localPosition).Magnitude < Range.Value and bedwars.BlockController:isBlockBreakable({blockPosition = v.Position / 3}, lplr) then
                if not SelfBreak.Enabled and v:GetAttribute('PlacedByUserId') == lplr.UserId then continue end
                if (v:GetAttribute('BedShieldEndTime') or 0) > workspace:GetServerTimeNow() then continue end
                if LimitItem.Enabled and not (store.hand.tool and bedwars.ItemMeta[store.hand.tool.Name].breakBlock) then continue end
    
                hit += 1
                local target, path, endpos = bedwars.breakBlock(v, Effect.Enabled, Animation.Enabled, CustomHealth.Enabled and customHealthbar or nil, AutoTool.Enabled, breakmethods[Mode.Value], Angle.Value)
                if path then
                    local currentnode = target
                    for _, part in parts do
                        part.Position = currentnode or Vector3.zero
                        if currentnode then
                            part.BoxHandleAdornment.Color3 = currentnode == endpos and Color3.new(1, 0.2, 0.2) or currentnode == target and Color3.new(0.2, 0.2, 1) or Color3.new(0.2, 1, 0.2)
                        end
                        currentnode = path[currentnode]
                    end
                end
    
                task.wait(InstantBreak.Enabled and (store.damageBlockFail > tick() and 4.5 or 0) or BreakSpeed.Value)
    
                return true
            end
        end
    
        return false
    end
    
    Breaker = vain.Categories.Minigames:CreateModule({
        Name = 'Nuker',
        Tooltip = 'Automatically breaks target blocks within range',
        Function = function(callback)
            if callback then
                for _ = 1, 30 do
                    local part = Instance.new('Part')
                    part.Anchored = true
                    part.CanQuery = false
                    part.CanCollide = false
                    part.Transparency = 1
                    part.Parent = gameCamera
                    local highlight = Instance.new('BoxHandleAdornment')
                    highlight.Size = Vector3.one
                    highlight.AlwaysOnTop = true
                    highlight.ZIndex = 1
                    highlight.Transparency = 0.5
                    highlight.Adornee = part
                    highlight.Parent = part
                    table.insert(parts, part)
                end
    
                local beds = collection('bed', Breaker)
                local luckyblock = collection('LuckyBlock', Breaker)
                local ironores = collection('iron_ore_mesh_block', Breaker)
                local teslas = collection('tesla-trap', Breaker, function(tab, obj)
    				task.delay(0.1, function()
    					local player = playersService:GetPlayerByUserId(obj:GetAttribute('PlacedByUserId'))
    					if player and player:GetAttribute('Team') ~= lplr:GetAttribute('Team') then
    						table.insert(tab, obj)
    					end
    				end)
    			end)
    			local hives = collection('beehive', Breaker, function(tab, obj)
    				task.delay(0.1, function()
    					local player = playersService:GetPlayerByUserId(obj:GetAttribute('PlacedByUserId'))
    					if player and player:GetAttribute('Team') ~= lplr:GetAttribute('Team') then
    						table.insert(tab, obj)
    					end
    				end)
    			end)
                
                customlist = collection('block', Breaker, function(tab, obj)
                    if table.find(Custom.ListEnabled, obj.Name) then
                        table.insert(tab, obj)
                    end
                end)
    
                repeat
                    task.wait(1 / UpdateRate.Value)
                    if not Breaker.Enabled then break end
                    if entitylib.isAlive then
                        local localPosition = entitylib.character.RootPart.Position
    
                        if attemptBreak(Bed.Enabled and beds, localPosition) then continue end
                        if attemptBreak(Tesla.Enabled and teslas, localPosition) then continue end
                        if attemptBreak(Hive.Enabled and hives, localPosition) then continue end
                        if attemptBreak(customlist, localPosition) then continue end
                        if attemptBreak(LuckyBlock.Enabled and luckyblock, localPosition) then continue end
                        if attemptBreak(IronOre.Enabled and ironores, localPosition) then continue end
    
                        for _, v in parts do
                            v.Position = Vector3.zero
                        end
                    end
                until not Breaker.Enabled
            else
                for _, v in parts do
                    v:ClearAllChildren()
                    v:Destroy()
                end
                table.clear(parts)
            end
        end,
        Tooltip = 'Break blocks around you automatically'
    })
    local methods = {}
    for i in breakmethods do
        table.insert(methods, i)
    end
    Mode = Breaker:CreateDropdown({
        Name = 'Break mode',
        Tooltip = 'Selects the block-breaking strategy',
        List = methods,
        Default = methods[1]
    })
    Range = Breaker:CreateSlider({
        Name = 'Break range',
        Tooltip = 'Maximum distance in studs to break blocks',
        Min = 1,
        Max = 30,
        Default = 30,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
    BreakSpeed = Breaker:CreateSlider({
        Name = 'Break speed',
        Tooltip = 'How fast blocks are broken (higher = faster)',
        Min = 0,
        Max = 0.3,
        Default = 0.25,
        Decimal = 100,
        Suffix = 'seconds'
    })
    Angle = Breaker:CreateSlider({
        Name = 'Max angle',
        Tooltip = 'Maximum angle in degrees from your look direction to engage',
        Min = 1,
        Max = 360,
        Default = 120
    })
    UpdateRate = Breaker:CreateSlider({
        Name = 'Update rate',
        Tooltip = 'How often to scan for targets (seconds)',
        Min = 1,
        Max = 120,
        Default = 60,
        Suffix = 'hz'
    })
    Custom = Breaker:CreateTextList({
        Name = 'Custom',
        Tooltip = 'Custom block break speed overrides (one per line)',
        Function = function()
            if not customlist then return end
            table.clear(customlist)
            for _, obj in store.blocks do
                if table.find(Custom.ListEnabled, obj.Name) then
                    table.insert(customlist, obj)
                end
            end
        end
    })
    Bed = Breaker:CreateToggle({
        Name = 'Break Bed',
        Tooltip = 'Targets enemy beds for automatic breaking',
        Default = true
    })
    Tesla = Breaker:CreateToggle({
    	Name = 'Break Tesla',
    	Tooltip = 'Targets Tesla coil structures for automatic breaking',
    	Default = true,
    })
    Hive = Breaker:CreateToggle({
    	Name = 'Break Hive',
    	Tooltip = 'Targets beehive structures for automatic breaking',
    	Default = true,
    })
    LuckyBlock = Breaker:CreateToggle({
        Name = 'Break Lucky Block',
        Tooltip = 'Targets lucky blocks for automatic breaking',
        Default = true
    })
    IronOre = Breaker:CreateToggle({
        Name = 'Break Iron Ore',
        Tooltip = 'Targets iron ore deposits for automatic breaking',
        Default = true
    })
    Effect = Breaker:CreateToggle({
        Name = 'Show Healthbar & Effects',
        Tooltip = 'Renders health bars and status effects on the target',
        Function = function(callback)
            if CustomHealth.Object then
                CustomHealth.Object.Visible = callback
            end
        end,
        Default = true
    })
    CustomHealth = Breaker:CreateToggle({
        Name = 'Custom Healthbar',
        Tooltip = 'Enables a custom-styled health bar overlay on the target',
        Default = true,
        Darker = true
    })
    Animation = Breaker:CreateToggle({Name = 'Animation', Tooltip = 'Shows the kit ability animation when activated'})
    SelfBreak = Breaker:CreateToggle({Name = 'Self Break', Tooltip = 'Allows Breaker to target and remove blocks you placed yourself'})
    InstantBreak = Breaker:CreateToggle({Name = 'Instant Break', Tooltip = 'Bypasses the break animation delay — blocks break immediately as fast as the server allows'})
    AutoTool = Breaker:CreateToggle({Name = 'Auto Tool', Tooltip = 'Automatically equips the most effective tool for each block type being broken'})
    LimitItem = Breaker:CreateToggle({
        Name = 'Limit to items',
        Tooltip = 'Only breaks when tools are held'
    })
end)

--[[
    Kits
]]

run(function()
    local AutoAdetunde

    AutoAdetunde = vain.Categories.Kits:CreateModule({
    	Name = 'Auto Adetunde',
    	Tooltip = 'Automates the Adetunde kit ability',
    	Function = function(callback)
    		if callback then
    			repeat
    				local crystal = getItem('frost_crystal')
    				if crystal then
    					for i, v in bedwars.AdetundeUtil.getUpgradesFromHammer(lplr) do
    						local new = getItem('frost_crystal')
    						if not new then
    							break
    						end

    						crystal = new

    						local nextUpgrade = AutoAdetunde.Options['Buy ' .. i].Enabled and bedwars.AdetundeUpgradeMeta[i].tiers[v + 1] or nil
    						if nextUpgrade then
    							if crystal.amount >= nextUpgrade.price then
    								bedwars.Client:Get('UpgradeFrostyHammer'):CallServer(i)
    								task.wait(0.1)
    							end
    						end
    					end
    				end
    				task.wait(0.5)
    			until not AutoAdetunde.Enabled
    		end
    	end,
    	Tooltip = 'Automatically upgrades ur frosty hammer'
    })

