    MinHP = AutoCaitlyn:CreateSlider({
    	Name = 'Minimum Health',
    	Tooltip = 'How low they have to be before contracting',
    	Min = 1,
    	Max = 100,
    	Default = 30,
    	Darker = true
    })
    Range = AutoCaitlyn:CreateSlider({
    	Name = 'Range',
    	Tooltip = 'Maximum distance in studs (raise it up to 500 for long-range On Hit + Low)',
    	Min = 1,
    	Max = 500,
    	Default = 50,
    	Suffix = function(val)
    		return val <= 1 and 'stud' or 'studs'
    	end
    })
end)

run(function()
    local AutoDavey
    local Switch
    local Break
    local Jump

    local old

    AutoDavey = vain.Categories.Kits:CreateModule({
    	Name = 'Auto Davey',
    	Tooltip = 'Automates the Davey kit cannon',
    	Function = function(call)
    		if call then
    			old = bedwars.CannonHandController.launchSelf
