run(function()
	local KitESP = {Enabled = false}
	local Notify
	local Background
	local Color
	local espobjs = {}
	local espfold = Instance.new("Folder")
	espfold.Parent = vain.gui
	local Tracers
	local tracerLines = {} -- [adornee part] = Drawing 'Line'
	local tracerConn
	local function clearTracers()
		for _, ln in tracerLines do pcall(function() ln:Remove() end) end
		table.clear(tracerLines)
	end
	local function updateTracers()
		if not (Tracers and Tracers.Enabled) then return end
		local view = gameCamera.ViewportSize
		local ox, oy = view.X / 2, view.Y
		local col = (Color and Color.Hue) and Color3.fromHSV(Color.Hue, Color.Sat, Color.Value) or Color3.new(1, 1, 1)
		for part, ln in tracerLines do
			if not espobjs[part] or (typeof(part) == 'Instance' and not part.Parent) then
				pcall(function() ln:Remove() end)
				tracerLines[part] = nil
			end
		end
		for part in espobjs do
			if typeof(part) == 'Instance' and part:IsA('BasePart') then
				local sp, vis = gameCamera:WorldToViewportPoint(part.Position)
				local ln = tracerLines[part]
				if vis and sp.Z > 0 then
					if not ln then ln = Drawing.new('Line') ln.Thickness = 1 tracerLines[part] = ln end
					ln.Color = col
					ln.From = Vector2.new(ox, oy)
					ln.To = Vector2.new(sp.X, sp.Y)
					ln.Visible = true
				elseif ln then
					ln.Visible = false
				end
			end
		end
	end

	local function espadd(v, icon)
		if not v then return end -- adornee (e.g. a model's PrimaryPart) may be nil
		local billboard = Instance.new("BillboardGui")
		billboard.Parent = espfold
		billboard.Name = icon
		billboard.StudsOffsetWorldSpace = Vector3.new(0, 3, 0)
		billboard.Size = UDim2.fromOffset(36, 36)
		billboard.AlwaysOnTop = true
		billboard.Adornee = v
		local image = Instance.new("ImageLabel")
		image.BorderSizePixel = 0
		image.Image = bedwars.getIcon({itemType = icon}, true)
		image.BackgroundColor3 = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
		image.BackgroundTransparency = 1 - (Background.Enabled and Color.Opacity or 0)
		image.Size = UDim2.fromOffset(36, 36)
		image.AnchorPoint = Vector2.new(0.5, 0.5)
		image.Parent = billboard
		local blur = addBlur(image)
		local uicorner = Instance.new("UICorner")
		uicorner.CornerRadius = UDim.new(0, 4)
		uicorner.Parent = image
		espobjs[v] = billboard
	end

	-- Resolve the part to adorn: tagged kit objects are sometimes a Model (use its
	-- PrimaryPart) and sometimes a BasePart itself (use it directly). The old code
	-- always used v.PrimaryPart, so BasePart-tagged objects (e.g. bees) resolved to
	-- nil -> nothing was ever shown.
	local function adorneeOf(v)
		if typeof(v) ~= 'Instance' then return nil end
		if v:IsA('BasePart') then return v end
		if v:IsA('Model') then return v.PrimaryPart or v:FindFirstChildWhichIsA('BasePart', true) end
		return v:FindFirstChildWhichIsA('BasePart', true)
	end

	local function addKit(tag, icon, custom)
		if (not custom) then
			KitESP:Clean(collectionService:GetInstanceAddedSignal(tag):Connect(function(v)
				espadd(adorneeOf(v), icon)
			end))
			KitESP:Clean(collectionService:GetInstanceRemovedSignal(tag):Connect(function(v)
				local a = adorneeOf(v)
				if a and espobjs[a] then
					espobjs[a]:Destroy()
					espobjs[a] = nil
				end
			end))
			for i,v in pairs(collectionService:GetTagged(tag)) do
				espadd(adorneeOf(v), icon)
			end
		else
			local function check(v)
				if v.Name == tag and v.ClassName == "Model" then
					espadd(v.PrimaryPart, icon)
				end
			end
			KitESP:Clean(game.Workspace.ChildAdded:Connect(check))
			KitESP:Clean(game.Workspace.ChildRemoved:Connect(function(v)
				pcall(function()
					if espobjs[v.PrimaryPart] then
						espobjs[v.PrimaryPart]:Destroy()
						espobjs[v.PrimaryPart] = nil
					end
				end)
			end))
			for i,v in pairs(game.Workspace:GetChildren()) do
				check(v)
			end
		end
	end

	local esptbl = {
		["metal_detector"] = {
			{"hidden-metal", "iron"}
		},
		["beekeeper"] = {
			{"bee", "bee"}
		},
		["bigman"] = {
			{"treeOrb", "natures_essence_1"}
		},
		["alchemist"] = {
			{"Thorns", "thorns", true},
			{"Mushrooms", "mushrooms", true},
			{"Flower", "wild_flower", true},
			{"alchemy_crystal", "spirit"}
		},
		["star_collector"] = {
			{"CritStar", "crit_star", true},
			{"VitalityStar", "vitality_star", true}
		},
		["spirit_gardener"] = {
			{"SpiritGardenerEnergy", "spirit", true}
		},
		["spirit_summoner"] = {
			{"spiritGolem", "spirit"}
		},
		["summoner"] = {
			{"spiritGolem", "spirit"}
		},
		["raven"] = {
			{"raven", "raven_kit"}
		},
		["jellyfish"] = {
			{"jellyfish", "jellyfish_kit"}
		},
		["axolotl"] = {
			{"axolotl_model", "axolotl_kit"}
		}
	}

	local kitESPCurrent = nil
	KitESP = vain.Categories.Render:CreateModule({
		Name = "KitESP",
		Tooltip = "ESP for the objects your equipped kit cares about (bees, ghosts, stars, rocks, etc.)",
		Function = function(callback)
			if callback then
				kitESPCurrent = nil
				espfold:ClearAllChildren()
				table.clear(espobjs)
				if tracerConn then tracerConn:Disconnect() end
				tracerConn = runService.RenderStepped:Connect(updateTracers)
				task.spawn(function()
					-- Rebuild whenever the equipped kit changes, so it works when
					-- enabled MID-MATCH (kit already equipped) and after a new match /
					-- kit switch -- not just the first time a kit appears.
					while KitESP.Enabled do
						local kit = store.equippedKit or ""
						if kit ~= kitESPCurrent then
							-- rebuild for the new kit (visuals cleared; the tag listeners
							-- from addKit are cleaned by KitESP:Clean on module disable)
							espfold:ClearAllChildren()
							table.clear(espobjs)
							local p1 = kit ~= "" and esptbl[kit]
							if p1 then
								for _, v in pairs(p1) do
									addKit(unpack(v))
								end
								if Notify and Notify.Enabled then
									vain:CreateNotification('KitESP', 'ESP active for kit: ' .. kit, 4, 'check')
								end
							elseif kit ~= "" and Notify and Notify.Enabled then
								vain:CreateNotification('KitESP', 'Kit "' .. kit .. '" has no ESP objects', 4, 'alert')
							end
							kitESPCurrent = kit
						end
						task.wait(0.5)
					end
					espfold:ClearAllChildren()
					table.clear(espobjs)
					kitESPCurrent = nil
				end)
			else
				espfold:ClearAllChildren()
				table.clear(espobjs)
				kitESPCurrent = nil
				if tracerConn then tracerConn:Disconnect() tracerConn = nil end
				clearTracers()
			end
		end
	})

	Notify = KitESP:CreateToggle({
		Name = 'Notify',
		Tooltip = 'Announce which kit was detected and whether it has ESP objects',
		Default = false
	})
	Tracers = KitESP:CreateToggle({
		Name = 'Tracers',
		Tooltip = 'Draw a line from the bottom of your screen to each tracked object',
		Default = false,
		Function = function(callback) if not callback then clearTracers() end end
	})
	Background = KitESP:CreateToggle({
		Name = 'Background',
		Function = function(callback)
			if Color and Color.Object then Color.Object.Visible = callback end
			for _, v in espobjs do
				v.ImageLabel.BackgroundTransparency = 1 - (callback and Color.Opacity or 0)
				v.Blur.Visible = callback
			end
		end,
		Default = true
	})
	Color = KitESP:CreateColorSlider({
		Name = 'Background Color',
		DefaultValue = 0,
		DefaultOpacity = 0.5,
		Function = function(hue, sat, val, opacity)
			for _, v in espobjs do
				v.ImageLabel.BackgroundColor3 = Color3.fromHSV(hue, sat, val)
				v.ImageLabel.BackgroundTransparency = 1 - opacity
			end
		end,
		Darker = true
	})
end)

run(function()
	local Killaura
	local Targets
	local Sort
	local SwingRange
	local AttackRange
	local ChargeTime
	local UpdateRate
	local AngleSlider
	local MaxTargets
	local Mouse
	local Swing
	local GUI
	local BoxSwingColor
	local BoxAttackColor
	local ParticleTexture
	local ParticleColor1
	local ParticleColor2
	local ParticleSize
	local Face
	local Animation
	local AnimationMode
	local AnimationSpeed
	local AnimationTween
	local Limit
	local LegitAura = {}
	local AttackCheck
	local kitChecks
	local FROZEN_THRESHOLD = 10
	local Particles, Boxes = {}, {}
	local anims, AnimDelay, AnimTween, armC0 = vain.Libraries.auraanims, tick()
	local AttackRemote = {FireServer = function() end}
	task.spawn(function()
		AttackRemote = bedwars.Client:Get(remotes.AttackEntity).instance
	end)

	local function flatAngle(selfpos, targetpos, facing)
		local flat = (targetpos - selfpos) * Vector3.new(1, 0, 1)
		if flat.Magnitude < 0.001 then return 0 end
		return math.acos(math.clamp(facing:Dot(flat.Unit), -1, 1))
	end

	local function flatFacing(rootCFrame)
		local lv = rootCFrame.LookVector * Vector3.new(1, 0, 1)
		if lv.Magnitude < 0.001 then return rootCFrame.RightVector * Vector3.new(1, 0, 1) end
		return lv.Unit
	end

	local lastFiredSwing = 0

	kitChecks = {
		['Sophia'] = function() return isFrozen(nil, FROZEN_THRESHOLD) end,
		['Sigrid'] = function() return entitylib.isAlive and lplr.Character and lplr.Character:FindFirstChild('elk') ~= nil end,
	}

	local function getAttackData()
		if AttackCheck and AttackCheck.Enabled then
			local stunTime = lplr.Character and lplr.Character:GetAttribute('StunnedUntilTime')
			if stunTime and stunTime > workspace:GetServerTimeNow() then return false end
			if kitChecks then
				for _, check in pairs(kitChecks) do
					if check() then return false end
				end
			end
		end
		if Mouse and Mouse.Enabled then
			local mousePressed = inputService:IsMouseButtonPressed(Enum.UserInputType.MouseButton1)
			if not mousePressed then return false end
		end
		if GUI and GUI.Enabled then
			if bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then return false end
		end
		local sword = (Limit and Limit.Enabled) and store.hand or store.tools.sword
		if not sword or not sword.tool then return false end
		local meta = bedwars.ItemMeta[sword.tool.Name]
		if not meta or not meta.sword then return false end
		if Limit and Limit.Enabled then
			if store.hand.toolType ~= 'sword' or bedwars.DaoController.chargingMaid then return false end
		end
		if LegitAura and LegitAura.Enabled then
			local lastSwing = bedwars.SwordController.lastSwing or 0
			if (tick() - lastSwing) > 0.5 then return false end
			if lastSwing == lastFiredSwing then return false end
		end
		return sword, meta
	end

	Killaura = vain.Categories.Blatant:CreateModule({
		Name = 'GrandKillaura',
		Tooltip = 'Enhanced killaura that attacks multiple targets at once',
		Function = function(callback)
			if callback then
				if inputService.TouchEnabled then
					pcall(function()
						lplr.PlayerGui.MobileUI['2'].Visible = Limit and Limit.Enabled
					end)
				end

				if Animation and Animation.Enabled and not (identifyexecutor and table.find({'Argon', 'Delta'}, ({identifyexecutor()})[1])) then
					local fake = {
						Controllers = {
							ViewmodelController = {
								isVisible = function() return not Attacking end,
								playAnimation = function(...)
									if not Attacking then
										bedwars.ViewmodelController:playAnimation(select(2, ...))
									end
								end
							}
						}
					}

					task.spawn(function()
						local started = false
						repeat
							if AttackCheck and AttackCheck.Enabled then
								local stunTime = lplr.Character and lplr.Character:GetAttribute('StunnedUntilTime')
								if stunTime and stunTime > workspace:GetServerTimeNow() then
									Attacking = false
									store.KillauraTarget = nil
									task.wait(0.3)
									continue
								end
								if kitChecks then
									local blocked = false
									for _, check in pairs(kitChecks) do
										if check() then blocked = true break end
									end
									if blocked then
										Attacking = false
										store.KillauraTarget = nil
										task.wait(0.3)
										continue
									end
								end
							end
							if Attacking then
								if not armC0 then
									armC0 = gameCamera.Viewmodel.RightHand.RightWrist.C0
								end
								local first = not started
								started = true
								if AnimationMode.Value == 'Random' then
									anims.Random = {{CFrame = CFrame.Angles(math.rad(math.random(1, 360)), math.rad(math.random(1, 360)), math.rad(math.random(1, 360))), Time = 0.12}}
								end
								for _, v in anims[AnimationMode.Value] do
									AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(first and (AnimationTween.Enabled and 0.001 or 0.1) or v.Time / AnimationSpeed.Value, Enum.EasingStyle.Linear), {
										C0 = armC0 * v.CFrame
									})
									AnimTween:Play()
									AnimTween.Completed:Wait()
									first = false
									if not Killaura.Enabled or not Attacking then break end
								end
							elseif started then
								started = false
								AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
									C0 = armC0
								})
								AnimTween:Play()
							end
							if not started then task.wait(1 / UpdateRate.Value) end
						until not Killaura.Enabled or not Animation.Enabled
					end)
				end

				local swingCooldown = 0
				repeat
					if AttackCheck and AttackCheck.Enabled then
						local stunTime = lplr.Character and lplr.Character:GetAttribute('StunnedUntilTime')
						if stunTime and stunTime > workspace:GetServerTimeNow() then
							Attacking = false
							store.KillauraTarget = nil
							task.wait(0.3)
							continue
						end
						if kitChecks then
							local blocked = false
							for _, check in pairs(kitChecks) do
								if check() then blocked = true break end
							end
							if blocked then
								Attacking = false
								store.KillauraTarget = nil
								task.wait(0.3)
								continue
							end
						end
					end

					local attacked, sword, meta = {}, getAttackData()
					Attacking = false
					store.KillauraTarget = nil

					if sword then
						local plrs = entitylib.AllPosition({
							Range = SwingRange.Value,
							Wallcheck = Targets.Walls.Enabled or nil,
							Part = 'RootPart',
							Players = Targets.Players.Enabled,
							NPCs = Targets.NPCs.Enabled,
							Limit = MaxTargets.Value,
							Sort = sortmethods[Sort.Value]
						})

						if #plrs > 0 then
							switchItem(sword.tool, 0)
							local selfpos = entitylib.character.RootPart.Position
							local facing = flatFacing(entitylib.character.RootPart.CFrame)
							local maxAngle = math.rad(AngleSlider.Value) / 2

							for _, v in plrs do
								local delta = (v.RootPart.Position - selfpos)
								if flatAngle(selfpos, v.RootPart.Position, facing) > maxAngle then continue end

								table.insert(attacked, {
									Entity = v,
									Check = delta.Magnitude > AttackRange.Value and BoxSwingColor or BoxAttackColor
								})
								targetinfo.Targets[v] = tick() + 1

								if not Attacking then
									Attacking = true
									store.KillauraTarget = v
									local inLegitRange = delta.Magnitude < 14.4
									local allowSwingAnim = not (Swing and Swing.Enabled) and AnimDelay < tick() and not (LegitAura and LegitAura.Enabled) and not (Animation and Animation.Enabled)
									if allowSwingAnim then
										AnimDelay = tick() + (meta.sword.respectAttackSpeedForEffects and meta.sword.attackSpeed or math.max(ChargeTime.Value, 0.11))
										bedwars.SwordController:playSwordEffect(meta, false)
										if meta.displayName:find(' Scythe') then
											bedwars.ScytheController:playLocalAnimation()
										end
										if vain.ThreadFix then
											setthreadidentity(8)
										end
									end
								end

								if delta.Magnitude > AttackRange.Value then continue end
								if delta.Magnitude < 14.4 and (tick() - swingCooldown) < math.max(ChargeTime.Value, 0.02) then continue end

								local actualRoot = v.Character.PrimaryPart
								if not actualRoot then continue end

								local dir = CFrame.lookAt(selfpos, actualRoot.Position).LookVector
								local pos = selfpos + dir * math.max(delta.Magnitude - 14.399, 0)
								swingCooldown = tick()
								if LegitAura and LegitAura.Enabled then
									lastFiredSwing = bedwars.SwordController.lastSwing or 0
								end
								bedwars.SwordController.lastAttack = workspace:GetServerTimeNow()
								store.attackReach = (delta.Magnitude * 100) // 1 / 100
								store.attackReachUpdate = tick() + 1

								if delta.Magnitude < 14.4 and ChargeTime.Value > 0.11 then
									AnimDelay = tick()
								end

								do
									local suc, plr = pcall(function() return playersService:GetPlayerFromCharacter(v.Character) end)
									if suc and plr then
										local targetTier = getAccountTier(plr)
										if targetTier >= 99 then continue end
										if targetTier == 4 and getAccountTier(lplr) <= 2 then
											local uid = plr.UserId
											local now = tick()
											if _t4LastHit[uid] and now - _t4LastHit[uid] < (10/32) then continue end
											_t4LastHit[uid] = now
										end
									end
								end
								AttackRemote:FireServer({
									weapon = sword.tool,
									chargedAttack = {chargeRatio = 0},
									lastSwingServerTimeDelta = math.clamp(lastSwingServerTimeDelta, 0.2, 0.8),
									entityInstance = v.Character,
									validate = {
										raycast = {
											cameraPosition = {value = pos},
											cursorDirection = {value = dir}
										},
										targetPosition = {value = actualRoot.Position},
										selfPosition = {value = pos}
									}
								})
							end
						end
					end

					pcall(function()
						for i, v in Boxes do
							v.Adornee = attacked[i] and attacked[i].Entity.RootPart or nil
							if v.Adornee then
								v.Color3 = Color3.fromHSV(attacked[i].Check.Hue, attacked[i].Check.Sat, attacked[i].Check.Value)
								v.Transparency = 1 - attacked[i].Check.Opacity
							end
						end
						for i, v in Particles do
							v.Position = attacked[i] and attacked[i].Entity.RootPart.Position or Vector3.new(9e9, 9e9, 9e9)
							v.Parent = attacked[i] and gameCamera or nil
						end
					end)

					if Face and Face.Enabled and attacked[1] then
						local vec = attacked[1].Entity.RootPart.Position * Vector3.new(1, 0, 1)
						entitylib.character.RootPart.CFrame = CFrame.lookAt(entitylib.character.RootPart.Position, Vector3.new(vec.X, entitylib.character.RootPart.Position.Y + 0.001, vec.Z))
					end

					task.wait(1 / UpdateRate.Value)
				until not Killaura.Enabled
			else
				store.KillauraTarget = nil
				for _, v in Boxes do v.Adornee = nil end
				for _, v in Particles do v.Parent = nil end
				if inputService.TouchEnabled then
					pcall(function() lplr.PlayerGui.MobileUI['2'].Visible = true end)
				end
				Attacking = false
				if armC0 then
					AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween and AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
						C0 = armC0
					})
					AnimTween:Play()
				end
			end
		end,
		Tooltip = 'Attack players around you\nwithout aiming at them.'
	})

	Targets = Killaura:CreateTargets({Players = true, NPCs = true, Tooltip = 'Configure which types of targets to include'})

	local methods = {'Damage', 'Distance'}
	for i in sortmethods do
		if not table.find(methods, i) then table.insert(methods, i) end
	end

	SwingRange = Killaura:CreateSlider({
		Name = 'Swing range', Min = 1, Max = 18, Default = 18,
		Tooltip = 'Distance at which the swing animation begins',
		Suffix = function(val) return val == 1 and 'stud' or 'studs' end
	})
	AttackRange = Killaura:CreateSlider({
		Name = 'Attack range', Min = 1, Max = 18, Default = 18,
		Tooltip = 'Distance at which the hit packet is sent',
		Suffix = function(val) return val == 1 and 'stud' or 'studs' end
	})
	ChargeTime = Killaura:CreateSlider({
		Name = 'Swing time', Min = 0, Max = 0.5, Default = 0.42, Decimal = 100,
		Tooltip = 'Minimum seconds between swings',
	})
	AngleSlider = Killaura:CreateSlider({Name = 'Max angle', Min = 1, Max = 360, Default = 360, Tooltip = 'Maximum angle in degrees from your look direction to engage'})
	UpdateRate = Killaura:CreateSlider({Name = 'Update rate', Min = 1, Max = 120, Default = 60, Suffix = 'hz', Tooltip = 'How often to scan for targets (seconds)'})
	MaxTargets = Killaura:CreateSlider({Name = 'Max targets', Min = 1, Max = 5, Default = 5, Tooltip = 'Maximum number of enemies to attack simultaneously'})
	Sort = Killaura:CreateDropdown({Name = 'Target Mode', List = methods, Tooltip = 'Selects how targets are prioritized and selected', ItemTooltips = {
		Distance = 'Targets the closest enemy by stud distance',
		Health = 'Targets the enemy with the lowest remaining health',
		Angle = 'Targets the enemy closest to your look direction',
		Cursor = 'Targets the enemy nearest to your mouse cursor',
		Damage = 'Targets the enemy who most recently took damage',
		Threat = 'Targets the enemy judged to be the greatest combat threat',
		Kit = 'Prioritizes dangerous kit users (Hannah, Spirit Assassin, etc.)',
	}})
	Mouse = Killaura:CreateToggle({Name = 'Require mouse down', Tooltip = 'Only activates while the left mouse button is held'})
	Swing = Killaura:CreateToggle({Name = 'No Swing', Tooltip = 'Sends hit packets without playing the swing animation'})
	GUI = Killaura:CreateToggle({Name = 'GUI check', Tooltip = 'Pauses the module when a GUI menu is open'})
	Killaura:CreateToggle({
		Name = 'Show target',
		Tooltip = 'Renders a visual indicator on the current target',
		Function = function(callback)
			BoxSwingColor.Object.Visible = callback
			BoxAttackColor.Object.Visible = callback
			if callback then
				for i = 1, 10 do
					local box = Instance.new('BoxHandleAdornment')
					box.Adornee = nil
					box.AlwaysOnTop = true
					box.Size = Vector3.new(3, 5, 3)
					box.CFrame = CFrame.new(0, -0.5, 0)
					box.ZIndex = 0
					box.Parent = vain.gui
					Boxes[i] = box
				end
			else
				for _, v in Boxes do v:Destroy() end
				table.clear(Boxes)
			end
		end
	})
	BoxSwingColor = Killaura:CreateColorSlider({Name = 'Target Color', Darker = true, DefaultHue = 0.6, DefaultOpacity = 0.5, Visible = false})
	BoxAttackColor = Killaura:CreateColorSlider({Name = 'Attack Color', Darker = true, DefaultOpacity = 0.5, Visible = false})
	Killaura:CreateToggle({
		Name = 'Target particles',
		Tooltip = 'Shows particles on the currently targeted enemy',
		Function = function(callback)
			ParticleTexture.Object.Visible = callback
			ParticleColor1.Object.Visible = callback
			ParticleColor2.Object.Visible = callback
			ParticleSize.Object.Visible = callback
			if callback then
				for i = 1, 10 do
					local part = Instance.new('Part')
					part.Size = Vector3.new(2, 4, 2)
					part.Anchored = true
					part.CanCollide = false
					part.Transparency = 1
					part.CanQuery = false
					part.Parent = Killaura.Enabled and gameCamera or nil
					local particles = Instance.new('ParticleEmitter')
					particles.Brightness = 1.5
					particles.Size = NumberSequence.new(ParticleSize.Value)
					particles.Shape = Enum.ParticleEmitterShape.Sphere
					particles.Texture = ParticleTexture.Value
					particles.Transparency = NumberSequence.new(0)
					particles.Lifetime = NumberRange.new(0.4)
					particles.Speed = NumberRange.new(16)
					particles.Rate = 128
					particles.Drag = 16
					particles.ShapePartial = 1
					particles.Color = ColorSequence.new({
						ColorSequenceKeypoint.new(0, Color3.fromHSV(ParticleColor1.Hue, ParticleColor1.Sat, ParticleColor1.Value)),
						ColorSequenceKeypoint.new(1, Color3.fromHSV(ParticleColor2.Hue, ParticleColor2.Sat, ParticleColor2.Value))
					})
					particles.Parent = part
					Particles[i] = part
				end
			else
				for _, v in Particles do v:Destroy() end
				table.clear(Particles)
			end
		end
	})
	ParticleTexture = Killaura:CreateTextBox({
		Name = 'Texture', Tooltip = 'Roblox asset ID for the particle effect texture', Default = 'rbxassetid://14736249347',
		Function = function()
			for _, v in Particles do v.ParticleEmitter.Texture = ParticleTexture.Value end
		end,
		Darker = true, Visible = false
	})
	ParticleColor1 = Killaura:CreateColorSlider({
		Name = 'Color Begin',
		Function = function(hue, sat, val)
			for _, v in Particles do
				v.ParticleEmitter.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, Color3.fromHSV(hue, sat, val)),
					ColorSequenceKeypoint.new(1, Color3.fromHSV(ParticleColor2.Hue, ParticleColor2.Sat, ParticleColor2.Value))
				})
			end
		end,
		Darker = true, Visible = false
	})
	ParticleColor2 = Killaura:CreateColorSlider({
		Name = 'Color End',
		Function = function(hue, sat, val)
			for _, v in Particles do
				v.ParticleEmitter.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, Color3.fromHSV(ParticleColor1.Hue, ParticleColor1.Sat, ParticleColor1.Value)),
					ColorSequenceKeypoint.new(1, Color3.fromHSV(hue, sat, val))
				})
			end
		end,
		Darker = true, Visible = false
	})
	ParticleSize = Killaura:CreateSlider({
		Name = 'Size', Min = 0, Max = 1, Default = 0.2, Decimal = 100,
		Tooltip = 'Display size of this element',
		Function = function(val)
			for _, v in Particles do v.ParticleEmitter.Size = NumberSequence.new(val) end
		end,
		Darker = true, Visible = false
	})
	Face = Killaura:CreateToggle({Name = 'Face target', Tooltip = 'Rotates your character to face the target during animation'})
	Animation = Killaura:CreateToggle({
		Name = 'Custom Animation',
		Tooltip = 'Plays a custom ability animation instead of the default',
		Function = function(callback)
			AnimationMode.Object.Visible = callback
			AnimationTween.Object.Visible = callback
			AnimationSpeed.Object.Visible = callback
			if Killaura.Enabled then Killaura:Toggle() Killaura:Toggle() end
		end
	})
	local animnames = {}
	for i in anims do table.insert(animnames, i) end
	AnimationMode = Killaura:CreateDropdown({Name = 'Animation Mode', List = animnames, Darker = true, Visible = false, Tooltip = 'Selects the animation style to use'})
	AnimationSpeed = Killaura:CreateSlider({Name = 'Animation Speed', Min = 0, Max = 2, Default = 1, Decimal = 10, Darker = true, Visible = false, Tooltip = 'Adjusts the animation speed value'})
	AnimationTween = Killaura:CreateToggle({Name = 'No Tween', Darker = true, Visible = false, Tooltip = 'Skips smooth interpolation for instant hitbox updates'})
	Limit = Killaura:CreateToggle({
		Name = 'Limit to items',
		Tooltip = 'Only activates when a required item is in your hand',
		Function = function(callback)
			if inputService.TouchEnabled and Killaura.Enabled then
				pcall(function() lplr.PlayerGui.MobileUI['2'].Visible = callback end)
			end
		end,
		Tooltip = 'Only attacks when the sword is held'
	})
	LegitAura = Killaura:CreateToggle({
		Name = 'Swing only',
		Tooltip = 'Only attacks while swinging manually'
	})
	AttackCheck = Killaura:CreateToggle({
		Name = 'Attack Check',
		Tooltip = 'Stops Killaura when stunned, frozen by Sophia, or riding Sigrid elk',
		Default = false
	})
end)

run(function()
    local moduleData = {
        Connection = nil,
        CurrentDuration = 1,
        CachedPrompts = {}
    }
    
    local function updatePrompt(prompt, duration)
        if prompt and prompt:IsA("ProximityPrompt") then
            prompt.HoldDuration = duration
        end
    end
    
    local function updateAllPrompts(duration)
        for prompt in pairs(moduleData.CachedPrompts) do
            if prompt and prompt.Parent then
                prompt.HoldDuration = duration
            else
                moduleData.CachedPrompts[prompt] = nil
            end
        end
    end
    
    local function cacheExistingPrompts()
        moduleData.CachedPrompts = {}
        
        for _, descendant in workspace:GetDescendants() do
            if descendant:IsA("ProximityPrompt") then
                moduleData.CachedPrompts[descendant] = true
                descendant.HoldDuration = moduleData.CurrentDuration
            end
        end
    end
    
	ProximityPromptDuration = vain.Categories.Utility:CreateModule({
		Name = 'ProximityPromptDuration',
		Tooltip = 'Enables the ProximityPromptDuration module',
		Function = function(callback)
			if callback then
				cacheExistingPrompts()
				ProximityPromptDuration:Clean(workspace.DescendantAdded:Connect(function(descendant)
					if descendant:IsA("ProximityPrompt") then
						moduleData.CachedPrompts[descendant] = true
						descendant.HoldDuration = moduleData.CurrentDuration
					end
				end))
			else
				moduleData.CachedPrompts = {}
			end
		end,
		Tooltip = 'Set custom duration for all proximity prompts'
	})
    
    local ProximityDurationSlider = ProximityPromptDuration:CreateSlider({
        Name = 'Duration',
        Tooltip = 'How long the effect lasts in seconds',
        Min = 0,
        Max = 10,
        Default = 1,
        Decimal = 100,
        Suffix = 's',
        Function = function(value)
            moduleData.CurrentDuration = value
            if ProximityPromptDuration.Enabled then
                updateAllPrompts(value)
            end
        end
    })
end)

run(function()
    local old
    local SophiaCheck
    local FROZEN_THRESHOLD = 10

    local NoSlowdown = vain.Categories.Blatant:CreateModule({
        Name = 'NoSlowdown',
        Tooltip = 'Removes all slowing effects applied to your character',
        Function = function(callback)
            local modifier = bedwars.SprintController:getMovementStatusModifier()
            if callback then
                old = modifier.addModifier
                modifier.addModifier = function(self, tab)
                    if SophiaCheck and SophiaCheck.Enabled and isFrozen(nil, FROZEN_THRESHOLD) then
                        return old(self, tab)
                    end

                    if tab.moveSpeedMultiplier then
                        tab.moveSpeedMultiplier = math.max(tab.moveSpeedMultiplier, 1)
                    end
                    return old(self, tab)
                end

                for i in modifier.modifiers do
                    if (i.moveSpeedMultiplier or 1) < 1 then
                        modifier:removeModifier(i)
                    end
                end
            else
                modifier.addModifier = old
                old = nil
            end
        end,
        Tooltip = 'Prevents slowing down when using items.'
    })

    SophiaCheck = NoSlowdown:CreateToggle({
        Name = 'Sophia Check',
        Tooltip = 'Allows slowdown ONLY when completely frozen',
        Default = false
    })
end)

run(function()
    local AutoVanessa
    local oldGetChargeTime
    local lastChargeTime = 0
    
    AutoVanessa = vain.Categories.Kits:CreateModule({
        Name = 'AutoVanessa',
        Tooltip = 'Automates the Vanessa kit ability',
        Function = function(callback)
            if callback then
                task.spawn(function()
                    repeat task.wait() until bedwars.TripleShotProjectileController
                    
                    if bedwars.TripleShotProjectileController then
                        oldGetChargeTime = bedwars.TripleShotProjectileController.getChargeTime
                        
                        bedwars.TripleShotProjectileController.getChargeTime = function(self)
                            return 0
                        end
                        
                        bedwars.TripleShotProjectileController.overchargeStartTime = tick()
                    end
                end)
            else
                if oldGetChargeTime and bedwars.TripleShotProjectileController then
                    bedwars.TripleShotProjectileController.getChargeTime = oldGetChargeTime
                end
                lastChargeTime = 0
            end
        end,
        Tooltip = 'Auto charges Vanessa triple shot'
    })
end)

run(function()
	local TaxRemover
	local oldDispatch
	local oldtax
	local oldadded
	local olditems
	local oldhook
	local oldConnect
	TaxRemover = vain.Categories.Blatant:CreateModule({
		Name = "TaxRemover",
		Tooltip = 'Removes the resource tax when depositing to shared banks',
		Function = function(callback)
			if callback then
				oldtax = bedwars.ShopTaxController.isTaxed
				oldadded = bedwars.ShopTaxController.getAddedTax
				olditems = bedwars.ShopTaxController.getTaxedItems
				oldDispatch = bedwars.Store.dispatch
				task.spawn(function()
					bedwars.Store.dispatch = function(...)
						local arg = select(2, ...)
						if arg and typeof(arg) == 'table' and arg.type == 'IncrementTaxState'  then
							return false
						end 	
						return oldDispatch(...)
					end
				end)
				task.spawn(function()
					bedwars.ShopTaxController.isTaxed = function(...)
						return 0
					end
				end)
				task.spawn(function()
					bedwars.ShopTaxController.getTaxedItems = function(...)
						return {}
					end
				end)
				task.spawn(function()
					bedwars.ShopTaxController.getAddedTax = function(...)
						return 0
					end
				end)

				task.spawn(function()
					if bedwars.ShopTaxController.taxStateUpdateEvent then
						oldConnect = bedwars.ShopTaxController.taxStateUpdateEvent.Connect
						bedwars.ShopTaxController.taxStateUpdateEvent.Connect = function() 
							return {Disconnect = function() end}
						end
					end
				end)
				task.spawn(function()
					repeat
						store.inventory.taxCheckUpdate = tick()
						if typeof(bedwars.ShopTaxController.hasTax) == "number" then
							bedwars.ShopTaxController.hasTax = 0
						elseif typeof(bedwars.ShopTaxController.hasTax) == "boolean" then
							bedwars.ShopTaxController.hasTax = false
						else
							vain:CreateNotification('TaxRemover',`Tax Remover error the type of hasTax is {typeof(bedwars.ShopTaxController.hasTax)} report to aero or soryed`,16,'alert')
							break
						end
						if typeof(bedwars.ShopTaxController.taxedItems) == "table" then
							bedwars.ShopTaxController.taxedItems = {}
						else
							vain:CreateNotification('TaxRemover',`Tax Remover error the type of taxedItems is NOT a TABLE PLEASE report to aero or soryed ASAP`,16,'alert')
							break
						end
						if typeof(bedwars.ShopTaxController.addedTaxMap) == "table" then
							bedwars.ShopTaxController.addedTaxMap = {}
						else
							vain:CreateNotification('TaxRemover',`Tax Remover error the type of addedTaxMap is NOT a TABLE PLEASE report to aero or soryed ASAP`,16,'alert')
							break
						end
						task.wait()
					until not TaxRemover.Enabled
				end)
			else
				bedwars.Store.dispatch = oldDispatch
				bedwars.ShopTaxController.isTaxed = oldtax
				bedwars.ShopTaxController.getAddedTax = oldadded
				bedwars.ShopTaxController.getTaxedItems = olditems
				bedwars.ShopTaxController.taxStateUpdateEvent.Connect = oldConnect
				oldDispatch = nil
				oldtax = nil
				oldadded = nil
				olditems = nil
				oldConnect = nil
			end
		end
	})
end)

